INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Zmienna (Variable)', 'Nazwane miejsce w pamięci przechowujące wartość określonego typu. Może zmieniać swoją wartość w trakcie działania programu.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stała (Constant)', 'Wartość, która po przypisaniu nie może być zmieniona w trakcie działania programu. Używana do przechowywania niezmiennych konfiguracji i wartości magicznych.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Typ danych (Data Type)', 'Klasyfikacja danych określająca dozwolone wartości i operacje. Podstawowe typy to: int, float, string, boolean.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Typowanie statyczne vs dynamiczne', 'Statyczne — typy sprawdzane w czasie kompilacji (Java, C++, TypeScript). Dynamiczne — typy sprawdzane w czasie wykonania (Python, JavaScript, Ruby).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Operator', 'Symbol lub słowo kluczowe wykonujące operację na operandach. Rodzaje: arytmetyczne (+, -, *), porównania (==, <), logiczne (&&, ||), bitowe (&, |).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyrażenie (Expression)', 'Kombinacja wartości, zmiennych i operatorów, która zwraca wartość. Np. 2 + 3 * x jest wyrażeniem arytmetycznym.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Instrukcja (Statement)', 'Pojedyncza jednostka wykonania w programie. W odróżnieniu od wyrażenia, instrukcja wykonuje akcję, ale niekoniecznie zwraca wartość.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Instrukcja warunkowa (if/else)', 'Konstrukcja sterująca przepływem programu na podstawie warunku logicznego. Pozwala wykonać różne bloki kodu w zależności od tego, czy warunek jest prawdziwy czy fałszywy.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Switch/Case', 'Instrukcja warunkowa porównująca wartość z wieloma przypadkami. Czytelniejsza alternatywa dla łańcucha if-else gdy sprawdzamy jedną zmienną.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pętla for', 'Pętla iterująca określoną liczbę razy. Składa się z inicjalizacji, warunku kontynuacji i kroku. Idealna gdy znamy liczbę iteracji z góry.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pętla while', 'Pętla wykonująca blok kodu dopóki warunek jest prawdziwy. Warunek sprawdzany przed każdą iteracją — może nie wykonać się ani razu.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pętla do-while', 'Pętla gwarantująca co najmniej jedno wykonanie bloku kodu. Warunek sprawdzany jest po wykonaniu ciała pętli, nie przed.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Break i Continue', 'Break przerywa działanie pętli natychmiast. Continue pomija resztę bieżącej iteracji i przechodzi do następnej.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Funkcja (Function)', 'Nazwany blok kodu wykonujący określone zadanie. Przyjmuje parametry wejściowe i opcjonalnie zwraca wartość. Umożliwia ponowne użycie kodu.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Parametr vs Argument', 'Parametr to zmienna w definicji funkcji. Argument to konkretna wartość przekazana przy wywołaniu. Np. def add(a, b) — a, b to parametry; add(2, 3) — 2, 3 to argumenty.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wartość zwracana (Return Value)', 'Dane przekazywane z powrotem do kodu wywołującego funkcję za pomocą instrukcji return. Funkcja może zwracać dowolny typ danych lub void (nic).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zakres zmiennych (Scope)', 'Obszar programu, w którym zmienna jest dostępna. Zakres lokalny — wewnątrz funkcji/bloku. Zakres globalny — w całym programie. Zmienne lokalne przesłaniają globalne.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rekurencja (Recursion)', 'Technika, w której funkcja wywołuje samą siebie. Wymaga warunku bazowego (base case), by uniknąć nieskończonej rekurencji. Przykład: silnia, ciąg Fibonacciego.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stos wywołań (Call Stack)', 'Struktura LIFO przechowująca informacje o aktywnych wywołaniach funkcji. Każde wywołanie dodaje ramkę (frame) na stos. Przepełnienie powoduje Stack Overflow.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tablica (Array)', 'Uporządkowana kolekcja elementów tego samego typu, dostępnych przez indeks numeryczny. Indeksowanie zwykle zaczyna się od 0. Stały rozmiar w wielu językach.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('String (Łańcuch znaków)', 'Sekwencja znaków traktowana jako pojedyncza wartość. W większości języków jest niezmienny (immutable). Obsługuje operacje: konkatenacja, substring, wyszukiwanie.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Null / None / Nil', 'Specjalna wartość reprezentująca brak wartości lub niezainicjalizowaną zmienną. Odwoływanie się do null powoduje NullPointerException/TypeError.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Klasa (Class)', 'Szablon definiujący strukturę i zachowanie obiektów. Zawiera pola (dane) i metody (funkcje). Jest fundamentem programowania obiektowego.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obiekt (Object)', 'Instancja klasy — konkretny egzemplarz utworzony na podstawie szablonu klasy. Posiada własny stan (wartości pól) i zachowanie (metody).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Konstruktor (Constructor)', 'Specjalna metoda wywoływana automatycznie przy tworzeniu obiektu. Służy do inicjalizacji pól obiektu wartościami początkowymi.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Enkapsulacja (Encapsulation)', 'Zasada OOP polegająca na ukrywaniu wewnętrznego stanu obiektu i udostępnianiu go tylko przez zdefiniowane metody (gettery/settery). Chroni integralność danych.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dziedziczenie (Inheritance)', 'Mechanizm OOP pozwalający klasie potomnej dziedziczyć pola i metody klasy bazowej. Umożliwia ponowne użycie kodu i tworzenie hierarchii.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Polimorfizm (Polymorphism)', 'Zdolność obiektów różnych klas do reagowania na to samo wywołanie metody w różny sposób. Umożliwia pisanie elastycznego kodu operującego na abstrakcjach.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Abstrakcja (Abstraction)', 'Ukrywanie szczegółów implementacji i eksponowanie tylko istotnego interfejsu. Klasy abstrakcyjne i interfejsy definiują kontrakt bez implementacji.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Interfejs (Interface)', 'Kontrakt definiujący zestaw metod, które klasa implementująca musi dostarczyć. Nie zawiera implementacji — tylko sygnatury metod.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metoda statyczna (Static Method)', 'Metoda należąca do klasy, nie do instancji. Wywoływana bez tworzenia obiektu. Nie ma dostępu do pól instancji (this/self).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obsługa wyjątków (Exception Handling)', 'Mechanizm przechwytywania i reagowania na błędy w trakcie wykonania programu. Konstrukcja try-catch-finally pozwala obsłużyć błąd bez przerywania działania.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjątek (Exception)', 'Obiekt reprezentujący sytuację błędną w programie. Może być przechwycony (catch) lub propagowany w górę stosu wywołań. Przykłady: FileNotFound, NullPointer.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Generyki / Typy generyczne', 'Mechanizm pozwalający pisać kod niezależny od konkretnego typu danych. Np. List<T> działa z dowolnym typem T. Zapewnia bezpieczeństwo typów przy zachowaniu elastyczności.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Enum (Typ wyliczeniowy)', 'Typ danych definiujący skończony zbiór nazwanych stałych. Np. enum Color { RED, GREEN, BLUE }. Zwiększa czytelność i bezpieczeństwo typów.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolekcja (Collection)', 'Struktura przechowująca grupę obiektów. Typowe implementacje: List (uporządkowana), Set (unikalne elementy), Map (klucz-wartość).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Iterator', 'Obiekt umożliwiający sekwencyjny dostęp do elementów kolekcji bez ujawniania jej struktury wewnętrznej. Wzorzec implementowany przez pętle for-each.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lambda / Funkcja anonimowa', 'Nienazwana funkcja definiowana inline. Często przekazywana jako argument do funkcji wyższego rzędu. Np. (x) => x * 2 w JavaScript.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Domknięcie (Closure)', 'Funkcja, która przechwytuje zmienne z otaczającego zakresu. Zachowuje dostęp do tych zmiennych nawet po zakończeniu zakresu, w którym została utworzona.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Callback', 'Funkcja przekazana jako argument do innej funkcji, wywoływana w odpowiednim momencie. Stosowana w programowaniu asynchronicznym i obsłudze zdarzeń.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Promise / Future', 'Obiekt reprezentujący wynik operacji asynchronicznej, która może zakończyć się w przyszłości. Może być w stanie pending, fulfilled lub rejected.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Async/Await', 'Składnia syntaktyczna dla operacji asynchronicznych, która pozwala pisać kod asynchroniczny w stylu synchronicznym. Eliminuje zagnieżdżone callbacki i łańcuchy .then().', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wątek (Thread)', 'Najmniejsza jednostka wykonania w procesie. Wątki współdzielą pamięć procesu. Wielowątkowość pozwala na równoległe wykonywanie zadań.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Deadlock', 'Sytuacja, w której dwa lub więcej wątków czeka na siebie nawzajem, blokując się wzajemnie. Żaden nie może kontynuować — program się zawiesza.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Garbage Collector (GC)', 'Automatyczny mechanizm zarządzania pamięcią. Identyfikuje i usuwa obiekty, do których nie istnieją referencje. Używany w Java, C#, Go, JavaScript.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Referencja vs Wartość', 'Przekazywanie przez wartość kopiuje dane — zmiana w funkcji nie wpływa na oryginał. Przez referencję — przekazywany jest adres, zmiany wpływają na oryginał.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Immutability (Niezmienność)', 'Obiekt niezmienny nie może być modyfikowany po utworzeniu. Każda zmiana tworzy nową kopię. Ułatwia pisanie bezpiecznego kodu wielowątkowego i funkcyjnego.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('DRY (Don''t Repeat Yourself)', 'Zasada mówiąca, że każda wiedza w systemie powinna mieć jedno, jednoznaczne źródło. Duplikacja kodu prowadzi do błędów i utrudnia utrzymanie.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('KISS (Keep It Simple, Stupid)', 'Zasada projektowa zalecająca prostotę. Prostszy kod jest łatwiejszy do zrozumienia, testowania i utrzymania. Unikaj nadmiernej inżynierii.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('YAGNI (You Aren''t Gonna Need It)', 'Zasada z XP: nie implementuj funkcjonalności, dopóki nie jest naprawdę potrzebna. Zapobiega tworzeniu zbędnego kodu i nadmiernej komplikacji.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SOLID — Single Responsibility', 'Klasa powinna mieć tylko jeden powód do zmiany — jedną odpowiedzialność. Ułatwia testowanie, utrzymanie i zrozumienie kodu.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SOLID — Open/Closed', 'Klasy powinny być otwarte na rozszerzanie, ale zamknięte na modyfikację. Nowe zachowanie dodajemy przez dziedziczenie lub kompozycję, nie edycję istniejącego kodu.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SOLID — Liskov Substitution', 'Obiekty klasy bazowej powinny być wymienne z obiektami klas pochodnych bez wpływu na poprawność programu. Podklasa nie może łamać kontraktu nadklasy.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SOLID — Interface Segregation', 'Wiele wyspecjalizowanych interfejsów jest lepsze niż jeden ogólny. Klasa nie powinna być zmuszana do implementacji metod, których nie używa.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SOLID — Dependency Inversion', 'Moduły wysokopoziomowe nie powinny zależeć od niskopoziomowych — oba powinny zależeć od abstrakcji. Abstrakcje nie zależą od szczegółów.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kompozycja vs Dziedziczenie', 'Kompozycja (obiekt zawiera inne obiekty) jest zwykle preferowana nad dziedziczeniem. Jest bardziej elastyczna — pozwala zmieniać zachowanie w runtime.', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Testy jednostkowe (Unit Tests)', 'Testy weryfikujące poprawność pojedynczych jednostek kodu (funkcji, metod) w izolacji. Szybkie, deterministyczne, niezależne od zewnętrznych zależności.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('TDD (Test-Driven Development)', 'Metodyka: najpierw piszemy test, potem minimalny kod go spełniający, potem refaktorujemy. Cykl Red-Green-Refactor. Prowadzi do lepiej zaprojektowanego kodu.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Git — podstawowe operacje', 'System kontroli wersji. Kluczowe komendy: git add (staging), git commit (zapis), git push (wysyłka), git pull (pobranie), git branch (gałęzie), git merge (łączenie).', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Big-O Notation', 'Notacja opisująca złożoność algorytmu. O(1) — stała, O(log n) — logarytmiczna, O(n) — liniowa, O(n log n) — liniowo-logarytmiczna, O(n²) — kwadratowa.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Tablica (Array)', 'Ciągły blok pamięci przechowujący elementy tego samego typu. Dostęp po indeksie: O(1). Wstawianie/usuwanie w środku: O(n). Stały rozmiar (w wariancie statycznym).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tablica dynamiczna (Dynamic Array)', 'Tablica automatycznie zwiększająca swoją pojemność (zwykle 2x) przy zapełnieniu. Amortyzowane dodawanie na koniec: O(1). Przykłady: ArrayList (Java), vector (C++), list (Python).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lista jednokierunkowa (Singly Linked List)', 'Sekwencja węzłów, gdzie każdy wskazuje na następny. Wstawianie/usuwanie na początku: O(1). Dostęp do elementu: O(n). Brak ciągłej pamięci — gorsze cache hit rate.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lista dwukierunkowa (Doubly Linked List)', 'Każdy węzeł ma wskaźnik na poprzedni i następny. Umożliwia przechodzenie w obu kierunkach. Wstawianie/usuwanie: O(1) przy znanym węźle. Wyszukiwanie: O(n).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stos (Stack)', 'Struktura LIFO (Last In, First Out). Operacje push/pop/peek: O(1). Zastosowania: cofanie operacji (undo), parsowanie nawiasów, stos wywołań.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolejka (Queue)', 'Struktura FIFO (First In, First Out). Operacje enqueue/dequeue: O(1). Zastosowania: BFS, kolejki zadań, buforowanie, systemy komunikatów.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolejka dwustronna (Deque)', 'Kolejka umożliwiająca wstawianie i usuwanie z obu końców w O(1). Może działać jako stos lub kolejka. Implementacja: tablica cykliczna lub lista dwukierunkowa.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolejka priorytetowa (Priority Queue)', 'Kolejka, w której elementy są pobierane wg priorytetu, nie kolejności wstawiania. Zwykle implementowana jako kopiec. Wstawianie i usunięcie min/max: O(log n).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hash Mapa (Hash Map / Hash Table)', 'Struktura klucz-wartość z dostępem średnio O(1). Używa funkcji haszującej do mapowania klucza na indeks tablicy. Kolizje rozwiązywane przez łańcuchowanie lub adresowanie otwarte.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Funkcja haszująca (Hash Function)', 'Funkcja mapująca dane wejściowe na wartość stałego rozmiaru (hash). Dobra funkcja: deterministyczna, równomierny rozkład, minimalizuje kolizje.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolizja w hash mapie', 'Sytuacja, gdy dwa różne klucze dają ten sam hash. Rozwiązania: łańcuchowanie (chaining) — lista w kubełku, lub otwarte adresowanie (open addressing) — szukamy kolejnego wolnego slotu.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zbiór (Set)', 'Kolekcja unikalnych elementów bez określonej kolejności. Sprawdzanie przynależności: O(1) przy implementacji hashowej. Operacje: unia, przecięcie, różnica.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Drzewo (Tree)', 'Hierarchiczna struktura danych składająca się z węzłów. Każdy węzeł ma rodzica (oprócz korzenia) i zero lub więcej dzieci. Brak cykli. Zastosowania: systemy plików, DOM, parsery.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Drzewo binarne (Binary Tree)', 'Drzewo, w którym każdy węzeł ma co najwyżej dwoje dzieci (lewe i prawe). Podstawa dla wielu wyspecjalizowanych struktur drzewiastych.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('BST (Binary Search Tree)', 'Drzewo binarne, gdzie lewe poddrzewo zawiera wartości mniejsze, prawe — większe od węzła. Wyszukiwanie/wstawianie/usuwanie: O(log n) średnio, O(n) w najgorszym przypadku.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Drzewo AVL', 'Samobalansujące BST. Różnica wysokości poddrzew każdego węzła wynosi co najwyżej 1. Rotacje (LL, RR, LR, RL) przywracają balans. Gwarantowane O(log n).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Drzewo czerwono-czarne (Red-Black Tree)', 'Samobalansujące BST z kolorowymi węzłami. Mniej restrykcyjne niż AVL — szybsze wstawianie/usuwanie kosztem nieco wolniejszego wyszukiwania. Używane w TreeMap (Java), std::map (C++).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kopiec (Heap)', 'Drzewo binarne spełniające warunek kopca: rodzic jest ≤ (min-heap) lub ≥ (max-heap) dzieci. Implementacja: tablica. Wstawianie/usuwanie korzenia: O(log n). Budowa: O(n).', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('B-drzewo (B-Tree)', 'Samobalansujące drzewo wielokierunkowe zoptymalizowane pod operacje dyskowe. Węzły mają wiele kluczy i dzieci. Używane w bazach danych i systemach plików. Wszystkie operacje: O(log n).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Trie (Drzewo prefiksowe)', 'Drzewo, gdzie każda krawędź reprezentuje znak. Ścieżka od korzenia do węzła tworzy prefiks. Wyszukiwanie słowa: O(m), gdzie m = długość słowa. Idealne do autouzupełniania.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Graf (Graph)', 'Struktura składająca się z wierzchołków (vertices) i krawędzi (edges) łączących pary wierzchołków. Może być skierowany lub nieskierowany, ważony lub nieważony.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Graf skierowany vs nieskierowany', 'Skierowany (digraph): krawędzie mają kierunek (A→B ≠ B→A). Nieskierowany: krawędzie są obustronne. Przykład skierowanego: sieć ulic jednokierunkowych.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reprezentacja grafu: macierz sąsiedztwa', 'Tablica 2D rozmiaru V×V, gdzie matrix[i][j]=1 oznacza krawędź. Sprawdzanie krawędzi: O(1). Pamięć: O(V²). Efektywna dla gęstych grafów.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reprezentacja grafu: lista sąsiedztwa', 'Tablica list — każdy wierzchołek ma listę sąsiadów. Pamięć: O(V + E). Iteracja po sąsiadach: O(stopień). Preferowana dla rzadkich grafów.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('BFS (Breadth-First Search)', 'Przeszukiwanie grafu wszerz. Używa kolejki. Odwiedza wierzchołki warstwa po warstwie. Złożoność: O(V + E). Znajduje najkrótszą ścieżkę w grafie nieważonym.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('DFS (Depth-First Search)', 'Przeszukiwanie grafu w głąb. Używa stosu (lub rekurencji). Idzie jak najdalej przed cofaniem. Złożoność: O(V + E). Wykrywanie cykli, sortowanie topologiczne.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dijkstra — najkrótsza ścieżka', 'Algorytm znajdujący najkrótszą ścieżkę od źródła do wszystkich wierzchołków w grafie ważonym (wagi ≥ 0). Złożoność: O((V + E) log V) z kolejką priorytetową.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sortowanie topologiczne', 'Liniowe uporządkowanie wierzchołków DAG (graf acykliczny skierowany) tak, by każda krawędź prowadziła od wcześniejszego do późniejszego elementu. Algorytm Kahna lub DFS.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przechodzenie drzewa: inorder', 'Lewe poddrzewo → Korzeń → Prawe poddrzewo. Dla BST daje elementy w porządku rosnącym. Złożoność: O(n).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przechodzenie drzewa: preorder', 'Korzeń → Lewe poddrzewo → Prawe poddrzewo. Używane do kopiowania drzewa i serializacji. Złożoność: O(n).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przechodzenie drzewa: postorder', 'Lewe poddrzewo → Prawe poddrzewo → Korzeń. Używane do usuwania drzewa i obliczania wyrażeń. Złożoność: O(n).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sortowanie bąbelkowe (Bubble Sort)', 'Porównuje sąsiednie elementy i zamienia je, jeśli są w złej kolejności. Złożoność: O(n²). Stabilne. Proste ale nieefektywne — głównie edukacyjne.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sortowanie przez wstawianie (Insertion Sort)', 'Buduje posortowany ciąg element po elemencie, wstawiając każdy w odpowiednie miejsce. O(n²) średnio, O(n) dla prawie posortowanych danych. Stabilne.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sortowanie przez scalanie (Merge Sort)', 'Algorytm dziel i zwyciężaj: dzieli tablicę na pół, sortuje rekurencyjnie, scala. Złożoność: O(n log n) zawsze. Stabilne. Wymaga O(n) dodatkowej pamięci.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sortowanie szybkie (Quick Sort)', 'Dziel i zwyciężaj: wybiera pivot, partycjonuje elementy na mniejsze i większe. Średnio O(n log n), pesymistycznie O(n²). In-place. Zwykle najszybszy w praktyce.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sortowanie przez kopcowanie (Heap Sort)', 'Buduje max-heap, wielokrotnie wyciąga korzeń (max) na koniec tablicy. Złożoność: O(n log n) zawsze. In-place, ale niestabilne.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sortowanie przez zliczanie (Counting Sort)', 'Zlicza wystąpienia każdej wartości i na tej podstawie buduje wynik. Złożoność: O(n + k), gdzie k = zakres wartości. Nie oparty na porównaniach. Efektywny dla małego k.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyszukiwanie binarne (Binary Search)', 'Wyszukiwanie w posortowanej tablicy: porównuje środkowy element, eliminuje połowę. Złożoność: O(log n). Wymaga posortowanych danych. Iteracyjne lub rekurencyjne.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tablica z haszowaniem (Hash Set)', 'Zbiór unikalnych elementów z operacjami dodawania, usuwania i sprawdzania przynależności w średnim O(1). Implementacja oparta na hash tabeli.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Drzewo przedziałowe (Segment Tree)', 'Drzewo binarne przechowujące informacje o przedziałach tablicy. Zapytanie i aktualizacja na przedziale: O(log n). Używane w zadaniach z zapytaniami zakresowymi (suma, min, max).', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Union-Find (Disjoint Set)', 'Struktura zarządzająca zbiorami rozłącznymi. Operacje Find (znajdź zbiór) i Union (połącz zbiory) — prawie O(1) z kompresją ścieżki i łączeniem rangą. Używana w algorytmie Kruskala.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('LRU Cache', 'Cache z polityką usuwania najdawniej używanego elementu (Least Recently Used). Implementacja: hash mapa + lista dwukierunkowa. Dostęp i wstawianie: O(1).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Filtr Blooma (Bloom Filter)', 'Probabilistyczna struktura sprawdzająca przynależność do zbioru. Może dać false positive, nigdy false negative. Bardzo oszczędna pamięciowo. Używana w cache, bazach danych.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tablica sufiksowa (Suffix Array)', 'Posortowana tablica wszystkich sufiksów tekstu. Umożliwia szybkie wyszukiwanie wzorca w tekście: O(m log n). Bardziej pamięciooszczędna niż drzewo sufiksowe.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Skip List', 'Probabilistyczna struktura danych: lista z wieloma poziomami „skrótów". Wyszukiwanie/wstawianie/usuwanie: O(log n) średnio. Prostsza alternatywa dla zbalansowanych drzew.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bufor cykliczny (Circular Buffer)', 'Tablica o stałym rozmiarze z dwoma wskaźnikami (head/tail) działająca jak kolejka FIFO. Gdy tail dojdzie do końca, owija się na początek. Wstawianie/usuwanie: O(1).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Programowanie dynamiczne (DP)', 'Technika rozwiązywania problemów z podproblemami nakładającymi się. Zamiast liczyć wielokrotnie to samo, zapisuje wyniki (memoizacja lub tabulacja). Przykłady: plecakowy, LCS.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Algorytm zachłanny (Greedy)', 'W każdym kroku wybiera lokalnie najlepszą opcję, licząc że prowadzi to do globalnego optimum. Nie zawsze daje optymalne rozwiązanie. Przykłady: Dijkstra, Huffman, problem wydawania reszty.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dziel i zwyciężaj (Divide and Conquer)', 'Strategia algorytmiczna: dzieli problem na mniejsze podproblemy, rozwiązuje je rekurencyjnie, łączy wyniki. Przykłady: Merge Sort, Quick Sort, wyszukiwanie binarne.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Złożoność amortyzowana', 'Średnia złożoność operacji w serii operacji. Pojedyncza operacja może być kosztowna, ale rozkłada się na wiele tanich. Np. dodawanie do tablicy dynamicznej: O(1) amortyzowane.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Komponent (Component)', 'Podstawowy blok budulcowy UI w Angular. Dekorator @Component definiuje selektor, szablon i style. W Angular 17+ domyślnie standalone — nie wymaga NgModule.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Standalone Component', 'Komponent z standalone: true (domyślne od v17). Samodzielnie deklaruje zależności w tablicy imports. Eliminuje potrzebę NgModule dla większości przypadków.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Signal (Sygnał)', 'Reaktywna wartość wprowadzona w Angular 16+. Tworzona przez signal(initialValue). Odczyt: mySignal(). Zapis: mySignal.set()/update(). Automatycznie powiadamia konsumentów o zmianach.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('computed()', 'Tworzy sygnał pochodny, którego wartość jest automatycznie przeliczana, gdy zmienią się sygnały źródłowe. Leniwy — oblicza się dopiero przy odczycie. Zawsze readonly.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('effect()', 'Wykonuje efekt uboczny (side effect) za każdym razem, gdy zmienią się sygnały odczytane wewnątrz niego. Uruchamiany w kontekście injection. Służy do logowania, synchronizacji z localStorage itp.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('linkedSignal()', 'Sygnał powiązany z innym źródłem — resetuje się automatycznie, gdy źródło się zmieni. Przydatny np. do resetowania wybranego elementu, gdy zmieni się lista.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('resource() / rxResource()', 'API do asynchronicznego pobierania danych w oparciu o sygnały. resource() dla Promise, rxResource() dla Observable. Zapewnia stany: loading, value, error.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('input() — Signal Input', 'Funkcja input() tworzy input oparty na sygnale (od v17.1). Typy: input<string>() (wymagany), input(defaultValue) (opcjonalny). Zastępuje dekorator @Input().', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('output()', 'Funkcja output() tworzy output oparty na EventEmitter (od v17.1). Zastępuje @Output(). Użycie: myOutput = output<string>(); this.myOutput.emit(value).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('model() — Two-way Binding', 'Funkcja model() tworzy sygnał z dwukierunkowym bindingiem (od v17.2). Rodzic używa [(myModel)]="value". Zastępuje kombinację @Input + @Output.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('@if / @else — Control Flow', 'Wbudowana składnia warunkowa w szablonach (od v17). Zastępuje *ngIf. Składnia: @if (condition) { ... } @else { ... }. Lepsza wydajność i czytelność.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('@for — Control Flow', 'Wbudowana pętla w szablonach (od v17). Zastępuje *ngFor. Składnia: @for (item of items; track item.id) { ... } @empty { ... }. Wymaga track expression.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('@switch — Control Flow', 'Wbudowany switch w szablonach (od v17). Składnia: @switch (value) { @case (x) { ... } @default { ... } }. Zastępuje [ngSwitch].', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('@defer — Lazy Loading bloków', 'Odkłada ładowanie części szablonu do momentu spełnienia warunku. Triggery: on viewport, on idle, on hover, on interaction, on timer, when condition. Zmniejsza initial bundle.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dependency Injection (DI)', 'Mechanizm dostarczania zależności komponentom i serwison. Hierarchiczny system injectorów. providedIn: ''root'' rejestruje singleton globalnie. inject() zamiast konstruktora.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('inject() Function', 'Funkcja pobierająca zależność z injectora (od v14). Używana w konstruktorze lub w kontekście injection. Zastępuje wstrzykiwanie przez parametry konstruktora.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Serwis (Service)', 'Klasa z logiką biznesową, dostępem do danych lub współdzielonym stanem. Dekorator @Injectable(). Wstrzykiwana przez DI. Nie zależy od UI.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Routing', 'System nawigacji w SPA. Konfiguracja: Routes[] z path, component, loadComponent (lazy). provideRouter(routes) w app.config.ts. RouterOutlet wyświetla aktywny komponent.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lazy Loading (loadComponent)', 'Opóźnione ładowanie komponentu route''a: loadComponent: () => import(''./page.component''). Tworzy osobny chunk JS. Zmniejsza czas ładowania aplikacji.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Guard (Route Guard)', 'Funkcja kontrolująca dostęp do route''a. canActivate, canDeactivate, canMatch, resolve. Zwraca boolean, UrlTree lub Observable. Służy do autoryzacji i walidacji.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Resolver', 'Funkcja ładująca dane przed aktywacją route''a. Gwarantuje, że dane są dostępne przy wyświetleniu komponentu. Zwraca Observable lub Promise.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reactive Forms', 'Formularz sterowany kodem TypeScript. FormControl, FormGroup, FormArray. Walidacja synchroniczna i async. Pełna kontrola nad wartościami i stanami formularza.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Template-driven Forms', 'Formularz sterowany dyrektywami w szablonie (ngModel). Prostszy, ale mniej elastyczny niż Reactive Forms. Odpowiedni dla prostych formularzy.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pipe (Rura)', 'Transformuje dane w szablonie. Wbudowane: date, currency, async, json. Tworzenie własnych: @Pipe + transform(). Pipe ''async'' automatycznie subskrybuje Observable/Signal.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dyrektywa (Directive)', 'Klasa modyfikująca zachowanie lub wygląd elementu DOM. Strukturalne (*ngIf, *ngFor — zastępowane przez @if, @for). Atrybutowe (ngClass, ngStyle). Własne dyrektywy.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('viewChild() / viewChildren()', 'Signal queries do elementów w widoku komponentu (od v17.2). viewChild(''ref'') zwraca Signal<ElementRef>. Zastępuje dekoratoryy @ViewChild/@ViewChildren.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('contentChild() / contentChildren()', 'Signal queries do elementów projektowanych (ng-content). contentChild() i contentChildren() zwracają sygnały. Zastępują @ContentChild/@ContentChildren.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('NgModule', 'Moduł grupujący komponenty, dyrektywy, pipe''y i serwisy. W Angular 17+ standalone components eliminują potrzebę NgModule. Wciąż używany w starszym kodzie.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('HttpClient', 'Serwis do komunikacji HTTP. Zwraca Observable. Konfiguracja: provideHttpClient(). Interceptory (withInterceptors) do modyfikacji żądań/odpowiedzi.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Interceptor (funkcyjny)', 'Funkcja przechwytująca żądania HTTP. Nowy styl (v15+): HttpInterceptorFn. Używana do: dodawania tokenów, logowania, obsługi błędów, retry. Rejestracja: withInterceptors([fn]).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('RxJS Observable', 'Strumień danych asynchronicznych. Leniwy — nie emituje, dopóki nie zasubskrybowany. Operatory (map, filter, switchMap, catchError) tworzą pipeline transformacji danych.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subject vs BehaviorSubject', 'Subject: multicast Observable + Observer. BehaviorSubject: przechowuje ostatnią wartość i emituje ją nowym subskrybentom natychmiast. Wymaga wartości początkowej.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('switchMap', 'Operator RxJS: anuluje poprzednią wewnętrzną subskrypcję przy każdej nowej emisji. Idealny do wyszukiwania (typeahead) i nawigacji — tylko ostatni wynik się liczy.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('takeUntilDestroyed', 'Operator RxJS z @angular/core/rxjs-interop. Automatycznie odsubskrybowuje Observable przy zniszczeniu komponentu/serwisu. Zastępuje ręczne unsubscribe.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('toSignal() / toObservable()', 'Funkcje z @angular/core/rxjs-interop. toSignal() konwertuje Observable na Signal. toObservable() — odwrotnie. Most między światem RxJS i Signals.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Change Detection', 'Mechanizm wykrywania zmian w Angular. Zone.js przechwytuje zdarzenia async i triggeruje sprawdzenie. OnPush sprawdza tylko przy zmianie inputów/zdarzeń. Signals to przyszłość — zoneless.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('OnPush Change Detection', 'Strategia: komponent sprawdzany tylko gdy zmienią się jego inputy (referencja), wyemituje event, lub ręcznie wywołamy markForCheck(). Znacząco poprawia wydajność.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zoneless Angular', 'Tryb bez Zone.js (eksperymentalny od v18). Zmiany wykrywane przez Signals. provideZonelessChangeDetection(). Mniejszy bundle, lepsza wydajność, prostszy model mentalny.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lifecycle Hooks', 'Metody wywoływane w kluczowych momentach życia komponentu. ngOnInit (po inicjalizacji), ngOnChanges (przy zmianie inputów), ngOnDestroy (przed zniszczeniem). afterNextRender() dla DOM.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('afterRender() / afterNextRender()', 'Callbacki wykonywane po renderowaniu DOM (od v16.2). afterNextRender() — raz, afterRender() — po każdym renderze. Zastępują ngAfterViewInit dla operacji DOM.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ng-content (Content Projection)', 'Mechanizm wstawiania treści rodzica do szablonu dziecka. Jak slot w Web Components. Wielokrotne sloty: <ng-content select="[header]">. Umożliwia tworzenie elastycznych layoutów.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Angular CLI', 'Narzędzie wiersza poleceń: ng new (nowy projekt), ng generate (generowanie kodu), ng serve (dev server), ng build (produkcja), ng test (testy). Konfiguracja: angular.json.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Environment / APP_INITIALIZER', 'Konfiguracja środowiskowa: pliki environment.ts. APP_INITIALIZER wykonuje kod przed startem aplikacji (np. ładowanie konfiguracji). provideAppInitializer() od v19.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('InjectionToken', 'Token umożliwiający wstrzykiwanie wartości nie-klasowych (stringi, obiekty konfiguracji). new InjectionToken<Type>(''opis''). Używany z provide/useValue w providers.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Host Element Binding', 'Wiązanie właściwości i zdarzeń na hoście komponentu. Nowy sposób: host: { ''[class.active]'': ''isActive()'', ''(click)'': ''onClick()'' } w metadanych @Component.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Angular Animations', 'System animacji oparty na Web Animations API. trigger(), transition(), animate(), style(). Konfiguracja: provideAnimationsAsync(). Animacje wejścia/wyjścia elementów.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SSR (Server-Side Rendering)', 'Renderowanie aplikacji na serwerze. Angular Universal / @angular/ssr. Poprawia SEO i First Contentful Paint. Hydration (od v16) przejmuje server-rendered DOM bez ponownego renderowania.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prerendering (SSG)', 'Generowanie statycznego HTML w czasie budowania. Szybsze niż SSR — nie wymaga serwera. Konfiguracja w angular.json: prerender: true. Idealne dla stron ze statyczną treścią.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('NgOptimizedImage', 'Dyrektywa optymalizująca obrazy: lazy loading, preconnect, srcset, fill mode. Import: NgOptimizedImage. Użycie: <img ngSrc="..." width="..." height="...">. Poprawia Core Web Vitals.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Testing w Angular', 'TestBed konfiguruje środowisko testowe. ComponentFixture daje dostęp do komponentu i DOM. Jasmine/Jest jako test runner. fakeAsync/tick dla kodu asynchronicznego. provideHttpClientTesting() dla HTTP.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('JSX', 'Rozszerzenie składni JavaScript pozwalające pisać HTML-owy markup w kodzie JS. Kompilowane do React.createElement(). Wymaga jednego elementu nadrzędnego — <Fragment> (<>) gdy nie chcesz dodawać DOM.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komponent funkcyjny', 'Funkcja JavaScript zwracająca JSX. Podstawowy sposób tworzenia komponentów w React. Przyjmuje props jako argument. Hooks dodają stan i efekty.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Props', 'Dane przekazywane z komponentu rodzica do dziecka. Tylko do odczytu (read-only). Mogą być dowolnego typu: string, number, function, komponent. Destructuring w parametrach.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('children (Props)', 'Specjalny prop zawierający elementy zagnieżdżone w komponencie. Umożliwia kompozycję — komponent może opakowywać dowolną treść: <Card><p>content</p></Card>.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useState', 'Hook do zarządzania lokalnym stanem komponentu. Zwraca [wartość, setter]. Setter może przyjmować nową wartość lub funkcję aktualizującą. Re-render przy zmianie.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useEffect', 'Hook do wykonywania efektów ubocznych (fetch, subskrypcje, DOM). Uruchamiany po renderze. Tablica zależności kontroluje kiedy się uruchamia. Funkcja cleanup przy demontażu.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useRef', 'Hook zwracający mutowalny obiekt ref (.current) zachowywany między renderami. Dwa zastosowania: referencja do elementu DOM i przechowywanie wartości bez re-renderu.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useContext', 'Hook odczytujący wartość z najbliższego Context.Provider w drzewie. Unika prop drilling. Re-renderuje komponent gdy wartość kontekstu się zmieni.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useMemo', 'Hook memoizujący wartość obliczoną — przelicza tylko gdy zmienią się zależności. Optymalizacja: unika kosztownych obliczeń przy każdym renderze. Nie gwarantuje cache — React może odrzucić.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useCallback', 'Hook memoizujący funkcję — zwraca tę samą referencję, dopóki zależności się nie zmienią. Przydatny przy przekazywaniu callbacków do zmemoizowanych komponentów dziecięcych.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useReducer', 'Hook do zarządzania złożonym stanem. Przyjmuje reducer (state, action) => newState i wartość początkową. Alternatywa dla wielu useState. Wzorzec znany z Redux.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useId', 'Hook generujący stabilny, unikalny identyfikator. Używany do powiązania label z input (htmlFor/id), atrybutów ARIA. Generuje ten sam ID na serwerze i kliencie (SSR-safe).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useTransition', 'Hook oznaczający aktualizację stanu jako niepriorytetową (transition). Umożliwia natychmiastową reakcję UI na pilne zmiany, odkładając ciężkie re-rendery. Zwraca [isPending, startTransition].', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useDeferredValue', 'Hook opóźniający aktualizację wartości do momentu, gdy przeglądarka nie jest zajęta. Podobny do useTransition, ale dla wartości, nie akcji. Dobry do filtrowania dużych list.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('use() — React 19', 'Nowy hook (React 19) do odczytywania zasobów: Promise i Context. W odróżnieniu od innych hooków, może być wywoływany warunkowo. use(promise) integruje się z Suspense.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useActionState — React 19', 'Hook do obsługi akcji formularzy (React 19). Zwraca [state, formAction, isPending]. Działa z Server Actions i zwykłymi formularzami. Zastępuje useFormState.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useOptimistic — React 19', 'Hook do optymistycznych aktualizacji UI (React 19). Tymczasowo pokazuje oczekiwany wynik przed zakończeniem operacji async. Automatycznie wycofuje przy błędzie.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Własny Hook (Custom Hook)', 'Funkcja zaczynająca się od „use", która kompozytuje inne hooki. Wydziela reużywalną logikę stanową. Każde użycie ma własny stan — hooki nie współdzielą stanu.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('React.memo', 'HOC zapobiegający re-renderowi komponentu, gdy props nie zmieniły się (shallow comparison). Optymalizacja — stosuj dla komponentów renderowanych często z tymi samymi props.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('React Compiler', 'Automatyczny kompilator (React 19+) optymalizujący re-rendery. Automatycznie memoizuje komponenty, hooki i wyrażenia JSX. Eliminuje potrzebę ręcznego memo/useMemo/useCallback.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Context API', 'Mechanizm udostępniania danych w drzewie bez prop drilling. createContext() tworzy kontekst, Provider dostarcza wartość, useContext() konsumuje. Dobry dla motywów, locale, auth.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Suspense', 'Komponent wyświetlający fallback (np. spinner) podczas oczekiwania na załadowanie asynchronicznego zasobu (lazy komponent, dane). <Suspense fallback={<Loader />}>. Granica ładowania.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('React.lazy', 'Funkcja do dynamicznego importu komponentów: React.lazy(() => import(''./Component'')). Tworzy osobny chunk. Wymaga Suspense. Code splitting na poziomie route''ów.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Error Boundary', 'Komponent klasowy przechwytujący błędy w podrzewie komponentów. Metody: getDerivedStateFromError(), componentDidCatch(). Wyświetla fallback UI zamiast białego ekranu.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Key (klucz)', 'Specjalny atrybut identyfikujący element w liście. Pomaga React rozpoznać, które elementy się zmieniły, dodano lub usunięto. Musi być unikalny wśród rodzeństwa. Nie używaj indeksu tablicy.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Controlled vs Uncontrolled Component', 'Controlled: React zarządza wartością inputa (value + onChange). Uncontrolled: DOM zarządza wartością (ref). Controlled daje pełną kontrolę, uncontrolled jest prostszy.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Portale (Portals)', 'ReactDOM.createPortal(child, domNode) renderuje dziecko w innym węźle DOM. Stosuj do modali, tooltipów, popoverów — elementy muszą wizualnie „uciec" z kontenera rodzica.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Forwarding Refs', 'React.forwardRef() pozwala przekazać ref do wewnętrznego elementu DOM komponentu. Przydatne w komponentach bibliotecznych, by rodzic mógł uzyskać dostęp do DOM dziecka.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Virtual DOM', 'Lekka kopia prawdziwego DOM trzymana w pamięci. React porównuje nowe drzewo z poprzednim (diffing), oblicza minimalne zmiany i batch''uje aktualizacje prawdziwego DOM.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reconciliation (Uzgadnianie)', 'Algorytm porównujący dwa drzewa Virtual DOM. Heurystyki: różne typy → wymiany całe poddrzewo, key identyfikuje elementy w listach. Złożoność: O(n).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Batching aktualizacji', 'React grupuje wiele setState w jedną aktualizację DOM. Od React 18 — automatyczny batching we wszystkich kontekstach (zdarzenia, setTimeout, Promises, fetch). Mniej re-renderów.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('StrictMode', '<React.StrictMode> pomaga znaleźć problemy w rozwoju. Renderuje komponenty dwukrotnie (dev only) do wykrycia nieczystych renderów. Uruchamia efekty dwukrotnie. Nie wpływa na produkcję.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Server Components (RSC)', 'Komponenty renderowane na serwerze — nigdy nie trafiają do bundla klienta. Mogą bezpośrednio odczytywać bazę/plik. Nie mogą używać hooków ani zdarzeń. Domyślne w Next.js App Router.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Server Actions', 'Funkcje async z dyrektywą "use server", wywoływane z klienta — wykonywane na serwerze. Używane do mutacji danych (formularz, przycisk). Integracja z useActionState.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('"use client" Directive', 'Dyrektywa oznaczająca komponent jako kliencki w architekturze RSC. Komponenty z "use client" mogą używać hooków, zdarzeń i stanu przeglądarki. Granica między serwerem a klientem.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zustand', 'Minimalistyczna biblioteka stanu globalnego. Store to hook: const useStore = create((set) => ({...})). Prostsze niż Redux, bez boilerplate. Selector pattern do optymalizacji.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Redux Toolkit', 'Oficjalny toolset do Redux: createSlice (reducer + actions), configureStore, createAsyncThunk. Upraszcza Redux boilerplate. Immer pozwala „mutować" stan w reducerach.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('TanStack Query (React Query)', 'Biblioteka do zarządzania stanem serwerowym. Automatyczny cache, refetch, stale-while-revalidate. useQuery (GET), useMutation (POST/PUT/DELETE). Eliminuje ręczne zarządzanie loading/error.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('React Router', 'Biblioteka routingu. Komponenty: <BrowserRouter>, <Routes>, <Route>. Hooki: useNavigate, useParams, useSearchParams, useLocation. Loader i action (v6.4+) dla data fetching.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Next.js App Router', 'System routingu Next.js oparty na folderach (app/). page.tsx, layout.tsx, loading.tsx, error.tsx. Domyślne Server Components. Streaming z Suspense. Metadata API dla SEO.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SSR vs SSG vs ISR', 'SSR: renderowanie na serwerze przy każdym żądaniu. SSG: generowanie statycznego HTML w build time. ISR: regeneracja statycznych stron w tle po ustaloonym czasie. Wybór zależy od świeżości danych.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hydration', 'Proces „ożywiania" statycznego HTML wyrenderowanego na serwerze — React podpina event handlery i stan do istniejącego DOM zamiast renderować od nowa. Mismatch powoduje błędy.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('useFormStatus — React 19', 'Hook odczytujący stan formularza rodzica (pending). Używany w komponentach wewnątrz <form> z Server Action. const { pending } = useFormStatus(). Dla przycisków „Wysyłanie...".', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('React Testing Library', 'Biblioteka testowa promująca testowanie zachowania, nie implementacji. render() montuje komponent, screen.getByRole/getByText wyszukuje elementy, userEvent symuluje interakcje.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Higher-Order Component (HOC)', 'Funkcja przyjmująca komponent i zwracająca nowy komponent z dodatkowym zachowaniem. Wzorzec kompozycji. Współcześnie zastępowany przez Custom Hooks jako prostszy alternatywny.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Render Props', 'Wzorzec: komponent przyjmuje funkcję jako prop (lub children), która zwraca JSX. Pozwala współdzielić logikę stanową. Dziś rzadziej używany — zastąpiony przez hooki.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('CSS Modules', 'Pliki .module.css generujące unikalne nazwy klas. Import: import styles from ''./X.module.css''. Używanie: className={styles.header}. Zapobiega kolizjom nazw. Wspierane natywnie.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fragment (<> </>)', 'Komponent grupujący wiele elementów bez dodawania DOM node. <React.Fragment> lub skrót <> </>. Wersja z key: <Fragment key={id}>. Rozwiązuje problem jednego elementu nadrzędnego.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Concurrent Rendering', 'Mechanizm React 18+: renderowanie jest przerywalne. React może wstrzymać rendering, obsłużyć pilniejszą aktualizację i wrócić. Wspiera Suspense, useTransition, useDeferredValue.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prop Drilling', 'Problem: przekazywanie danych przez wiele warstw komponentów, które same ich nie potrzebują. Rozwiązania: Context API, state management (Zustand, Redux), kompozycja komponentów.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Composition API', 'API do organizacji logiki komponentu w Vue 3. Funkcja setup() lub <script setup>. Umożliwia grupowanie logiki wg funkcji, nie wg opcji. Lepsze TypeScript support i reużywalność.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('<script setup>', 'Skrót składniowy Composition API. Zmienne i funkcje zadeklarowane na top-level są automatycznie dostępne w szablonie. Mniej boilerplate niż export default { setup() }.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ref()', 'Tworzy reaktywną referencję dla wartości prymitywnych i obiektów. Dostęp do wartości: myRef.value w JS, automatyczny unwrap w szablonie. Śledzony przez system reaktywności.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('reactive()', 'Tworzy reaktywny obiekt (Proxy). Działa tylko z obiektami, nie prymitywami. Nie wymaga .value. Nie można zastąpić całego obiektu — traci reaktywność. Preferuj ref() w większości przypadków.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('computed()', 'Tworzy wartość obliczaną, automatycznie przeliczaną przy zmianie zależności. Cachowana — nie przelicza się, jeśli zależności nie zmieniły się. Zwraca ref. Opcjonalnie: get/set.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('watch()', 'Obserwuje źródło reaktywne i wykonuje callback przy zmianie. Źródło: ref, reactive, getter. Opcje: immediate, deep, once. Zwraca funkcję stop do ręcznego zatrzymania.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('watchEffect()', 'Automatycznie śledzi reaktywne zależności użyte wewnątrz callbacka i re-wykonuje się przy ich zmianie. Nie trzeba deklarować zależności explicite. Uruchamia się od razu.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Composable', 'Funkcja zaczynająca się od „use", enkapsulująca logikę z Composition API. Np. useFetch(), useAuth(). Odpowiednik Custom Hook z React. Reużywalny, testowalny.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Props (defineProps)', 'Dane przekazywane z rodzica do dziecka. <script setup>: const props = defineProps<{ title: string }>() z pełnym TypeScript support. Walidacja typów w runtime i compile-time.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Emit (defineEmits)', 'Mechanizm komunikacji dziecka z rodzicem. defineEmits<{ (e: ''update'', value: string): void }>(). Dziecko: emit(''update'', data). Rodzic: @update="handler".', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('v-model', 'Dwukierunkowy binding danych. Na inputach: wiąże value + input event. Na komponentach: modelValue prop + update:modelValue emit. Wiele v-model: v-model:title, v-model:content.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('defineModel() — Vue 3.4+', 'Makro upraszczające v-model w komponentach. const title = defineModel<string>(''title''). Zwraca ref — zmiana automatycznie emituje update. Eliminuje boilerplate prop+emit.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('v-bind (:)', 'Dynamicznie wiąże atrybut HTML lub prop komponentu z wyrażeniem JS. Skrót: :attr="expr". v-bind="obj" — spreaduje obiekt na atrybuty. Klasy: :class="[a, { b: true }]".', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('v-on (@)', 'Nasłuchuje zdarzenia DOM lub niestandardowe. Skrót: @click="handler". Modyfikatory: .prevent, .stop, .once, .self, .capture. Dostęp do eventu: @click="handler($event)".', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('v-if / v-else / v-else-if', 'Warunkowo renderuje element. Tworzy/niszczy element w DOM. Leniwe — nie renderuje, dopóki warunek nie jest prawdziwy. Różnica od v-show: pełne montowanie/odmontowanie.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('v-show', 'Warunkowo wyświetla element przez CSS display: none. Element zawsze istnieje w DOM. Szybsze przełączanie niż v-if. Używaj dla elementów często przełączanych.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('v-for', 'Renderuje listę elementów na podstawie tablicy/obiektu. Składnia: v-for="(item, index) in items" :key="item.id". Key jest obowiązkowy — umożliwia efektywne śledzenie.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sloty (Slots)', 'Mechanizm content projection. <slot> w dziecku, treść w rodzicu. Named slots: <slot name="header"> + <template #header>. Scoped slots: slot przekazuje dane do rodzica.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('provide() / inject()', 'Mechanizm przekazywania danych w dół drzewa bez prop drilling. provide(key, value) w przodku, inject(key) w potomku. Może być reaktywne (ref/computed).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lifecycle Hooks', 'Funkcje wywoływane w kluczowych momentach życia komponentu. onMounted (po montażu DOM), onUpdated (po aktualizacji), onUnmounted (przed odmontowaniem). Wywoływane w setup().', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Template Refs', 'Referencje do elementów DOM: <div ref="myDiv">. W <script setup>: const myDiv = ref<HTMLDivElement>(). Dostępne po onMounted. Dla komponentów: ref do instancji.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pinia — Store', 'Oficjalna biblioteka state management dla Vue 3. defineStore(id, () => { ... }) z Composition API. Store to composable — zawiera state (ref), getters (computed), actions (funkcje).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pinia — storeToRefs()', 'Konwertuje reaktywne właściwości store''a na referencje zachowujące reaktywność. Bez tego destrukturyzacja traci reaktywność. const { count } = storeToRefs(store).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vue Router', 'Oficjalny router. createRouter({ history, routes }). <RouterView> wyświetla komponent route''a. <RouterLink> do nawigacji. useRouter() i useRoute() composables.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Navigation Guards', 'Funkcje kontrolujące nawigację. Globalne: router.beforeEach(). Per-route: beforeEnter. W komponencie: onBeforeRouteLeave. Zwracają false (blokuj) lub ścieżkę (przekieruj).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lazy Loading (Routes)', 'Dynamiczny import komponentu route''a: component: () => import(''./Page.vue''). Tworzy osobny chunk JS. Zmniejsza initial bundle. Automatycznie obsługiwany przez bundler.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Teleport', 'Wbudowany komponent renderujący zawartość w innym miejscu DOM. <Teleport to="body">modal</Teleport>. Odpowiednik React Portals. Używany do modali, tooltipów, dropdownów.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Transition / TransitionGroup', 'Wbudowane komponenty do animacji wejścia/wyjścia elementów. CSS klasy: v-enter-from, v-enter-active, v-leave-to. TransitionGroup dla list. Integracja z bibliotekami animacji.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Suspense', 'Komponent eksperymentalny wyświetlający fallback podczas ładowania async komponentów lub async setup(). <Suspense> z #default i #fallback slotami. Podobny do React Suspense.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('KeepAlive', 'Komponent cachujący nieaktywne komponenty zamiast je niszczyć. <KeepAlive><Component /></KeepAlive>. Props: include, exclude, max. Hooki: onActivated, onDeactivated.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dyrektywa niestandardowa', 'Niskopoziomowy dostęp do DOM. const vFocus = { mounted: (el) => el.focus() }. Użycie: <input v-focus>. Hooki: created, beforeMount, mounted, updated, unmounted.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Plugin', 'Rozszerzenie dodające funkcjonalność globalną. app.use(plugin). Plugin to obiekt z metodą install(app, options). Używany do: dodawania komponentów globalnych, dyrektyw, provide.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Shallow Ref (shallowRef)', 'Ref śledzący tylko zmianę samej referencji, nie głębokich zmian obiektu. Optymalizacja dla dużych obiektów, których pola zmieniamy triggerRef() manualnie.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('toRef() / toRefs()', 'toRef(reactive, ''key'') — tworzy ref powiązany z polem reaktywnego obiektu. toRefs(reactive) — konwertuje wszystkie pola. Zachowuje reaktywność przy destrukturyzacji.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nuxt 3', 'Meta-framework dla Vue 3 z SSR, SSG, file-based routing, auto-imports. Serwer API (server/api/), middleware, layouts. useFetch() i useAsyncData() do data fetching.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vite', 'Nowoczesny build tool i dev server. Błyskawiczny HMR dzięki natywnym ES modules w przeglądarce. Domyślny bundler dla Vue 3, React, Svelte. Konfiguracja: vite.config.ts.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('VueUse', 'Kolekcja composables dla Vue. Ponad 200 funkcji: useFetch, useLocalStorage, useDark, useIntersectionObserver, useVModel. Ekosystemowy odpowiednik react-use / ahooks.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Single File Component (SFC)', 'Plik .vue łączący <template>, <script> i <style> w jednym pliku. Scoped styles (<style scoped>) izolują CSS do komponentu. <style module> dla CSS Modules.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SSR w Vue (Nuxt / createSSRApp)', 'Renderowanie na serwerze: createSSRApp() zamiast createApp(). Nuxt automatyzuje SSR/SSG. Hydration: klient przejmuje server-rendered HTML. Universal rendering.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Testing (Vitest + Vue Test Utils)', 'Vitest — test runner oparty na Vite. @vue/test-utils: mount(), wrapper.find(), wrapper.trigger(). Testowanie composables: bezpośrednie wywołanie funkcji z ref/reactive.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Os frontale', 'Kość czołowa — tworzy przednią część sklepienia czaszki i górną ścianę oczodołu. Zawiera zatokę czołową (sinus frontalis).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os parietale', 'Kość ciemieniowa — parzysta kość sklepienia czaszki. Dwie kości ciemieniowe łączą się w szwie strzałkowym (sutura sagittalis).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os occipitale', 'Kość potyliczna — tylna część czaszki. Posiada otwór wielki (foramen magnum), przez który rdzeń kręgowy łączy się z mózgiem.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os temporale', 'Kość skroniowa — parzysta kość bocznej części czaszki. Zawiera narząd słuchu i równowagi, wyrostek sutkowaty i dół żuchwowy.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os sphenoidale', 'Kość klinowa — leży w środkowej części podstawy czaszki. Posiada siodło tureckie (sella turcica), w którym znajduje się przysadka mózgowa.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os ethmoidale', 'Kość sitowa — drobna kość podstawy czaszki między oczodołami. Tworzy blaszki sitowe i małżowinę nosową górną. Uczestniczy w budowie jamy nosowej.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os nasale', 'Kość nosowa — parzysta, mała kość tworząca grzbiet nosa. Łączy się z kością czołową i wyrostkiem czołowym szczęki.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os zygomaticum', 'Kość jarzmowa — tworzy wyniosłość policzka i boczną ścianę oczodołu. Łączy się z kością skroniową tworząc łuk jarzmowy.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Maxilla', 'Szczęka — największa nieruchoma kość twarzy. Tworzy dno oczodołu, boczną ścianę jamy nosowej. Zawiera zatokę szczękową i zęby górne.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mandibula', 'Żuchwa — jedyna ruchoma kość czaszki. Posiada trzon, gałęzie, wyrostek kłykciowy (staw skroniowo-żuchwowy) i wyrostek dziobiasty.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os lacrimale', 'Kość łzowa — najmniejsza kość twarzy, leży w przyśrodkowej ścianie oczodołu. Zawiera dół woreczka łzowego.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vomer', 'Lemiesz — nieparzysty element tylno-dolnej części przegrody nosowej. Łączy się z kością klinową i podniebieniem twardym.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os palatinum', 'Kość podniebienna — parzysta kość tworzącą tylną część podniebienia twardego i boczną ścianę jamy nosowej.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os hyoideum', 'Kość gnykowa — jedyna kość nie połączona stawowo z innymi kośćmi. Leży w szyi powyżej chrząstki tarczowatej krtani. Miejsce przyczepów mięśni języka.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Concha nasalis inferior', 'Małżowina nosowa dolna — samodzielna kość jamy nosowej. Zwiększa powierzchnię błony śluzowej, ogrzewa i nawilża wdychane powietrze.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Atlas (C1)', 'Kręg szczytowy (atlas) — pierwszy kręg szyjny, nie posiada trzonu. Tworzy staw szczytowo-potyliczny umożliwiający ruchy zgięcia i wyprostu głowy.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Axis (C2)', 'Kręg obrotowy (axis) — drugi kręg szyjny z zębem (dens axis), wokół którego obraca się atlas. Umożliwia rotację głowy.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebrae cervicales (C1-C7)', 'Kręgi szyjne — 7 kręgów odcinka szyjnego kręgosłupa. Charakterystyczne otwory wyrostków poprzecznych, przez które przechodzą tętnice kręgowe.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebrae thoracicae (Th1-Th12)', 'Kręgi piersiowe — 12 kręgów łączących się z żebrami. Posiadają dołki żebrowe na trzonach i wyrostkach poprzecznych. Tworzą tylną ścianę klatki piersiowej.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebrae lumbales (L1-L5)', 'Kręgi lędźwiowe — 5 największych kręgów. Przenoszą największe obciążenia. Najczęstsze miejsce przepuklin jądra miażdżystego (L4-L5, L5-S1).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os sacrum', 'Kość krzyżowa — powstaje ze zrośnięcia 5 kręgów krzyżowych. Tworzy tylną ścianę miednicy. Łączy się ze stawami krzyżowo-biodrowymi.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os coccygis', 'Kość guziczna — szczątkowa kość z 3-5 zrośniętych kręgów guzicznych. Miejsce przyczepu mięśni dna miednicy i więzadła krzyżowo-guzicznego.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sternum', 'Mostek — płaska kość przedniej ściany klatki piersiowej. Składa się z rękojeści (manubrium), trzonu i wyrostka mieczykowatego. Miejsce punkcji szpiku.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Costae (I-XII)', 'Żebra — 12 par: 7 prawdziwych (I-VII), 3 rzekome (VIII-X) i 2 wolne (XI-XII). Chronią narządy klatki piersiowej i uczestniczą w oddychaniu.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Clavicula', 'Obojczyk — kość łącząca kończynę górną z tułowiem. Łączy się z mostkiem (staw mostkowo-obojczykowy) i wyrostkiem barkowym łopatki. Najczęściej łamana kość.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Scapula', 'Łopatka — płaska, trójkątna kość tylnej powierzchni klatki piersiowej. Posiada grzebień, wyrostek barkowy (acromion) i wyrostek kruczy (processus coracoideus).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Humerus', 'Kość ramienna — długa kość ramienia. Głowa łączy się z łopatką (staw ramienno-łopatkowy). W rowku międzyguzkowym biegnie ścięgno głowy długiej bicepsa.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Radius', 'Kość promieniowa — leży po stronie kciuka przedramienia. Głowa tworzy staw z kością ramienną i łokciową. Dalszy koniec łączy się z kośćmi nadgarstka.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ulna', 'Kość łokciowa — leży po stronie małego palca. Wyrostek łokciowy (olecranon) tworzy szczyt łokcia. Wcięcie bloczkowe obejmuje bloczek kości ramiennej.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa carpi', 'Kości nadgarstka — 8 kości w dwóch rzędach. Bliższy: łódeczkowata, księżycowata, trójgraniasta, grochowata. Dalszy: czworoboczna większa i mniejsza, główkowata, haczykowata.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os scaphoideum', 'Kość łódeczkowata — najczęściej łamana kość nadgarstka. Złamania często niewidoczne na RTG. Zagrożenie martwicą z powodu wstecznego ukrwienia.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os lunatum', 'Kość księżycowata — centralna kość bliższego rzędu nadgarstka. Zwichnięcie może uciskać nerw pośrodkowy w kanale nadgarstka.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa metacarpi (I-V)', 'Kości śródręcza — 5 kości łączących nadgarstek z paliczkami. Złamanie V kości śródręcza (złamanie boksera) jest częstą urazową patologią.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Phalanges manus', 'Paliczki ręki — kciuk ma 2 paliczki (bliższy i dalszy), pozostałe palce po 3 (bliższy, środkowy, dalszy). Łącznie 14 paliczków w każdej ręce.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os ilium', 'Kość biodrowa — największa część kości miednicznej. Talerz kości biodrowej jest miejscem pobierania szpiku do biopsji. Grzebień biodrowy jest punktem orientacyjnym.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os ischii', 'Kość kulszowa — dolno-tylna część kości miednicznej. Guz kulszowy (tuber ischiadicum) jest punktem podparcia przy siedzeniu i przyczepem mięśni kulszowo-goleniowych.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os pubis', 'Kość łonowa — przednio-dolna część kości miednicznej. Obie kości łonowe łączą się w spojeniu łonowym (symphysis pubica). Tworzy część panewki stawu biodrowego.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Acetabulum', 'Panewka stawu biodrowego — powstaje ze zrośnięcia trzech kości miedniczych (biodrowej, kulszowej, łonowej). Obejmuje głowę kości udowej.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Femur', 'Kość udowa — najdłuższa i najsilniejsza kość ciała. Głowa łączy się z panewką. Szyjka kości udowej jest częstym miejscem złamań u osób starszych (osteoporoza).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Patella', 'Rzepka — największa kość sezamoidalna. Leży w ścięgnie mięśnia czworogłowego uda. Chroni staw kolanowy i zwiększa ramię dźwigni wyprostu kolana.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tibia', 'Kość piszczelowa — większa kość goleni, przenosi obciążenie ciała. Plateau piszczelowe tworzy dolną powierzchnię stawu kolanowego. Guzowatość piszczeli to przyczep więzadła rzepki.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fibula', 'Kość strzałkowa — cienka kość boczna goleni. Nie przenosi obciążenia ciała. Kostka boczna stabilizuje staw skokowy. Nerw strzałkowy owija się wokół jej szyjki.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Talus', 'Kość skokowa — łączy się z piszczelą i strzałką tworząc staw skokowy górny. Nie ma przyczepów mięśniowych. Podatna na martwicę jałową po złamaniach.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Calcaneus', 'Kość piętowa — największa kość stopy. Przenosi siły przy chodzeniu. Przyczep ścięgna Achillesa. Złamania powstają przy upadku z wysokości.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa tarsi', 'Kości stępu — 7 kości: skokowa, piętowa, łódkowata, sześcienna i trzy klinowate. Tworzą łuki stopy przenoszące obciążenia.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa metatarsi (I-V)', 'Kości śródstopia — 5 kości między stępem a paliczkami. Złamanie zmęczeniowe II lub III kości śródstopia (złamanie marszowe) typowe u żołnierzy i biegaczy.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Phalanges pedis', 'Paliczki stopy — paluchy mają 2 paliczki, pozostałe palce po 3. Łącznie 14 paliczków. Paluch koślawy (hallux valgus) to częsta deformacja I paliczka.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os naviculare', 'Kość łódkowata stopy — leży po przyśrodkowej stronie stępu między kością skokową a klinowatymi. Guzek kości łódkowatej jest przyczepem mięśnia piszczelowego tylnego.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os cuboideum', 'Kość sześcienna — leży po bocznej stronie stępu. Tworzy rowek dla ścięgna mięśnia strzałkowego długiego. Łączy się z piętową i IV-V kością śródstopia.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa cuneiformia', 'Kości klinowate — trzy kości (przyśrodkowa, pośrednia, boczna) między kością łódkowatą a I-III kością śródstopia. Współtworzą sklepienie poprzeczne stopy.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebra prominens (C7)', 'Kręg wyniosły — siódmy kręg szyjny o najdłuższym wyrostku kolczystym, wyczuwalny przy zgięciu szyi. Ważny punkt orientacyjny kliniczny.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Foramen magnum', 'Otwór wielki kości potylicznej — przejście rdzenia przedłużonego w rdzeń kręgowy. Przechodzą przez niego także tętnice kręgowe i rdzeń przedłużony.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fossa glenoidalis', 'Panewka stawowa łopatki — płytkie zagłębienie wyrostka barkowego łopatki. Tworzy staw ramienny. Obrąbek stawowy (labrum glenoidale) pogłębia panewkę.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Processus mastoideus', 'Wyrostek sutkowaty kości skroniowej — wyczuwalny za uchem. Zawiera komórki powietrzne. Przyczep mięśnia mostkowo-obojczykowo-sutkowego. Zapalenie = mastoiditis.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Processus styloideus radii', 'Wyrostek rylcowaty kości promieniowej — wyczuwalny po stronie kciuka. Punkt orientacyjny do badania tętna na tętnicy promieniowej.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Epicondylus lateralis humeri', 'Nadkłykieć boczny kości ramiennej — przyczep mięśni prostowników nadgarstka. Zapalenie przyczepów = łokieć tenisisty (epicondylitis lateralis).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Epicondylus medialis humeri', 'Nadkłykieć przyśrodkowy kości ramiennej — przyczep mięśni zginaczy nadgarstka. Zapalenie przyczepów = łokieć golfisty. Za nadkłykciem biegnie nerw łokciowy.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Trochanter major', 'Krętarz większy kości udowej — duży guz na bocznej stronie bliższego końca kości udowej. Przyczep mięśni pośladkowych. Wyczuwalny przez skórę, punkt orientacyjny.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Malleolus medialis', 'Kostka przyśrodkowa — dolny koniec kości piszczelowej, wyczuwalny po wewnętrznej stronie stawu skokowego. Złamania kostek to najczęstsze złamania kończyny dolnej.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Malleolus lateralis', 'Kostka boczna — dolny koniec kości strzałkowej, wyczuwalny po zewnętrznej stronie stawu skokowego. Stabilizuje staw skokowo-goleniowy bocznie.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Musculus sternocleidomastoideus', 'Mięsień mostkowo-obojczykowo-sutkowy — przyczep: mostek i obojczyk → wyrostek sutkowaty. Jednostronny skurcz: przechylenie głowy w swoją stronę i obrót w przeciwną. Obustronny: zgięcie szyi.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus trapezius', 'Mięsień czworoboczny — rozciąga się od kości potylicznej i wyrostków kolczystych C1-Th12 do obojczyka, wyrostka barkowego i grzebienia łopatki. Unosi, zbliża i obraca łopatkę.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus deltoideus', 'Mięsień naramienny — przyczep: obojczyk, wyrostek barkowy, grzebień łopatki → guzowatość naramienna kości ramiennej. Odwodzi ramię. Dominujące miejsce iniekcji domięśniowych.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus pectoralis major', 'Mięsień piersiowy większy — przyczep: obojczyk, mostek, chrząstki żebrowe → grzebień guzka większego kości ramiennej. Przywiedzenie, zgięcie i rotacja wewnętrzna ramienia.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus latissimus dorsi', 'Mięsień najszerszy grzbietu — największy mięsień ciała. Przyczep: wyrostki kolczyste Th7-L5, powięź piersiowo-lędźwiowa → grzebień guzka mniejszego. Prostowanie, przywiedzenie i rotacja wewnętrzna ramienia.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus biceps brachii', 'Mięsień dwugłowy ramienia — głowa długa: guzek nadpanewkowy łopatki, głowa krótka: wyrostek kruczy → guzowatość kości promieniowej. Zgięcie przedramienia i supinacja.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus triceps brachii', 'Mięsień trójgłowy ramienia — jedyny prostownik łokcia. Głowa długa: guzek podpanewkowy, głowa boczna i przyśrodkowa: kość ramienna → wyrostek łokciowy. Nerw promieniowy.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus brachioradialis', 'Mięsień ramienno-promieniowy — przyczep: grzebień nadkłykciowy boczny kości ramiennej → wyrostek rylcowaty kości promieniowej. Zgięcie przedramienia w pozycji pośredniej. Unerwienie: nerw promieniowy.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus supraspinatus', 'Mięsień nadgrzebieniowy — od dołu nadgrzebieniowego łopatki → guzek większy kości ramiennej. Inicjuje odwodzenie ramienia (pierwsze 15°). Najczęściej uszkadzany mięsień stożka rotatorów.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus infraspinatus', 'Mięsień podgrzebieniowy — od dołu podgrzebieniowego łopatki → guzek większy kości ramiennej. Rotacja zewnętrzna ramienia. Drugi najczęściej uszkadzany mięsień stożka rotatorów.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus subscapularis', 'Mięsień podłopatkowy — od dołu podłopatkowego → guzek mniejszy kości ramiennej. Główny rotator wewnętrzny ramienia w stożku rotatorów.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus teres minor', 'Mięsień obły mniejszy — od bocznego brzegu łopatki → guzek większy kości ramiennej. Rotacja zewnętrzna ramienia. Element stożka rotatorów. Unerwienie: nerw pachowy.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diaphragma', 'Przepona — główny mięsień oddechowy, oddziela jamę klatki piersiowej od jamy brzusznej. Unerwiona przez nerw przeponowy (C3-C5). Posiada otwory dla aorty, żyły głównej dolnej i przełyku.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus rectus abdominis', 'Mięsień prosty brzucha — od wyrostka mieczykowatego i chrząstek żebrowych V-VII → spojenie łonowe. Zgięcie tułowia i tłocznia brzuszna. Przecinany przy laparotomii pośrodkowej.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus obliquus externus abdominis', 'Mięsień skośny zewnętrzny brzucha — od żeber V-XII → grzebień biodrowy i więzadło pachwinowe. Zgięcie i rotacja tułowia, tłocznia brzuszna. Rozcięgno tworzy kanał pachwinowy.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus obliquus internus abdominis', 'Mięsień skośny wewnętrzny brzucha — od powięzi piersiowo-lędźwiowej i grzebienia biodrowego → żebra X-XII i linia biała. Obraca tułów w swoją stronę. Tworzy mięsień dźwigacz jądra.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus transversus abdominis', 'Mięsień poprzeczny brzucha — najgłębszy mięsień ściany brzucha. Stabilizacja kręgosłupa lędźwiowego i tłocznia brzuszna. Przyczep: chrząstki żebrowe VII-XII → linia biała.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus erector spinae', 'Mięsień prostownik grzbietu — grupa mięśni (biodrowo-żebrowy, najdłuższy, kolcowy) biegnąca wzdłuż kręgosłupa. Prostowanie i stabilizacja tułowia. Bóle lędźwiowe często związane z tym mięśniem.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gluteus maximus', 'Mięsień pośladkowy wielki — największy i najsilniejszy mięsień ciała. Przyczep: kość biodrowa, krzyżowa → pasmo biodrowo-piszczelowe i guzowatość pośladkowa. Prostowanie i rotacja zewnętrzna biodra.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gluteus medius', 'Mięsień pośladkowy średni — od zewnętrznej powierzchni kości biodrowej → krętarz większy. Odwodzenie biodra i stabilizacja miednicy w chodzie. Osłabienie = objaw Trendelenburga.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gluteus minimus', 'Mięsień pośladkowy mały — od kości biodrowej → krętarz większy. Odwodzenie i rotacja wewnętrzna biodra. Współpracuje z m. pośladkowym średnim w stabilizacji miednicy.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus iliopsoas', 'Mięsień biodrowo-lędźwiowy — złożony z m. biodrowego i m. lędźwiowego większego. Najsilniejszy zginacz biodra. Przyczep: kręgi lędźwiowe i dół biodrowy → krętarz mniejszy kości udowej.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus piriformis', 'Mięsień gruszkowaty — od kości krzyżowej → krętarz większy. Rotacja zewnętrzna biodra. Nerw kulszowy biegnie pod nim lub przez niego — zespół mięśnia gruszkowatego może imitować rwę kulszową.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus quadriceps femoris', 'Mięsień czworogłowy uda — 4 głowy: prosty uda, obszerny boczny, przyśrodkowy i pośredni → rzepka → guzowatość piszczeli. Jedyny prostownik kolana. Unerwienie: nerw udowy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus rectus femoris', 'Mięsień prosty uda — jedyna głowa m. czworogłowego przechodząca przez dwa stawy. Przyczep: kolec biodrowy przedni dolny → rzepka. Zgięcie biodra i wyprost kolana.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus sartorius', 'Mięsień krawiecki — najdłuższy mięsień ciała. Od kolca biodrowego przedniego górnego → powierzchnia przyśrodkowa piszczeli (gęsia stopka). Zgięcie, odwodzenie i rotacja zewnętrzna biodra.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus adductor magnus', 'Mięsień przywodziciel wielki — największy mięsień grupy przywodzicieli. Przyczep: guz kulszowy i gałąź kości łonowej → kresa chropawa i guzek przywodzicieli. Przywiedzenie i prostowanie biodra.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gracilis', 'Mięsień smukły — jedyny przywodziciel krzyżujący staw kolanowy. Od gałęzi dolnej kości łonowej → gęsia stopka piszczeli. Przywiedzenie biodra i zgięcie kolana.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus biceps femoris', 'Mięsień dwugłowy uda — głowa długa: guz kulszowy, głowa krótka: kresa chropawa → głowa strzałki. Zgięcie kolana i rotacja zewnętrzna goleni. Unerwienie: nerw kulszowy.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus semitendinosus', 'Mięsień półścięgnisty — od guza kulszowego → gęsia stopka piszczeli. Zgięcie kolana i rotacja wewnętrzna goleni. Ścięgno używane jako przeszczep w rekonstrukcji ACL.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus semimembranosus', 'Mięsień półbłoniasty — od guza kulszowego → kłykieć przyśrodkowy piszczeli. Zgięcie kolana i rotacja wewnętrzna goleni. Najgłębszy z mięśni kulszowo-goleniowych.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gastrocnemius', 'Mięsień brzuchaty łydki — dwie głowy od kłykci kości udowej → ścięgno Achillesa → kość piętowa. Zgięcie podeszwowe stopy i zgięcie kolana. Najsilniejszy mięsień łydki.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus soleus', 'Mięsień płaszczkowaty — leży pod m. brzuchatym łydki. Od piszczeli i strzałki → ścięgno Achillesa. Zgięcie podeszwowe stopy. Ważny w utrzymaniu postawy stojącej (pompa żylna łydki).', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tendo calcaneus (Achillis)', 'Ścięgno Achillesa — najgrubsze i najsilniejsze ścięgno ciała. Łączy mięśnie łydki z kością piętową. Zerwanie typowe u sportowców 30-50 lat (nagły ból, test Thompsona dodatni).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus tibialis anterior', 'Mięsień piszczelowy przedni — od piszczeli → kość klinowata przyśrodkowa i I kość śródstopia. Zgięcie grzbietowe stopy i supinacja. Porażenie = stopa opadająca (nerw strzałkowy głęboki).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus tibialis posterior', 'Mięsień piszczelowy tylny — najgłębszy mięsień tylnej grupy goleni. Od piszczeli, strzałki i błony międzykostnej → kość łódkowata i klinowate. Utrzymuje łuk przyśrodkowy stopy.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus peroneus longus', 'Mięsień strzałkowy długi — od głowy i trzonu strzałki → kość klinowata przyśrodkowa i I kość śródstopia (od strony podeszwy). Pronacja i zgięcie podeszwowe stopy. Podtrzymuje łuk poprzeczny.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus masseter', 'Mięsień żwacz — od łuku jarzmowego → gałąź i kąt żuchwy. Najsilniejszy mięsień żucia (podnoszenie żuchwy). Unerwienie: nerw żwaczowy z V3 (n. trójdzielny).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus temporalis', 'Mięsień skroniowy — od dołu skroniowego → wyrostek dziobiasty żuchwy. Podnoszenie i cofanie żuchwy. Unerwienie: nerwy skroniowe głębokie z n. żuchwowego (V3).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus pterygoideus lateralis', 'Mięsień skrzydłowy boczny — jedyny mięsień otwierający usta (opuszczanie żuchwy). Przyczep: skrzydło większe kości klinowej → szyjka wyrostka kłykciowego. Wysuwanie żuchwy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus orbicularis oculi', 'Mięsień okrężny oka — mięsień mimiczny otaczający oczodół. Zamyka powieki (mruganie, zaciskanie). Unerwienie: nerw twarzowy (VII). Porażenie = lagophthalmos (niezdolność zamknięcia oka).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus orbicularis oris', 'Mięsień okrężny ust — mięsień mimiczny otaczający szparę ust. Zamykanie, zaciskanie ust i formowanie dźwięków mowy. Unerwienie: nerw twarzowy (VII).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus serratus anterior', 'Mięsień zębaty przedni — od żeber I-IX → brzeg przyśrodkowy łopatki. Odwodzenie i obrót łopatki, przyciskanie do klatki piersiowej. Porażenie (n. piersiowy długi) = łopatka skrzydlata.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus rhomboideus major', 'Mięsień równoległoboczny większy — od wyrostków kolczystych Th2-Th5 → brzeg przyśrodkowy łopatki. Przyciąga łopatkę do kręgosłupa i unosi ją. Unerwienie: nerw grzbietowy łopatki (C5).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus levator scapulae', 'Mięsień dźwigacz łopatki — od wyrostków poprzecznych C1-C4 → kąt górny łopatki. Unosi łopatkę i przechyla szyjny odcinek kręgosłupa. Częsta przyczyna bólu karku.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus psoas major', 'Mięsień lędźwiowy większy — od trzonów i wyrostków poprzecznych Th12-L5 → krętarz mniejszy kości udowej. Silny zginacz biodra. Ropień m. lędźwiowego może towarzyszyć gruźlicy kręgosłupa.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus tensor fasciae latae', 'Mięsień napinacz powięzi szerokiej — od kolca biodrowego przedniego górnego → pasmo biodrowo-piszczelowe. Zgięcie, odwodzenie i rotacja wewnętrzna biodra. Stabilizacja kolana w wyproście.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus popliteus', 'Mięsień podkolanowy — od kłykcia bocznego kości udowej → tylna powierzchnia piszczeli. Odryglowuje kolano z pełnego wyprostu (rotacja wewnętrzna piszczeli). Unerwienie: nerw piszczelowy.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculi intercostales externi', 'Mięśnie międzyżebrowe zewnętrzne — od dolnego brzegu żebra wyżej → górny brzeg żebra niżej. Unoszą żebra przy wdechu (mięśnie wdechowe). 11 par po każdej stronie.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculi intercostales interni', 'Mięśnie międzyżebrowe wewnętrzne — przebieg przeciwny do zewnętrznych. Obniżają żebra przy forsownym wydechu (mięśnie wydechowe). Aktywne przy kaszlu i kichaniu.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Inhibitory ACE (ACEi)', 'Mechanizm: hamowanie konwertazy angiotensyny (ACE), zmniejszenie syntezy angiotensyny II. Przykłady: enalapril, ramipril, lisinopril. Wskazania: nadciśnienie, niewydolność serca, nefropatia cukrzycowa. DN: suchy kaszel, hiperkaliemia, obrzęk naczynioruchowy.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sartany (ARB)', 'Mechanizm: blokada receptora AT1 angiotensyny II. Przykłady: losartan, walsartan, telmisartan. Wskazania: nadciśnienie (alternatywa przy nietolerancji ACEi), niewydolność serca. DN: hiperkaliemia, hipotonia. Nie powodują kaszlu.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Beta-adrenolityki (β-blokery)', 'Mechanizm: blokada receptorów β-adrenergicznych. Przykłady: metoprolol, bisoprolol (β1-selektywne), propranolol (nieselektywny). Wskazania: nadciśnienie, niewydolność serca, arytmie, po zawale. DN: bradykardia, bronchoskurcz, maskowanie hipoglikemii.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Blokery kanału wapniowego — dihydropirydyny', 'Mechanizm: blokada kanałów Ca²⁺ typu L w mięśniach gładkich naczyń → rozszerzenie naczyń. Przykłady: amlodipina, nifedipina, felodipina. Wskazania: nadciśnienie, dławica. DN: obrzęki kostek, bóle głowy, zaczerwienienie twarzy.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Blokery kanału wapniowego — niedihydropirydyny', 'Mechanizm: blokada kanałów Ca²⁺ w sercu i naczyniach → zmniejszenie częstości, kurczliwości i rozszerzenie naczyń. Przykłady: werapamil, diltiazem. Wskazania: arytmie nadkomorowe, dławica. DN: bradykardia, zaparcia (werapamil).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diuretyki tiazydowe', 'Mechanizm: hamowanie kotransportera Na⁺/Cl⁻ w kanaliku dalszym. Przykłady: hydrochlorotiazyd, indapamid, chlortalidon. Wskazania: nadciśnienie, obrzęki. DN: hipokaliemia, hiperurykemia, hiperglikemia, hiponatremia.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diuretyki pętlowe', 'Mechanizm: hamowanie kotransportera Na⁺/K⁺/2Cl⁻ w ramieniu wstępującym pętli Henlego. Przykłady: furosemid, torasemid. Wskazania: obrzęk płuc, niewydolność serca, ostra niewydolność nerek. DN: hipokaliemia, ototoksyczność, odwodnienie.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diuretyki oszczędzające potas', 'Mechanizm: spironolakton — antagonista aldosteronu; amilorid — blokada kanału Na⁺ w kanaliku zbiorczym. Wskazania: niewydolność serca, hiperaldosteronizm, wodobrzusze. DN: hiperkaliemia, ginekomastia (spironolakton).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Statyny', 'Mechanizm: hamowanie reduktazy HMG-CoA → zmniejszenie syntezy cholesterolu w wątrobie, zwiększenie ekspresji receptorów LDL. Przykłady: atorwastatyna, rosuwastatyna, simwastatyna. DN: mialgia, rabdomioliza (rzadko), hepatotoksyczność.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fibraty', 'Mechanizm: agoniści receptorów PPARα → zmniejszenie trójglicerydów, zwiększenie HDL. Przykłady: fenofibrat, gemfibrozyl. Wskazania: hipertriglicerydemia. DN: mialgia (zwiększone ryzyko z statynami), kamica żółciowa, hepatotoksyczność.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Inhibitory pompy protonowej (IPP)', 'Mechanizm: nieodwracalne hamowanie H⁺/K⁺-ATPazy komórek okładzinowych żołądka. Przykłady: omeprazol, pantoprazol, esomeprazol. Wskazania: GERD, wrzody, eradykacja H. pylori. DN: hipoMg, złamania (długotrwale), zakażenia C. difficile.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Antagoniści receptora H2', 'Mechanizm: blokada receptora histaminowego H2 w komórkach okładzinowych → zmniejszenie wydzielania HCl. Przykłady: ranitydyna (wycofana w wielu krajach), famotydyna. Wskazania: wrzody, GERD. DN: bóle głowy, rzadko ginekomastia (cymetydyna).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metformina', 'Mechanizm: aktywacja AMPK, zmniejszenie glukoneogenezy wątrobowej, zwiększenie wrażliwości na insulinę. Lek I rzutu w cukrzycy typu 2. DN: biegunka, nudności, kwasica mleczanowa (rzadko). Przeciwwskazanie: ciężka niewydolność nerek.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pochodne sulfonylomocznika', 'Mechanizm: blokada kanałów K-ATP w komórkach β trzustki → wydzielanie insuliny. Przykłady: gliklazyd, glimepiryd, glipizyd. Wskazania: cukrzyca typu 2. DN: hipoglikemia, przyrost masy ciała. Wymagają czynnych komórek β.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Inhibitory SGLT2 (flozyny)', 'Mechanizm: hamowanie kotransportera Na⁺/glukoza w kanaliku bliższym → glukozuria. Przykłady: empagliflozyna, dapagliflozyna, kanagliflozyna. Wskazania: cukrzyca t.2, niewydolność serca. DN: zakażenia dróg moczowych, kwasica ketonowa.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Agoniści GLP-1', 'Mechanizm: naśladowanie inkretyny GLP-1 → stymulacja wydzielania insuliny, hamowanie glukagonu, opóźnienie opróżniania żołądka. Przykłady: liraglutyd, semaglutyd. DN: nudności, wymioty, zapalenie trzustki (rzadko).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Insulina — szybkodziałająca', 'Przykłady: lispro, aspart, glulizynowa. Początek: 10-15 min, szczyt: 1-2 h, czas: 3-5 h. Podawana przed posiłkami. Stosowana w pompach insulinowych i jako bolus w intensywnej insulinoterapii.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Insulina — długodziałająca', 'Przykłady: glargina, detemir, degludek. Początek: 1-2 h, brak wyraźnego szczytu, czas: 20-42 h. Zapewnia stałe stężenie bazalne insuliny. DN: hipoglikemia (rzadziej niż NPH), lipodystrofia w miejscu wkłucia.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leki z grupy NLPZ', 'Mechanizm: hamowanie cyklooksygenazy (COX-1 i COX-2) → zmniejszenie syntezy prostaglandyn. Przykłady: ibuprofen, diklofenak, naproksen. Wskazania: ból, zapalenie, gorączka. DN: wrzody żołądka, nefrotoksyczność, ryzyko sercowo-naczyniowe.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Selektywne inhibitory COX-2 (koksiby)', 'Mechanizm: wybiórcze hamowanie COX-2 → mniejsze ryzyko uszkodzenia żołądka. Przykłady: celekoksyb, etorikoksyb. Wskazania: OA, RZS. DN: zwiększone ryzyko sercowo-naczyniowe (zawał, udar). Rofekoksyb wycofany z rynku.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Paracetamol (acetaminofen)', 'Mechanizm: hamowanie COX w OUN (dokładny mechanizm niejasny), brak działania przeciwzapalnego obwodowo. Wskazania: ból łagodny/umiarkowany, gorączka. DN: hepatotoksyczność przy przedawkowaniu (antidotum: N-acetylocysteina). Max 4 g/dobę.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opioidy — silne', 'Mechanizm: agonizm receptorów opioidowych μ → analgezja, euforia, depresja oddechowa. Przykłady: morfina, fentanyl, oksykodon. DN: zaparcia, nudności, sedacja, depresja oddechowa, uzależnienie. Antidotum: nalokson.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tramadol', 'Mechanizm: słaby agonista receptora μ + hamowanie wychwytu zwrotnego serotoniny i noradrenaliny. Wskazania: ból umiarkowany/silny. DN: nudności, zawroty głowy, drgawki (obniża próg), ryzyko zespołu serotoninowego z SSRI.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Penicyliny', 'Mechanizm: hamowanie syntezy ściany komórkowej bakterii (wiązanie z PBP). Przykłady: amoksycylina, ampicylina, penicylina G. Wskazania: szerokie spektrum infekcji. DN: reakcje alergiczne (do anafilaksji), biegunka. Oporność: β-laktamazy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cefalosporyny', 'Mechanizm: hamowanie syntezy ściany komórkowej (jak penicyliny). Generacje I-V o coraz szerszym spektrum wobec Gram(-). Przykłady: cefaleksyna (I), cefuroksym (II), ceftriakson (III), cefepim (IV). DN: alergia krzyżowa z penicylinami (~2%).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Makrolidy', 'Mechanizm: wiązanie z podjednostką 50S rybosomu → hamowanie syntezy białek bakterii. Przykłady: azytromycyna, klarytromycyna, erytromycyna. Wskazania: atypowe zapalenia płuc, H. pylori. DN: wydłużenie QT, zaburzenia żołądkowo-jelitowe.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fluorochinolony', 'Mechanizm: hamowanie gyrazy DNA (topoizomerazy II) i topoizomerazy IV bakterii. Przykłady: ciprofloksacyna, lewofloksacyna, moksyfloksacyna. DN: tendinopatia (zerwanie ścięgna Achillesa), neuropatia, wydłużenie QT, fotosensybilizacja.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aminoglikozydy', 'Mechanizm: wiązanie z podjednostką 30S rybosomu → błędne odczytywanie mRNA. Przykłady: gentamycyna, amikacyna, tobramycyna. Wskazania: ciężkie infekcje Gram(-), endocarditis. DN: nefrotoksyczność, ototoksyczność (nieodwracalna). Monitorowanie stężeń.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tetracykliny', 'Mechanizm: wiązanie z podjednostką 30S → hamowanie przyłączania aminoacylo-tRNA. Przykłady: doksycyklina, tetracyklina, minocyklina. Wskazania: borelioza, trądzik, chlamydia. DN: fotosensybilizacja, przebarwienia zębów u dzieci, zaburzenia GI.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metronidazol', 'Mechanizm: tworzenie toksycznych metabolitów uszkadzających DNA w warunkach beztlenowych. Wskazania: zakażenia beztlenowe (Bacteroides, Clostridium), lamblioza, ameboza, H. pylori. DN: metaliczny smak, neuropatia, efekt disulfiramowy z alkoholem.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wankomycyna', 'Mechanizm: hamowanie syntezy ściany komórkowej przez wiązanie z D-Ala-D-Ala peptydoglikanu. Wskazania: ciężkie infekcje MRSA, rzekomobłoniaste zapalenie jelit (doustnie). DN: zespół czerwonego człowieka (zbyt szybki wlew), nefrotoksyczność.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Trimetoprim-sulfametoksazol (ko-trimoksazol)', 'Mechanizm: synergistyczne hamowanie syntezy kwasu foliowego — sulfametoksazol hamuje syntazę dihydropteroilową, trimetoprim reduktazę dihydrofolianową. Wskazania: ZUM, PCP (Pneumocystis). DN: wysypka, hiperkaliemia, supresja szpiku.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Heparyna niefrakcjonowana (UFH)', 'Mechanizm: aktywacja antytrombiny III → hamowanie trombiny (IIa) i Xa. Podawanie: dożylne, monitorowanie aPTT. Wskazania: zakrzepica, zatorowość, terapia pomostowa. DN: krwawienia, małopłytkowość poheparynowa (HIT). Antidotum: protamina.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Heparyny drobnocząsteczkowe (LMWH)', 'Mechanizm: głównie hamowanie czynnika Xa przez antytrombinę III. Przykłady: enoksaparyna, dalteparyna, nadroparyna. Podawanie: podskórne, bez rutynowego monitorowania. DN: krwawienia, HIT (rzadziej niż UFH).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Warfaryna', 'Mechanizm: hamowanie reduktazy epoksydowej witaminy K → zmniejszenie syntezy czynników II, VII, IX, X. Monitorowanie: INR (cel 2-3). DN: krwawienia, teratogenność, martwica skóry. Liczne interakcje pokarmowe i lekowe.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('DOAC — riwaroksaban, apiksaban', 'Mechanizm: bezpośrednie hamowanie czynnika Xa. Wskazania: profilaktyka udarów w AF, leczenie DVT/PE. DN: krwawienia. Antidotum: andeksanet alfa. Nie wymagają monitorowania INR. Ostrożnie w niewydolności nerek.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dabigatran', 'Mechanizm: bezpośredni inhibitor trombiny (czynnika IIa). Wskazania: profilaktyka udarów w AF, DVT/PE. DN: krwawienia, dyspepsja. Antidotum: idarucizumab. Wydalanie nerkowe — przeciwwskazany przy GFR <30 ml/min.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwas acetylosalicylowy (aspiryna)', 'Mechanizm: nieodwracalne hamowanie COX-1 → zmniejszenie syntezy tromboksanu A2 → hamowanie agregacji płytek. Niskie dawki (75-100 mg): antyagregacyjne. DN: wrzody, krwawienia z GI, zespół Reye''a u dzieci.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Klopidogrel', 'Mechanizm: nieodwracalna blokada receptora P2Y12 dla ADP na płytkach → hamowanie agregacji. Wskazania: po zawale, PCI ze stentem, udar. Podwójna terapia z ASA (DAPT). DN: krwawienia, TTP (rzadko). Prolek — wymaga aktywacji CYP2C19.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SSRI (selektywne inhibitory wychwytu serotoniny)', 'Mechanizm: hamowanie wychwytu zwrotnego serotoniny (5-HT) w synapsie. Przykłady: fluoksetyna, sertralina, escitalopram, paroksetyna. Wskazania: depresja, lęk, OCD, PTSD. DN: dysfunkcja seksualna, nudności, zespół serotoninowy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SNRI (inhibitory wychwytu serotoniny i noradrenaliny)', 'Mechanizm: hamowanie wychwytu zwrotnego serotoniny i noradrenaliny. Przykłady: wenlafaksyna, duloksetyna. Wskazania: depresja, lęk uogólniony, ból neuropatyczny (duloksetyna). DN: nadciśnienie (wyższe dawki), nudności, zespół odstawienny.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Benzodiazepiny', 'Mechanizm: nasilenie działania GABA na receptorze GABA-A (zwiększenie częstotliwości otwarcia kanału Cl⁻). Przykłady: diazepam, lorazepam, midazolam. Wskazania: lęk, bezsenność, drgawki, sedacja. DN: sedacja, uzależnienie, depresja oddechowa. Antidotum: flumazenil.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leki przeciwpadaczkowe — walproinian', 'Mechanizm: blokada kanałów Na⁺, zwiększenie GABA, hamowanie kanałów Ca²⁺ typu T. Szerokie spektrum: napady uogólnione i ogniskowe. DN: hepatotoksyczność, teratogenność (wady cewy nerwowej), przyrost masy ciała, trombocytopenia.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Karbamazepina', 'Mechanizm: blokada kanałów Na⁺ zależnych od napięcia. Wskazania: padaczka (napady ogniskowe), neuralgia nerwu trójdzielnego, zaburzenie afektywne dwubiegunowe. DN: hiponatremia, agranulocytoza, zespół SJS/TEN, indukcja CYP3A4.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glikokortykosteroidy ogólnoustrojowe', 'Mechanizm: wiązanie z receptorem GR → hamowanie NF-κB → supresja cytokin zapalnych. Przykłady: prednizon, metyloprednizolon, deksametazon. Wskazania: stany zapalne, autoimmunologiczne, alergia. DN: osteoporoza, cukrzyca, zespół Cushinga.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leki antyhistaminowe H1 — II generacja', 'Mechanizm: blokada receptora H1 histaminy. Przykłady: cetyryzyna, loratadyna, feksofenadyna. Wskazania: alergiczny nieżyt nosa, pokrzywka. DN: minimalna sedacja (w przeciwieństwie do I generacji). Nie przenikają przez barierę krew-mózg.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('β₂-mimetyki krótkodziałające (SABA)', 'Mechanizm: stymulacja receptorów β₂ w mięśniach gładkich oskrzeli → rozkurcz. Przykłady: salbutamol (albuterol), fenoterol. Wskazania: doraźne leczenie astmy i POChP. DN: tachykardia, drżenie rąk, hipokaliemia. Lek ratunkowy.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wziewne glikokortykosteroidy (ICS)', 'Mechanizm: miejscowe działanie przeciwzapalne w drogach oddechowych. Przykłady: budezonid, flutykazon, beklometazon. Wskazania: przewlekłe leczenie astmy (lek bazowy). DN: kandydoza jamy ustnej, chrypka. Płukanie ust po inhalacji.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lewotyroksyna (L-T4)', 'Mechanizm: syntetyczny analog tyroksyny (T4), konwertowany do aktywnej T3 w tkankach. Wskazania: niedoczynność tarczycy. DN: przy przedawkowaniu objawy nadczynności (tachykardia, spadek masy, drżenia). Przyjmować na czczo, 30 min przed posiłkiem.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tiamazol (metimazol)', 'Mechanizm: hamowanie peroksydazy tarczycowej → zmniejszenie syntezy T3 i T4. Wskazania: nadczynność tarczycy (choroba Gravesa-Basedowa). DN: agranulocytoza (zagrożenie życia), hepatotoksyczność, wysypka. Kontrola morfologii krwi.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('-itis', 'Przyrostek oznaczający zapalenie. Przykłady: appendicitis (zapalenie wyrostka robaczkowego), arthritis (zapalenie stawu), meningitis (zapalenie opon mózgowo-rdzeniowych).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-ectomia', 'Przyrostek oznaczający chirurgiczne usunięcie (wycięcie). Przykłady: appendectomia (wycięcie wyrostka), cholecystectomia (wycięcie pęcherzyka żółciowego), mastectomia (wycięcie piersi).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-otomia', 'Przyrostek oznaczający nacięcie chirurgiczne (otwarcie). Przykłady: tracheotomia (nacięcie tchawicy), laparotomia (otwarcie jamy brzusznej), thoracotomia (otwarcie klatki piersiowej).', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-stomia', 'Przyrostek oznaczający wytworzenie sztucznego ujścia (przetoki). Przykłady: colostomia (przetoka jelita grubego), tracheostomia (przetoka tchawicy), gastrostomia (przetoka żołądkowa).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-osis / -oza', 'Przyrostek oznaczający stan chorobowy (zwykle niezapalny) lub proces. Przykłady: fibrosis (włóknienie), stenosis (zwężenie), necrosis (martwica), thrombosis (zakrzepica).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-penia', 'Przyrostek oznaczający niedobór, zmniejszenie liczby. Przykłady: leukopenia (niedobór leukocytów), thrombocytopenia (niedobór płytek), pancytopenia (niedobór wszystkich linii komórkowych).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-emia', 'Przyrostek oznaczający stan we krwi. Przykłady: anemia (niedokrwistość), hyperglycemia (podwyższony cukier we krwi), septicemia (posocznica), hyperkaliemia (podwyższony potas we krwi).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-uria', 'Przyrostek oznaczający obecność substancji w moczu. Przykłady: hematuria (krew w moczu), proteinuria (białko w moczu), glycosuria (glukoza w moczu), polyuria (wielomocz).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-algia / -odynia', 'Przyrostek oznaczający ból. Przykłady: neuralgia (ból nerwowy), myalgia (ból mięśniowy), cephalalgia (ból głowy), pleurodynia (ból opłucnowy).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-plastica', 'Przyrostek oznaczający naprawę chirurgiczną lub kształtowanie. Przykłady: rhinoplastica (plastyka nosa), angioplastica (plastyka naczynia), arthroplastica (plastyka stawu — endoproteza).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-scopia', 'Przyrostek oznaczający oglądanie, badanie wzrokowe. Przykłady: endoscopia (wziernikowanie narządu), colonoscopia (wziernikowanie jelita grubego), bronchoscopia (wziernikowanie oskrzeli).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-graphia', 'Przyrostek oznaczający zapis, rejestrację. Przykłady: electrocardiographia (EKG — zapis czynności serca), electromyographia (EMG — zapis mięśni), mammographia (rtg piersi).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-megalia', 'Przyrostek oznaczający powiększenie. Przykłady: hepatomegalia (powiększenie wątroby), splenomegalia (powiększenie śledziony), cardiomegalia (powiększenie serca), acromegalia (powiększenie kończyn).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-malacia', 'Przyrostek oznaczający rozmiękanie tkanki. Przykłady: osteomalacia (rozmiękanie kości), chondromalacia (rozmiękanie chrząstki), tracheomalacia (rozmiękanie tchawicy).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-lysis', 'Przyrostek oznaczający rozpad, rozpuszczenie, zniszczenie. Przykłady: haemolysis (rozpad krwinek), thrombolysis (rozpuszczenie skrzepu), osteolysis (rozpad kości).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-genesis / -genia', 'Przyrostek oznaczający powstawanie, tworzenie się. Przykłady: carcinogenesis (powstawanie raka), osteogenesis (tworzenie kości), pathogenesis (mechanizm powstawania choroby).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-rrhaphia', 'Przyrostek oznaczający zszycie chirurgiczne. Przykłady: herniorrhaphia (zszycie przepukliny), neurorrhaphia (zszycie nerwu), tenorrhaphia (zszycie ścięgna).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-rrhagia / -rrhexis', 'Przyrostki oznaczające krwotok / pęknięcie. Przykłady: haemorrhagia (krwotok), menorrhagia (obfite miesiączki). -rrhexis: karyorrhexis (rozpad jądra komórkowego).', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hyper-', 'Przedrostek oznaczający nadmiar, powyżej normy. Przykłady: hypertensio (nadciśnienie), hyperthyreoidismus (nadczynność tarczycy), hyperglycaemia (hiperglikemia).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hypo-', 'Przedrostek oznaczający niedobór, poniżej normy. Przykłady: hypotensio (niedociśnienie), hypothyreoidismus (niedoczynność tarczycy), hypoglycaemia (hipoglikemia).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('tachy-', 'Przedrostek oznaczający szybki, przyspieszony. Przykłady: tachycardia (przyspieszone bicie serca >100/min), tachypnoea (przyspieszony oddech), tachyarrhythmia (szybka arytmia).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('brady-', 'Przedrostek oznaczający wolny, zwolniony. Przykłady: bradycardia (zwolnione bicie serca <60/min), bradypnoea (zwolniony oddech), bradykinesia (spowolnienie ruchowe — choroba Parkinsona).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('dys-', 'Przedrostek oznaczający zaburzenie, trudność, nieprawidłowość. Przykłady: dyspnoea (duszność), dysphagia (zaburzenie połykania), dysuria (bolesne oddawanie moczu), dysplasia (zaburzenie rozwoju).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('a- / an-', 'Przedrostek oznaczający brak, bez. Przykłady: apnoea (bezdech), anuria (bezmocz), aphasia (utrata zdolności mowy), anaemia (niedokrwistość).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('poly-', 'Przedrostek oznaczający wiele, dużo. Przykłady: polyuria (wielomocz), polydipsia (nadmierne pragnienie), polyneuropathia (uszkodzenie wielu nerwów), polycythaemia (nadmiar krwinek).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('oligo-', 'Przedrostek oznaczający mało, niedostatecznie. Przykłady: oliguria (skąpomocz <500 ml/dobę), oligohydramnion (małowodzie), oligospermia (zmniejszona liczba plemników).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('endo-', 'Przedrostek oznaczający wewnątrz. Przykłady: endocardium (wsierdzie), endoscopia (wziernikowanie wewnętrzne), endometrium (błona śluzowa macicy), endocrinologia (nauka o gruczołach dokrewnych).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ecto- / exo-', 'Przedrostki oznaczające na zewnątrz. Przykłady: ectopia (przemieszczenie poza normalne miejsce), exocrinologia (wydzielanie zewnętrzne), exostosis (narośl kostna na zewnątrz kości).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('peri-', 'Przedrostek oznaczający wokół, dookoła. Przykłady: pericardium (osierdzie — worek otaczający serce), periosteum (okostna), peritoneum (otrzewna), perinatalny (wokół porodu).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('epi-', 'Przedrostek oznaczający nad, powyżej, na powierzchni. Przykłady: epidermis (naskórek), epigastrium (nadbrzusze), epiduralis (nad oponą twardą), epiglottis (nagłośnia).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('sub-', 'Przedrostek oznaczający pod, poniżej. Przykłady: subcutaneus (podskórny), sublingualis (podjęzykowy), subduralis (podtwardówkowy), subfebrilis (stan podgorączkowy).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('inter-', 'Przedrostek oznaczający między. Przykłady: intercostalis (międzyżebrowy), intervertebralis (międzykręgowy), interstitialis (śródmiąższowy).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('intra-', 'Przedrostek oznaczający wewnątrz, do wnętrza. Przykłady: intravenous (dożylny), intramuscular (domięśniowy), intracranialis (wewnątrzczaszkowy), intrathecalis (dooponowy).', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('retro-', 'Przedrostek oznaczający za, do tyłu. Przykłady: retroperitonealis (zaotrzewnowy), retroflexio (zagięcie do tyłu, np. macicy), retrobulbaris (za gałką oczną).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ante- / pre-', 'Przedrostki oznaczające przed (w czasie lub przestrzeni). Przykłady: antenatalis (przedporodowy), praeoperativus (przedoperacyjny), praeeclampsia (stan przedrzucawkowy).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('post-', 'Przedrostek oznaczający po, za (w czasie). Przykłady: postoperativus (pooperacyjny), postpartum (po porodzie), post mortem (po śmierci — sekcja zwłok).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('neo-', 'Przedrostek oznaczający nowy. Przykłady: neoplasma (nowotwór — nowy twór), neonatologia (nauka o noworodkach), neovascularisatio (tworzenie nowych naczyń).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('cardio-', 'Rdzeń oznaczający serce. Przykłady: cardiologia (nauka o sercu), cardiomyopathia (choroba mięśnia sercowego), cardiopulmonalis (sercowo-płucny), tachycardia (przyspieszenie akcji serca).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hepato-', 'Rdzeń oznaczający wątrobę (gr. hepar). Przykłady: hepatitis (zapalenie wątroby), hepatomegalia (powiększenie wątroby), hepatocellularis (wątrobowokomórkowy), hepatotoxicus (uszkadzający wątrobę).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('nephro- / ren-', 'Rdzeń oznaczający nerkę (gr. nephros / łac. ren). Przykłady: nephrologia (nefrologia), nephritis (zapalenie nerek), insufficientia renalis (niewydolność nerek), nephrotoxicus (nefrotoksyczny).', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('pneumo- / pulmo-', 'Rdzeń oznaczający płuco (gr. pneumon / łac. pulmo). Przykłady: pneumonia (zapalenie płuc), pneumothorax (odma opłucnowa), pulmonologia (nauka o płucach), embolismus pulmonalis (zatorowość płucna).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('gastro-', 'Rdzeń oznaczający żołądek (gr. gaster). Przykłady: gastritis (zapalenie żołądka), gastrectomia (wycięcie żołądka), gastroscopia (wziernikowanie żołądka), gastroenterologia (nauka o chorobach GI).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('entero-', 'Rdzeń oznaczający jelito (gr. enteron). Przykłady: enteritis (zapalenie jelita), enterococcus (paciorkowiec jelitowy), gastroenteritis (nieżyt żołądkowo-jelitowy), enteropathia (choroba jelita).', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('chole- / cholecysto-', 'Rdzeń oznaczający żółć / pęcherzyk żółciowy. Przykłady: cholecystitis (zapalenie pęcherzyka żółciowego), cholelithiasis (kamica żółciowa), cholangitis (zapalenie dróg żółciowych), cholestasis (zastój żółci).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('haemo- / haemato-', 'Rdzeń oznaczający krew (gr. haima). Przykłady: haemorrhagia (krwotok), haematoma (krwiak), haematuria (krew w moczu), haematologia (nauka o chorobach krwi).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('osteo-', 'Rdzeń oznaczający kość (gr. osteon). Przykłady: osteoporosis (zrzeszotnienie kości), osteomyelitis (zapalenie szpiku kostnego), osteoarthritis (choroba zwyrodnieniowa stawów), osteocyt (komórka kości).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('myo-', 'Rdzeń oznaczający mięsień (gr. mys). Przykłady: myocardium (mięsień sercowy), myalgia (ból mięśniowy), myositis (zapalenie mięśni), myopathia (choroba mięśni).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('neuro-', 'Rdzeń oznaczający nerw (gr. neuron). Przykłady: neurologia (nauka o chorobach układu nerwowego), neuropathia (uszkodzenie nerwu), neuralgia (ból nerwowy), neuritis (zapalenie nerwu).', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('dermo- / dermato-', 'Rdzeń oznaczający skórę (gr. derma). Przykłady: dermatologia (nauka o chorobach skóry), dermatitis (zapalenie skóry), epidermis (naskórek), dermatomyositis (zapalenie skórno-mięśniowe).', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('onco-', 'Rdzeń oznaczający guz, nowotwór (gr. onkos). Przykłady: oncologia (nauka o nowotworach), oncogenesis (powstawanie nowotworu), oncogene (gen nowotworowy).', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lateralis / medialis', 'Lateralis — boczny (dalej od linii środkowej ciała). Medialis — przyśrodkowy (bliżej linii środkowej). Przykład: malleolus lateralis (kostka boczna) vs medialis (kostka przyśrodkowa).', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Proximalis / distalis', 'Proximalis — bliższy (bliżej tułowia lub początku struktury). Distalis — dalszy (dalej od tułowia). Przykład: phalanx proximalis (paliczek bliższy) vs distalis (dalszy).', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Anterior (ventralis) / posterior (dorsalis)', 'Anterior — przedni (ku przodowi ciała). Posterior — tylny (ku tyłowi). Ventralis = brzuszny. Dorsalis = grzbietowy. Przykład: mięśnie przednie (flexores) vs tylne (extensores) przedramienia.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Superior / inferior', 'Superior — górny (bliżej głowy, cranialis). Inferior — dolny (bliżej stóp, caudalis). Przykład: vena cava superior (żyła główna górna) vs inferior (żyła główna dolna).', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Superficialis / profundus', 'Superficialis — powierzchowny (bliżej skóry). Profundus — głęboki (dalej od powierzchni). Przykład: arcus palmaris superficialis (łuk dłoniowy powierzchowny) vs profundus (głęboki).', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Supinatio / pronatio', 'Supinacja — obrót przedramienia tak, że dłoń zwraca się ku górze (jak trzymanie talerza zupy — supiny). Pronacja — dłoń zwraca się ku dołowi. Dotyczy też stopy (uniesienie/obniżenie brzegu przyśrodkowego).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Abductio / adductio', 'Abductio — odwodzenie (oddalanie kończyny od linii środkowej ciała). Adductio — przywodzenie (przybliżanie do linii środkowej). Przykład: m. deltoideus odwodzi ramię, m. pectoralis major przywodzi.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Flexio / extensio', 'Flexio — zgięcie (zmniejszenie kąta stawowego). Extensio — wyprost (zwiększenie kąta). Przykład: zgięcie łokcia (flexio) = skurcz bicepsa, wyprost (extensio) = skurcz tricepsa.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Idiopathicus', 'Termin oznaczający chorobę o nieznanej przyczynie. Przykłady: fibrosis pulmonalis idiopathica (samoistne włóknienie płuc), thrombocytopenia idiopathica (ITP), scoliosis idiopathica.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Iatrogenicus', 'Termin oznaczający szkodę wywołaną działaniem medycznym (leczeniem, procedurą). Przykłady: zakażenie jatrogenne (po operacji), pneumothorax jatrogenny (po nakłuciu żyły podobojczykowej).', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym jest programowanie obiektowe i jakie są jego filary?', 'OOP opiera się na czterech filarach: enkapsulacji (ukrywanie szczegółów implementacji), dziedziczeniu (tworzenie hierarchii klas), polimorfizmie (różne zachowanie pod wspólnym interfejsem) i abstrakcji (modelowanie istotnych cech). W praktyce pozwala to pisać kod modularny i łatwiejszy do utrzymania.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij zasady SOLID.', 'SOLID to pięć zasad: S — klasa ma jeden powód do zmiany, O — otwarta na rozszerzenia, zamknięta na modyfikacje, L — podtyp musi być wymienialny z typem bazowym, I — wiele małych interfejsów zamiast jednego dużego, D — zależność od abstrakcji, nie konkretów. Stosowanie SOLID redukuje coupling i ułatwia testowanie.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się klasa abstrakcyjna od interfejsu?', 'Klasa abstrakcyjna może mieć implementację metod i stan (pola), interfejs definiuje tylko kontrakt (sygnatury metod). Klasa może implementować wiele interfejsów, ale dziedziczyć po jednej klasie abstrakcyjnej. Interfejsy promują luźne powiązanie — używaj ich, gdy chcesz zdefiniować zachowanie bez narzucania hierarchii.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz metody HTTP i kiedy je stosujesz?', 'GET — pobieranie zasobów, POST — tworzenie nowych, PUT — pełna aktualizacja, PATCH — częściowa aktualizacja, DELETE — usuwanie. GET i PUT są idempotentne (wielokrotne wywołanie daje ten sam efekt). POST nie jest idempotentny. HEAD zwraca tylko nagłówki, OPTIONS informuje o dostępnych metodach.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest REST API i jakie są jego zasady?', 'REST to styl architektoniczny oparty na zasobach identyfikowanych przez URI. Kluczowe zasady: bezstanowość (serwer nie przechowuje sesji), jednolity interfejs, klient-serwer, cache''owalność odpowiedzi i system warstwowy. Dobrze zaprojektowane REST API używa odpowiednich kodów HTTP i jest intuicyjne w nawigacji.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się REST od GraphQL?', 'REST zwraca ustaloną strukturę danych per endpoint, GraphQL pozwala klientowi określić dokładnie jakie pola potrzebuje w jednym zapytaniu. GraphQL eliminuje over-fetching i under-fetching, ale jest bardziej złożony w implementacji. REST jest prostszy, lepiej cache''owalny i lepiej wspierany przez infrastrukturę (CDN, proxy).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Git i po co się go używa?', 'Git to rozproszony system kontroli wersji. Śledzi historię zmian, umożliwia równoległą pracę wielu osób (branching), cofanie błędów i przeglądanie historii. Każdy developer ma pełną kopię repozytorium. Kluczowe komendy to commit, push, pull, branch, merge. Jest fundamentem współczesnego workflow developmentu.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest merge conflict i jak go rozwiązujesz?', 'Merge conflict powstaje, gdy dwie gałęzie modyfikują te same linie pliku. Git oznacza konflikty znacznikami <<<<<<<, =======, >>>>>>>. Rozwiązuję je ręcznie analizując obie zmiany, wybieram poprawną wersję lub łączę obie, a następnie commituję. Używam też narzędzi jak VS Code diff editor do wizualnego porównania.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są testy jednostkowe i dlaczego są ważne?', 'Testy jednostkowe weryfikują izolowane fragmenty kodu (funkcje, metody) niezależnie od zależności zewnętrznych. Dają szybki feedback, dokumentują oczekiwane zachowanie i pozwalają bezpiecznie refaktoryzować. Dobrze napisany test ma fazę arrange (przygotowanie), act (wykonanie) i assert (weryfikacja). Powinny być szybkie i deterministyczne.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się testy jednostkowe od integracyjnych i e2e?', 'Jednostkowe testują izolowane fragmenty (mockując zależności), integracyjne sprawdzają współpracę kilku modułów (np. serwis + baza), e2e testują cały flow z perspektywy użytkownika (np. Cypress/Playwright). Piramida testów mówi: dużo jednostkowych, mniej integracyjnych, najmniej e2e. Im wyżej, tym wolniejsze, ale bardziej realistyczne.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co oznaczają zasady DRY i KISS?', 'DRY (Don''t Repeat Yourself) — unikaj duplikacji logiki, wydzielaj wspólny kod do funkcji/modułów. KISS (Keep It Simple, Stupid) — preferuj proste rozwiązania nad złożone. Czasem DRY i KISS stoją w sprzeczności: nie abstrahuj na siłę tylko dlatego, że kod wygląda podobnie — premature abstraction jest tak samo szkodliwa jak duplikacja.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest SQL i czym różni się od NoSQL?', 'SQL to relacyjne bazy danych ze schematem (tabele, relacje, zapytania SQL) — np. PostgreSQL, MySQL. NoSQL to rodzina baz bez sztywnego schematu: dokumentowe (MongoDB), klucz-wartość (Redis), kolumnowe (Cassandra), grafowe (Neo4j). SQL daje ACID i spójność, NoSQL skalowalność horyzontalną i elastyczność schematu.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest programowanie asynchroniczne?', 'Programowanie asynchroniczne pozwala wykonywać operacje (I/O, HTTP) bez blokowania głównego wątku. W JS/TS używamy Promise i async/await. Callback był starszym podejściem, ale prowadził do „callback hell". Event loop w JS kolejkuje asynchroniczne operacje i wykonuje je, gdy stos wywołań jest pusty.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Promise w JavaScript?', 'Promise to obiekt reprezentujący wynik operacji asynchronicznej, która może być pending, fulfilled (resolved) lub rejected. Łańcuchujemy je metodami .then() i .catch(). Async/await to syntactic sugar nad Promises — czytelniejszy kod. Promise.all() uruchamia równolegle, Promise.allSettled() czeka na wszystkie niezależnie od wyniku.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak debugujesz problemy w aplikacji?', 'Zaczynam od reprodukcji problemu, analizuję logi i komunikaty błędów. Używam breakpointów w debuggerze (Chrome DevTools, IDE debugger) do śledzenia przepływu. Sprawdzam Network tab dla problemów z API, Console dla błędów JS. Stosuję też rubber duck debugging i dzielę problem na mniejsze części. Git bisect pomaga znaleźć commit wprowadzający bug.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Agile i Scrum?', 'Agile to filozofia iteracyjnego wytwarzania oprogramowania — krótkie cykle, ciągły feedback, adaptacja do zmian. Scrum to framework Agile z rolami (Product Owner, Scrum Master, Dev Team), ceremoniami (sprint planning, daily, review, retro) i artefaktami (backlog, sprint backlog). Sprinty trwają 1-4 tygodnie.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest code review i po co się go robi?', 'Code review to przegląd kodu przez innego programistę przed mergem. Łapie błędy, poprawia jakość, upowszechnia wiedzę w zespole i wymusza spójność stylu. Dobry review skupia się na logice, edge case''ach, bezpieczeństwie i czytelności — nie na stylu (od tego jest linter). Staram się dawać konstruktywny feedback z uzasadnieniem.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CI/CD?', 'CI (Continuous Integration) to automatyczne budowanie i testowanie kodu po każdym pushu. CD (Continuous Delivery/Deployment) to automatyczne wdrażanie na środowiska. Pipeline CI/CD typowo obejmuje: build, lint, testy jednostkowe, testy integracyjne, deploy na staging, deploy na produkcję. Narzędzia: GitHub Actions, GitLab CI, Jenkins.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz podstawy bezpieczeństwa aplikacji webowych?', 'Najczęstsze zagrożenia (OWASP Top 10): XSS (wstrzyknięcie skryptów — waliduj input, escapuj output), SQL Injection (parametryzuj zapytania), CSRF (tokeny), broken authentication. Zawsze: HTTPS, hashuj hasła (bcrypt), waliduj dane po stronie serwera, stosuj zasadę least privilege, aktualizuj zależności.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest XSS i jak się przed nim chronić?', 'XSS (Cross-Site Scripting) to atak polegający na wstrzyknięciu złośliwego JavaScript do strony. Wyróżniamy Stored (zapisany w bazie), Reflected (w URL) i DOM-based. Ochrona: escapowanie outputu HTML, Content Security Policy (CSP), używanie frameworków które automatycznie sanityzują (Angular, React). Nigdy nie używaj innerHTML z danymi użytkownika.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest SQL Injection?', 'SQL Injection to atak, w którym atakujący wstrzykuje złośliwy SQL przez dane wejściowe (np. formularz logowania). Zapobieganie: parametryzowane zapytania (prepared statements), ORM, walidacja danych wejściowych, zasada least privilege dla konta bazodanowego. Nigdy nie buduj zapytań SQL przez konkatenację stringów z danymi użytkownika.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest HTTP i HTTPS?', 'HTTP to protokół komunikacji klient-serwer w modelu request-response. HTTPS dodaje szyfrowanie TLS/SSL — dane są zaszyfrowane w tranzycie, serwer jest uwierzytelniony certyfikatem. HTTPS jest wymagany dla nowoczesnych API przeglądarki (geolokacja, service workers) i wpływa na SEO. Certyfikaty można uzyskać za darmo z Let''s Encrypt.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest DOM?', 'DOM (Document Object Model) to drzewiasta reprezentacja dokumentu HTML w pamięci przeglądarki. JavaScript manipuluje DOM-em, aby dynamicznie zmieniać treść strony. Bezpośrednia manipulacja DOM jest kosztowna — dlatego frameworki (React, Angular) używają Virtual DOM lub change detection, aby minimalizować operacje na prawdziwym DOM.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest event loop w JavaScript?', 'Event loop to mechanizm, który pozwala single-threaded JS obsługiwać asynchroniczność. Callstack wykonuje synchroniczny kod, Web APIs (setTimeout, fetch) delegują operacje, callback queue (macrotasks) i microtask queue (Promises) czekają na pusty stack. Microtaski mają priorytet nad macrotaskami. To dlatego Promise.resolve() wykona się przed setTimeout(0).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest closure w JavaScript?', 'Closure to funkcja, która „pamięta" zmienne z zakresu, w którym została utworzona, nawet po zakończeniu tego zakresu. Powstaje automatycznie, gdy funkcja wewnętrzna odwołuje się do zmiennych funkcji zewnętrznej. Zastosowania: enkapsulacja stanu, fabryki funkcji, moduły. Uwaga na closures w pętlach — var vs let ma znaczenie.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między var, let i const?', 'var ma function scope i jest hoistowany (podnoszony z wartością undefined). let i const mają block scope i temporal dead zone (błąd przy dostępie przed deklaracją). const wymaga inicjalizacji i nie pozwala na reassignment, ale obiekty przypisane do const mogą być mutowane. Zawsze używaj const, let tylko gdy musisz reassignować.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest hoisting?', 'Hoisting to mechanizm JS, w którym deklaracje zmiennych i funkcji są „przenoszone" na górę ich zakresu przed wykonaniem kodu. Deklaracje var są hoistowane z wartością undefined. Deklaracje function są hoistowane w całości (można wywołać przed deklaracją). let/const są hoistowane, ale w temporal dead zone — dostęp przed deklaracją rzuca ReferenceError.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest this w JavaScript?', 'this zależy od kontekstu wywołania: w metodzie obiektu — referencja do obiektu, w funkcji zwykłej — window (strict mode: undefined), w arrow function — dziedziczy this z zakresu nadrzędnego. Metody bind/call/apply pozwalają jawnie ustawić this. W klasach this wskazuje instancję. Arrow functions rozwiązują problem zagubionego this w callbackach.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się == od === w JavaScript?', '== (loose equality) wykonuje koercję typów przed porównaniem: "1" == 1 to true, null == undefined to true. === (strict equality) porównuje wartość i typ bez konwersji: "1" === 1 to false. Zawsze używaj === aby uniknąć nieintuicyjnych wyników koercji. Jedyny wyjątek: x == null sprawdza jednocześnie null i undefined.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest responsive web design?', 'RWD to podejście, w którym strona dostosowuje układ do rozmiaru ekranu. Narzędzia: media queries, flexbox, CSS Grid, relatywne jednostki (rem, %, vw/vh). Podejście mobile-first (styl bazowy dla mobile, media queries dla większych ekranów) jest preferowane. Viewport meta tag jest konieczny. Testuj na różnych urządzeniach i rozdzielczościach.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest box model w CSS?', 'Box model opisuje, jak przeglądarka renderuje elementy: content (treść), padding (wewnętrzny odstęp), border (obramowanie), margin (zewnętrzny odstęp). Domyślnie width dotyczy content-box — padding i border dodają się do szerokości. box-sizing: border-box sprawia, że width obejmuje padding i border, co jest zdecydowanie wygodniejsze.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest flexbox i kiedy go używasz?', 'Flexbox to jednowymiarowy system layoutu CSS (wiersze LUB kolumny). Kluczowe właściwości: display: flex, flex-direction, justify-content (oś główna), align-items (oś poprzeczna), flex-wrap, gap. Świetny do nawigacji, centrownia elementów, rozkładu kart. Dla dwuwymiarowych layoutów (wiersze I kolumny jednocześnie) lepszy jest CSS Grid.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest API i jak z niego korzystasz?', 'API (Application Programming Interface) to zdefiniowany interfejs komunikacji między systemami. W kontekście webowym najczęściej REST API lub GraphQL — klient wysyła HTTP request, serwer zwraca dane (JSON). Korzystam przez fetch/axios, obsługuję odpowiedzi i błędy. Dokumentacja (Swagger/OpenAPI) opisuje dostępne endpointy i formaty.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest JSON i do czego służy?', 'JSON (JavaScript Object Notation) to lekki format wymiany danych, czytelny dla ludzi i łatwy do parsowania przez maszyny. Obsługuje typy: string, number, boolean, null, object, array. Jest standardem w REST API. W JS: JSON.parse() konwertuje string na obiekt, JSON.stringify() — obiekt na string. Nie obsługuje komentarzy, funkcji ani undefined.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest npm/yarn i po co się go używa?', 'npm i yarn to package managery dla Node.js — zarządzają zależnościami projektu. package.json definiuje zależności i skrypty, node_modules przechowuje zainstalowane paczki, lock file (package-lock.json / yarn.lock) zapewnia powtarzalne buildy. Komendy: install, add, remove, update, audit (bezpieczeństwo). Nigdy nie commituj node_modules.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest TypeScript i dlaczego warto go używać?', 'TypeScript to nadzbiór JavaScript dodający statyczne typowanie. Łapie błędy w compile-time zamiast runtime, zapewnia lepsze autocomplete i refactoring w IDE, dokumentuje kod przez typy. Kompiluje się do JS. Kluczowe cechy: interfejsy, generics, enums, union types. Jest standardem w dużych projektach (Angular wymaga TS, React/Vue mocno go wspierają).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest SPA (Single Page Application)?', 'SPA to aplikacja webowa ładująca jedną stronę HTML, a następnie dynamicznie aktualizująca treść przez JavaScript (bez przeładowania). Routing odbywa się po stronie klienta. Zalety: płynne UX, szybka nawigacja. Wady: wolniejszy initial load, problemy z SEO (rozwiązanie: SSR/SSG). Frameworki: Angular, React, Vue.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest wzorzec MVC?', 'MVC (Model-View-Controller) to wzorzec architektoniczny dzielący aplikację na trzy warstwy: Model (dane i logika biznesowa), View (prezentacja), Controller (obsługa requestów i koordynacja). Separacja ułatwia testowanie i rozwój. Warianty: MVVM (Angular), MVP. W praktyce frameworki frontendowe używają komponentów, które łączą View i Controller.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest dependency injection?', 'DI to wzorzec, w którym zależności obiektu są dostarczane z zewnątrz zamiast tworzone wewnątrz. Umożliwia luźne powiązanie, łatwiejsze testowanie (podmiana na mocki) i konfigurowalność. W Angular DI jest wbudowane — serwisy rejestruje się w providerach, a framework wstrzykuje je przez konstruktor lub inject(). W testach łatwo podmienić na fake.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest middleware?', 'Middleware to warstwa pośrednia przetwarzająca request/response w pipeline. W Express.js to funkcja (req, res, next) — może logować, autoryzować, parsować body, obsługiwać błędy. Middleware wykonuje się sekwencyjnie, next() przekazuje do następnego. Przykłady: cors(), body-parser, sprawdzanie tokenu JWT, rate limiting.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz kody statusu HTTP?', '2xx — sukces: 200 OK, 201 Created, 204 No Content. 3xx — przekierowania: 301 Moved Permanently, 304 Not Modified. 4xx — błąd klienta: 400 Bad Request, 401 Unauthorized (brak uwierzytelnienia), 403 Forbidden (brak uprawnień), 404 Not Found, 409 Conflict, 422 Unprocessable Entity. 5xx — błąd serwera: 500, 502, 503.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CORS?', 'CORS (Cross-Origin Resource Sharing) to mechanizm bezpieczeństwa przeglądarki blokujący żądania do innej domeny. Serwer musi odpowiedzieć nagłówkami Access-Control-Allow-Origin, Allow-Methods, Allow-Headers. Preflight request (OPTIONS) jest wysyłany przed zapytaniami z custom headers. Na developmencie rozwiązuję proxy w webpack/angular.json.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest localStorage, sessionStorage i cookies?', 'localStorage — dane trwałe w przeglądarce (do 5-10MB), dostępne po odświeżeniu i zamknięciu. sessionStorage — dane na czas sesji karty. Cookies — małe dane (4KB) wysyłane automatycznie z każdym HTTP request, mają expiry, path, domain, flagi Secure/HttpOnly. Do tokenów JWT preferuję httpOnly cookies (bezpieczniejsze niż localStorage — odporne na XSS).', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Docker?', 'Docker to platforma konteneryzacji — pakuje aplikację ze wszystkimi zależnościami w lekki, przenośny kontener. Dockerfile definiuje instrukcje budowania obrazu. Kontener jest izolowanym procesem dzielącym kernel hosta. Zalety: „works on my machine" znika, spójne środowiska dev/staging/prod, szybki deploy. Docker Compose orkiestruje wiele kontenerów.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest token JWT i jak działa?', 'JWT (JSON Web Token) to standard tokenów składający się z trzech części: header (algorytm), payload (dane/claims) i signature (podpis). Serwer generuje JWT po logowaniu, klient wysyła go w nagłówku Authorization: Bearer <token>. Serwer weryfikuje podpis bez bazy — token jest self-contained. Uwaga: payload jest tylko base64, nie szyfrowany.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest ORM i po co się go używa?', 'ORM (Object-Relational Mapping) mapuje tabele bazy na obiekty w kodzie — zamiast pisać SQL, operujesz na obiektach. Przykłady: Prisma, TypeORM, Sequelize, Hibernate. Zalety: bezpieczeństwo (ochrona przed SQL injection), produktywność, migracje schematu. Wady: N+1 problem, mniejsza kontrola nad zapytaniami — czasem trzeba wrócić do raw SQL.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest garbage collection?', 'Garbage collection (GC) to automatyczne zarządzanie pamięcią — zwalnia obiekty, do których nie ma referencji. W JS/Java/C# nie musisz ręcznie alokować/zwalniać pamięci. GC w V8 (JS) używa algorytmu mark-and-sweep. Memory leak powstaje, gdy obiekt jest niepotrzebny, ale wciąż ma referencję (np. event listener, closure, timer nie wyczyszczony).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa prototypowe dziedziczenie w JavaScript?', 'Każdy obiekt JS ma ukryty link [[Prototype]] do innego obiektu. Gdy JS szuka właściwości, idzie w górę łańcucha prototypów. Object.create() tworzy obiekt z danym prototypem. Klasy ES6 to syntactic sugar nad prototypami. __proto__ to getter/setter, Object.getPrototypeOf() jest preferowany. Modyfikowanie wbudowanych prototypów jest antywzorcem.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest array destructuring i spread operator?', 'Destructuring to skrócony zapis wyciągania wartości: const [a, b] = [1, 2]; const {name} = obj. Spread (...) „rozpakowuje" iterable: [...arr1, ...arr2] łączy tablice, {...obj, key: val} tworzy nowy obiekt z nadpisanymi polami. Rest parameter (...args) zbiera argumenty do tablicy. Oba są niezbędne w codziennej pracy z JS/TS.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są higher-order functions?', 'Higher-order function to funkcja przyjmująca inną funkcję jako argument lub zwracająca funkcję. Przykłady wbudowane: map, filter, reduce, forEach, sort. Umożliwiają programowanie deklaratywne i kompozycję. Np. arr.filter(x => x > 0).map(x => x * 2) jest czytelniejsze niż pętla for z warunkiem. Reduce jest najpotężniejszy — można nim zaimplementować map i filter.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest immutability i dlaczego jest ważna?', 'Niemutowalność to zasada, w której obiekt po utworzeniu nie jest modyfikowany — tworzy się nową kopię ze zmianami. Zapobiega side-effectom, ułatwia debugowanie i śledzenie zmian (np. Redux, NgRx). W JS: Object.freeze() (płytki), spread operator i map/filter (tworzą nowe tablice). Biblioteki: Immer (JS), readonly w TypeScript.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa async/await?', 'async/await to syntactic sugar nad Promises. Funkcja oznaczona async zawsze zwraca Promise. await wstrzymuje wykonanie do rozwiązania Promise. Obsługa błędów: try/catch zamiast .catch(). Uwaga: await w pętli for wykonuje sekwencyjnie — do równoległego użyj Promise.all(). Top-level await działa w ES modules.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest webpack/vite i po co się go używa?', 'Webpack i Vite to bundlery — pakują moduły JS, CSS, assety w zoptymalizowane pliki do przeglądarki. Webpack jest konfigurowalne (loadery, pluginy), Vite jest szybszy (ESM w dev, Rollup w build). Funkcje: tree-shaking (usuwanie nieużywanego kodu), code splitting (lazy loading), hot module replacement (HMR) — zmiany bez przeładowania.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest semantic HTML?', 'Semantic HTML to używanie elementów o znaczeniu (header, nav, main, article, section, footer) zamiast generycznych div i span. Poprawia dostępność (screen readery interpretują strukturę), SEO (wyszukiwarki lepiej rozumieją treść) i czytelność kodu. Button zamiast div z onClick, label z for, odpowiednie nagłówki h1-h6.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest accessibility (a11y)?', 'Dostępność to projektowanie aplikacji użytecznych dla osób z niepełnosprawnościami. Kluczowe praktyki: semantic HTML, atrybuty ARIA, nawigacja klawiaturą (tabindex, focus management), kontrast kolorów (WCAG 2.1), alt na obrazach, labels na formularzach. Testuję narzędziami: Lighthouse, axe DevTools. Dostępność jest też wymogiem prawnym (EU: EAA).', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między null a undefined w JS?', 'undefined oznacza, że zmienna została zadeklarowana, ale nie przypisano jej wartości — to domyślna wartość. null to jawne przypisanie „brak wartości" przez programistę. typeof undefined === "undefined", typeof null === "object" (historyczny bug). W praktyce: null używam, gdy chcę jawnie oznaczyć brak, undefined jest wynikiem braku inicjalizacji.', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są design patterns i jakie znasz?', 'Design patterns to sprawdzone rozwiązania powtarzalnych problemów projektowych. Kreacyjne: Singleton (jedna instancja), Factory (tworzenie obiektów), Builder. Strukturalne: Adapter, Decorator, Facade. Behawioralne: Observer (pub/sub), Strategy, Iterator. W codziennej pracy najczęściej spotykam Observer (RxJS), Singleton (Angular services), Factory i Strategy.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest refactoring?', 'Refactoring to zmiana wewnętrznej struktury kodu bez zmiany zewnętrznego zachowania. Cele: poprawa czytelności, redukcja duplikacji, uproszczenie logiki. Wymaga dobrych testów (safety net). Typowe techniki: extract method/function, rename, inline, introduce parameter object. Refaktoryzuję małymi krokami, uruchamiając testy po każdej zmianie.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest PWA (Progressive Web App)?', 'PWA to aplikacja webowa z cechami natywnej: działa offline (Service Worker + Cache API), instalowalna na urządzeniu (manifest.json), obsługuje push notyfikacje. Service Worker to proxy między przeglądarką a siecią — przechwytuje requesty i serwuje z cache. PWA musi działać na HTTPS. Strategie cache: cache-first, network-first, stale-while-revalidate.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wygląda Twój typowy dzień pracy jako developer?', 'Zaczynam od daily standup — co zrobiłem, co planuję, jakie blokery. Pobieram zadania z backlogu (Jira/Linear), piszę kod na feature branchu z testami, tworzę PR i proszę o code review. Poprawiam uwagi, po akceptacji merge do main. Uczestniczę w refinement i planning. Automatyczne CI/CD wdraża zmiany. Poświęcam też czas na naukę i pair programming.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Jak zaprojektowałbyś system skracania URL-i (np. bit.ly)?', 'Potrzebuję: serwis generujący unikalny krótki klucz (base62 z auto-increment ID lub hash), baza klucz-URL (Redis dla szybkości + persistent store), redirect 301/302. Skalowalność: load balancer, sharding bazy po kluczu, CDN. Cache popular URLs. Rozważenia: rate limiting, analytics (zliczanie kliknięć), TTL na linki, collision handling.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mikroserwisy vs monolit — kiedy co wybrać?', 'Monolit na start: prostszy deploy, łatwiejsze debugowanie, jeden repo. Mikroserwisy gdy: zespół rośnie (autonomia), różne komponenty skalują się niezależnie, potrzeba różnych technologii. Mikroserwisy dodają złożoność: distributed transactions, eventual consistency, service discovery, observability. Zacznij od modularnego monolitu i wydzielaj serwisy, gdy jest jasna potrzeba.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij twierdzenie CAP.', 'CAP mówi, że rozproszony system może gwarantować tylko dwa z trzech: Consistency (każdy odczyt widzi najnowszy zapis), Availability (każdy request dostaje odpowiedź), Partition tolerance (system działa mimo utraty komunikacji). W praktyce partycje się zdarzają, więc wybierasz CP (np. ZooKeeper) lub AP (np. Cassandra). PACELC rozszerza: nawet bez partycji — latency vs consistency.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest event-driven architecture?', 'EDA to architektura, w której komponenty komunikują się przez zdarzenia (events) zamiast bezpośrednich wywołań. Producent emituje event, broker (Kafka, RabbitMQ) go dystrybuuje, konsumenci reagują. Zalety: luźne powiązanie, skalowalność, odporność. Wyzwania: eventual consistency, ordering, idempotency, debugging flow rozproszonych zdarzeń.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CQRS i kiedy go stosować?', 'CQRS (Command Query Responsibility Segregation) rozdziela model odczytu od zapisu. Komendy (write) modyfikują stan, zapytania (read) go pobierają — z osobnymi modelami/bazami. Stosuj, gdy: read i write mają różne wymagania skalowania, potrzebujesz zdenormalizowanych widoków, system jest event-driven. Często łączony z Event Sourcing. Dodaje złożoność — nie stosuj „bo można".', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak optymalizujesz wolne zapytanie SQL?', 'Zaczynam od EXPLAIN ANALYZE — patrzę na seq scan vs index scan, koszt, liczbę wierszy. Dodaję brakujące indeksy (na kolumnach WHERE, JOIN, ORDER BY). Sprawdzam: N+1 problem, brak LIMIT, niepotrzebne SELECT *, złe JOINy. Rozważam: composite index, partial index, materialized view. Monitoruję pg_stat_statements. Denormalizacja jako ostateczność.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz strategie cache''owania?', 'Cache-aside (lazy): aplikacja najpierw sprawdza cache, przy miss pobiera z bazy i zapisuje. Write-through: zapis jednocześnie do cache i bazy. Write-behind: zapis do cache, asynchronicznie do bazy. TTL zapobiega stale data. Invalidation: time-based, event-based. Narzędzia: Redis, Memcached. Cachuj na wielu warstwach: CDN, reverse proxy, aplikacja, baza.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest message queue i kiedy jej używasz?', 'Message queue (RabbitMQ, SQS, Kafka) to pośrednik asynchronicznej komunikacji. Producent wysyła wiadomość, konsument przetwarza. Zastosowania: odciążenie ciężkich operacji (email, generowanie PDF), decoupling serwisów, load leveling, retry logic. Kafka dodatkowo zapewnia log-based streaming z retencją. Ważne: idempotentny consumer, dead letter queue dla błędów.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa load balancing?', 'Load balancer rozdziela ruch między wiele instancji serwera. Algorytmy: round-robin, least connections, IP hash, weighted. L4 (transport — TCP) vs L7 (application — HTTP, routing po URL/header). Health checks wykrywają martwe instancje. Narzędzia: Nginx, HAProxy, AWS ALB. Session affinity (sticky sessions) dla stateful apps, ale preferuj stateless z shared session store.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest containerization i jaka jest różnica między kontenerem a VM?', 'Kontener to izolowany proces dzielący kernel hosta — lekki, szybki start (ms), mały rozmiar. VM to pełny system operacyjny z hypervisorem — cięższy, ale pełna izolacja. Docker używa namespaces i cgroups Linuxa. Kontenery idealnie pasują do mikroserwisów: immutable infrastructure, szybki deploy, łatwe skalowanie. Kubernetes orkiestruje kontenery w produkcji.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest observability i czym różni się od monitoringu?', 'Monitoring to zbieranie predefiniowanych metryk (CPU, pamięć, czas odpowiedzi) i alertowanie na thresholds. Observability to zdolność zrozumienia stanu systemu na podstawie jego outputów — trzy filary: logs (zdarzenia), metrics (liczby agregowane), traces (przepływ requestu między serwisami). Narzędzia: Prometheus+Grafana, ELK, Jaeger/Zipkin. Structured logging jest kluczowy.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz technical debt?', 'Tech debt to kompromisy w jakości kodu przyspieszające dostarczanie, ale spowalniające przyszły rozwój. Zarządzam: identyfikuję i dokumentuję (ADR), priorytetyzuję według wpływu na velocity, alokuję % sprintu na spłatę (np. 20%). Nie każdy dług jest zły — świadomy dług z planem spłaty jest OK. Refactoring ciągły jest lepszy niż wielkie przepisywanie.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak mentorujesz juniorów?', 'Zaczynam od zrozumienia ich poziomu i celów. Daję zadania stopniowo trudniejsze z jasnym kontekstem „dlaczego". Code review traktuję jako narzędzie nauki — wyjaśniam, nie tylko wskazuję. Pair programming na trudniejszych zadaniach. Zachęcam do zadawania pytań i samodzielnego rozwiązywania (dając wskazówki, nie gotowe rozwiązania). Regularne 1:1 i feedback.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak podejmujesz decyzje architektoniczne?', 'Zaczynam od zrozumienia wymagań (funkcjonalnych i niefunkcjonalnych: skala, latency, budżet). Analizuję opcje z tradeoffami. Dokumentuję w ADR (Architecture Decision Record): kontekst, rozważane opcje, decyzja, konsekwencje. Konsultuję z zespołem. Preferuję proste rozwiązania, reversible decisions i evolutionary architecture. YAGNI — nie projektuj na zapas.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Event Sourcing?', 'Event Sourcing przechowuje sekwencję zdarzeń (events) zamiast aktualnego stanu. Stan odtwarzasz przez replay eventów. Zalety: pełna historia zmian, audit log, możliwość projekcji różnych widoków, temporal queries. Wyzwania: event versioning, event schema evolution, wydajność odtwarzania (rozwiązanie: snapshots). Często łączony z CQRS.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak skanujesz horyzontalnie bazę danych?', 'Sharding: dzielisz dane między wiele instancji po kluczu (np. user_id mod N). Wybór shard key jest krytyczny — musi równomiernie rozkładać dane. Wyzwania: cross-shard queries, rebalancing, distributed transactions. Alternatywy: read replicas (skalowanie odczytów), partitioning (w jednej instancji). Managed sharding: CockroachDB, Vitess, Citus. Skaluj pionowo, dopóki się da.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest distributed transaction i jak ją obsłużyć?', 'Transakcja rozproszona obejmuje wiele serwisów/baz. Two-phase commit (2PC): koordynator pyta o gotowość, potem commituje — wolny, blokujący. Saga pattern: sekwencja lokalnych transakcji z kompensacjami przy błędzie (choreography lub orchestration). W mikroserwisach preferuj Saga z eventual consistency. Idempotentne handlery są kluczowe.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system notyfikacji?', 'Komponenty: API przyjmujący event, router decydujący o kanale (email, push, SMS, in-app), queue per kanał, providerzy (SendGrid, FCM, Twilio), baza preferencji użytkownika. Ważne: rate limiting, deduplication, retry z exponential backoff, dead letter queue, template engine, tracking (delivered/read). Skalowanie: osobne consumers per kanał, priority queue.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest API Gateway?', 'API Gateway to single entry point dla klientów w architekturze mikroserwisowej. Funkcje: routing, autentykacja, rate limiting, load balancing, request/response transformation, circuit breaker, caching, logging. Narzędzia: Kong, AWS API Gateway, Nginx. BFF (Backend for Frontend) to wariant — osobny gateway per typ klienta (mobile, web).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest circuit breaker pattern?', 'Circuit breaker chroni system przed kaskadowymi awariami. Stany: Closed (normal flow), Open (blokuje requesty po przekroczeniu progu błędów, zwraca fallback), Half-Open (próbuje po timeout). Implementacja: Hystrix (legacy), Resilience4j, Polly (.NET). Kluczowe: sensowne thresholds, fallback response, monitoring stanu circuit breakerów.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak podchodzisz do migracji legacy systemu?', 'Strangler Fig Pattern: stopniowo zastępuję fragmenty legacy nowym kodem, routując ruch przez proxy. Nie big bang rewrite (ryzyko!). Kroki: zrozum obecny system (dokumentacja, testy characterization), zidentyfikuj granice, wydzielaj bounded contexts. Parallel run: nowy i stary działają równocześnie, porównuję wyniki. Feature flags do kontrolowanego przełączania.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest twelve-factor app?', 'Twelve-factor to metodologia budowania SaaS. Kluczowe czynniki: codebase w VCS, dependencies jawnie deklarowane, config w env variables, backing services jako attached resources, build/release/run oddzielone, stateless processes, port binding, concurrency przez procesy, disposability (szybki start/stop), dev/prod parity, logs jako event stream, admin tasks jako one-off.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zapewnić wysoką dostępność systemu?', 'Redundancja: multiple instances, multi-AZ/region. Eliminacja SPOF (single point of failure). Load balancing z health checks. Database: primary-replica z automatic failover. Graceful degradation (fallbacki, feature flags). Chaos engineering (testuj awarie). SLA/SLO definiują target. Blue-green deploy eliminuje downtime. Circuit breakery chronią przed cascading failures.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest DDD (Domain-Driven Design)?', 'DDD to podejście, w którym architektura odzwierciedla domenę biznesową. Kluczowe koncepty: ubiquitous language (wspólny język z biznesem), bounded contexts (granice modeli), aggregates (spójne grupy encji), entities (identyfikowane po ID), value objects (identyfikowane po wartości), domain events. Bounded contexts mapują się na mikroserwisy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest idempotentność i dlaczego jest ważna w API?', 'Operacja idempotentna daje ten sam wynik niezależnie od liczby wywołań. GET, PUT, DELETE powinny być idempotentne. POST zazwyczaj nie jest. Ważna w distributed systems: retry nie powoduje duplikatów. Implementacja: idempotency key w nagłówku, sprawdzanie czy operacja już wykonana (deduplication). Krytyczna dla payment systems i message queues.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz REST API dla dużego systemu?', 'Konwencje: pluralne rzeczowniki (/users/{id}), HTTP verbs odpowiednio, status codes, wersjonowanie (URL lub header). Paginacja: cursor-based (skalowalny) > offset. Filtrowanie: query params. Rate limiting (429). HATEOAS dla discoverability. Dokumentacja: OpenAPI/Swagger. Bulk operations. Idempotency keys. Consistent error format. Backwards compatibility.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest blue-green deployment?', 'Blue-green to strategia deploy, w której masz dwa identyczne środowiska: blue (aktualne) i green (nowe). Deploy na green, testuj, przełącz ruch. Rollback = przełączenie z powrotem na blue. Zalety: zero downtime, szybki rollback. Wady: podwójne zasoby, migracje bazy wymagają backward compatibility. Wariant: canary — kierujesz % ruchu na nową wersję stopniowo.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system rate limiting?', 'Algorytmy: token bucket (steady rate z burst), sliding window (precyzyjny), fixed window (prosty, ale edge case na granicy okna), leaky bucket. Implementacja: Redis (INCR + EXPIRE, lub sorted sets dla sliding window). Klucze: per user, per IP, per endpoint. Nagłówki: X-RateLimit-Limit, Remaining, Reset. 429 Too Many Requests + Retry-After header.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz graceful shutdown w aplikacji?', 'Przy SIGTERM: przestań przyjmować nowe requesty, dokończ in-flight requests (timeout), zamknij połączenia do bazy/cache, zwolnij zasoby, exit z kodem 0. W Kubernetes: preStop hook + terminationGracePeriodSeconds. Health check przechodzi na unhealthy, load balancer przestaje kierować ruch. Consumer: dokończ przetwarzanie bieżącej wiadomości, commituj offset.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest eventual consistency?', 'Eventual consistency to model, w którym system gwarantuje, że dane będą spójne „w końcu" (po pewnym czasie), ale nie natychmiast. Przeciwieństwo strong consistency. Typowe w systemach rozproszonych (AP z CAP). Przykład: po dodaniu komentarza inny user może go zobaczyć z opóźnieniem. Wymaga: idempotentne operacje, retry, conflict resolution, kompensacja.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz system uwierzytelniania i autoryzacji?', 'Authentication (kim jesteś): OAuth2/OIDC z IdP (Keycloak, Auth0), JWT z refresh tokens, MFA. Authorization (co możesz): RBAC (role), ABAC (atrybuty), policy engine (OPA). JWT w httpOnly cookie. Access token krótki (15min), refresh token długi + rotation. Centralized auth service. Principle of least privilege. Audit log wszystkich zmian uprawnień.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest infrastructure as code?', 'IaC to zarządzanie infrastrukturą przez kod (deklaratywny) zamiast manualnych konfiguracji. Narzędzia: Terraform (multi-cloud, state file), Pulumi (real programming languages), CloudFormation (AWS), Ansible (configuration management). Zalety: wersjonowanie, powtarzalność, code review na infrastrukturę, disaster recovery. GitOps: infrastruktura driven przez Git.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak radzisz sobie z N+1 query problem?', 'N+1 to sytuacja, gdy pobierasz listę encji (1 query) i dla każdej z nich dopytywasz o relację (N queries). Rozwiązania: eager loading (JOIN/LEFT JOIN), batch loading (WHERE id IN(...)), dataloader pattern (batching + caching per request w GraphQL). W ORM: include/eager option. Wykrywanie: logowanie SQL, APM tools, testy liczby zapytań.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest feature flag i jak go używasz?', 'Feature flag to warunek w kodzie kontrolujący dostępność funkcjonalności bez deploy. Zastosowania: canary release (% userów), A/B testing, kill switch, trunk-based development (merge nieskończony feature). Narzędzia: LaunchDarkly, Unleash, Flagsmith. Ważne: cleanup starych flag, nie zagnieżdżaj wielu flag, testuj obie ścieżki. Technical debt jeśli nie usuwasz.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak monitorujesz wydajność aplikacji w produkcji?', 'APM (Application Performance Monitoring): Datadog, New Relic, Dynatrace — śledzą response time, throughput, error rate. RED metrics (Rate, Errors, Duration) dla serwisów, USE (Utilization, Saturation, Errors) dla zasobów. Distributed tracing (Jaeger) dla mikrousług. Alerting: PagerDuty/OpsGenie. Dashboardy w Grafana. SLI/SLO jako target. Real User Monitoring (RUM) dla frontendu.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest backpressure i jak go obsłużyć?', 'Backpressure to sytuacja, gdy producent generuje dane szybciej niż konsument może je przetworzyć. Bez obsługi: memory overflow, crash. Strategie: buforowanie (ograniczone), dropping (najstarsze lub losowe), throttling producenta, dynamiczne skalowanie konsumentów. W RxJS: switchMap, debounceTime. W Kafka: partycje + consumer groups. Queue z max size i back-off.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Service Mesh?', 'Service mesh to warstwa infrastruktury zarządzająca komunikacją między mikroserwisami. Sidecar proxy (np. Envoy) obsługuje: mTLS, load balancing, circuit breaking, retry, observability — bez zmian w kodzie aplikacji. Narzędzia: Istio, Linkerd. Control plane zarządza konfiguracją, data plane przetwarza ruch. Dodaje latency i złożoność — rozważ, czy potrzebujesz.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz konfiguracją w mikroserwisach?', 'Hierarchia: defaults w kodzie, environment variables (12-factor), config files per environment, centralized config service (Consul, Spring Cloud Config, AWS Parameter Store). Sekrety: Vault, AWS Secrets Manager — nigdy w kodzie/repo. Config hot-reload bez restartu. Feature flags dla runtime configuration. GitOps: config w repozytorium, sync automatyczny.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest database connection pooling?', 'Connection pool to zbiór wcześniej otwartych połączeń do bazy, reużywanych między requestami. Tworzenie połączenia jest kosztowne (TCP handshake, auth, SSL). Pool manager: PgBouncer (PostgreSQL), HikariCP (Java). Konfiguracja: min/max connections, idle timeout, max lifetime. Za mało — bottleneck, za dużo — baza przeciążona. Formuła: connections = (core_count * 2) + disk_spindles.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś feed aktywności (np. Twitter)?', 'Dwa podejścia: fan-out on write (przy poście, wstaw do feed każdego followera — szybki odczyt, kosztowny zapis dla celebrytów) lub fan-out on read (przy odczycie, pobierz posty followowanych — wolniejszy odczyt, prostszy zapis). Hybrid: fan-out on write dla zwykłych, on read dla celebrytów. Cache timeline w Redis. Paginacja cursor-based. Ranking algorytm.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest optimistic vs pessimistic locking?', 'Optimistic: zakłada brak konfliktów, sprawdza wersję przy zapisie (version column). Jeśli wersja się zmieniła — retry. Dobry przy niskim contention. Pessimistic: blokuje rekord na czas edycji (SELECT FOR UPDATE). Gwarantuje brak konfliktów, ale zmniejsza throughput. Optimistic preferowany w web apps (request-response), pessimistic w krytycznych operacjach (finanse).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest trunk-based development?', 'TBD to strategia, w której wszyscy commitują do main/trunk. Feature branche są krótkotrwałe (max 1-2 dni). Wymaga: CI, feature flags, pair programming, dobra test suite. Zalety: mniej merge conflictów, szybszy feedback, prostszy pipeline. Kontrastuje z Git Flow (długotrwałe branche develop, release). Google, Facebook, Netflix stosują TBD.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz API backward compatible?', 'Zasady: dodawaj pola, nie usuwaj. Nowe pola opcjonalne z defaults. Wersjonowanie: URL (/v2/) lub header (Accept-Version). Deprecation policy: ogłoś, daj czas na migrację, monitoruj użycie starej wersji. Nie zmieniaj semantyki istniejących pól. Breaking change = nowa wersja. Consumer-driven contract testing (Pact) wykrywa niezgodności.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są SLI, SLO i SLA?', 'SLI (Service Level Indicator) to metryka: np. % requestów < 200ms. SLO (Service Level Objective) to cel wewnętrzny: np. 99.9% requestów < 200ms. SLA (Service Level Agreement) to kontrakt z klientem z konsekwencjami (kary, kredyty). Error budget = 100% - SLO — gdy się wyczerpie, stop nowych features, focus na reliability. Mierz to, co użytkownik odczuwa.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak radzisz sobie z distributed logging?', 'Structured logging (JSON) z correlation ID przekazywanym między serwisami (przez header). Centralized log aggregation: ELK Stack (Elasticsearch, Logstash, Kibana) lub Loki+Grafana. Log levels: error (wymaga akcji), warn (anomalia), info (flow), debug (troubleshooting). Nie loguj PII/secrets. Retention policy. Alerting na error patterns.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest chaos engineering?', 'Chaos engineering to praktyka celowego wprowadzania awarii w systemie produkcyjnym (lub staging) by zweryfikować odporność. Narzędzia: Chaos Monkey (Netflix), Gremlin, LitmusChaos. Eksperymenty: kill instancji, dodanie latency, partycja sieci, pełny dysk. Wymaga: hipoteza, blast radius limitation, monitoring. Buduje zaufanie do systemu i ujawnia ukryte zależności.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system kolejkowania zadań?', 'Komponenty: producer API, queue (Redis/SQS/RabbitMQ), consumer workers. Cechy: priority queues, delay/scheduled jobs, retry z exponential backoff, dead letter queue, job deduplication (idempotency key), rate limiting. Monitoring: queue depth, processing time, failure rate. Autoscaling workers na podstawie queue depth. Narzędzia: BullMQ (Node), Celery (Python), Sidekiq (Ruby).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz mikroserwisy?', 'Piramida: unit testy (logika), integration testy (serwis + baza/queue), contract testy (Pact — zgodność API między serwisami), component testy (serwis z mockowanymi zależnościami), e2e testy (full flow, minimalizuj). Testcontainers dla real dependencies w CI. Consumer-driven contracts łapią breaking changes. Chaos testing w staging/prod.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest database migration i jak ją zarządzasz?', 'Migracje to wersjonowane zmiany schematu bazy w kodzie. Narzędzia: Flyway, Liquibase, Prisma Migrate, Knex, Django migrations. Zasady: additive changes (nie usuwaj kolumn od razu), backward compatible (stary kod musi działać z nowym schematem), ekspanduj-kontrakcja (dodaj nową, migruj dane, usuń starą). Rollback: oddzielna migracja, nie revert. Testuj migracje na kopii produkcji.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak komunikujesz się z nietechnicznymi stakeholderami?', 'Unikam żargonu technicznego, tłumaczę w kontekście biznesowym (wartość, ryzyko, czas, koszt). Używam analogii i wizualizacji. Przy decyzjach architektonicznych prezentuję opcje z tradeoffami. Transparentnie komunikuję ryzyka i blockers. Regularne statusy. RFC/ADR dokumentują decyzje. Słucham wymagań biznesowych i proponuję techniczne rozwiązania spełniające je.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest data partitioning i jakie są typy?', 'Partitioning dzieli duże tabele na mniejsze fragmenty. Typy: range (np. po dacie — miesiące), hash (równomierny rozkład po kluczu), list (po kategorii). Zalety: szybsze query (partition pruning), łatwiejsze archiwizowanie, parallel scan. PostgreSQL obsługuje declarative partitioning. Partycja vs sharding: partitioning w jednej bazie, sharding na wielu maszynach.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wdrażasz zero-downtime deployment?', 'Wymagania: rolling update (nowa wersja stopniowo zastępuje starą), backward-compatible migrations (expand-contract), health checks, graceful shutdown. Blue-green lub canary deployment. Database: additive schema changes, dual-write jeśli konieczne. Feature flags do stopniowego włączania. Kubernetes rolling update strategy z maxSurge i maxUnavailable.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest bounded context w DDD?', 'Bounded context to granica, w której model domeny jest spójny i ma jednoznaczne definicje. Każdy kontekst ma swój ubiquitous language — „User" może znaczyć co innego w kontekście billing i auth. Konteksty komunikują się przez events lub API, nie współdzielą bazy. Mapują się naturalnie na mikroserwisy. Context mapping definiuje relacje: shared kernel, customer-supplier, conformist.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektowałbyś system wyszukiwania pełnotekstowego?', 'Elasticsearch (lub OpenSearch): inverted index, analyzers (tokenization, stemming, synonyms), relevance scoring (TF-IDF/BM25). Architektura: source of truth w primary DB, async sync do ES (CDC lub event). Typy queries: match, multi_match, bool, fuzzy. Pagination: search_after (nie offset). Sugestie: completion suggester. Facets: aggregations. Skalowanie: shards, replicas.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest webhook i jak go poprawnie zaimplementować?', 'Webhook to HTTP callback — serwis A wysyła POST do URL serwisu B przy zdarzeniu. Implementacja: retry z exponential backoff, signature verification (HMAC), idempotency (deduplication po event ID), timeout i circuit breaker. Odbiorca: szybki ACK (202), przetwarzanie async w queue. Delivery guarantee: at-least-once. Dead letter dla nieosiągalnych endpointów.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak podchodzisz do postmortem po incydencie?', 'Blameless postmortem po każdym poważnym incydencie. Struktura: timeline zdarzeń, impact, root cause (5 Whys), contributing factors, co zadziałało, co nie, action items z właścicielami i deadlinami. Cel: zapobiec powtórzeniu, nie karać ludzi. Dzielenie się wiedzą z zespołem. Śledź completion rate action items. Budowanie kultury uczenia się na błędach.', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest GraphQL Federation?', 'Federation pozwala wielu mikroserwsom udostępniać jeden spójny graf GraphQL. Każdy serwis definiuje swój subgraph (schema). Apollo Router/Gateway łączy je w supergraph. Dyrektywy @key, @shareable, @external definiują jak typy i pola są rozdzielone. Zalety: team autonomy, single endpoint dla klienta. Wyzwania: query planning, latency, distributed tracing.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz wersjami API w dużym systemie?', 'Strategie: URI versioning (/v1/users — najprostsze), header versioning (Accept: application/vnd.api+json;version=2), query param (?version=2). Preferuję URI dla public API. Sunset header informuje o deprecation. Monitoruj użycie starych wersji. API changelog. Minimum 2 wersje jednocześnie. Consumer-driven contract testy zapobiegają niezamierzonym zmianom.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz system odporny na awarie (resilient)?', 'Wzorce: circuit breaker (fail fast), retry z jitter, timeout (nie czekaj w nieskończoność), bulkhead (izolacja zasobów), fallback (graceful degradation). Redundancja: multi-AZ, replicas. Health checks: liveness (restart) i readiness (ruch). Graceful shutdown. Chaos engineering do weryfikacji. Cel: system działa z degradacją, nie pada całkowicie.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak oceniasz, czy microservice powinien zostać wydzielony?', 'Kryteria: niezależny cykl deploymentu (inny team/tempo zmian), różne wymagania skalowania, bounded context z jasną granicą, inna technologia potrzebna. Kontra: shared data model, tight coupling, potrzeba distributed transactions — zostawiaj razem. Zacznij od modularnego monolitu z jasnymi granicami modułów. Wydzielaj, gdy masz dowody potrzeby, nie „bo mikroserwisy są cool".', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różni się type od interface w TypeScript?', 'Interface deklaruje kształt obiektu i może być rozszerzany (extends) oraz mergowany (declaration merging). Type alias jest bardziej elastyczny — obsługuje union, intersection, mapped types, conditional types. Interfejsy lepiej sprawdzają się do definiowania kontraktów publicznych API, type aliasy do złożonych typów. Od TS 4.x różnice maleją, ale declaration merging jest unikalne dla interface.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są generics i po co je stosować?', 'Generics to parametryzowane typy pozwalające pisać reusable kod zachowujący type safety. Zamiast any, deklarujesz placeholder <T>, który jest konkretyzowany przy użyciu. Przykład: function identity<T>(arg: T): T. Ograniczenia: <T extends HasId> wymusza, że T ma pole id. Generics są kluczowe w utility types, kolekcjach i serwisach HTTP.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są conditional types?', 'Conditional types to ternary na poziomie typów: T extends U ? X : Y. Pozwalają na logikę w typach. Z infer wyciągają typy: type ReturnType<T> = T extends (...args: any) => infer R ? R : never. Distributive behavior: gdy T jest union, conditional type jest aplikowany do każdego membera osobno. Kluczowe w budowaniu zaawansowanych utility types.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są mapped types?', 'Mapped types iterują po kluczach i transformują typ: type Readonly<T> = { readonly [K in keyof T]: T[K] }. Modyfikatory: readonly, ?, z + i - (dodanie/usunięcie). as w mapped types (TS 4.1) pozwala remapować klucze: [K in keyof T as `get${Capitalize<K>}`]. Przykłady: Partial, Required, Pick, Record. Bardzo potężne do generowania typów na podstawie istniejących.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są template literal types?', 'Template literal types budują typy stringowe z interpolacji: type Event = `on${Capitalize<string>}`. Przykład: type Color = "red" | "blue"; type BgColor = `bg-${Color}` daje "bg-red" | "bg-blue". W połączeniu z mapped types i conditional types pozwalają na typed routes, CSS class names, event handlers. Potężne do typowania API z konwencjami nazewnictwa.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są type guards i jak je pisać?', 'Type guard to wyrażenie zawężające typ w runtime. Wbudowane: typeof, instanceof, in. Custom: function isFish(pet: Fish | Bird): pet is Fish { return ''swim'' in pet; } — predykat is. Discriminated unions + switch to najlepszy pattern. Assertion functions: function assertDefined<T>(val: T | undefined): asserts val is T. Narrowing jest kluczowy dla type-safe kodu.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest discriminated union?', 'Discriminated union to union type, gdzie każdy member ma wspólne pole „dyskryminator" o literalnym typie: type Shape = { kind: "circle"; radius: number } | { kind: "square"; side: number }. Switch po kind daje exhaustive type checking — TypeScript wie jakie pola są dostępne w każdym case. Dodanie nowego wariantu powoduje compile error w niewyczerpujących switchach (z never).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij Partial<T>, Required<T>, Pick<T,K> i Omit<T,K>.', 'Partial<T> robi wszystkie pola opcjonalne — idealne do update DTO. Required<T> robi wszystkie wymagane. Pick<T, "a" | "b"> wybiera podzbiór pól. Omit<T, "secret"> wyklucza pola. Implementacje oparte na mapped types. Composable: Partial<Pick<User, "name" | "email">>. Kluczowe w codziennym TS — modelują częściowe dane, formy, API responses.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Record<K,V>, Extract<T,U> i Exclude<T,U>?', 'Record<K, V> tworzy typ obiektowy z kluczami K i wartościami V: Record<string, number> to { [key: string]: number }. Extract<T, U> wyciąga z union T te typy, które pasują do U. Exclude<T, U> usuwa z T typy pasujące do U. Przykład: Exclude<"a"|"b"|"c", "a"> = "b"|"c". Przydatne do filtrowania union types i tworzenia dictionary-like structures.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest declaration merging?', 'Declaration merging to mechanizm, w którym TypeScript łączy wiele deklaracji o tej samej nazwie. Dotyczy interfaces (pola się łączą), namespaces, function overloads. Interfejsy o tej samej nazwie automatycznie się mergują — dlatego można rozszerzać zewnętrzne typy (np. Window, Request). Type aliasy NIE mergują się — to kluczowa różnica. Używane w module augmentation.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest module augmentation?', 'Module augmentation pozwala dodawać typings do istniejących modułów bez modyfikowania ich kodu. Składnia: declare module "express" { interface Request { user?: User } }. Wymaga, by plik był modułem (import/export). Praktyczne: dodanie pól do req w Express, rozszerzenie interfejsów bibliotek, dodanie globalnych typów. Bez tego trzeba by castować na any.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest strictNullChecks i dlaczego warto go włączyć?', 'strictNullChecks sprawia, że null i undefined nie są przypisywalne do innych typów bez jawnego oznaczenia (string | null). Bez tego flaga null może się wkraść wszędzie i powodować runtime errors. Z tą flagą kompilator wymusza obsługę nullable wartości. Włączaj zawsze — łapie ogromną kategorię bugów. Optional chaining (?.) i nullish coalescing (??) pomagają elegancko obsługiwać null.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się unknown od any?', 'any wyłącza type checking — pozwala na dowolne operacje bez weryfikacji (niebezpieczne). unknown jest typem top — możesz przypisać cokolwiek do unknown, ale nie możesz nic z tym zrobić bez narrowingu (type guard, assertion). unknown zmusza do sprawdzenia typu przed użyciem — jest bezpiecznym zamiennikiem any. Używaj unknown do danych z zewnątrz (API responses, user input).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest typ never?', 'never to typ bottom — żadna wartość go nie ma. Funkcje zwracające never: rzucają exception lub mają infinite loop (nigdy nie returnują). W exhaustive checking: default case w switch na discriminated union — jeśli zapomnimy wariantu, TypeScript pokaże błąd, bo wartość nie jest przypisywalna do never. Conditional types: typ eliminowany z union (Exclude).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest readonly i jak go używać?', 'readonly modyfikator zapobiega modyfikacji pola po inicjalizacji: readonly name: string. Readonly<T> utility type robi wszystkie pola readonly. ReadonlyArray<T> (lub readonly T[]) blokuje push, pop itd. Uwaga: readonly jest shallow — nested obiekty mogą być mutowane. Dla deep readonly: DeepReadonly z bibliotekami lub rekurencyjny mapped type. as const daje deepest readonly.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest const assertion (as const)?', 'as const zamienia wartość w literal type i dodaje readonly na wszystkich poziomach. const colors = ["red", "blue"] as const daje readonly ["red", "blue"] (tuple z literal types) zamiast string[]. Obiekt z as const ma literal types na wartościach. Przydatne: definiowanie enum-like constów, generowanie union types z tablicy (typeof colors[number] = "red" | "blue").', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa type narrowing w TypeScript?', 'Narrowing to proces zawężania typu w bloku kodu. Mechanizmy: typeof (primitives), instanceof (klasy), in (pola), equality checks, truthiness checks, discriminated unions (switch), custom type guards (is), assertion functions (asserts). TypeScript analizuje control flow — po if (typeof x === "string") w bloku x jest string. Narrowing działa też z optional chaining i nullish coalescing.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest infer keyword w conditional types?', 'infer deklaruje tymczasowy typ w conditional type: type ReturnType<T> = T extends (...args: any) => infer R ? R : never — R jest inferowany z return type. Inne przykłady: type ElementType<T> = T extends (infer U)[] ? U : T wyciąga element z tablicy. infer działa tylko w extends clause. Można mieć wiele infer w jednym wyrażeniu. Potężne do „wyciągania" typów.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest keyof i typeof na poziomie typów?', 'keyof T zwraca union kluczy typu T: keyof { name: string; age: number } = "name" | "age". typeof w kontekście typu (nie runtime) wyciąga typ ze zmiennej: const user = {name: "Jan"}; type User = typeof user. Razem: typeof + keyof do dynamicznego generowania typów z wartości. Object.keys() zwraca string[], keyof daje dokładne klucze — ważna różnica.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest intersection type (T & U)?', 'Intersection łączy typy — wynikowy typ ma WSZYSTKIE pola z obu: type Employee = Person & { company: string }. Różni się od union (T | U), który ma JEDEN z typów. Intersection dla interfejsów działa jak extends/merge. Dla primitives: string & number = never (brak wspólnych wartości). Przydatne do mixowania typów: WithTimestamps<T> = T & { createdAt: Date; updatedAt: Date }.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować funkcje wyższego rzędu w TypeScript?', 'Generics są kluczowe: function map<T, U>(arr: T[], fn: (item: T) => U): U[]. Callback z określonym typem: (event: MouseEvent) => void. Overloads dla różnych sygnatur. Higher-order function zwracająca funkcję: function withLogging<T extends (...args: any[]) => any>(fn: T): T. Typy funkcyjne: type Predicate<T> = (item: T) => boolean.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest enum w TypeScript i jakie ma wady?', 'Enum definiuje nazwane stałe: enum Direction { Up, Down }. Numeric enum generuje reverse mapping (dodatkowy JS). String enum ("UP") nie generuje reverse mapping. Wady: enums emitują runtime kod, tree-shaking problematyczny, numeric enums nie są type-safe (można przypisać dowolną liczbę). Alternatywa: const enum (inlinowane) lub union of literals: type Dir = "up" | "down" (zero runtime cost).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest satisfies operator w TypeScript?', 'satisfies (TS 4.9+) sprawdza, czy wartość spełnia typ BEZ poszerzania go. const colors = { red: "#f00" } satisfies Record<string, string> — TypeScript sprawdza zgodność, ale zachowuje literal types (red jest "red", nie string). Bez satisfies musiałbyś wybrać: poszerzony typ (: Record<>) lub brak walidacji (as const). satisfies daje walidację + precyzyjny typ.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa type assertion (as) i kiedy go unikać?', 'Type assertion (x as Type) mówi kompilatorowi „wiem lepiej". Nie wykonuje konwersji runtime — tylko zmienia typ w kompilatorze. Niebezpieczne: jeśli assertion jest błędny, runtime error. Unikaj: preferuj type guards, narrowing, generics. Użyj gdy: TS nie może wywnioskować typu (DOM: document.getElementById() as HTMLInputElement). Double assertion (x as unknown as Y) to red flag.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest function overloading w TypeScript?', 'Overloading pozwala zdefiniować wiele sygnatur dla jednej funkcji: function parse(input: string): number; function parse(input: number): string; function parse(input: string | number): any { ... }. Implementacja musi obsłużyć wszystkie warianty. TS wybiera najlepsze dopasowanie. Używaj gdy zachowanie zależy od typów argumentów. Alternatywa: generic z conditional return type.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest covariance i contravariance w TypeScript?', 'Covariance: jeśli Dog extends Animal, to Array<Dog> jest przypisywalny do Array<Animal> (typy wyjściowe). Contravariance: parametry funkcji — (animal: Animal) => void NIE jest przypisywalny do (dog: Dog) => void (strictFunctionTypes). Bivariance: bez strict — oba kierunki dozwolone (niebezpieczne). Ważne przy typowaniu callbacków i generics z extends.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak tworzyć recursive types w TypeScript?', 'Typy rekurencyjne odwołują się do siebie: type Json = string | number | boolean | null | Json[] | { [key: string]: Json }. Praktyczne: type DeepPartial<T> = { [K in keyof T]?: T[K] extends object ? DeepPartial<T[K]> : T[K] }. Rekurencyjne conditional types (TS 4.1+): type DeepReadonly, Flatten nested arrays. Uwaga na głębokość rekursji — TS ma limit.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest branded/nominal typing w TypeScript?', 'TS ma structural typing — typy są kompatybilne jeśli mają te same pola. Branded types dodają unikalne pole „phantom" dla type safety: type UserId = string & { __brand: "UserId" }. Funkcja acceptująca UserId nie przyjmie zwykłego stringa. Zapobiega pomyleniu UserID z OrderID (oba string). Implementacja: factory function + type assertion. Alternatywa: opaque types z unique symbol.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest strict mode w tsconfig i jakie flagi obejmuje?', 'strict: true włącza zestaw flag: strictNullChecks (null/undefined osobne), strictFunctionTypes (contravariance), strictBindCallApply, strictPropertyInitialization, noImplicitAny (wymusza typy), noImplicitThis, alwaysStrict (JS strict mode). Zawsze włączaj na starcie — dodawanie do istniejącego projektu jest bolesne. Każda flaga łapie real-world bugs.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować async/await i Promises w TypeScript?', 'Async function zawsze zwraca Promise<T>: async function fetchUser(): Promise<User>. Await „wypakowuje" Promise: const user = await fetchUser() — user ma typ User. Promise.all zwraca tuple typów: Promise.all([fetchUser(), fetchPosts()]) → [User, Post[]]. Error handling: try/catch z unknown (TS 4.4+) — catch(e: unknown), narrowing e przed użyciem.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest index signature i jakie ma ograniczenia?', 'Index signature: { [key: string]: number } pozwala na dowolne klucze string z wartością number. Ograniczenia: wszystkie pola muszą być kompatybilne z index signature. Record<string, unknown> jest bezpieczniejszy. noUncheckedIndexedAccess (TS 4.1) dodaje | undefined do wyników — wymusza sprawdzenie. Map<K,V> jest alternatywą z lepszym API i brakiem prototype pollution risk.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają tuple types w TypeScript?', 'Tuple to tablica o stałej długości z typem na każdej pozycji: [string, number, boolean]. Nazwane: [name: string, age: number]. Rest element: [string, ...number[]]. Optional: [string, number?]. Readonly: readonly [string, number]. Przydatne jako return type wielu wartości: function usePair(): [value, setter]. Destructuring daje poprawne typy: const [name, age] = tuple.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest utility type NonNullable<T>?', 'NonNullable<T> usuwa null i undefined z union type: NonNullable<string | null | undefined> = string. Implementacja: type NonNullable<T> = T extends null | undefined ? never : T (conditional type z distribution). Przydatne przy danych z API, gdy wiesz, że wartość istnieje po walidacji. Łączy się z Optional chaining: po sprawdzeniu if (x != null) TS sam narrowuje.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są ReturnType<T> i Parameters<T>?', 'ReturnType<T> wyciąga typ zwracany: ReturnType<typeof fetchUser> = Promise<User>. Parameters<T> wyciąga tuple parametrów: Parameters<typeof fn> = [string, number]. Implementacja: conditional type z infer. Przydatne: tworzenie typów z istniejących funkcji bez duplikacji, wrappery zachowujące sygnaturę. ConstructorParameters<T> i InstanceType<T> — analogicznie dla klas.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować React props z TypeScript?', 'Interface lub type dla props: interface ButtonProps { label: string; onClick: () => void; variant?: "primary" | "secondary" }. FC<Props> lub function Button(props: ButtonProps). Children: React.ReactNode. Event handlers: React.MouseEvent<HTMLButtonElement>. Generics dla reusable components: Table<T>. PropsWithChildren<P>. ComponentProps<"button"> dla natywnych elementów.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Awaited<T> w TypeScript?', 'Awaited<T> (TS 4.5+) wypakowuje typ z Promise, nawet zagnieżdżonego: Awaited<Promise<Promise<string>>> = string. Zastępuje ręczne: T extends Promise<infer U> ? U : T. Używany wewnętrznie przez Promise.all, Promise.race. Przydatne do typowania wyniku async operacji: type Result = Awaited<ReturnType<typeof fetchData>>.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa structural typing vs nominal typing?', 'TypeScript używa structural typing — typy są kompatybilne jeśli mają zgodną strukturę (shape), niezależnie od nazwy. { name: string } jest przypisywalne do interface Named { name: string }. W C#/Java jest nominal — klasy muszą jawnie implementować interfejs. Structural jest elastyczniejszy, ale mniej precyzyjny. Branded types dodają nominalność tam, gdzie trzeba (UserId vs OrderId).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest variadic tuple type?', 'Variadic tuples (TS 4.0) pozwalają na spread typów w tuples: type Concat<A extends any[], B extends any[]> = [...A, ...B]. Concat<[1, 2], [3, 4]> = [1, 2, 3, 4]. Przydatne do typowania variadic functions, partial application, pipe/compose. Łączą się z infer: type Last<T extends any[]> = T extends [...any, infer L] ? L : never.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest declaration file (.d.ts)?', 'Declaration file (.d.ts) zawiera tylko typy — bez implementacji. Opisuje kształt biblioteki JS dla TypeScript. Generowany automatycznie (declaration: true w tsconfig) lub ręcznie. DefinitelyTyped (@types/*) to repozytorium deklaracji dla bibliotek bez wbudowanych typów. declare module, declare global rozszerzają istniejące typy. skipLibCheck: true przyspiesza kompilację.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak używać generic constraints?', 'Generic constraint (extends) ogranicza, jakie typy można przekazać: function getProperty<T, K extends keyof T>(obj: T, key: K): T[K]. T extends { id: string } wymaga, by T miał pole id. Multiple constraints: T extends A & B. Default generic: <T = string>. Constraints zapewniają type safety zachowując elastyczność — kompilator wie jakie operacje są bezpieczne na T.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest type predicate i assertion function?', 'Type predicate (is): function isString(x: unknown): x is string { return typeof x === "string" } — zwraca boolean, ale narrowuje typ w callerze. Assertion function (asserts): function assertString(x: unknown): asserts x is string { if (typeof x !== "string") throw Error() } — rzuca lub narrowuje (nie zwraca boolean). Assertion przydatna w validation pipelines.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak TypeScript obsługuje mixins?', 'Mixin to wzorzec dodawania funkcjonalności do klasy bez dziedziczenia. W TS: function Timestamped<T extends Constructor>(Base: T) { return class extends Base { createdAt = new Date() } }. class User extends Timestamped(Base) {}. Wymaga typowania Constructor: type Constructor = new (...args: any[]) => {}. Alternatywa: interface merging + Object.assign w TS.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest using keyword (TS 5.2) i Disposable?', 'using (TS 5.2+) to deklaracja zmiennej z automatycznym cleanup — jak C# using/Python with. Obiekt musi implementować Symbol.dispose (sync) lub Symbol.asyncDispose (async). Po wyjściu z scope dispose jest wywołany automatycznie. Przydatne: połączenia DB, file handles, temporary resources. Eliminuje try/finally boilerplate. Bazuje na TC39 Explicit Resource Management proposal.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak typować wzorzec Builder w TypeScript?', 'Builder z chainable API: class QueryBuilder<T> { where<K extends keyof T>(field: K, value: T[K]): this { ... return this }. this typ pozwala na chaining w podklasach. Generics śledzą stan buildera: AddField<T, K, V> dodaje pole. Wynikowy typ zmienia się z każdym krokiem — kompilator wymusza wymagane pola. Implementacja: mapped types + intersection.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest NoInfer<T> w TypeScript 5.4?', 'NoInfer<T> (TS 5.4+) blokuje inference z danej pozycji. Przykład: function fn<T>(values: T[], defaultValue: NoInfer<T>) — TS nie inferuje T z defaultValue, tylko z values. Rozwiązuje problem, gdy TS infers zbyt szeroką unię z wielu argumentów. Przydatne w API z wieloma parametrami tego samego typu generycznego, gdy chcesz kontrolować skąd TS bierze typ.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementować exhaustive check w TypeScript?', 'Exhaustive check zapewnia obsługę wszystkich wariantów union. Wzorzec: function assertNever(x: never): never { throw new Error("Unexpected: " + x) }. W switch na discriminated union: default: return assertNever(variant). Jeśli zapomnimy case, TS zgłosi błąd — variant nie jest never. Alternatywa: satisfies Record<MyUnion, handler>. Chroni przed dodaniem wariantu bez obsługi.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest path mapping w tsconfig?', 'Path mapping (paths w tsconfig) tworzy aliasy importów: "@app/*": ["src/app/*"], "@shared/*": ["src/shared/*"]. Zamiast "../../../shared/utils" piszesz "@shared/utils". Wymaga baseUrl. Bundler (webpack/vite) musi też znać aliasy. W monorepo: paths do bibliotek. Uwaga: tsc nie transformuje paths w output — potrzebny bundler lub tsc-alias. Czytelniejsze importy.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak używać TS z biblioteką bez typów?', 'Opcje: 1) @types/nazwa z DefinitelyTyped (npm i -D @types/lodash). 2) declare module "lib" { export function fn(): void } w pliku .d.ts. 3) // @ts-ignore lub as any (ostateczność). 4) Napisz własny .d.ts z typami. allowJs + checkJs dla stopniowej migracji JS→TS. skipLibCheck: true pomija sprawdzanie .d.ts (szybsza kompilacja, mniej false positives).', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest project references w TypeScript?', 'Project references (references w tsconfig) dzielą duży projekt na mniejsze z oddzielnymi tsconfig. Każdy sub-project buduje się niezależnie (incremental). tsc --build buduje w kolejności zależności. Zalety: szybsza kompilacja (tylko zmienione projekty), enforcement granic (moduł A nie importuje z wewnętrznego B). Idealne dla monorepo z shared libraries.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak TypeScript obsługuje type widening i narrowing?', 'Widening: TS rozszerza literal typy — let x = "hello" → string, const x = "hello" → "hello". as const blokuje widening. Narrowing: zawężanie typów w control flow — if, typeof, instanceof, in, type guards. TS śledzi control flow i automatycznie narrowuje. Widening jest domyślne dla mutowalnych zmiennych, narrowing działa w warunkach i type guard functions.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różnią się INNER JOIN, LEFT JOIN, RIGHT JOIN i FULL JOIN?', 'INNER JOIN zwraca wiersze z dopasowaniem w obu tabelach. LEFT JOIN — wszystkie z lewej + dopasowane z prawej (NULL gdy brak). RIGHT JOIN — odwrotnie. FULL JOIN — wszystkie z obu stron (NULL po obu stronach gdy brak dopasowania). LEFT JOIN jest najczęstszy — „pokaż wszystkich userów i ich zamówienia, nawet jeśli nie mają zamówień".', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CROSS JOIN?', 'CROSS JOIN zwraca iloczyn kartezjański — każdy wiersz z tabeli A z każdym z tabeli B. 10 x 10 = 100 wierszy. Rzadko używany celowo. Zastosowania: generowanie kombinacji (rozmiary x kolory), calendar tables (daty x sloty). Bez warunku ON. Implicitly: SELECT * FROM a, b. Uwaga na wydajność — wynik rośnie wykładniczo.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między WHERE a HAVING?', 'WHERE filtruje wiersze PRZED grupowaniem (GROUP BY) — nie może użyć agregatów. HAVING filtruje grupy PO grupowaniu — może użyć SUM, COUNT itd. Przykład: WHERE status = ''active'' GROUP BY city HAVING COUNT(*) > 10. WHERE jest szybsze (mniej danych do grupowania). Kolejność: FROM → WHERE → GROUP BY → HAVING → SELECT → ORDER BY.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są window functions i podaj przykłady?', 'Window functions wykonują obliczenia na zestawie wierszy (window) powiązanych z bieżącym wierszem, bez grupowania. OVER() definiuje okno. Ranking: ROW_NUMBER(), RANK(), DENSE_RANK(). Agregaty: SUM() OVER(PARTITION BY dept), running total. Offset: LAG(), LEAD(), FIRST_VALUE(). PARTITION BY dzieli, ORDER BY sortuje wewnątrz okna. Niezbędne przy raportach i analityce.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się subquery od CTE?', 'Subquery to zapytanie zagnieżdżone: SELECT * FROM (SELECT ...) sub. CTE (Common Table Expression) to nazwane podzapytanie: WITH active AS (SELECT ...) SELECT * FROM active. CTE jest czytelniejsze, reużywalne w jednym zapytaniu, wspiera rekurencję (WITH RECURSIVE). Wydajność: w PostgreSQL CTE jest optimization fence (do v11), od v12 może być inline. Subquery jest prostsze dla jednorazowych.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest indeks B-tree i kiedy go używać?', 'B-tree to domyślny typ indeksu w większości baz — zbalansowane drzewo umożliwiające wyszukiwanie w O(log n). Idealny dla: equality (=), range (<, >, BETWEEN), ORDER BY, GROUP BY. Indeks na (city, name) wspiera WHERE city = ''X'' i WHERE city = ''X'' AND name = ''Y'', ale NIE sam WHERE name = ''Y'' (leftmost prefix rule). Dodaj na kolumnach w WHERE, JOIN, ORDER BY.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest indeks GIN i kiedy go używać?', 'GIN (Generalized Inverted Index) indeksuje wartości wewnątrz kontenerów: tablice, JSONB, tsvector (full-text search). Dla JSONB: WHERE data @> ''{"status": "active"}''. Dla tablic: WHERE tags @> ARRAY[''sql'']. Wolniejszy zapis (aktualizacja odwróconego indeksu), ale szybki odczyt. GiST to alternatywa dla danych geometrycznych i zakresów (range types).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest composite index i jakie ma zasady?', 'Composite index to indeks na wielu kolumnach: CREATE INDEX idx ON orders(user_id, created_at). Zasada leftmost prefix: indeks (A, B, C) wspiera zapytania na A, A+B, A+B+C, ale nie na B ani C osobno. Kolejność kolumn ma znaczenie — najpierw kolumny z equality, potem range. Covering index (INCLUDE) dodaje kolumny do liści, eliminując index-only scan.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak czytać wynik EXPLAIN ANALYZE?', 'EXPLAIN ANALYZE wykonuje zapytanie i pokazuje plan z rzeczywistymi czasami. Kluczowe: Seq Scan (full table scan — brak indeksu), Index Scan (OK), Nested Loop (dużo iteracji = wolne), Sort (spilluje na dysk?), actual time, rows (estimated vs actual — duża rozbieżność = nieaktualne statystyki → ANALYZE). Buffers: shared hit (cache) vs read (disk). Cost to estymata, actual time to prawda.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest normalizacja bazy danych?', 'Normalizacja eliminuje redundancję i anomalie danych. 1NF: atomowe wartości, brak powtarzających się grup. 2NF: 1NF + brak częściowych zależności od klucza złożonego. 3NF: 2NF + brak zależności tranzytywnych (kolumna zależy od nie-klucza). BCNF: silniejsza 3NF. W praktyce 3NF wystarcza. Denormalizacja jest OK dla wydajności odczytu (raporty, cache).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ACID w kontekście transakcji?', 'ACID to właściwości transakcji: Atomicity (wszystko albo nic — rollback), Consistency (dane przechodzą z jednego spójnego stanu do drugiego), Isolation (równoległe transakcje nie interferują), Durability (po COMMIT dane przetrwają crash). PostgreSQL gwarantuje ACID. NoSQL często oferuje BASE (Basically Available, Soft state, Eventually consistent) zamiast ACID.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są poziomy izolacji transakcji?', 'Read Uncommitted: widzi niezacommitowane dane (dirty read). Read Committed (domyślny PG): widzi tylko committed (no dirty reads, ale non-repeatable reads). Repeatable Read: snapshot na starcie (no phantom reads w PG). Serializable: pełna izolacja — jakby transakcje szły sekwencyjnie (najwolniejszy). Wyższy poziom = mniej anomalii, ale więcej locków/retry. PG nie ma true Read Uncommitted.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest deadlock i jak go unikać?', 'Deadlock to sytuacja, gdy dwie transakcje czekają na siebie nawzajem — żadna nie może kontynuować. Baza wykrywa i zabija jedną (rollback). Unikanie: lockuj zasoby w stałej kolejności, krótkie transakcje, unikaj trzymania locków między interakcjami z userem. Advisory locks dla custom logiki. Monitoring: pg_stat_activity, deadlock_timeout w PostgreSQL.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest problem N+1 w kontekście bazy danych?', 'N+1: pobierasz N użytkowników (1 query), potem dla każdego pobierasz posty (N queries). Razem N+1 zapytań zamiast 1-2. Rozwiązania: JOIN (1 query), WHERE id IN (...) (batch — 2 queries), eager loading w ORM (include/with). Wykrywanie: logowanie zapytań, pg_stat_statements, APM. W GraphQL: DataLoader. N+1 to jedna z najczęstszych przyczyn wolnych API.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest partycjonowanie tabel?', 'Partitioning dzieli dużą tabelę na mniejsze fizyczne części (partycje) z jednym logicznym interfejsem. Typy: RANGE (np. po dacie — miesiące/lata), LIST (po kategorii), HASH (równomierny rozkład). Zalety: partition pruning (query skanuje tylko relevantne partycje), łatwe archiwizowanie (DROP PARTITION), parallel query. PostgreSQL: PARTITION BY RANGE (created_at).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest materialized view?', 'Materialized view to wynik zapytania przechowywany fizycznie — jak tabela cache. CREATE MATERIALIZED VIEW mv AS SELECT ... . REFRESH MATERIALIZED VIEW odświeża dane (CONCURRENTLY bez blokowania odczytu). Idealny dla ciężkich raportów, dashboardów, denormalizacji. Wadą jest stale data między refreshami. Indeksy na matview przyspieszają odczyty. Scheduler (pg_cron) do automatycznego refresh.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się stored procedures od functions w PostgreSQL?', 'Function: wywołana w SELECT, zwraca wartość, działa w transakcji callera, nie może COMMIT/ROLLBACK wewnątrz. Procedure (PG 11+): wywołana CALL, może zarządzać transakcjami wewnątrz (COMMIT/ROLLBACK), nie zwraca wartości przez RETURN (ale przez OUT params). Functions do obliczeń i transformacji danych, procedures do złożonej logiki biznesowej z wieloma transakcjami.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest trigger w bazie danych?', 'Trigger to funkcja wykonywana automatycznie BEFORE/AFTER/INSTEAD OF operacji INSERT/UPDATE/DELETE. Zastosowania: audit log, walidacja, aktualizacja updated_at, synchronizacja denormalizowanych danych. Zmienne: NEW (nowy wiersz), OLD (stary). Uwaga: triggery utrudniają debugowanie (ukryta logika), spowalniają operacje. Preferuj logikę w aplikacji; triggery na audit/timestamps.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa VACUUM w PostgreSQL?', 'PostgreSQL używa MVCC — UPDATE/DELETE nie usuwają wierszy fizycznie, tylko oznaczają jako „dead". VACUUM odzyskuje przestrzeń z dead tuples. AUTOVACUUM działa automatycznie (konfigurowalny próg). VACUUM FULL przepisuje tabelę (wymaga exclusive lock, zwraca przestrzeń OS). Monitoruj: pg_stat_user_tables.n_dead_tup. Źle skonfigurowany autovacuum = table bloat i wolne query.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest MVCC?', 'MVCC (Multi-Version Concurrency Control) to mechanizm, w którym każda transakcja widzi snapshot danych z momentu jej startu. Pisanie nie blokuje czytania i odwrotnie. PostgreSQL implementuje MVCC przez xmin/xmax na każdym wierszu — wersje wierszy współistnieją. Pozwala na wysoką współbieżność. Koszt: dead tuples wymagające VACUUM. Alternatywa: pesymistyczne lockowanie (gorsze dla read-heavy).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest partial index?', 'Partial index to indeks z warunkiem WHERE: CREATE INDEX idx ON orders(created_at) WHERE status = ''pending''. Indeksuje tylko wiersze spełniające warunek — mniejszy rozmiar, szybsze aktualizacje. Idealny gdy query zawsze filtruje po danym warunku. Przykład: indeks na active users (WHERE deleted_at IS NULL) gdy 90% jest deleted. Planner użyje go tylko gdy query pasuje do WHERE.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zoptymalizować wolne zapytanie z wieloma JOINami?', 'Kroki: 1) EXPLAIN ANALYZE — zidentyfikuj bottleneck (Seq Scan, duże Nested Loop). 2) Indeksy na JOIN kluczach i WHERE. 3) Sprawdź statystyki (ANALYZE table). 4) Zmień kolejność JOINów (planner robi to sam, ale check). 5) CTE zamiast correlated subquery. 6) Materialized view dla ciężkich agregacji. 7) LIMIT wcześnie. 8) Denormalizacja jako last resort.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest recursive CTE?', 'WITH RECURSIVE cte AS (base_query UNION ALL recursive_query) SELECT * FROM cte. Base query: punkt startowy. Recursive: odwołuje się do cte. Zastosowania: hierarchie (drzewo kategorii, org chart), grafy (najkrótsza ścieżka), generowanie serii. Wymaga warunku stopu (WHERE level < 10 lub brak wyników). Uwaga na infinite loops — dodaj LIMIT lub cycle detection.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest cursor-based pagination vs offset-based?', 'Offset: LIMIT 20 OFFSET 100 — prosty, ale wolny dla dużych offsetów (skanuje i odrzuca wiersze). Cursor: WHERE id > last_seen_id ORDER BY id LIMIT 20 — stała wydajność niezależnie od strony. Cursor wymaga stabilnego unikalnego klucza sortowania. Offset pozwala na „skacz do strony 50", cursor nie. Cursor jest standardem w API z dużymi zbiorami danych.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest connection pooling i po co?', 'Connection pool utrzymuje pulę otwartych połączeń do bazy, reużywanych między requestami. Otwarcie połączenia jest kosztowne (TCP, TLS, auth). PgBouncer: transaction mode (połączenie na czas transakcji — najefektywniejszy), session mode. Supabase/Vercel mają built-in pooler. Konfiguracja: max connections (baza), pool_size (aplikacja). Za dużo połączeń = degradacja bazy.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają indeksy w kontekście INSERT/UPDATE/DELETE?', 'Każdy indeks spowalnia zapisy — przy INSERT/UPDATE/DELETE baza musi zaktualizować wszystkie indeksy na tabeli. Dlatego: nie indeksuj na zapas, usuwaj nieużywane indeksy (pg_stat_user_indexes.idx_scan = 0). Dla bulk insert: DROP INDEX → INSERT → CREATE INDEX jest szybsze. Partial index i covering index minimalizują overhead. Balans: szybkie odczyty vs szybkie zapisy.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest JSONB w PostgreSQL i kiedy go używać?', 'JSONB przechowuje JSON w binarnym formacie — szybkie operacje, indeksowalny (GIN). Operatory: ->> (tekst), -> (JSON), @> (contains), ? (has key). Kiedy: semi-structured data, zmienny schemat, metadata, ustawienia. Kiedy NIE: dane relacyjne z wieloma JOINami, dane wymagające referential integrity. JSONB path queries (@@) od PG 12. Indeks GIN na jsonb_path_ops jest mniejszy.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest row-level security (RLS)?', 'RLS pozwala definiować polityki dostępu na poziomie wierszy: CREATE POLICY user_policy ON orders FOR SELECT USING (user_id = current_setting(''app.user_id'')). Po ALTER TABLE orders ENABLE ROW LEVEL SECURITY, każdy SELECT/UPDATE/DELETE jest filtrowany automatycznie. Supabase intensywnie używa RLS. Polityki USING (SELECT) i WITH CHECK (INSERT/UPDATE). Superuser omija RLS.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest foreign key i jakie ma ON DELETE opcje?', 'Foreign key zapewnia referential integrity — wartość w kolumnie musi istnieć w referenced table. ON DELETE opcje: CASCADE (usuń powiązane), SET NULL (ustaw NULL), SET DEFAULT, RESTRICT (blokuj jeśli ma powiązania), NO ACTION (domyślny, check na końcu transakcji). CASCADE jest wygodny ale niebezpieczny — przypadkowe usunięcie kaskaduje. Preferuję RESTRICT + soft delete.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak monitorować wydajność PostgreSQL?', 'Narzędzia: pg_stat_statements (top zapytania po czasie/wywołaniach), pg_stat_user_tables (seq scan, dead tuples), pg_stat_user_indexes (użycie indeksów), pg_stat_activity (aktywne połączenia/locki). Metryki: connection count, cache hit ratio (>99%), transaction rate, replication lag. Zewnętrzne: pganalyze, Datadog, Grafana+Prometheus z postgres_exporter. auto_explain loguje wolne plany.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest lateral join?', 'LATERAL JOIN pozwala subquery odwoływać się do kolumn z wcześniejszych tabel w FROM: SELECT * FROM users u, LATERAL (SELECT * FROM orders WHERE user_id = u.id ORDER BY created_at DESC LIMIT 3) o. Działa jak foreach — dla każdego usera wykona subquery. Przydatne: top-N per group, zależne subqueries. Bez LATERAL subquery nie widzi outer query columns.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są prepared statements i dlaczego są ważne?', 'Prepared statement to prekompilowane zapytanie z placeholderami ($1, $2) zamiast wartości. Baza parsuje i planuje raz, wykonuje wiele razy z różnymi parametrami. Dwie korzyści: bezpieczeństwo (ochrona przed SQL injection — parametry nie są interpretowane jako SQL) i wydajność (reuse plan). Każdy ORM i driver bazodanowy powinien używać prepared statements domyślnie.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest database replication?', 'Replication kopiuje dane z primary do replica(s). Streaming replication (PG): synchronous (gwarantuje spójność, wyższy latency) lub asynchronous (szybsze, ryzyko utraty danych). Logical replication: selektywna (wybrane tabele), cross-version. Use cases: read replicas (skalowanie odczytu), HA failover, backup, analytics na replice. Replication lag to kluczowa metryka.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektować schemat dla systemu tagów (many-to-many)?', 'Trzy tabele: items (id, name), tags (id, name UNIQUE), item_tags (item_id FK, tag_id FK, PRIMARY KEY (item_id, tag_id)). Indeks na (tag_id, item_id) dla wyszukiwania po tagu. Query: JOIN item_tags ON ... JOIN tags ON ... WHERE tag.name IN (...) GROUP BY item.id HAVING COUNT(*) = N (all tags). Alternatywa: array column z GIN index — prostsze, ale bez referential integrity.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest UPSERT (INSERT ON CONFLICT)?', 'UPSERT to INSERT, który przy konflikcie (unique constraint) wykonuje UPDATE zamiast błędu. PostgreSQL: INSERT INTO ... ON CONFLICT (email) DO UPDATE SET name = EXCLUDED.name. DO NOTHING ignoruje konflikt. EXCLUDED referuje do wartości, które miały być wstawione. Przydatne: synchronizacja danych, idempotentne operacje. Atomowe — bez race condition między SELECT a INSERT.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest covering index (INCLUDE)?', 'Covering index zawiera wszystkie kolumny potrzebne w query — baza nie musi sięgać do tabeli (index-only scan). CREATE INDEX idx ON orders(user_id) INCLUDE (total, status). Kolumny w INCLUDE nie są częścią klucza (nie służą do wyszukiwania), ale są przechowywane w liściach indeksu. Drastycznie przyspiesza query, które SELECT-ują kilka kolumn z dużej tabeli.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest GROUP BY ROLLUP/CUBE/GROUPING SETS?', 'Rozszerzenia GROUP BY dla raportów. GROUPING SETS: grupuj po wielu kombinacjach w jednym query. ROLLUP (a, b): grupuje po (a,b), (a), () — hierarchiczne subtotale. CUBE (a, b): wszystkie kombinacje — (a,b), (a), (b), (). Zastępują UNION ALL wielu GROUP BY. GROUPING() function rozróżnia NULL od subtotalu. Potężne do dashboardów i raportów.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługiwać soft delete w bazie danych?', 'Soft delete: zamiast DELETE, ustawiasz deleted_at = now(). Zalety: odwracalność, audit trail. Wyzwania: każdy query musi dodać WHERE deleted_at IS NULL (łatwo zapomnieć — użyj view lub RLS), foreign keys nie chronią przed „sierotem", indeksy rosną. Partial index: WHERE deleted_at IS NULL. Alternatywa: archive table (przenoś usunięte rekordy). Supabase: RLS z policy na deleted_at.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CTid w PostgreSQL?', 'ctid to systemowa kolumna identyfikująca fizyczną lokalizację wiersza (block_number, tuple_index). Zmienia się po VACUUM FULL lub UPDATE (nowa wersja wiersza). Użyteczna: deduplication (DELETE FROM t WHERE ctid NOT IN (SELECT min(ctid) FROM t GROUP BY unique_cols)), debugging. Nie używaj jako trwałego identyfikatora — niestabilna. Odpowiednik ROWID w Oracle.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest TOAST w PostgreSQL?', 'TOAST (The Oversized-Attribute Storage Technique) to mechanizm przechowywania wartości > 2KB. PG kompresuje (pglz lub lz4) i/lub dzieli na chunki przechowywane w osobnej tabeli TOAST. Strategie per kolumna: PLAIN (bez TOAST), EXTENDED (kompresja + external), EXTERNAL (only external), MAIN (kompresja, external jako last resort). Transparentne dla użytkownika.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementować full-text search w PostgreSQL?', 'tsvector przechowuje znormalizowane tokeny, tsquery definiuje wyszukiwanie. WHERE to_tsvector(''polish'', content) @@ to_tsquery(''polish'', ''angular & typescript''). Indeks GIN na tsvector. Ranking: ts_rank(), ts_rank_cd(). Wagi: setweight() dla tytułu vs treści. Trigram (pg_trgm) dla fuzzy search i LIKE. Dla zaawansowanych potrzeb: Elasticsearch.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest optimistic locking w SQL?', 'Optimistic locking zakłada brak konfliktów. Implementacja: kolumna version (integer). UPDATE orders SET total = 100, version = version + 1 WHERE id = 1 AND version = 5. Jeśli affected_rows = 0 — ktoś zmienił wcześniej, retry. Alternatywa: updated_at timestamp. Lekki — brak locków w bazie. Idealny dla web apps z niskim contention. Pessimistic: SELECT FOR UPDATE.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest advisory lock w PostgreSQL?', 'Advisory lock to lock na arbitralnej wartości (integer) — nie na wierszu/tabeli. pg_advisory_lock(123) blokuje do zwolnienia lub końca sesji. pg_try_advisory_lock() nie blokuje, zwraca boolean. Zastosowania: distributed locking, rate limiting, zapobieganie równoległemu uruchomieniu (np. migration, cron job). Transaction-level: pg_advisory_xact_lock() — auto-release po transakcji.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa EXPLAIN w PostgreSQL — koszt, wiersze, czas?', 'EXPLAIN pokazuje plan bez wykonania (estimaty). EXPLAIN ANALYZE wykonuje i pokazuje actual. cost=0.00..10.50: startup cost..total cost (arbitrary units). rows: estymowana liczba wierszy. actual time: ms. Planning Time + Execution Time. Seq Scan cost proporcjonalny do rozmiaru tabeli. Index Scan ma wyższy startup cost, niższy total dla selektywnych queries. Buffers (ANALYZE + BUFFERS): hit (cache) vs read (disk).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest expression index?', 'Expression index indeksuje wynik wyrażenia: CREATE INDEX idx ON users (LOWER(email)). Query WHERE LOWER(email) = ''jan@test.pl'' użyje tego indeksu. Bez niego — Seq Scan, bo indeks na email nie pasuje do LOWER(email). Przykłady: EXTRACT(year FROM created_at), (data->>''type''), unaccent(name). Przydatne gdy query zawsze stosuje funkcję na kolumnie.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest pg_stat_statements?', 'pg_stat_statements to rozszerzenie PostgreSQL śledzące statystyki wszystkich wykonanych zapytań: total_time, calls, mean_time, rows, shared_blks_hit/read. Kluczowe do identyfikacji: najwolniejszych zapytań (ORDER BY total_time DESC), najczęstszych (calls), z największym I/O. Reset: pg_stat_statements_reset(). Powinno być włączone na każdej produkcyjnej bazie.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak migrować schemat bazy bez downtime?', 'Expand-contract pattern: 1) Dodaj nową kolumnę (nullable, z default), 2) Deploy kod piszący do obu kolumn, 3) Backfill starych danych, 4) Deploy kod czytający z nowej, 5) Usuń starą kolumnę. Additive changes: ADD COLUMN (instant w PG 11+ z non-volatile default), CREATE INDEX CONCURRENTLY (bez lock). Nigdy: ALTER COLUMN TYPE na dużej tabeli (rewrite), DROP COLUMN w jednym deploy.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest logical replication vs physical replication?', 'Physical: replika bitowa WAL stream — identyczna kopia, ten sam PG version, cała instancja. Logical: replikuje zmiany na poziomie tabeli/row — selektywna, cross-version, cross-platform. Logical: publication/subscription model. Use cases physical: HA failover, read replicas. Logical: migracja między wersjami, selective sync, CDC (Change Data Capture) do Kafka/Elasticsearch.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaprojektować schemat dla hierarchii (drzewo kategorii)?', 'Opcje: 1) Adjacency list: parent_id FK — proste, ale recursive query dla drzewa. 2) Materialized path: path = "1/4/7" — LIKE ''1/4/%'' szybkie, ale rebalancing. 3) Nested sets: lft/rgt — szybki odczyt, wolny zapis. 4) ltree extension (PG): natywny typ drzewa z operatorami. 5) Closure table: osobna tabela ancestor/descendant. Adjacency + recursive CTE jest najprostsze i zazwyczaj wystarczające.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest pg_cron i do czego go używać?', 'pg_cron to rozszerzenie PostgreSQL umożliwiające scheduling zadań w bazie (cron syntax). SELECT cron.schedule(''vacuum'', ''0 3 * * *'', ''VACUUM ANALYZE orders''). Zastosowania: REFRESH MATERIALIZED VIEW, archiwizacja starych danych, czyszczenie expired sessions, statystyki. Alternatywa: external cron + psql, pg_agent. W Supabase pg_cron jest dostępny out-of-the-box.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różni się git rebase od git merge?', 'Merge tworzy merge commit łączący dwie gałęzie — zachowuje pełną historię z rozgałęzieniami. Rebase przenosi commity z brancha na szczyt target brancha — liniowa historia, czytelniejsza, ale przepisuje commity (nowe hashe). Zasada: rebase lokalnych zmian, merge publicznych branchy. Nigdy nie rebase''uj tego, co już pushowałeś (shared history).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest git cherry-pick?', 'Cherry-pick kopiuje pojedynczy commit z innego brancha na bieżący: git cherry-pick <hash>. Tworzy nowy commit z tym samym patchem ale innym hashem. Zastosowania: hotfix z develop na main, przeniesienie konkretnej zmiany bez merge. Uwaga: może powodować konflikty i duplikację logiki. Preferuj merge/rebase dla większych zmian. --no-commit pozwala zmodyfikować przed commitem.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest git bisect?', 'Git bisect to binarne wyszukiwanie commita, który wprowadził bug. git bisect start, bisect bad (bieżący), bisect good <hash> (znany dobry). Git checkout''uje środkowy commit — testujesz i mówisz good/bad. W O(log n) krokach znajdujesz winny commit. Automatyzacja: git bisect run ./test.sh. Niezastąpione przy regresji w projekcie z dużą historią.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest git reflog?', 'Reflog to log WSZYSTKICH zmian HEAD — nawet tych „utraconych" po reset, rebase, amend. git reflog pokazuje historię ruchów HEAD. Ratunkowy: git reset --hard HEAD@{3} przywraca stan sprzed 3 operacji. Reflog jest lokalny (nie pushowany), trzymany domyślnie 90 dni. Niezastąpiony gdy zrobisz błędny reset --hard lub rebase. „Git nigdy niczego nie traci" — dzięki reflogowi.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Git Flow i trunk-based development.', 'Git Flow: long-lived branches (main, develop, feature/*, release/*, hotfix/*). Formalne releasy. Odpowiedni dla wersjonowanego software. Trunk-based: wszyscy commitują do main, short-lived feature branches (max 1-2 dni), feature flags. Wymaga: CI, dobre testy, small increments. TBD preferowany w CI/CD z frequent deploys. Git Flow dla regulated/versioned products.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest CI/CD pipeline i jakie ma typowe etapy?', 'Pipeline to zautomatyzowany proces od commitu do produkcji. Etapy: 1) Checkout kodu, 2) Install dependencies, 3) Lint/format check, 4) Build, 5) Unit tests, 6) Integration tests, 7) Security scan (SAST, dependency audit), 8) Build artifact/image, 9) Deploy staging, 10) E2E tests, 11) Deploy production. Fast feedback: fail early. Narzędzia: GitHub Actions, GitLab CI, Jenkins.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Docker i czym jest Dockerfile?', 'Docker buduje obrazy z Dockerfile — sekwencji instrukcji: FROM (bazowy obraz), COPY/ADD (pliki), RUN (komendy), ENV, EXPOSE, CMD/ENTRYPOINT. Każda instrukcja tworzy warstwę (layer) — cached jeśli się nie zmienił. Multi-stage build: osobny stage na build (z devDependencies) i runtime (lekki obraz). .dockerignore wyklucza pliki. Obraz jest immutable, kontener jest uruchomioną instancją.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest multi-stage build w Dockerze?', 'Multi-stage build używa wielu FROM w jednym Dockerfile. Pierwszy stage: buduje aplikację (z devDependencies, kompilatorem). Drugi stage: kopiuje tylko artefakty (COPY --from=builder) do lekkiego obrazu (alpine/distroless). Efekt: mały finalny obraz bez build tools i źródeł. Przykład: Node.js — build stage z npm ci, production stage z node:alpine i skopiowanym dist/.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Docker volumes i kiedy ich używać?', 'Volume to mechanizm persistowania danych poza kontenerem (filesystem kontenera jest ephemeral). Typy: named volumes (Docker zarządza), bind mounts (mapowanie katalogu hosta), tmpfs (tylko RAM). Zastosowania: bazy danych (pgdata), upload files, shared state między kontenerami. docker-compose: volumes sekcja. Backup: docker cp lub volume driver. Nie przechowuj stanu w kontenerze.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Docker Compose i do czego służy?', 'Docker Compose to narzędzie do definiowania multi-container applications w pliku docker-compose.yml. Definiujesz: services (kontenery), networks, volumes. docker compose up startuje wszystko. Idealny dla dev environment: app + baza + redis + queue. depends_on kontroluje kolejność, healthcheck czeka na gotowość. Override: docker-compose.override.yml dla dev. Nie do produkcji — tam Kubernetes.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Kubernetes i jakie problemy rozwiązuje?', 'Kubernetes (K8s) to orkiestrator kontenerów: automatyczny deployment, skalowanie, self-healing. Kluczowe koncepty: Pod (grupa kontenerów), Deployment (desired state), Service (networking), Ingress (HTTP routing), ConfigMap/Secret (konfiguracja). K8s rozwiązuje: auto-scaling (HPA), rolling updates, service discovery, load balancing, resource management. Managed: EKS, GKE, AKS.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się blue-green od canary deployment?', 'Blue-green: dwa identyczne środowiska, przełączasz ruch z blue na green naraz (zero downtime, szybki rollback, podwójne zasoby). Canary: nowa wersja dostaje mały % ruchu (np. 5%), monitorujesz metryki, stopniowo zwiększasz. Canary wykrywa problemy wcześnie z minimalnym blast radius. Blue-green jest prostszy. K8s: Argo Rollouts, Flagger dla canary.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Infrastructure as Code (IaC)?', 'IaC zarządza infrastrukturą (serwery, sieci, bazy) przez kod zamiast manualnych operacji. Deklaratywne: Terraform (HCL, state file, multi-cloud), CloudFormation (AWS). Imperatywne: Pulumi (TS/Python). Configuration management: Ansible (serwery). Zalety: wersjonowanie, code review, powtarzalność, disaster recovery. GitOps: Git jako source of truth, ArgoCD/Flux synchronizuje.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest monitoring vs logging vs tracing?', 'Monitoring: zbieranie metryk (CPU, memory, request rate, error rate) i alertowanie. Prometheus + Grafana. Logging: zapis zdarzeń (structured JSON, levels). ELK Stack, Loki. Tracing: śledzenie requestu przez wiele serwisów — span ID, trace ID. Jaeger, Zipkin. Razem tworzą three pillars of observability. Correlation ID łączy logi z trace''ami. Każdy filar odpowiada na inny typ pytania o system.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są SLI, SLO, SLA w kontekście DevOps?', 'SLI (Service Level Indicator): mierzalna metryka (latency p99, availability %). SLO (Objective): wewnętrzny cel (99.9% availability). SLA (Agreement): kontrakt z klientem z konsekwencjami. Error budget = 100% - SLO. Gdy budget się wyczerpie: stop feature work, focus na reliability. SRE (Site Reliability Engineering) zarządza tym procesem. Mierz to, co wpływa na user experience.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa git stash?', 'git stash zapisuje lokalne zmiany (staged + unstaged) na stos i przywraca clean working directory. git stash pop przywraca i usuwa ze stosu. git stash apply przywraca bez usuwania. git stash list — lista. git stash drop — usuń. Zastosowania: szybkie przełączenie brancha bez commitowania WIP, testowanie czystego stanu. --include-untracked stashuje też nowe pliki.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest git interactive rebase?', 'git rebase -i HEAD~5 pozwala na modyfikację ostatnich 5 commitów: pick (zostaw), squash (połącz z poprzednim), fixup (squash bez message), reword (zmień message), edit (zatrzymaj do edycji), drop (usuń). Zastosowania: cleanup historii przed merge, squash WIP commitów, reorder. Tylko na lokalne commity — nie przepisuj shared history.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest .gitignore i jakie pliki powinno ignorować?', '.gitignore definiuje wzorce plików, które Git nie śledzi. Typowe: node_modules/, dist/, build/, .env*, *.log, .DS_Store, .idea/, .vscode/ (opcjonalnie). Wzorce: * (wildcard), ** (recursive), ! (negate). .gitignore w root, ale mogą być per directory. Jeśli plik już jest tracked, gitignore go nie usunie — trzeba git rm --cached. gitignore.io generuje templates.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wygląda Twoja strategia branchowania?', 'Preferuję trunk-based z short-lived feature branches. Konwencja: feature/TICKET-123-description, fix/..., chore/.... PR = 1 logical change. Squash merge do main (czysta historia). Protected main: CI musi przejść, wymagany review. Release: tag na main lub release branch (jeśli potrzeba). Hotfix: branch z main, merge z powrotem. Ważne: branch żyje max 2-3 dni.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Docker networking?', 'Docker sieci: bridge (domyślna, kontenery komunikują się po nazwie w docker-compose), host (kontener dzieli sieć hosta), none (izolacja). docker-compose domyślnie tworzy bridge network — kontenery widzą się po nazwie serwisu. Exposed ports (EXPOSE/ports) mapują porty kontenera na hosta. W K8s: ClusterIP (internal), NodePort, LoadBalancer, Ingress.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zabezpieczasz sekrety w CI/CD?', 'Nigdy w kodzie/repo! Sekrety jako encrypted variables w CI (GitHub Secrets, GitLab CI Variables). Runtime: environment variables, Vault (HashiCorp), AWS Secrets Manager, SOPS (encrypted files w Git). Docker: Docker secrets (Swarm), K8s Secrets (base64, nie encrypted — użyj sealed-secrets lub external-secrets). Rotacja sekretów. Audit access. Least privilege.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest GitHub Actions i jak działa?', 'GitHub Actions to CI/CD wbudowane w GitHub. Workflow (.github/workflows/*.yml): trigger (push, PR, schedule, manual), jobs (runner: ubuntu-latest), steps (uses: actions/*, run: commands). Matrix strategy: testuj na wielu wersjach. Cache (actions/cache) dla node_modules. Secrets: ${{ secrets.API_KEY }}. Reusable workflows. Marketplace z gotowymi actions.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Docker layer caching i jak go optymalizować?', 'Każda instrukcja Dockerfile tworzy warstwę. Docker cache''uje warstwy — zmiana invalidity tę i kolejne warstwy. Optymalizacja: COPY package*.json . i RUN npm ci PRZED COPY . . (dependencies cache''owane gdy się nie zmieniły). Porządek: rzadko zmieniane na górze. Łącz RUN (mniej warstw). .dockerignore wyklucza niepotrzebne pliki. Multi-stage: mniejszy kontekst buildu.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest rollback strategy?', 'Strategia cofania wadliwego deploy. Opcje: redeploy poprzedniej wersji (artifact/image), blue-green switch back, feature flag off, database rollback migration. Wymaga: immutable artifacts z wersją, backward-compatible migrations, health checks wykrywające problemy. Automatyczny rollback: K8s rollout undo, CI/CD po failed health check. Testuj rollback regularnie — nietestowany rollback nie zadziała.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak monitorujesz kontenery w produkcji?', 'Container metrics: CPU, memory, restart count, network I/O. K8s: kubectl top, metrics-server, Prometheus + kube-state-metrics. Logi: stdout/stderr → log driver → aggregator (Loki, ELK). Alerting: Prometheus Alertmanager, PagerDuty. Dashboard: Grafana. Health checks: liveness probe (restart), readiness probe (traffic). Resource limits (requests/limits) zapobiegają noisy neighbor.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest git hook i jakie są przydatne hooki?', 'Git hooks to skrypty uruchamiane automatycznie przy operacjach Git. Client-side: pre-commit (lint, format), commit-msg (walidacja formatu), pre-push (testy). Server-side: pre-receive, post-receive. Narzędzia: Husky (JS), lefthook, pre-commit (Python). lint-staged uruchamia lint tylko na staged plikach. Conventional commits: commitlint sprawdza format „feat: ...", „fix: ...".', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Terraform state i jak go zarządzać?', 'Terraform state (.tfstate) to JSON mapujący zasoby w kodzie na rzeczywiste ID w chmurze. Bez state: Terraform nie wie co istnieje. Remote backend (S3 + DynamoDB lock, Terraform Cloud) — współdzielony, lockowany. State zawiera sekrety — encrypt at rest. terraform plan porównuje state z kodem i realnym stanem. State drift: terraform refresh. Nigdy nie edytuj state ręcznie.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak debugujesz kontener w produkcji?', 'Kroki: 1) kubectl logs pod-name (logi), 2) kubectl describe pod (events, status), 3) kubectl exec -it pod -- sh (wejdź do kontenera), 4) kubectl port-forward (dostęp do serwisu). Ephemeral debug containers: kubectl debug. Distributed tracing (Jaeger) dla cross-service issues. Jeśli kontener crashuje: check OOMKilled (memory limit), CrashLoopBackOff (logi z poprzedniego run).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest GitOps?', 'GitOps to podejście, w którym Git jest single source of truth dla infrastruktury i deploymentu. Operator (ArgoCD, Flux) monitoruje repo i synchronizuje klaster z desired state w Git. Zalety: audit trail (Git history), rollback (git revert), code review na infrastrukturę, deklaratywność. Pull-based: operator pobiera zmiany (bezpieczniejsze niż CI push do produkcji).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zminimalizować rozmiar obrazu Docker?', 'Techniki: 1) Lekki bazowy obraz (alpine, distroless, slim). 2) Multi-stage build (kopiuj tylko artefakty). 3) Łącz RUN (mniej warstw). 4) Czyszcz cache w tym samym RUN (apt-get clean, rm -rf /var/lib/apt/lists/*). 5) .dockerignore. 6) Nie instaluj devDependencies w finalnym stage. Mały obraz: szybszy pull, mniejsza powierzchnia ataku, mniej kosztów storage.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest conventional commits?', 'Conventional Commits to konwencja formatu commit messages: type(scope): description. Typy: feat (nowa funkcja), fix (bug), docs, chore, refactor, test, style, perf, ci. Breaking change: feat!: lub BREAKING CHANGE w footer. Automatyzacja: semantic-release generuje wersje i changelog na podstawie commitów. commitlint + Husky wymusza format. Czytelna historia i automatyczne wersjonowanie.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest health check w kontekście deploymentu?', 'Health check to endpoint (/health, /ready) zwracający status aplikacji. Liveness: „czy aplikacja działa?" — restart jeśli nie. Readiness: „czy może obsługiwać ruch?" — nie kieruj traffic jeśli nie (np. warmup, dependency down). K8s: livenessProbe, readinessProbe, startupProbe (dla wolno startujących). Load balancer: health check endpoint. Sprawdzaj: DB connection, disk space, key dependencies.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz environment variables w różnych środowiskach?', 'Per environment: .env.development, .env.staging, .env.production (NIE commituj .env z sekretami!). CI/CD: environment variables w pipeline (GitHub Secrets, GitLab CI Variables). Runtime: ConfigMap/Secret w K8s, Parameter Store (AWS). 12-factor: config w env vars. Walidacja: sprawdzaj wymagane zmienne na starcie (fail fast). dotenv w dev, native env vars w prod.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest semantic versioning (SemVer)?', 'SemVer: MAJOR.MINOR.PATCH — np. 2.1.3. MAJOR: breaking changes (niekompatybilne API). MINOR: nowe funkcje backward-compatible. PATCH: bug fix. Pre-release: 1.0.0-beta.1. Range w package.json: ^1.2.3 (minor+patch), ~1.2.3 (patch only). Lock file gwarantuje exact versions. 0.x.y: unstable, anything goes. Automatyzacja z conventional commits + semantic-release.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak konfigurujesz K8s pod z resource limits?', 'resources: requests (minimum gwarantowane — scheduler) i limits (maximum — OOM Kill jeśli przekroczy). CPU: requests: 100m (0.1 core), limits: 500m. Memory: requests: 128Mi, limits: 256Mi. QoS classes: Guaranteed (requests = limits), Burstable, BestEffort. Pod bez limits może zużyć cały node. LimitRange i ResourceQuota na namespace. Prawidłowe ustawienie wymaga profiling.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest container registry?', 'Container registry to repozytorium obrazów Docker. Docker Hub (publiczny), ECR (AWS), GCR (Google), GHCR (GitHub), Harbor (self-hosted). Workflow: build → tag (version + git SHA) → push → pull w deploy. Security: vulnerability scanning (Trivy, Snyk), signed images (cosign), least privilege (read-only w produkcji). Cache: pull-through cache zmniejsza latency i koszty.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest git worktree?', 'git worktree pozwala mieć wiele working directories z jednego repo. git worktree add ../hotfix main — nowy katalog z branchem main. Przydatne: praca na hotfix bez stashowania, porównanie branchy, długi build na jednym worktree, review PR w drugim. Współdzielą .git (oszczędność miejsca). git worktree list, remove. Alternatywa dla git stash przy częstym przełączaniu kontekstu.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wdrażasz zero-downtime deployment w K8s?', 'Rolling update: K8s stopniowo zastępuje pody (maxSurge, maxUnavailable). Readiness probe zapewnia, że nowy pod jest gotowy przed usunięciem starego. Graceful shutdown: preStop hook + SIGTERM handling. PodDisruptionBudget gwarantuje minAvailable. Database: backward-compatible migrations. Health check endpoint. Alternatywa: canary z Argo Rollouts, blue-green z Service switch.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest DORA metrics?', 'DORA (DevOps Research and Assessment) — 4 metryki wydajności zespołu: 1) Deployment Frequency (jak często deploy), 2) Lead Time for Changes (commit → produkcja), 3) Change Failure Rate (% deployów powodujących incydent), 4) Time to Restore (MTTR — czas naprawy). Elite: deploy on demand, < 1h lead time, < 5% failure, < 1h restore. Mierzone narzędziami: Sleuth, LinearB, DORA dashboard.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak automatyzujesz security scanning w CI/CD?', 'SAST (Static Analysis): SonarQube, Semgrep — skanują kod. DAST (Dynamic): OWASP ZAP — skanują uruchomioną aplikację. Dependency scanning: npm audit, Snyk, Dependabot — znane CVE w zależnościach. Container scanning: Trivy, Grype — vulnerabilities w obrazach. Secret scanning: detect-secrets, GitGuardian. Integracja: GitHub Actions step, fail pipeline na critical. Shift-left security.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Jakie są semantyki metod HTTP i kiedy której używać?', 'GET: pobieranie (safe, idempotent, cacheable). POST: tworzenie zasobu (nie idempotent). PUT: pełna aktualizacja lub stworzenie (idempotent). PATCH: częściowa aktualizacja. DELETE: usunięcie (idempotent). HEAD: jak GET, ale bez body (sprawdzanie istnienia). OPTIONS: dostępne metody (CORS preflight). Safe = nie zmienia stanu, idempotent = wielokrotne wywołanie = ten sam efekt.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest idempotentność w kontekście HTTP?', 'Operacja idempotentna daje ten sam rezultat niezależnie od liczby wywołań. GET, PUT, DELETE, HEAD, OPTIONS są idempotentne. POST nie jest — każde wywołanie może tworzyć nowy zasób. Znaczenie: retry jest bezpieczny dla idempotentnych metod (network failure → retry bez duplikatów). PUT /users/1 wielokrotnie = ten sam efekt. POST /orders wielokrotnie = wiele zamówień.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij najważniejsze kody statusu HTTP z przykładami.', '200 OK, 201 Created (POST sukces), 204 No Content (DELETE sukces). 301 Moved Permanently, 304 Not Modified (cache). 400 Bad Request (walidacja), 401 Unauthorized (brak tokenu), 403 Forbidden (brak uprawnień), 404 Not Found, 409 Conflict (duplikat), 422 Unprocessable Entity, 429 Too Many Requests. 500 Internal Error, 502 Bad Gateway, 503 Service Unavailable.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są constraints REST wg Fieldinga?', 'Roy Fielding zdefiniował 6 ograniczeń: 1) Client-Server (separacja UI od danych), 2) Stateless (serwer nie przechowuje stanu sesji), 3) Cacheable (odpowiedzi oznaczone jako cacheable/not), 4) Uniform Interface (ujednolicony interfejs — URI, HTTP methods), 5) Layered System (klient nie wie, czy łączy się bezpośrednio czy przez proxy), 6) Code-On-Demand (opcjonalny, np. JS).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HATEOAS?', 'HATEOAS (Hypermedia As The Engine Of Application State) to constraint REST, w którym odpowiedź zawiera linki do powiązanych zasobów i akcji: {"id": 1, "_links": {"self": "/orders/1", "cancel": "/orders/1/cancel"}}. Klient nawiguje API przez linki, nie hardkodowane URL-e. W praktyce rzadko implementowane w pełni — większość API jest „RESTful" na poziomie 2 (Richardson Maturity Model).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są strategie wersjonowania API?', 'URI: /v1/users (najprostsze, explicit). Header: Accept: application/vnd.myapi.v2+json (czyste URL). Query: /users?version=2. Content negotiation: Accept header z media type. Najczęstsze: URI versioning. Zasady: minimum breaking changes, deprecation policy z sunset header, monitoruj użycie starych wersji, maintain max 2-3 wersje jednocześnie.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się cursor pagination od offset pagination?', 'Offset: ?page=5&limit=20 — OFFSET 80 LIMIT 20. Proste, pozwala skakać do strony, ale wolne dla dużych offsetów (skanuje wiersze) i niestabilne (nowe rekordy przesuwają strony). Cursor: ?after=abc123&limit=20 — WHERE id > cursor. Stała wydajność, stabilne wyniki, ale nie ma „skoku do strony 50". Cursor preferowany dla dużych zbiorów i infinite scroll.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementować rate limiting w API?', 'Algorytmy: token bucket (stały rate z burst), sliding window log, fixed window counter. Redis: INCR + EXPIRE lub sorted sets. Klucze: per user/API key, per IP, per endpoint. Response: 429 Too Many Requests + nagłówki X-RateLimit-Limit, X-RateLimit-Remaining, X-RateLimit-Reset, Retry-After. Tiery: free 100/h, paid 10000/h. API Gateway (Kong, AWS) ma built-in rate limiting.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa CORS i kiedy jest potrzebny?', 'CORS (Cross-Origin Resource Sharing) to mechanizm przeglądarki zezwalający na cross-origin requests. Serwer musi odpowiedzieć nagłówkami: Access-Control-Allow-Origin, Allow-Methods, Allow-Headers. Preflight (OPTIONS) wysyłany dla non-simple requests (custom headers, PUT/DELETE). Access-Control-Max-Age cache''uje preflight. Credentials: Allow-Credentials + explicit origin (nie *). Backend-to-backend nie podlega CORS.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się JWT od session-based authentication?', 'Session: serwer przechowuje sesję (w pamięci/Redis), klient dostaje session ID w cookie. Stateful — serwer wie o sesji. JWT: token zawiera dane (claims), podpisany — serwer weryfikuje podpis bez bazy. Stateless — łatwe skalowanie. JWT wady: nie da się unieważnić bez blacklisty, payload widoczny (base64), rozmiar. Session wady: wymaga shared storage w klasterze. Hybrid: krótki JWT + refresh token.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa OAuth 2.0?', 'OAuth 2.0 to framework autoryzacji (nie uwierzytelniania — to OIDC). Flow: 1) User redirectowany do Authorization Server, 2) loguje się i zatwierdza scope, 3) AS zwraca authorization code, 4) backend wymienia code na access token (+ refresh token). Granty: Authorization Code (web), PKCE (SPA/mobile), Client Credentials (server-to-server). Access token: krótki (15min), refresh token: długi + rotation.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się OAuth 2.0 od OpenID Connect?', 'OAuth 2.0 to framework autoryzacji — „co możesz zrobić" (access token). OpenID Connect (OIDC) to warstwa uwierzytelniania nad OAuth — „kim jesteś" (ID token z claims: sub, email, name). OIDC dodaje: ID token (JWT z identity), userinfo endpoint, standard scopes (openid, profile, email). Providery: Google, GitHub, Auth0, Keycloak. Używaj OIDC gdy potrzebujesz identity, OAuth gdy tylko dostęp.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zabezpieczasz API keys?', 'API key to prosty token identyfikujący klienta. Przekazywany w header (X-API-Key) lub query param (gorszy — logi). Zabezpieczenia: HTTPS (zawsze), hash w bazie (nie plain text), rate limiting per key, scoping (readonly vs write), rotation policy, expiration. Nie używaj API key jako jedynej autentykacji użytkowników — brak kontekstu „kto". Dla users: OAuth/JWT. API keys dla server-to-server.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest content negotiation?', 'Content negotiation to mechanizm, w którym klient i serwer uzgadniają format danych. Klient wysyła Accept: application/json (lub xml, csv). Serwer odpowiada Content-Type: application/json. Jeśli serwer nie obsługuje formatu: 406 Not Acceptable. Accept-Language dla lokalizacji. Accept-Encoding dla kompresji (gzip, br). W praktyce większość API obsługuje tylko JSON.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa cache HTTP (ETag, Cache-Control)?', 'Cache-Control: max-age=3600 (klient cache''uje 1h), no-cache (waliduj z serwerem), no-store (nie cache''uj). ETag: serwer zwraca hash contentu. Klient wysyła If-None-Match: etag — serwer odpowiada 304 Not Modified (nie przesyła body) lub 200 z nowym contentem. Last-Modified + If-Modified-Since analogicznie z datą. CDN cache''uje na krawędzi. Vary header: cache per Accept-Encoding/Language.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest OpenAPI/Swagger?', 'OpenAPI Specification (dawniej Swagger) to standard opisu REST API w YAML/JSON: endpointy, parametry, request/response schemas, autentykacja. Swagger UI generuje interaktywną dokumentację. Swagger Codegen generuje klienty i serwery. Design-first: napisz spec, potem implementuj. Code-first: generuj spec z kodu (annotacje). OpenAPI jest de facto standardem dokumentacji API.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest webhook i czym różni się od pollingu?', 'Polling: klient periodycznie odpytuje serwer „masz coś nowego?" — prosty, ale marnotrawny (puste odpowiedzi), opóźniony. Webhook: serwer wysyła HTTP POST do klienta gdy zdarzenie nastąpi — real-time, efektywny. Webhook wymaga: endpoint po stronie klienta, retry z backoff, signature verification, idempotency. Long polling i SSE to pośrednie rozwiązania. WebSocket dla bidirectional real-time.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektujesz error response w API?', 'Spójny format: { "error": { "code": "VALIDATION_ERROR", "message": "Email is required", "details": [...] } }. HTTP status code odpowiedni do typu błędu. Machine-readable code (enum) + human-readable message. Nie ujawniaj stack trace w produkcji. Walidacja: lista błędów per pole. RFC 7807 (Problem Details): standaryzowany format. Lokalizacja: Accept-Language dla message. Dokumentuj możliwe błędy per endpoint.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest REST maturity model (Richardson)?', 'Level 0: jeden endpoint, wszystko POST (SOAP-like). Level 1: zasoby z URI (/users, /orders), ale jeden method. Level 2: HTTP methods prawidłowo (GET, POST, PUT, DELETE) + status codes. Level 3: HATEOAS — hypermedia links w odpowiedziach. Większość „REST API" jest na Level 2. Level 3 jest rzadko implementowany w pełni. Prawdziwy REST wg Fieldinga wymaga Level 3.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektować URL-e w REST API?', 'Zasady: pluralne rzeczowniki (/users, /orders), hierarchia zasobów (/users/{id}/orders), HTTP methods zamiast akcji w URL (nie /getUser, ale GET /users/{id}). Filtrowanie: query params (?status=active&sort=name). Avoid: verbs w URL, zagnieżdżenie > 2 poziomy, camelCase (use kebab-case lub snake_case). Konsekwentnie w całym API. Wersja: /v1/users.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest GraphQL i jakie ma zalety/wady vs REST?', 'GraphQL: klient definiuje kształt odpowiedzi w query. Jeden endpoint. Zalety: brak over/under-fetching, typed schema, introspection, świetne tooling (GraphiQL, codegen). Wady: trudniejszy caching (POST, dynamic shapes), complexity (N+1 bez DataLoader), file upload problematic, learning curve. REST: prostszy, lepszy HTTP caching, dojrzalszy ekosystem. GraphQL sprawdza się gdy masz wiele klientów z różnymi potrzebami.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest gRPC i kiedy go wybrać zamiast REST?', 'gRPC to framework RPC od Google używający Protocol Buffers (binary serialization) i HTTP/2. Zalety: szybki (binary, multiplexing), typed contracts (.proto), streaming (uni/bi-directional), code generation. Wady: nie human-readable, trudny w przeglądarce (grpc-web), mniej tooling. Kiedy: microservice-to-microservice (internal), high-performance, streaming. REST dla public API, gRPC wewnętrznie.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsłużyć bulk operations w REST API?', 'Opcje: 1) POST /users/bulk z tablicą obiektów — prosty, ale atomowy (all or nothing). 2) Batch endpoint: POST /batch z tablicą requestów. 3) Async: POST /jobs zwraca job ID, GET /jobs/{id} sprawdza status. Odpowiedzi: 200 z partial success (tablica wyników per item) lub 207 Multi-Status. Idempotency key per item. Limit batch size. Async dla długich operacji.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HTTP/2 i jakie ma zalety?', 'HTTP/2: binary framing (szybsze parsowanie), multiplexing (wiele requestów na jednym połączeniu — brak head-of-line blocking na level HTTP), header compression (HPACK), server push (preemptive wysyłanie zasobów). Zalety: szybsze ładowanie stron, mniej połączeń TCP. Wymaga HTTPS (w praktyce). HTTP/3 (QUIC): UDP zamiast TCP, eliminuje HOL blocking na transport level.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz filtrowanie, sortowanie i projekcję w API?', 'Filtrowanie: query params — ?status=active&role=admin, zaawansowane: ?filter[age][gte]=18. Sortowanie: ?sort=name,-created_at (- = desc). Projekcja: ?fields=id,name,email (zwróć tylko te pola). Paginacja: ?page=2&limit=20 lub ?after=cursor. Standardy: JSON:API, OData. Waliduj i whitelist dozwolone pola (security). Nie pozwalaj na sort po nieindeksowanych kolumnach.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest idempotency key i jak go używać?', 'Idempotency key to unikalny identyfikator (UUID) wysyłany w header (Idempotency-Key) przez klienta. Serwer zapamiętuje wynik dla danego klucza — kolejne requesty zwracają cached response. Kluczowe dla: płatności (unikaj podwójnych charge), POST (nieidempotentny). Implementacja: Redis z TTL, check before processing. Stripe, AWS, PayPal używają tego wzorca.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Server-Sent Events (SSE)?', 'SSE to jednokierunkowy streaming od serwera do klienta przez HTTP. Content-Type: text/event-stream. Format: data: message\\n\\n. EventSource API w przeglądarce: auto-reconnect, last-event-id. Zastosowania: notyfikacje, live feed, dashboardy. Prostrzy niż WebSocket (HTTP, auto-reconnect, compatible z proxy/LB). Wada: jednokierunkowy, text only. WebSocket lepszy dla bidirectional (chat, gaming).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz long-running operations w API?', 'Wzorzec async: POST /exports → 202 Accepted + Location: /jobs/123. GET /jobs/123 → { "status": "processing" } lub { "status": "completed", "result_url": "..." }. Polling lub webhook notification po zakończeniu. Timeout: nigdy nie trzymaj HTTP connection minutami. Queue + worker przetwarza w tle. Retry z idempotency. Status tracking: pending → processing → completed/failed.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest API Gateway i jakie ma funkcje?', 'API Gateway to single entry point dla klientów. Funkcje: routing (URL → microservice), autentykacja/autoryzacja, rate limiting, request/response transformation, caching, logging, circuit breaker, SSL termination. Narzędzia: Kong, AWS API Gateway, Nginx, Traefik. BFF pattern: osobny gateway per klient (web, mobile). Uwaga: single point of failure — wymaga HA setup.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wersjonujesz zmiany w API bez łamania klientów?', 'Backward-compatible changes (nie wymagają nowej wersji): dodanie opcjonalnego pola, dodanie endpointu, dodanie enum value (jeśli klient ignoruje unknown). Breaking changes (wymagają nowej wersji): usunięcie/zmiana pola, zmiana typu, zmiana semantyki. Strategia: additive changes, deprecation z Sunset header, monitoring usage starych pól/endpointów, minimum 6 miesięcy na migrację.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest request validation i jak ją implementować?', 'Walidacja requestu: sprawdzanie danych wejściowych przed przetworzeniem. Warstwy: 1) Schema validation (Zod, Joi, class-validator) — typy, format, range. 2) Business validation — logika biznesowa. Odpowiedź: 400/422 z listą błędów per pole. Waliduj: body, query params, path params, headers. Fail fast — nie przetwarzaj nieprawidłowych danych. Server-side walidacja jest obowiązkowa (klient jest niezaufany).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HTTPS i jak działa TLS handshake?', 'HTTPS = HTTP + TLS (Transport Layer Security). Handshake: 1) Client Hello (supported ciphers), 2) Server Hello (chosen cipher + certificate), 3) Klient weryfikuje certyfikat (CA chain), 4) Key exchange (asymmetric → symmetric key), 5) Szyfrowana komunikacja (symmetric). TLS 1.3: szybszy (1-RTT, 0-RTT resume). Let''s Encrypt: darmowe certyfikaty z auto-renewal. HSTS header wymusza HTTPS.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak projektować sub-resources w REST?', 'Sub-resources to zasoby zagnieżdżone: /users/{userId}/orders — zamówienia danego usera. GET /users/1/orders — lista, POST /users/1/orders — stwórz. Ale: GET /orders/123 (nie /users/1/orders/123) jeśli order ma global ID. Zasada: max 2 poziomy zagnieżdżenia. Jeśli sub-resource ma sens niezależnie — daj mu top-level endpoint. Alternatively: filter ?userId=1 na /orders.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest PATCH i czym różni się od PUT?', 'PUT zastępuje cały zasób — musisz wysłać kompletny obiekt. PATCH modyfikuje częściowo — wysyłasz tylko zmieniane pola. PUT jest idempotentny (ten sam request = ten sam stan). PATCH formalnie nie musi być idempotentny (JSON Patch: operacje add/remove). W praktyce: JSON Merge Patch (wysyłasz { "name": "Jan" }) jest najprostszy i najczęstszy. Używaj PATCH dla update formularzy.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak logować requesty API bezpiecznie?', 'Loguj: method, URL, status code, response time, request ID, user ID. NIE loguj: passwords, tokens, full credit card, PII (RODO). Maskowanie: Authorization header → "Bearer ***", body fields → sanitize. Structured logging (JSON): łatwiejszy parsing. Correlation ID: generuj w API Gateway, przekazuj przez serwisy. Request ID w response header (X-Request-ID) — debugging z klientem.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest WebSocket i kiedy go używać?', 'WebSocket to protokół bidirectional, full-duplex na jednym TCP połączeniu. Handshake: HTTP upgrade → ws://. Zastosowania: chat, gaming, collaborative editing, live data (trading). Zalety: real-time, low latency, oba kierunki. Wady: trudniejsze skalowanie (sticky sessions/Redis pub-sub), reconnect logic, firewall issues. Alternatywy: SSE (one-way), long polling (prostsze). Socket.io opakowuje z fallback.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz file upload w API?', 'Multipart: POST z Content-Type: multipart/form-data — klasyczne, limit rozmiaru. Base64 w JSON: proste, ale 33% overhead. Signed URL: klient dostaje presigned URL (S3), uploaduje bezpośrednio do storage — serwer nie jest bottleneckiem. Chunked upload: resumable, duże pliki (tus protocol). Walidacja: typ pliku (magic bytes, nie tylko extension), rozmiar, virus scan. Storage: S3, GCS, nie filesystem serwera.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest circuit breaker w kontekście API?', 'Circuit breaker chroni klienta przed ciągłym wysyłaniem requestów do nieosiągalnego serwisu. Stany: Closed (normalny flow), Open (po X błędach — natychmiastowy fallback, bez wysyłania), Half-Open (po timeout próbuje — sukces = Closed, błąd = Open). Implementacja: interceptor/middleware. Fallback: cached data, default response, graceful degradation message. Axios + custom logic lub dedykowana biblioteka.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testować REST API?', 'Unit: testuj handlery/kontrolery z mockowanymi serwisami. Integration: supertest/httptest — prawdziwe HTTP requesty do serwera in-memory + testowa baza. Contract: Pact — weryfikacja zgodności klient-serwer. E2E: Postman/Newman, REST Client. Testuj: happy path, walidacja (400), auth (401/403), not found (404), edge cases. CI: automatyczne testy API w pipeline. Collection testing: Postman z env variables.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ETL vs API w kontekście integracji systemów?', 'API (real-time): synchroniczne zapytania, aktualne dane, niski latency. ETL (Extract, Transform, Load — batch): periodyczne kopiowanie danych między systemami, transformacja po drodze. API lepsze dla: user-facing operations, real-time needs. ETL lepsze dla: analytics, data warehouse, duże wolumeny, systemy bez API. Hybrid: CDC (Change Data Capture) — real-time streaming zmian z bazy do innego systemu.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym są Signals w Angular i czym różnią się od Observables z RxJS?', 'Signals to synchroniczny, reaktywny prymityw wprowadzony w Angular 16+. W przeciwieństwie do Observable, Signal zawsze ma aktualną wartość (nie wymaga subskrypcji) i automatycznie śledzi zależności. Observable jest push-based i asynchroniczny, Signal jest pull-based i synchroniczny. Signals są idealne do stanu UI, Observables do strumieni zdarzeń, HTTP i złożonych transformacji asynchronicznych.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy użyjesz Signal, a kiedy Observable? Podaj konkretne przykłady.', 'Signal: stan komponentu (licznik, formularz, flagi UI), computed values, prosty stan współdzielony między komponentami. Observable: wywołania HTTP, WebSocket, zdarzenia DOM (resize, scroll), złożone łańcuchy operatorów (debounce, retry, race conditions). W praktyce: Signal do „co jest teraz", Observable do „co się dzieje w czasie".', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest computed() i effect() w kontekście Signals?', 'computed() tworzy sygnał pochodny, który automatycznie przelicza wartość gdy zależności się zmienią — jest leniwy i memoizowany. effect() to funkcja uboczna uruchamiana gdy zmienią się odczytywane sygnały. Ważne: effect() nie powinien modyfikować sygnałów (jednokierunkowy przepływ), a computed() nie może mieć side effects. Angular śledzi zależności dynamicznie w runtime.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Change Detection w Angular? Czym różni się Default od OnPush?', 'Default CD sprawdza cały komponent i jego dzieci po każdym zdarzeniu (klik, HTTP, timer). OnPush sprawdza komponent tylko gdy: zmieni się referencja @Input, wyemituje zdarzenie, ręcznie wywołamy markForCheck() lub użyjemy async pipe. OnPush wymaga traktowania danych jako immutable — mutacja obiektu nie wywoła renderowania.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest zoneless Angular i jak działa bez zone.js?', 'Zoneless (Angular 18+) eliminuje zone.js, który patchował wszystkie asynchroniczne API (setTimeout, Promise, addEventListener). Zamiast tego Angular opiera się na Signals do śledzenia zmian. Korzyści: mniejszy bundle (~15 KB mniej), lepsza wydajność, brak nieoczekiwanych cykli CD. Wymaga provideExperimentalZonelessChangeDetection() i konsekwentnego używania Signals.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij hierarchiczny Dependency Injection w Angular.', 'Angular ma drzewo injectorów: root (providedIn: ''root'') → module → element (komponent). Każdy komponent może mieć własny injector (providers: []). Usługi w komponencie tworzą nową instancję dla tego komponentu i jego dzieci. To umożliwia np. osobne instancje FormService w każdym formularzu. Wyszukiwanie zależności idzie w górę drzewa aż do root.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest InjectionToken i kiedy go używasz?', 'InjectionToken to unikalny klucz do wstrzykiwania wartości nieklasowych (string, konfiguracja, funkcja). Używamy gdy nie mamy klasy jako tokenu, np. new InjectionToken<AppConfig>(''APP_CONFIG''). Pozwala na wstrzykiwanie konfiguracji środowiskowej, flag feature toggle czy abstrakcji na localStorage/window bez bezpośredniej zależności.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są multi providers w Angular DI?', 'Multi providers pozwalają zarejestrować wiele wartości pod jednym tokenem — Angular zwróci tablicę wszystkich. Używamy {provide: TOKEN, useValue: val, multi: true}. Klasyczne zastosowanie: HTTP_INTERCEPTORS, gdzie wiele interceptorów jest zarejestrowanych pod jednym tokenem. Kolejność tablicy odpowiada kolejności rejestracji.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są standalone components i dlaczego Angular odchodzi od NgModules?', 'Standalone components (Angular 14+) to samowystarczalne komponenty deklarujące swoje zależności bezpośrednio w imports: []. Eliminują NgModules jako pośrednika. Powód: NgModules dodawały złożoność, utrudniały tree-shaking i lazy loading. Standalone upraszczają mental model — komponent importuje to, czego potrzebuje, bez sztucznego grupowania.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opisz nowy control flow w Angular (@if, @for, @switch, @defer).', '@if/@else zastępuje *ngIf z czytelniejszą składnią bloków. @for wymaga track — funkcji identyfikującej elementy (jak trackBy). @switch to pattern matching. @defer umożliwia lazy loading fragmentów template''u z warunkami (on viewport, on idle, on timer). Nowy flow jest wbudowany w kompilator, nie wymaga importu dyrektyw i generuje wydajniejszy kod.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest @defer i jakie ma triggery?', '@defer to mechanizm leniwego ładowania fragmentów szablonu. Triggery: on idle (gdy przeglądarka jest bezczynna), on viewport (element widoczny), on interaction (klik/focus), on hover, on timer(Xms), when warunek. Wspiera @placeholder, @loading i @error. Każdy @defer tworzy osobny chunk JS — idealny do ciężkich komponentów poniżej fold.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się input(), output() i model() od dekoratorów @Input/@Output?', 'input()/output()/model() to signal-based API (Angular 17+). input() zwraca InputSignal (readonly), output() zwraca OutputEmitterRef. model() tworzy dwukierunkowe wiązanie (ModelSignal — writable signal + event). Korzyści: lepsza typizacja, wymagane inputy (input.required()), łatwiejsze transformacje (transform), integracja z Signals. Dekoratory są legacy.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są różnice między switchMap, mergeMap, concatMap i exhaustMap?', 'switchMap: anuluje poprzednią subskrypcję przy nowej emisji (szukajka, autocomplete). mergeMap: uruchamia równolegle (batch operations, niezależne requesty). concatMap: kolejkuje, czeka na zakończenie poprzedniej (sekwencyjne zapisy). exhaustMap: ignoruje nowe emisje dopóki bieżąca nie zakończy się (submit formularza, zapobieganie podwójnym kliknięciom).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używasz switchMap a kiedy exhaustMap? Podaj scenariusze.', 'switchMap: pole wyszukiwania (każde nowe wpisanie anuluje poprzedni request), nawigacja (nowa trasa cancelluje starą). exhaustMap: przycisk „Zapisz" (ignoruje kolejne kliknięcia do zakończenia zapisu), logowanie, operacje płatnicze. Użycie switchMap zamiast exhaustMap przy submit = ryzyko wielokrotnego zapisu. Użycie exhaustMap przy search = brak wyników dla ostatniego zapytania.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa lazy loading w Angular i jakie są best practices?', 'Lazy loading ładuje moduły/komponenty na żądanie przez loadComponent/loadChildren w routingu. Angular tworzy osobny chunk JS. Best practices: lazy loaduj każdą feature route, używaj @defer dla ciężkich UI, preloading strategy (PreloadAllModules lub custom) dla przewidywalnych ścieżek. Route-level lazy loading zmniejsza initial bundle nawet o 60-70%.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są route guards i jakie typy istnieją w Angular?', 'Guards to funkcje kontrolujące nawigację. Typy: canActivate (czy użytkownik może wejść), canDeactivate (czy może opuścić, np. niezapisany formularz), canMatch (czy route pasuje), resolve (preload danych). Od Angular 15+ guards to zwykłe funkcje (functional guards), nie klasy. canActivate zwraca boolean, Observable<boolean> lub UrlTree (redirect).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest resolver w routingu i jakie ma wady?', 'Resolver ładuje dane przed aktywacją route — komponent otrzymuje gotowe dane. Wada: blokuje nawigację do zakończenia ładowania, więc użytkownik widzi „zamrożony" UI. Alternatywa: ładować dane w komponencie z @defer/@placeholder lub w ngOnInit z loading state. Resolver ma sens tylko dla krytycznych danych wymaganych do renderowania.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Reactive Forms z Template-driven Forms. Kiedy co wybrać?', 'Reactive Forms: model formularza w TypeScript (FormGroup/FormControl), synchroniczne, łatwe testowanie, dynamiczne formularze (FormArray). Template-driven: model w szablonie z ngModel, prostsze dla małych formularzy, asynchroniczne walidacje. Reactive Forms wybieramy do złożonych formularzy, dynamicznych pól, zaawansowanej walidacji. Template-driven do prostych formularzy kontaktowych.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Signal Forms i jak się mają do Reactive/Template Forms?', 'Signal Forms to eksperymentalne API (Angular 19+) łączące zalety obu podejść. Używają Signals zamiast Observable do śledzenia stanu. FormControl zyskuje .value jako signal, walidacja jest synchroniczna i reaktywna. Cel: prostota template-driven z mocą reactive, eliminacja .valueChanges na rzecz computed(). Nadal w fazie rozwoju.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa SSR w Angular (@angular/ssr)?', '@angular/ssr (dawniej Angular Universal) renderuje aplikację na serwerze do HTML. Klient otrzymuje gotowy HTML (szybszy FCP/LCP), potem Angular hydruje — podłącza event listenery bez ponownego renderowania DOM. Od Angular 17: partial hydration z @defer, event replay (buforowanie zdarzeń przed hydracją). SSR poprawia SEO i Core Web Vitals.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest hydration w Angular i czym różni się partial hydration?', 'Hydration to proces „ożywiania" statycznego HTML renderowanego na serwerze — Angular dopasowuje DOM do komponentów i podpina interaktywność. Full hydration hydruje całą stronę od razu. Partial hydration (z @defer) hydruje fragmenty na żądanie — np. komentarze dopiero gdy użytkownik scrolluje do nich. Zmniejsza TTI nawet o 50%.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak konfiguruje się TestBed w Angular i po co jest?', 'TestBed to środowisko testowe Angular tworzące mini-moduł testowy. Konfiguracja: TestBed.configureTestingModule({ imports: [KomponentTestowany], providers: [{ provide: Serwis, useValue: mockSerwis }] }). Pozwala nadpisywać zależności mockami, testować interakcje z DOM. Od Angular 15+ preferowane jest testowanie standalone komponentów bez NgModules.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Component Harnesses w Angular Material i dlaczego warto je używać?', 'Component Harness to abstrakcja nad DOM komponentu Material. Zamiast selectorów CSS (kruche na zmiany) używamy API: MatButtonHarness.getText(), MatSelectHarness.open(). Harness jest odporny na zmiany wewnętrznej struktury DOM komponentu. Działa w unit testach i e2e. Własne harnessy tworzymy przez ComponentHarness — dobrze dla shared komponentów.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest trackBy w @for i dlaczego jest wymagany?', 'track w @for identyfikuje elementy listy, by Angular wiedział, które elementy dodać/usunąć/przesunąć zamiast przebudowywać cały DOM. Bez track Angular usunie i stworzy wszystkie elementy od nowa — katastrofa dla wydajności. Najlepiej trackować po unikalnym ID (track item.id), nie po indeksie (track $index niweluje korzyści przy sortowaniu/wstawianiu).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest pure pipe i czemu jest wydajniejszy od metody w szablonie?', 'Pure pipe wykonuje transformację tylko gdy zmieni się referencja wejścia — Angular cachuje wynik. Metoda w szablonie wykonuje się przy każdym cyklu CD (nawet kilkadziesiąt razy/s). Dla listy 100 elementów pipe wykona się 100 razy przy zmianie, metoda 100 × N cykli CD. Impure pipe (pure: false) działa jak metoda — używać ostrożnie.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa virtual scrolling i kiedy go stosujesz?', 'Virtual scrolling (CDK ScrollingModule) renderuje tylko widoczne elementy listy + bufor. Przy 10 000 elementach w DOM będzie np. 20 zamiast 10 000 — drastycznie mniej operacji DOM i pamięci. Stosujemy dla list >100 elementów o stałej/przewidywalnej wysokości. Uwaga: dynamiczna wysokość wymaga itemSize lub autosize, co jest trudniejsze.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest NgRx SignalStore i jak się ma do klasycznego NgRx Store?', 'SignalStore (NgRx 17+) to lekki store oparty na Signals zamiast Redux pattern. Definiujemy store jako signalStore({}) z withState(), withComputed(), withMethods(). Brak actions, reducers, effects — znacznie mniej boilerplate''u. Klasyczny NgRx Store lepszy dla bardzo dużych aplikacji z potrzebą DevTools, entity adaptera i undo/redo.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy serwis z Signals wystarczy zamiast NgRx?', 'Serwis z signal() i computed() wystarczy gdy: stan jest prosty (kilka pól), nie potrzebujesz time-travel debugging, nie masz wielu niezależnych konsumentów ani złożonych efektów ubocznych. NgRx dodaje strukturę wymuszającą przewidywalność w dużych zespołach. Dla >80% aplikacji serwis z Signals jest prostszy i wystarczający. NgRx jest overkillem dla CRUD-ów.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają HTTP Interceptors w Angular i jakie mają zastosowania?', 'Interceptory przechwytują każdy HTTP request/response. Zastosowania: dodawanie tokenu JWT (Authorization header), obsługa błędów 401 (refresh token), retry przy błędach sieci, logowanie, cache''owanie, loading spinner. Od Angular 15+ preferowane są functional interceptors: withInterceptors([authInterceptor]) zamiast klas implementujących HttpInterceptor.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz błędy HTTP globalnie w Angular?', 'Globalny interceptor przechwytuje błędy: catchError w interceptorze sprawdza status. 401 → refresh token i retry. 403 → redirect do /forbidden. 5xx → toast z komunikatem. Dodatkowo ErrorHandler (globalny) łapie niezłapane wyjątki. Ważne: interceptor musi przekazać błąd dalej (throwError) jeśli nie może go obsłużyć, by komponent mógł zareagować lokalnie.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest content projection (ng-content) i jakie są jej rodzaje?', 'Content projection to wstawianie treści z rodzica do dziecka. Rodzaje: single slot (<ng-content>), multi-slot (select="[header]"), conditional (ngProjectAs). Zastosowanie: wrapper komponenty (card, modal, tab). Uwaga: projected content jest tworzony w kontekście rodzica, nie dziecka — zmienny detection i DI działają na poziomie rodzica.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się ng-template od ng-container?', 'ng-template to szablon, który nie jest renderowany domyślnie — wymaga jawnego użycia (*ngIf then/else, ngTemplateOutlet, ViewContainerRef). ng-container to logiczny kontener grupujący elementy bez dodawania elementu do DOM. Użycie: ng-container gdy potrzebujemy strukturalnej dyrektywy bez wrapper div, ng-template do reużywalnych fragmentów szablonu.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest ngTemplateOutlet i jak go używasz?', 'ngTemplateOutlet dynamicznie renderuje ng-template w danym miejscu. Składnia: <ng-container *ngTemplateOutlet="szablon; context: {$implicit: dane}">. Pozwala na renderowanie różnych szablonów w zależności od warunku, tworzenie konfigurowalnych komponentów (np. custom row template w tabeli). Context przekazuje dane do szablonu.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest ViewChild i ContentChild? Czym się różnią?', 'ViewChild szuka elementu w szablonie komponentu (jego własny template). ContentChild szuka elementu w projected content (treść przekazana przez rodzica). ViewChild dostępny od AfterViewInit, ContentChild od AfterContentInit. Signal-based: viewChild()/contentChild() zwracają sygnały, dostępne natychmiast bez lifecycle hooks.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa providedIn: ''root'' i czym różni się od providers w komponencie?', 'providedIn: ''root'' tworzy singleton na poziomie root injector — jedna instancja w całej aplikacji, tree-shakeable (usuwana jeśli nieużywana). providers w komponencie tworzy nową instancję dla każdej instancji komponentu i jego dzieci. Użyj root dla globalnych serwisów (auth, http), providers w komponencie dla izolowanego stanu (formularz, wizard).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest inject() function i czym różni się od constructor injection?', 'inject() to funkcja dostępna w kontekście DI (konstruktor, factory, guard). Pozwala pobierać zależności bez deklarowania ich w konstruktorze. Korzyści: działa w funkcjach (functional guards, interceptors), ułatwia composable patterns, mniej boilerplate. Ograniczenie: musi być wywołana w injection context — nie w setTimeout czy subscribe.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest linkedSignal() i kiedy go użyjesz?', 'linkedSignal() (Angular 19+) to writable signal, który resetuje się gdy zmieni się źródłowy signal. Przykład: lista produktów (signal) i wybrany produkt (linkedSignal) — po zmianie listy wybrany produkt resetuje się do pierwszego. Rozwiązuje problem „stale state" bez ręcznego effect(). Jest to computed + WritableSignal w jednym.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest resource() API w Angular i do czego służy?', 'resource() (Angular 19+) to reaktywny prymityw do asynchronicznego ładowania danych oparty na Signals. Definiujesz request (signal z parametrami) i loader (async function). resource automatycznie wywołuje loader gdy request się zmieni. Zwraca signal z value, status, error. Zastępuje ręczne subskrypcje w ngOnInit i loading/error boilerplate.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz formularz wielokrokowy (wizard) w Angular?', 'Podejścia: 1) Jeden FormGroup z zagnieżdżonymi grupami per krok, walidacja per krok. 2) Osobne FormGroup per krok + serwis trzymający stan. 3) Stepper z CDK. Kluczowe: canDeactivate guard chroni przed utratą danych, serwis z signal przechowuje stan między krokami, walidacja lazy (waliduj krok przy przejściu dalej, nie od razu).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest HostListener i HostBinding? Czy nadal ich używamy?', 'HostListener dekoruje metodę reagującą na zdarzenia host elementu. HostBinding binduje właściwość DOM hosta. Od Angular 15+ preferowane jest host: {} w metadanych komponentu — czytelniejsze i tree-shakeable. Przykład: host: { ''(click)'': ''onClick()'', ''[class.active]'': ''isActive()'' }. Dekoratory nadal działają, ale nowy sposób jest lepszy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz globalny error handler w Angular?', 'Implementujesz ErrorHandler i nadpisujesz handleError(). Rejestrujesz: { provide: ErrorHandler, useClass: GlobalErrorHandler }. W handleError logujesz błąd do serwisu (Sentry, LogRocket), wyświetlasz toast. Ważne: HttpErrors łatwiej obsługiwać w interceptorze — ErrorHandler łapie głównie błędy runtime JS. Unikaj throwError w ErrorHandler — tworzy pętlę.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest DestroyRef i takeUntilDestroyed w Angular?', 'DestroyRef (Angular 16+) to injectable referencja do lifecycle destroy komponentu/serwisu. takeUntilDestroyed() automatycznie odsubskrybowuje Observable przy zniszczeniu. Zastępuje ręczne ngOnDestroy + Subject + takeUntil. Użycie: this.http.get(''/api'').pipe(takeUntilDestroyed()).subscribe(). Musi być wywołane w injection context (konstruktor).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zoptymalizujesz dużą aplikację Angular pod kątem wydajności?', 'Checklist: OnPush na wszystkich komponentach, Signals zamiast zwykłych properties, lazy loading routes + @defer, trackBy w @for, pure pipes zamiast metod w szablonie, virtual scrolling dla list, preloadingStrategy, budowanie z --optimization, analiza bundle (source-map-explorer). Profiluj z Angular DevTools — nie optymalizuj na ślepo.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest Angular DevTools i jak pomaga w debugowaniu?', 'Angular DevTools to rozszerzenie Chrome do profilowania i debugowania. Pozwala: przeglądać drzewo komponentów z ich stanem, mierzyć czas change detection per komponent, wykrywać niepotrzebne cykle CD, inspektować DI tree. Profiler pokazuje ile czasu każdy komponent „kosztuje" w cyklu CD — kluczowe do znalezienia bottlenecków.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ng-container i kiedy go stosujesz?', 'ng-container to logiczny element nie renderujący niczego w DOM. Stosujemy gdy: potrzebujemy wielu dyrektyw strukturalnych na jednym elemencie (nie można dwóch *ngIf na jednym), chcemy zastosować *ngFor bez dodatkowego div, grupujemy elementy dla *ngIf. Alternatywa w nowym control flow: @if i @for nie wymagają ng-container.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa dependency injection z useFactory?', 'useFactory pozwala tworzyć instancję serwisu z niestandardową logiką. Przykład: { provide: API_URL, useFactory: (env: Env) => env.production ? ''prod.api'' : ''dev.api'', deps: [ENV_TOKEN] }. Przydatne do warunkowej konfiguracji, tworzenia instancji z parametrami runtime, integracji z kodem spoza Angular (np. firebase).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest toSignal() i toObservable()? Kiedy konwertujesz?', 'toSignal() konwertuje Observable na Signal — wymaga wartości początkowej (initialValue) lub requireSync. toObservable() konwertuje Signal na Observable. Konwertujesz gdy: używasz RxJS serwisu w Signals komponentcie (toSignal), lub Signal w bibliotece wymagającej Observable. Uwaga: toSignal() subskrybuje od razu i zarządza subskrypcją automatycznie.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz strategie preloadingu modułów w Angular?', 'Wbudowane: NoPreloading (domyślna — nic nie preloaduje), PreloadAllModules (ładuje wszystkie lazy modules po starcie). Custom strategy: możesz preloadować na podstawie route data, np. data: { preload: true }. QuicklinkStrategy (third-party) preloaduje tylko trasy widoczne jako linki na stronie. Wybór zależy od rozmiaru aplikacji i wzorców nawigacji.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij różnicę między forRoot() i forChild().', 'forRoot() rejestruje serwisy i konfigurację na poziomie root — wywoływane raz w AppModule. forChild() rejestruje tylko routes/features bez powielania serwisów. Klasyczny przykład: RouterModule.forRoot(routes) w app, RouterModule.forChild(routes) w feature modules. Bez tego rozróżnienia lazy-loaded moduły tworzyłyby duplikaty singletonów.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz komponent z zależnościami w Angular?', 'W TestBed nadpisujesz prawdziwe serwisy mockami: providers: [{ provide: UserService, useValue: jasmine.createSpyObj(''UserService'', [''getUser'']) }]. Dla HTTP: HttpClientTestingModule + HttpTestingController do mockowania requestów. Dla routera: RouterTestingModule. Alternatywnie: testuj komponent bez TestBed jako zwykłą klasę, wstrzykując mocki ręcznie.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest canMatch guard i czym różni się od canActivate?', 'canMatch decyduje czy route w ogóle „pasuje" — jeśli zwróci false, router szuka dalej w tablicy routes. canActivate blokuje nawigację po dopasowaniu route. canMatch pozwala mieć tę samą ścieżkę z różnymi komponentami: {path: ''dashboard'', canMatch: [isAdmin], component: AdminDashboard}, {path: ''dashboard'', component: UserDashboard}.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz komunikację między komponentami w Angular?', 'Sposoby: 1) @Input/@Output (rodzic-dziecko), 2) Serwis z Subject/Signal (dowolna relacja), 3) ViewChild (rodzic czyta dziecko), 4) Content projection (przekazywanie szablonów), 5) Router state (parametry, query params, data). Dla prostej komunikacji rodzic-dziecko: Input/Output. Dla współdzielonego stanu: serwis z Signals. Unikaj event busów.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest async pipe i dlaczego jest preferowany?', 'async pipe automatycznie subskrybuje Observable/Promise i wyświetla wartość w szablonie. Kluczowa zaleta: automatyczna odsubskrypcja przy zniszczeniu komponentu — brak memory leaks. Działa z OnPush (triggeruje CD). Wada: wielokrotne użycie tego samego Observable w szablonie = wielokrotna subskrypcja. Rozwiązanie: *ngIf="obs$ | async as value" lub Signals.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz techniki zapobiegania memory leaks w Angular?', 'Techniki: 1) takeUntilDestroyed() — najnowsze, 2) async pipe — automatyczna odsubskrypcja, 3) Subject + takeUntil + ngOnDestroy — klasyczne, 4) DestroyRef.onDestroy(), 5) Signals (nie wymagają subskrypcji). Najczęstsze źródła leaków: subskrypcje w subscribe() bez cleanup, setInterval bez clearInterval, addEventListener bez removeEventListener.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Renderer2 i kiedy go używasz zamiast bezpośredniego DOM?', 'Renderer2 to abstrakcja nad DOM API zapewniająca kompatybilność z SSR i Web Workers (gdzie nie ma document). Zamiast element.style.color = ''red'' → renderer.setStyle(el, ''color'', ''red''). W praktyce od Angular 17+ rzadko potrzebny — Signals i template binding obsługują większość przypadków. Używaj gdy musisz dynamicznie manipulować DOM spoza szablonu.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa router events i do czego można je wykorzystać?', 'Router emituje zdarzenia: NavigationStart, NavigationEnd, NavigationCancel, NavigationError, GuardsCheckStart/End, ResolveStart/End. Zastosowania: globalny loading spinner (NavigationStart → show, NavigationEnd → hide), analityka (NavigationEnd → trackPageView), breadcrumbs. Subskrybuj: router.events.pipe(filter(e => e instanceof NavigationEnd)).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest afterNextRender i afterRender w Angular?', 'afterNextRender() wykonuje callback po następnym renderowaniu (jednorazowo). afterRender() wykonuje callback po każdym renderowaniu. Zastępują ngAfterViewInit dla inicjalizacji DOM (np. integracja z bibliotekami JS). Działają tylko w przeglądarce (nie na serwerze) — bezpieczne dla SSR. Fazy: read (odczyt DOM), write (zapis DOM) — unikanie layout thrashing.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz dynamiczne komponenty w Angular?', 'Nowoczesne podejście: @if z dynamicznym komponentem lub NgComponentOutlet. Klasycznie: ViewContainerRef.createComponent(). NgComponentOutlet przyjmuje typ komponentu i renderuje go dynamicznie: <ng-container *ngComponentOutlet="activeComponent; inputs: {data: value}">. Przydatne do tabów, dashboardów, pluginów — komponent wybierany w runtime.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest environment injection (inject) vs constructor injection?', 'Oba mechanizmy dostarczają zależności z tego samego DI tree. inject() (funkcyjna) działa w injection context — konstruktor, factory, route guard/resolver. Constructor injection wymaga deklaracji parametrów. inject() jest lepsza w standalone world: mniej boilerplate, działa w functional guards i interceptors, umożliwia tworzenie composable helper functions.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest APP_INITIALIZER i jak go stosujesz?', 'APP_INITIALIZER to multi-provider token wykonywany przed uruchomieniem aplikacji. Zwraca Promise lub Observable — Angular czeka na zakończenie. Zastosowania: ładowanie konfiguracji z serwera, sprawdzanie sesji, ładowanie tłumaczeń. Uwaga: zbyt wolny initializer blokuje start aplikacji. Od Angular 16+: provideAppInitializer(() => inject(ConfigService).load()).', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym jest Virtual DOM i jak działa rekoncyliacja w React?', 'Virtual DOM to lekka kopia prawdziwego DOM w pamięci. Przy zmianie stanu React tworzy nowe vDOM, porównuje je ze starym (diffing) i aplikuje minimalne zmiany do prawdziwego DOM (reconciliation). Algorytm zakłada: różne typy elementów = różne drzewa, key identyfikuje elementy listy. Złożoność O(n) dzięki heurystykom zamiast O(n³).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Fiber architecture w React?', 'Fiber to przepisany od podstaw silnik renderowania (React 16+). Zamienia rekurencyjny, synchroniczny rendering na iteracyjny, przerywalny. Każdy komponent to fiber node z informacjami o stanie, efektach i priorytecie. Pozwala React przerwać renderowanie, obsłużyć ważniejszą aktualizację (np. input użytkownika) i wrócić. Jest fundamentem concurrent features.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij różnicę między useState a useReducer. Kiedy co wybrać?', 'useState: prosty stan (boolean, string, number). useReducer: złożony stan z wieloma powiązanymi wartościami, logika przejść między stanami. useReducer gdy: nowy stan zależy od poprzedniego w złożony sposób, wiele akcji modyfikuje ten sam stan, chcesz wyciągnąć logikę do testowania. useState wystarczy dla >90% przypadków. useReducer to useState pod spodem.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są zasady hooks? Dlaczego nie można wywoływać ich warunkowo?', 'Zasady: 1) Wywołuj tylko na najwyższym poziomie (nie w if/for/try), 2) Wywołuj tylko w komponentach funkcyjnych lub custom hookach. Powód: React identyfikuje hooki po kolejności wywołania w danym renderze. Jeśli warunek pominie hook, kolejność się przesunie i React przypisze stan do złego hooka. Lint reguła: react-hooks/rules-of-hooks.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij useEffect — dependency array, cleanup, typowe błędy.', 'useEffect(fn, deps) wykonuje efekt uboczny po renderze. [] = raz (mount), [dep] = gdy dep się zmieni, brak = co render. Cleanup (return () => {}) uruchamia się przed kolejnym efektem i przy unmount. Typowe błędy: brak deps (nieskończona pętla), obiekt/tablica w deps (nowa referencja = ciągłe wywołania), brak cleanup (memory leak: subskrypcje, timery).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useRef i jakie ma zastosowania poza DOM?', 'useRef zwraca mutable obiekt {current: value} persystentny między renderami. Zastosowania: 1) referencja DOM (ref={inputRef}), 2) przechowywanie wartości bez triggerowania rerendera (previous value, timer ID, flagi), 3) utrzymywanie mutable wartości w closures. Kluczowe: zmiana .current NIE powoduje rerenderowania — to nie stan, to „skrzynka".', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy useMemo i useCallback naprawdę pomagają? Kiedy szkodzą?', 'useMemo/useCallback pomagają gdy: memoizowany komponent dziecko (React.memo) otrzymuje obiekt/funkcję jako prop, kosztowna kalkulacja w renderze, stabilna referencja potrzebna w deps. Szkodzą gdy: koszt memoizacji > koszt rekalkulacji (proste obliczenia), wartość nie jest przekazywana niżej. Premature optimization — profileuj najpierw, memoizuj potem.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa React.memo i jakie ma ograniczenia?', 'React.memo to HOC memoizujący komponent — nie rerenderuje go jeśli props się nie zmieniły (shallow compare). Ograniczenia: porównuje referencje, nie wartości (nowy obiekt/tablica = rerender), nie pomaga jeśli komponent pobiera kontekst (zmiana kontekstu = rerender mimo memo). Accepts custom comparator: React.memo(Comp, arePropsEqual).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij Context API — kiedy używać, jakie są pułapki?', 'Context przekazuje dane przez drzewo bez prop drilling. Pułapki: KAŻDA zmiana wartości context rerenduje WSZYSTKICH konsumentów, nawet jeśli używają tylko części danych. Rozwiązania: dziel context na mniejsze, memoizuj value obiektu (useMemo), użyj use-context-selector. Nie używaj Context jako state managera dla częstych aktualizacji (np. pozycja myszy).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Suspense i Error Boundaries? Jak współpracują?', 'Suspense wyświetla fallback UI gdy dziecko się ładuje (lazy component, data fetching z use()). Error Boundary łapie błędy w renderze dzieci i wyświetla fallback error UI. Razem tworzą kompletny wzorzec: Suspense + Error Boundary owijają komponent. Suspense obsługuje loading, EB obsługuje error, komponent obsługuje success. Deklaratywna obsługa async stanów.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są React Server Components (RSC)? Jak działają?', 'RSC renderują się na serwerze i wysyłają do klienta jako gotowe vDOM (nie HTML). Nie mają stanu, hooków ani event handlerów. Mogą bezpośrednio czytać bazę danych, system plików. Korzyść: zero JS w bundlu klienta dla RSC. RSC mogą importować Client Components, ale nie odwrotnie. Fundamentalna zmiana: komponenty dzielą się na server/client boundary.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się Server Component od Client Component?', 'Server Component: renderowany na serwerze, brak useState/useEffect, dostęp do backendu, 0 KB JS klienta. Client Component: oznaczony ''use client'', renderowany w przeglądarce, ma pełne API Reacta. Granica: gdy potrzebujesz interaktywności (onClick, useState) — Client. Statyczny content, data fetching — Server. Domyślnie w Next.js App Router wszystko jest Server.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są Server Actions i jak ich używasz?', 'Server Actions to asynchroniczne funkcje oznaczone ''use server'' wykonywane na serwerze. Wywoływane z Client Components przez formularz (action={}) lub bezpośrednio. Zastępują API routes dla mutacji. React automatycznie serializuje dane formularza. Obsługują optimistic updates z useOptimistic. Działają bez JS po stronie klienta (progressive enhancement).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest hook use() w React 19?', 'use() to specjalny hook, który może być wywoływany warunkowo (wyjątek od rules of hooks). Przyjmuje Promise lub Context. Z Promise: integruje się z Suspense (suspenduje komponent do resolve). Z Context: alternatywa dla useContext z conditional calling. use(promise) zastępuje useState + useEffect do data fetchingu w nowym modelu RSC.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useTransition i kiedy go stosujesz?', 'useTransition oznacza aktualizację stanu jako „niski priorytet" — React może ją przerwać na rzecz pilniejszych (np. input). Zwraca [isPending, startTransition]. Zastosowanie: filtrowanie dużej listy, przełączanie tabów z ciężkim renderem, nawigacja. Input aktualizuje się natychmiast, wynik filtrowania „dogania". Unika zamrożenia UI przy kosztownych rerendera.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useDeferredValue i jak różni się od useTransition?', 'useDeferredValue opóźnia aktualizację wartości — React najpierw renderuje ze starą wartością, potem z nową w tle. useTransition opakowuje setState, useDeferredValue opakowuje wartość. Użyj useDeferredValue gdy nie kontrolujesz setState (np. prop z rodzica). useTransition gdy wywołujesz setState. Oba korzystają z concurrent rendering do płynnego UI.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak tworzyć custom hooks? Podaj zasady i wzorce.', 'Custom hook to funkcja zaczynająca się od „use" używająca innych hooks. Zasady: wydzielaj logikę reużywalną (useForm, useFetch, useDebounce), zwracaj tuple/obiekt, obsługuj cleanup. Wzorce: useLocalStorage (synchronizacja ze storage), useMediaQuery (responsywność), useClickOutside (zamykanie dropdownu). Custom hook to composability Reacta — odpowiednik mixinów, ale bez ich wad.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest concurrent rendering w React?', 'Concurrent rendering to zdolność Reacta do przygotowywania wielu wersji UI jednocześnie. React może przerwać render, obsłużyć ważniejsze zadanie i wrócić. Nie jest multithreading — to kooperatywny scheduling na jednym wątku. Włączany przez createRoot(). Umożliwia: useTransition, useDeferredValue, Suspense streaming. Eliminuje „zamrażanie" UI przy ciężkich aktualizacjach.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dlaczego key jest ważny w listach? Co się stanie bez niego lub z index jako key?', 'Key identyfikuje element listy między renderami. Bez key React porównuje po pozycji — przy wstawieniu elementu na początek przerenderowuje wszystko. Z index: ten sam problem przy sortowaniu/usuwaniu — stan komponentu przypisany do złego elementu. Używaj stabilnego, unikalnego ID. Index jako key bezpieczny tylko dla list statycznych, niesortowalnych.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różnią się controlled i uncontrolled components?', 'Controlled: wartość zarządzana przez React state (value={state} + onChange). Każda zmiana przechodzi przez setState. Uncontrolled: wartość zarządzana przez DOM (defaultValue + useRef). Controlled daje pełną kontrolę (walidacja na żywo, formatowanie, warunkowe zmiany). Uncontrolled jest prostszy (integracja z bibliotekami, pliki). Unikaj mieszania w jednym input.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa code splitting z React.lazy i Suspense?', 'React.lazy(() => import(''./Component'')) tworzy dynamiczny import — osobny chunk JS ładowany na żądanie. Suspense opakowuje lazy komponent i wyświetla fallback podczas ładowania. Typowe użycie: lazy loading routes, ciężkie moduły (edytor, wykresy). Uwaga: React.lazy działa tylko z default exports. Named exports: React.lazy(() => import(''./X'').then(m => ({default: m.Named}))).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Zustand, Jotai i TanStack Query jako state management.', 'Zustand: globalny store, minimalne API (create + hook), idealny do client state (UI, auth). Jotai: atomowy (bottom-up), każdy atom to niezależny kawałek stanu, lepszy do wielu izolowanych wartości. TanStack Query: server state management (cache, refetch, stale-while-revalidate), nie jest zamiennikiem Zustand — uzupełnieniem. Często: TanStack Query (server) + Zustand (client).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz komponenty React z React Testing Library?', 'RTL testuje z perspektywy użytkownika: render(<Comp />), screen.getByRole(''button''), fireEvent.click() / userEvent.click(). Nie testuj implementacji (stanu, instancji). Szukaj po roli (getByRole), tekście (getByText), labelu (getByLabelText). Mockuj API z MSW (Mock Service Worker). Asynchroniczne: await screen.findByText(). RTL wymusza dobre praktyki dostępności.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest MSW (Mock Service Worker) i dlaczego jest lepszy od mocków fetch?', 'MSW interceptuje requesty na poziomie sieci (Service Worker w przeglądarce, interceptor w Node). Korzyści: ten sam mock dla testów i dev, realistyczne zachowanie (opóźnienia, statusy), kod produkcyjny nie wie o mocku. Vs mockowanie fetch/axios: kruche, nie testuje pełnego flow, trzeba mockować implementację. MSW testuje integrację z prawdziwym kodem HTTP.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Next.js App Router z Pages Router.', 'App Router (Next 13+): RSC domyślnie, nested layouts, Suspense streaming, Server Actions, fine-grained caching. Pages Router: klasyczny SSR/SSG z getServerSideProps/getStaticProps, _app.tsx, _document.tsx. App Router jest przyszłością — głębsza integracja z React 18+ features. Pages Router stabilniejszy, prostszy, ale nie będzie rozwijany. Migracja jest stopniowa — oba mogą współistnieć.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają layouts w Next.js App Router?', 'Layout to komponent opakowujący stronę, persystentny między nawigacjami (nie rerenderuje się). layout.tsx w folderze stosuje się do wszystkich stron w tym folderze i podfolderach. Nested layouts: app/layout.tsx (root) > app/dashboard/layout.tsx (dashboard). Idealne do nawigacji, sidebar, kontekstów. Template.tsx to layout bez persystencji — rerenderuje się przy nawigacji.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useOptimistic w React 19?', 'useOptimistic pozwala natychmiast wyświetlić oczekiwany wynik akcji zanim serwer potwierdzi. Np. przy wysyłaniu komentarza — pojawia się od razu, a po odpowiedzi serwera stan się synchronizuje. Jeśli akcja się nie powiedzie, React automatycznie cofnie optymistyczną aktualizację. Drastycznie poprawia perceived performance aplikacji.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak unikasz prop drilling w React? Porównaj podejścia.', 'Sposoby: 1) Context API (prosty, ale rerendery), 2) Composition (przekazywanie JSX jako children/props), 3) Zustand/Jotai (zewnętrzny store), 4) Component composition (render props, compound components). Często najlepsze: composition pattern — zamiast przekazywać dane przez 5 poziomów, przenieś komponent wyżej i przekaż jako children. Unikaj Context dla częstych zmian.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są compound components pattern w React?', 'Compound components to wzorzec gdzie rodzic i dzieci współdzielą implicit state. Przykład: <Select><Option value="a">A</Option></Select>. Implementacja: Context w rodzicu, children go konsumują. Korzyści: deklaratywne API, elastyczny układ, enkapsulacja logiki. Używane w: Headless UI, Radix, Reach UI. Alternatywa dla „prop hell" w jednym mega-komponencie.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak React batching działa w v18+ i czym różni się od v17?', 'W React 17 batching (łączenie setState) działał tylko w event handlerach Reacta. W React 18+ automatic batching łączy WSZYSTKIE aktualizacje stanu — w setTimeout, Promises, natywnych event handlerach. Jeden render zamiast kilku. Jeśli potrzebujesz natychmiastowego rerenderowania: flushSync(() => setState(val)). Batching to bezpłatna optymalizacja v18.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest forwardRef i kiedy jest potrzebny?', 'forwardRef przekazuje ref z rodzica do wewnętrznego DOM elementu komponentu. Bez niego ref wskazuje na instancję komponentu (która w funkcyjnym nie istnieje). Potrzebny: biblioteki komponentów (button, input), animacje (ref do DOM), integracja z imperatywnym kodem. W React 19: ref jest zwykłym propem — forwardRef nie jest już potrzebny.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useImperativeHandle i kiedy go stosujesz?', 'useImperativeHandle pozwala kontrolować co rodzic widzi przez ref. Zamiast pełnego DOM elementu eksponujesz ograniczone API: useImperativeHandle(ref, () => ({ focus: () => inputRef.current.focus(), reset })). Użycie: komponenty formularzy z custom API, edytory, playery. Chroni enkapsulację — rodzic nie ma dostępu do całego DOM.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz formularze w React? Porównaj podejścia.', 'Podejścia: 1) Controlled z useState (najprostsze, pełna kontrola), 2) react-hook-form (uncontrolled, minimalne rerendery, świetna walidacja), 3) Formik (controlled, popularny ale ciężki), 4) Server Actions z formData (progressive enhancement). react-hook-form jest najczęstszym wyborem: najlepsza wydajność, integracja z zod/yup do walidacji schematów.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest render prop pattern i czy nadal jest aktualny?', 'Render prop to wzorzec przekazywania funkcji renderującej jako prop/children: <Mouse render={({x,y}) => <Cat x={x} y={y}/>}/>. Był popularny pre-hooks do reużywania logiki. Dziś custom hooks lepiej rozwiązują ten problem. Render props nadal przydatne: dynamiczne sloty w komponentach UI, biblioteki (TanStack Table, Downshift), gdy potrzebujesz JSX callback.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak profilować i optymalizować wydajność React?', 'Narzędzia: React DevTools Profiler (flamegraph, ranked view, „why did this render"), Chrome DevTools Performance tab, why-did-you-render library. Optymalizacje: React.memo dla czystych komponentów, useMemo/useCallback dla stabilnych referencji, lazy loading, virtualizacja list (react-window), debounce inputów. Zasada: nie optymalizuj bez pomiaru — profileuj najpierw.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest React Compiler (dawniej React Forget)?', 'React Compiler to kompilator automatycznie memoizujący komponenty i hooki w build time. Eliminuje potrzebę ręcznego useMemo, useCallback, React.memo. Analizuje kod i dodaje memoizację tam gdzie potrzeba. Działa z istniejącym kodem (opt-in). Wymaga przestrzegania reguł Reacta (pure render, rules of hooks). Dostępny eksperymentalnie w React 19+.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Suspense streaming w Next.js?', 'Suspense streaming wysyła HTML fragmentami. Serwer natychmiast wysyła shell (layout + fallback Suspense), potem streamuje gotowe fragmenty w miarę ich renderowania. Przeglądarka „wstrzykuje" je w placeholder. Korzyść: szybki TTFB, progresywne ładowanie. Implementacja: opakowujesz async komponent w <Suspense fallback={<Skeleton/>}> i React automatycznie streamuje.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useId i do czego służy?', 'useId generuje unikalne ID stabilne między serwerem a klientem. Użycie: łączenie label z input (htmlFor={id}), aria-describedby, unikalne ID w listach komponentów. Dlaczego nie Math.random()? — różny wynik na serwerze i kliencie = hydration mismatch. useId gwarantuje identyczne ID w SSR i CSR. Nie używaj do key w listach.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz autentykację w Next.js App Router?', 'Podejścia: 1) Middleware (middleware.ts) — sprawdza cookie/token przed każdym request. 2) Layout Server Component — sprawdza sesję, redirect jeśli brak. 3) NextAuth.js/Auth.js — pełne rozwiązanie z providerami. Cookie-based session jest preferowana (httpOnly, secure). Middleware do route protection, Server Components do conditional rendering, Server Actions do login/logout.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest stale-while-revalidate w kontekście data fetchingu?', 'SWR to strategia cache: zwróć stale (przestarzałe) dane z cache natychmiast, w tle pobierz świeże, po pobraniu zaktualizuj UI. Użytkownik widzi dane od razu bez loadera. Implementacja: TanStack Query (staleTime, cacheTime), SWR library, Next.js fetch cache. Idealne do danych zmieniających się rzadko (profil, lista produktów), nie do real-time (chat).', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest useFormStatus i jak go używasz z Server Actions?', 'useFormStatus() zwraca {pending, data, method, action} dla najbliższego nadrzędnego <form>. pending=true podczas trwania Server Action — idealny do disable buttona i wyświetlania spinnera. Musi być w komponencie dziecku formularza (nie w tym samym komponencie co form). Eliminuje ręczne zarządzanie loading state dla formularzy.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz cache''owaniem w Next.js App Router?', 'Next.js ma 4 warstwy cache: 1) Request Memoization (deduplikacja fetch w jednym renderze), 2) Data Cache (persystentny cache fetch na serwerze), 3) Full Route Cache (statyczny HTML), 4) Router Cache (client-side cache segmentów). Kontrola: revalidate (ISR), cache: ''no-store'', revalidatePath/revalidateTag. Domyślnie agresywne cache''owanie — musisz świadomie invalidować.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest hydration mismatch i jak go unikasz?', 'Hydration mismatch to różnica między HTML z serwera a tym co React renderuje na kliencie. Powody: Math.random(), Date.now(), window/localStorage, warunkowy render po stronie klienta. Rozwiązania: useEffect dla client-only kodu, suppressHydrationWarning (ostrożnie), useId zamiast random. Next.js: dynamic(() => import(''./Comp''), {ssr: false}) dla client-only komponentów.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz infinite scroll w React?', 'Podejścia: 1) Intersection Observer API — obserwuj element „sentinel" na dole listy, fetch przy widoczności. 2) react-intersection-observer + TanStack Query (useInfiniteQuery). 3) Virtualizacja (@tanstack/react-virtual) dla wydajności. Kluczowe: useInfiniteQuery zarządza stronami, hasNextPage/fetchNextPage, loading/error states. Nie zapomnij o scroll restoration.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest portal w React i kiedy go używasz?', 'ReactDOM.createPortal(children, domNode) renderuje dzieci w innym miejscu DOM niż rodzic. Zastosowania: modale, tooltipy, dropdown menu — elementy, które muszą być nad innymi (z-index) lub poza overflow:hidden rodzica. Ważne: event bubbling nadal działa w React tree (nie DOM tree) — klik w portalu bąbelkuje do React rodzica.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz dark mode w React?', 'Podejścia: 1) CSS custom properties + atrybut data-theme na html, toggle zmienia atrybut. 2) Tailwind dark: z class strategy. 3) CSS prefers-color-scheme media query. Persystencja: localStorage + system preference jako default. SSR: cookie zamiast localStorage (uniknięcie flash). next-themes w Next.js rozwiązuje SSR flash. Kontekst lub Zustand do globalnego stanu.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są Higher-Order Components (HOC)? Czy nadal ich używamy?', 'HOC to funkcja przyjmująca komponent i zwracająca nowy z dodaną funkcjonalnością: withAuth(Dashboard). Problemy: wrapper hell, name collision, trudność śledzenia propsów. Dziś custom hooks lepiej rozwiązują reużywanie logiki. HOC nadal spotykane: connect() z Redux (legacy), withRouter, w bibliotekach. Preferuj hooks + composition nad HOC.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz globalne błędy w React?', 'Error Boundary (class component z getDerivedStateFromError + componentDidCatch) łapie błędy w renderze dzieci. Nie łapie: event handlerów, async kodu, SSR, samego EB. Dla event handlerów: try/catch. Dla async: .catch() lub error state. Architektura: Root EB (generic fallback) + granularne EB per feature (izolacja błędów). react-error-boundary upraszcza implementację.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useLayoutEffect i czym różni się od useEffect?', 'useLayoutEffect wykonuje się synchronicznie PO DOM mutations ale PRZED paintem przeglądarki. useEffect wykonuje się asynchronicznie po paincie. useLayoutEffect do: pomiarów DOM (getBoundingClientRect), zapobiegania migotaniu (flash of unstyled content), animacji wymagających natychmiastowej zmiany. Użycie useLayoutEffect nadmiernie blokuje painting — używaj oszczędnie.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają slot patterns w React (children, render props, named slots)?', 'React nie ma formalnych slotów jak Vue/Angular. Realizacja: 1) children prop = default slot, 2) Named props z JSX: header={<Header/>}, 3) Compound components: <Card><Card.Header/></Card>. Compound components to najbliższy odpowiednik named slots — enkapsulują logikę i dają kontrolę nad układem. Children prop to najprostszy i najczęstszy wzorzec.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Strict Mode w React i dlaczego wywołuje podwójne renderowanie?', 'StrictMode w dev mode celowo podwójnie wywołuje render i efekty aby wykryć side effects w renderze, brak cleanup w efektach, użycie deprecjowanych API. Symuluje mount → unmount → mount. Jeśli komponent psuje się przy podwójnym renderze, ma bug (np. efekt bez cleanup, mutacja w renderze). Nie wpływa na produkcję — zero narzutu.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz route protection (auth guard) w Next.js?', 'Middleware (middleware.ts): interceptuje requesty, sprawdza cookie sesji, redirect do /login. Zaletą jest centralny punkt, działa dla wszystkich routes (config matcher). Alternatywa: sprawdzanie sesji w layout.tsx Server Component z redirect(). Nie polegaj na client-side sprawdzaniu — dane i tak mogą wyciec z Server Components bez middleware.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest ISR (Incremental Static Regeneration) i jak go konfigurujesz?', 'ISR pozwala odświeżać statyczne strony bez pełnego rebuildu. W App Router: export const revalidate = 3600 (sekundy) lub fetch(url, {next: {revalidate: 3600}}). On-demand: revalidatePath(''/blog'') lub revalidateTag(''posts'') w Server Action. Pierwsza wizyta po wygaśnięciu: stale content + background regeneration. Łączy zalety SSG (szybkość) z dynamicznymi danymi.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz stanem URL w React (search params, pathname)?', 'Next.js: useSearchParams(), usePathname(), useRouter(). Vanilla React: useSearchParams z react-router. Wzorzec: stan filtrowania/sortowania/paginacji w URL zamiast useState. Korzyści: shareability, back button, SSR. nuqs library upraszcza typowane search params z walidacją. Unikaj synchronizacji useState ↔ URL — to źródło bugów.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa useCallback w kontekście event handlerów?', 'useCallback memoizuje referencję funkcji. Bez niego każdy render tworzy nową funkcję. Ma sens gdy: przekazujesz handler do React.memo dziecka (nowa ref = rerender), handler jest w deps innego hooka. Bez tych przypadków useCallback to niepotrzebny narzut. W React 19+ z Compiler — useCallback jest dodawany automatycznie. Nie opakowuj każdej funkcji.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest streaming SSR i jak różni się od klasycznego SSR?', 'Klasyczny SSR: serwer renderuje CAŁY HTML, wysyła jeden response. Streaming SSR: serwer wysyła HTML fragmentami (Transfer-Encoding: chunked). Suspense boundaries definiują granice streamingu. Korzyść: szybszy TTFB (użytkownik widzi shell natychmiast), progresywne ładowanie. Next.js App Router domyślnie streamuje. Wymaga infrastruktury obsługującej streaming (nie statyczny hosting).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz loading i error states w Next.js App Router?', 'loading.tsx — automatyczny Suspense boundary dla segmentu route, wyświetla się podczas ładowania. error.tsx — automatyczny Error Boundary, otrzymuje error i reset(). not-found.tsx — wyświetla się przy notFound(). Zagnieżdżanie: każdy folder route może mieć własne. Granularne: <Suspense> w komponencie dla mniejszych fragmentów. Te pliki to convention over configuration.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz middleware pattern w Next.js?', 'middleware.ts w root projektu interceptuje KAŻDY request. Zastosowania: auth (redirect), i18n (locale detection), A/B testing, rate limiting. Config: export const config = {matcher: [''/dashboard/:path*'']}. Ograniczenia: działa na Edge Runtime (nie pełny Node.js), ograniczone API. Nie używaj do data fetching — tylko routing/redirect logic. Kolejność: middleware → route handler.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest taint API (experimental) w React?', 'taint API (experimental) oznacza obiekty/wartości jako „zanieczyszczone" — nie mogą być przekazane do Client Components. experimental_taintObjectReference(message, object) i taintUniqueValue. Cel: zapobieganie przypadkowemu wyciekowi danych wrażliwych (tokeny, hasła) z Server Components do klienta. Dodatkowa warstwa bezpieczeństwa na granicy server/client.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz internationalizację (i18n) w Next.js App Router?', 'Podejścia: 1) next-intl — najpopularniejszy, middleware do locale detection, useTranslations() hook, Server Components support. 2) Subpath routing (/en/about, /pl/about) z [locale] dynamic segment. 3) Domain routing. Klucz: middleware wykrywa locale (header Accept-Language, cookie), redirect do odpowiedniego segmentu. Tłumaczenia w JSON, lazy loaded per locale.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Czym różni się Options API od Composition API? Dlaczego Vue 3 promuje Composition?', 'Options API organizuje kod po typie (data, methods, computed, watch). Composition API organizuje po funkcjonalności — logika jednej feature w jednym miejscu. Powody przejścia: lepsza reużywalność (composables zamiast mixinów), pełna typizacja TypeScript, brak problemów z this, elastyczne grupowanie logiki. Options API nadal działa, ale Composition jest standardem.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się ref() od reactive()? Kiedy co wybrać?', 'ref() opakowuje dowolną wartość (prymityw/obiekt) w {value: ...} — dostęp przez .value w JS, automatyczne unwrapping w template. reactive() tworzy głęboko reaktywny proxy obiektu — bezpośredni dostęp bez .value. ref() preferowany: prymitywy, wymiana referencji, klarowność. reactive() dla obiektów bez potrzeby wymiany. Uwaga: destructuring reactive() traci reaktywność.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dlaczego destructuring reactive() traci reaktywność i jak to naprawić?', 'reactive() zwraca Proxy — destructuring kopiuje wartości prymitywne, tracąc Proxy. const {name} = reactive({name: ''Jan''}) — name to zwykły string. Rozwiązania: 1) toRefs() — konwertuje properties na ref, 2) storeToRefs() w Pinia, 3) używaj ref() od początku. To najczęstszy „gotcha" Vue 3 na rozmowach rekrutacyjnych.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj computed(), watch() i watchEffect(). Kiedy co stosować?', 'computed(): wartość pochodna, leniwa, cachowana, readonly (chyba że writable). watch(): reaguje na zmianę konkretnego źródła, ma dostęp do starej i nowej wartości, lazy domyślnie. watchEffect(): automatycznie śledzi zależności (jak useEffect bez deps array), eager, brak dostępu do starej wartości. computed do transformacji danych, watch do side effects z kontrolą, watchEffect do prostych efektów.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest script setup i jakie daje korzyści?', '<script setup> to compile-time sugar dla Composition API. Korzyści: mniej boilerplate (brak return, defineComponent), automatyczny expose propsów/emitów, lepszy TypeScript inference, tree-shaking top-level imports. Zmienne zadeklarowane na top-level są automatycznie dostępne w template. defineProps/defineEmits to compiler macros (nie importy).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Porównaj Pinia z Vuex. Dlaczego Pinia jest teraz standardem?', 'Pinia to oficjalny state manager Vue 3. Vs Vuex: brak mutations (bezpośrednia modyfikacja stanu), pełny TypeScript bez deklaracji typów, modularny (brak nested modules), lekki (1 KB), devtools integration. Vuex miał mutations→actions→getters co dodawało boilerplate. Pinia: defineStore z state, getters, actions — prostszy mental model. Vuex jest w maintenance mode.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają defineProps i defineEmits w script setup?', 'defineProps<{title: string; count?: number}>() definiuje typowane propsy. defineEmits<{(e: ''update'', value: string): void}>() definiuje typowane zdarzenia. Są compiler macros — nie wymagają importu. Runtime validation: defineProps({title: {type: String, required: true}}). withDefaults() dodaje wartości domyślne. Kompilator Vue zamienia je na odpowiedni Options API pod spodem.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest defineModel() i jak upraszcza v-model na komponentach?', 'defineModel() (Vue 3.4+) automatycznie tworzy prop + emit dla v-model. Zamiast ręcznego modelValue prop + update:modelValue emit — const model = defineModel<string>(). model.value = ''abc'' automatycznie emituje update. Wspiera named models: defineModel(''title''). Drastycznie redukuje boilerplate dla komponentów formularza z dwukierunkowym wiązaniem.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa provide/inject w Vue 3?', 'provide(key, value) w rodzicu udostępnia dane. inject(key, defaultValue) w dziecku/wnuku je pobiera. Działa przez drzewo komponentów — nie trzeba przekazywać propsów przez pośrednie poziomy. Typowanie: const key = Symbol() as InjectionKey<Type>. Reaktywność: provide ref() lub reactive() — inject dostanie reaktywną wartość. Odpowiednik Context API z Reacta.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są composables i jak się mają do mixinów?', 'Composables to funkcje reużywające logikę Composition API (np. useMouse, useFetch). Vs mixiny: brak name collision (jawne nazwy), jasne źródło danych, pełna typizacja TS, łatwe testowanie (zwykła funkcja). Konwencja: use* prefix. Composable może zwracać ref, computed, watch — pełny reaktywny kontekst. To główny mechanizm reużywania logiki w Vue 3.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Teleport w Vue i kiedy go stosujesz?', '<Teleport to="body"> renderuje zawartość w innym miejscu DOM niż pozycja w drzewie komponentów. Zastosowania: modale, tooltipy, notyfikacje — elementy wymagające pozycjonowania względem body (ucieczka z overflow:hidden, stacking context). Zachowuje logiczne powiązanie z rodzicem (props, events, DI). Warunkowy teleport: <Teleport :disabled="isMobile">.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Suspense w Vue 3 i jak go używasz?', '<Suspense> wyświetla #fallback slot dopóki async zależność w #default się nie załaduje. Wspiera: async setup() w komponentach, async komponenty (defineAsyncComponent). Dwa sloty: default (treść) i fallback (loading). onErrorCaptured w rodzicu łapie błędy. Experimental w Vue 3, ale szeroko używane z Nuxt 3. Deklaratywna obsługa loading states.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak Virtual DOM w Vue różni się od Reacta?', 'Oba używają vDOM, ale Vue optymalizuje kompilacją: compiler analizuje template i oznacza statyczne fragmenty (hoisting), dynamiczne bindingi (patch flags). React porównuje całe drzewo, Vue pomija znane statyczne części. Vue generuje zoptymalizowany render code z patch flags (TEXT, CLASS, STYLE). W efekcie Vue ma mniejszy overhead diffingu dla typowych szablonów.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa v-model na custom komponencie?', 'v-model="val" na komponencie to skrót dla :modelValue="val" @update:modelValue="val = $event". Komponent przyjmuje prop modelValue i emituje update:modelValue. Multiple v-models: v-model:title="t" v-model:content="c" (named models). Modyfikatory: v-model.trim, custom modifiers przez defineProps + modelModifiers. defineModel() od Vue 3.4 upraszcza to drastycznie.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie rodzaje slotów istnieją w Vue i kiedy ich używasz?', 'Default slot: <slot/> — domyślna treść z rodzica. Named slot: <slot name="header"/> — <template #header>. Scoped slot: <slot :item="item"/> — dziecko przekazuje dane do rodzica: <template #default="{item}">. Scoped slots kluczowe dla: tabel (custom row rendering), list, komponentów render-less. Slot to główny mechanizm composition w Vue templates.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opisz lifecycle hooks w Composition API.', 'onMounted, onUpdated, onUnmounted, onBeforeMount, onBeforeUpdate, onBeforeUnmount, onActivated/Deactivated (keep-alive), onErrorCaptured. W script setup nie ma beforeCreate/created — kod na top-level JEST created. Najczęstsze: onMounted (dostęp do DOM, fetch danych), onUnmounted (cleanup: listeners, timery). Mogą być wielokrotnie wywoływane (wielu onMounted w jednym komponencie).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest v-once, v-memo i kiedy je stosujesz?', 'v-once renderuje element raz — dalsze zmiany nie powodują rerenderowania. Użycie: statyczne treści (nagłówki, tekst prawny). v-memo=[deps] memoizuje fragment — rerender tylko gdy deps się zmienią. Użycie: lista z v-for gdzie większość elementów się nie zmienia. v-memo na v-for z key to odpowiednik React.memo. Nie nadużywaj — Vue i tak jest wydajny.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa keep-alive i kiedy go używasz?', '<KeepAlive> cachuje instancje komponentów zamiast je niszczyć. Przy powrocie do komponentu — stan jest zachowany (formularze, scroll position, dane). Props: include/exclude (filtrowanie po nazwie), max (limit cache). Lifecycle: onActivated/onDeactivated zamiast mounted/unmounted. Użycie: zakładki, kroki wizardów, nawigacja z powrotem do listy z pozycją scrollu.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest shallowRef i shallowReactive? Kiedy je stosujesz?', 'shallowRef: reaktywność tylko na .value (nie zagnieżdżone properties). shallowReactive: reaktywność tylko na pierwszym poziomie obiektu. Zastosowanie: duże obiekty gdzie śledzenie głębokich zmian jest kosztowne (lista 10k elementów, canvas state, dane z API). Przy modyfikacji zagnieżdżonych danych musisz ręcznie triggerować: triggerRef(ref) lub zamienić cały .value.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Nuxt 3 auto-imports?', 'Nuxt 3 automatycznie importuje: composables (ref, computed, useState, useFetch z Vue/Nuxt), komponenty z components/, composables z composables/, utility z utils/. Brak ręcznych importów w 90% kodu. Konfiguracja w nuxt.config.ts: imports.dirs. Typowanie generowane w .nuxt/. Korzyść: czystszy kod, szybszy development. Wada: mniej oczywiste zależności dla nowych w projekcie.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest universal rendering w Nuxt 3?', 'Universal rendering = SSR + client-side hydration. Serwer renderuje HTML (SEO, szybki FCP), klient hydruje (interaktywność). Nuxt 3 pozwala konfigurować per route: routeRules: {''/admin/**'': {ssr: false}}. Tryby: universal (SSR+hydration), spa (CSR only), static (pre-rendering). Hybrid rendering łączy je: strona główna SSR, dashboard SPA, blog pre-rendered.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają server routes w Nuxt 3?', 'Pliki w server/api/ i server/routes/ tworzą endpointy API automatycznie. server/api/users.get.ts → GET /api/users. Dostęp do request: defineEventHandler((event) => {...}). Obsługa: query params (getQuery), body (readBody), params, cookies. Działają na Nitro engine — deploy na Node, Cloudflare Workers, Vercel Edge. Brak potrzeby osobnego backendu dla prostych API.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useFetch vs useAsyncData w Nuxt 3?', 'useFetch(url) to wrapper na useAsyncData + $fetch. useAsyncData(key, () => fetchFn()) daje pełną kontrolę nad fetch logiką. Oba: deduplikacja na serwerze i kliencie, automatyczny transfer danych (payload), lazy option, immediate/watch. useFetch dla prostych GET, useAsyncData gdy potrzebujesz custom logiki (transformacja, multiple calls). Oba obsługują SSR + client hydration.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz komponenty Vue z Vitest i Vue Test Utils?', 'Vue Test Utils: mount(Comp, {props, global: {plugins, stubs, provide}}). mount = full render, shallowMount = stub children. Szukanie: wrapper.find(''button''), wrapper.findComponent(Child). Triggery: wrapper.trigger(''click''), setValue(). Asynchroniczność: await nextTick(), await flushPromises(). Vitest zamiast Jest — szybszy, natywny ESM, kompatybilne API. Testuj zachowanie, nie implementację.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa system reaktywności Vue 3 pod spodem?', 'Vue 3 używa ES Proxy (zamiast Object.defineProperty z Vue 2). Proxy przechwytuje get (śledzenie zależności — track) i set (triggerowanie aktualizacji — trigger). Każdy efekt (render, watch, computed) ma Set zależności. Przy get: efekt dodaje się do dependency set. Przy set: wszystkie efekty w secie są reexecutowane. Proxy obsługuje dynamiczne property, Map/Set, tablice.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym się różni Vue 3 Proxy-based reactivity od Vue 2 Object.defineProperty?', 'Vue 2: Object.defineProperty nie wykrywa dodawania/usuwania properties (potrzebny Vue.set()), nie obsługuje natywnie Map/Set, problemy z tablicami (index assignment). Vue 3 Proxy: pełne przechwytywanie operacji, dynamiczne property, natywna obsługa kolekcji, lepsza wydajność dla dużych obiektów. To główny powód techniczny upgrade z Vue 2 do 3.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz globalny error handling w Vue 3?', 'app.config.errorHandler = (err, instance, info) => {...} łapie błędy z komponentów, lifecycle hooks, event handlerów. onErrorCaptured w komponencie łapie błędy z dzieci (jak Error Boundary). Zwróć false aby zatrzymać propagację. Dla async: window.onunhandledrejection. Architektura: globalny handler loguje do Sentry, granularne onErrorCaptured wyświetlają fallback UI per sekcja.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działają tranzycje (transitions) i animacje w Vue 3?', '<Transition> opakowuje element i dodaje klasy CSS przy wejściu/wyjściu: v-enter-from, v-enter-active, v-enter-to (analogicznie leave). <TransitionGroup> dla list z v-for. JavaScript hooks: @before-enter, @enter, @leave. Integracja z GSAP/anime.js przez hooks. Tryb: mode="out-in" (stary wychodzi, nowy wchodzi). Key na elemencie wymusza re-transition.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest defineAsyncComponent i jak realizujesz lazy loading komponentów?', 'defineAsyncComponent(() => import(''./Heavy.vue'')) tworzy komponent ładowany na żądanie. Opcje: loadingComponent, errorComponent, delay, timeout. Z <Suspense>: async component integruje się natywnie. W Nuxt 3: prefix Lazy — <LazyHeavyChart/> automatycznie lazy-loaduje. Użycie: modalne okna, ciężkie wykresy, edytory — wszystko co nie jest potrzebne na start.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz formularzami w Vue 3?', 'Podejścia: 1) v-model na inputach + reactive/ref (najprostsze), 2) VeeValidate + zod/yup (walidacja schematów), 3) FormKit (full-featured form framework). v-model daje dwukierunkowe wiązanie out of the box. Walidacja: computed z regexami (prosty), zod schema + VeeValidate useForm (zaawansowane). FormKit dodaje accessibility, multi-step, i18n — ciężki ale kompletny.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest watchEffect vs watch? Kiedy wolisz które?', 'watchEffect automatycznie śledzi wszystkie reaktywne zależności użyte wewnątrz — nie deklarujesz ich explicite. watch wymaga jawnego źródła i daje dostęp do oldValue/newValue. watchEffect lepszy: proste efekty z wieloma zależnościami, nie potrzebujesz starej wartości. watch lepszy: jedna konkretna zmienna, potrzebujesz porównania old/new, deep watch z kontrolą.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest toRefs() i toRef() i kiedy ich potrzebujesz?', 'toRefs(reactive) konwertuje każdy property reaktywnego obiektu na osobny ref — zachowuje reaktywność przy destructuring. toRef(reactive, ''key'') konwertuje jeden property. Typowe użycie: const {name, age} = toRefs(props) w Composition API, storeToRefs(store) w Pinia. Bez toRefs destructuring daje plain values — utrata reaktywności, najczęstszy bug początkujących.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz komunikację między komponentami w Vue 3?', 'Sposoby: 1) props/emit (rodzic-dziecko), 2) provide/inject (przodek-potomek), 3) Pinia store (globalny stan), 4) composables (współdzielona logika), 5) template refs (imperatywny dostęp). Emits dla zdarzeń w górę, props dla danych w dół. Pinia gdy wiele komponentów współdzieli stan. Unikaj event bus — trudny do debugowania, Pinia jest lepszy.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa defineExpose w script setup?', 'W script setup nic nie jest domyślnie dostępne przez template ref rodzica. defineExpose({method, value}) jawnie eksponuje API komponentu. Przykład: child.value.focus() — zadziała tylko jeśli focus jest w defineExpose. To lepsza enkapsulacja niż Options API, gdzie wszystko było dostępne. Używaj oszczędnie — preferuj props/emit nad imperatywne wywołania.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest effectScope() i kiedy go używasz?', 'effectScope() grupuje reaktywne efekty (watch, watchEffect, computed) i pozwala je wszystkie zatrzymać jednym scope.stop(). Użycie: composables tworzone poza komponentem, cleanup logiki w bibliotekach, testowanie (scope izoluje efekty). Pinia używa effectScope wewnętrznie dla każdego store. W komponentach scope tworzony automatycznie i czyszczony przy unmount.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zoptymalizujesz wydajność dużej aplikacji Vue?', 'Checklist: shallowRef dla dużych danych, v-memo na v-for, KeepAlive dla tab/route cache, lazy loading komponentów, virtual scrolling (vue-virtual-scroller), computed zamiast metod w template, v-once dla statycznych fragmentów. Narzędzia: Vue DevTools Performance, Chrome DevTools. Unikaj: głębokich reactive obiektów bez potrzeby, watchers zamiast computed, zbyt wielu provide/inject.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Vapor Mode w Vue i co obiecuje?', 'Vapor Mode (w rozwoju) to alternatywny tryb kompilacji Vue eliminujący Virtual DOM. Kompiluje template do imperatywnych operacji DOM (jak Svelte/Solid). Korzyści: mniejszy runtime (~6 KB vs ~50 KB), szybsze aktualizacje, mniej pamięci. Kompatybilny z istniejącym Composition API. Opt-in per komponent. Idealny do lekkich widgetów i aplikacji wymagających ekstremalnej wydajności.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa routing w Vue Router 4?', 'createRouter({history: createWebHistory(), routes}) z typowanymi routes. Composition API: useRouter() (nawigacja), useRoute() (aktualne dane trasy). Navigation guards: beforeEach (globalny), beforeEnter (per route), onBeforeRouteLeave (w komponencie). Dynamic params: /user/:id → useRoute().params.id. Nested routes: children array. Lazy loading: component: () => import(''./View.vue'').', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz dynamiczne komponenty w Vue?', '<component :is="currentComponent"/> dynamicznie renderuje komponent na podstawie zmiennej. Przydatne: system tabów, konfigurowalny dashboard, formularze z dynamicznymi polami. Z KeepAlive: cachuje instancje przy przełączaniu. Z async: is może być defineAsyncComponent. Alternatywa: v-if/v-else-if dla kilku wariantów, ale <component :is> jest elastyczniejszy.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest plugin w Vue 3 i jak go tworzysz?', 'Plugin to obiekt z install(app, options) method. app.use(plugin) wywołuje install. Wewnątrz: app.component() (globalne komponenty), app.directive() (dyrektywy), app.provide() (globalne provide), app.config.globalProperties (globalne właściwości). Przykłady: i18n plugin, toast plugin, analytics. W Vue 3 preferuj composables nad globalProperties — lepsze typowanie i testowanie.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa custom directive w Vue 3?', 'Dyrektywa to obiekt z lifecycle hooks: created, beforeMount, mounted, beforeUpdate, updated, beforeUnmount, unmounted. Rejestracja: app.directive(''focus'', {mounted(el) {el.focus()}}). W template: v-focus. Argumenty: v-directive:arg.modifier="value". Shorthand: function syntax = mounted + updated. Użycie: DOM manipulation nie objęte Vue API (focus, tooltip, click-outside).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Nuxt 3 middleware i jakie ma typy?', 'Middleware w Nuxt 3 to funkcje uruchamiane przed nawigacją. Typy: 1) Named: middleware/auth.ts, używane per route (definePageMeta({middleware: ''auth''})), 2) Global: middleware/auth.global.ts — dla każdej route. defineNuxtRouteMiddleware((to, from) => {if (!loggedIn) return navigateTo(''/login'')}). Server middleware w server/middleware/ — dla HTTP requestów (logi, CORS, auth API).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak implementujesz SSR-safe kod w Vue/Nuxt?', 'Problemy SSR: brak window/document na serwerze, różnice w renderze (hydration mismatch). Rozwiązania: onMounted dla client-only kodu (DOM API), <ClientOnly> komponent w Nuxt, import.meta.client / import.meta.server checks, useNuxtApp().$isHydrating. Unikaj: localStorage w setup, Math.random w template, Date.now bez stabilizacji. Testuj z SSR włączonym.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest useState w Nuxt 3 i jak różni się od ref()?', 'useState(''key'', () => initialValue) to Nuxt composable tworzący SSR-friendly, współdzielony stan. Różnice od ref(): 1) Shared między komponentami (ten sam key = ten sam stan), 2) Serializable (przenoszony z serwera na klienta), 3) Przeżywa nawigację. ref() jest lokalny dla komponentu i nie przeżywa SSR. useState dla globalnego stanu bez Pinia, ref dla lokalnego.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zarządzasz SEO w Nuxt 3?', 'useHead({title, meta: [{name: ''description'', content: ''...''}]}), useSeoMeta({ogTitle, ogDescription, ogImage}). Konfiguracja globalna: nuxt.config.ts app.head. Dynamiczne per strona: useHead w setup z computed title. Nuxt generuje SSR HTML z metatagami. Sitemap: @nuxtjs/sitemap. Robots: nuxt-simple-robots. Structured data: useSchemaOrg. SSR jest kluczowy — bez SSR meta tagi nie są widoczne dla crawlerów.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa system typów w Vue 3 z TypeScript?', 'Vue 3 to rewrite w TypeScript — pełna typizacja. defineProps<{name: string}>() — generics inference. ref<number>(0) — typowany ref. Computed auto-infers return type. defineEmits<{(e: ''change'', id: number): void}>() — typowane eventy. Pinia stores: pełne typy stanu, getterów, akcji. Problemem bywają dynamic slots i provide/inject — wymagają manualnych typów.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak realizujesz internacjonalizację (i18n) w Vue/Nuxt?', 'Vue: vue-i18n z createI18n({locale, messages}). useI18n() w Composition API: t(''key''), locale.value. Nuxt: @nuxtjs/i18n (wrapper na vue-i18n) z routingiem /en/about, /pl/about. Lazy loading tłumaczeń: każdy locale to osobny chunk. SEO: hreflang tagi automatycznie. Pluralizacja: t(''items'', count). Interpolacja: t(''hello'', {name: ''Jan''}). Fallback locale dla brakujących tłumaczeń.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Nuxt Content i kiedy go używasz?', 'Nuxt Content to moduł do zarządzania treścią (Markdown, YAML, JSON, CSV) jako file-based CMS. Pliki w content/ → queryContent API z filtrami, sortowaniem, paginacją. Renderowanie Markdown z Vue komponentami wewnątrz (MDC syntax). Użycie: blog, dokumentacja, landing page z CMS-like edycją. Alternatywa dla headless CMS gdy treść jest w repozytorium.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Nitro engine w Nuxt 3?', 'Nitro to server engine Nuxt 3 — uniwersalny, deploy-anywhere. Buduje server jako portable output dla: Node.js, Cloudflare Workers, Deno, Vercel, Netlify, AWS Lambda. Features: auto-imports server utils, file-based API routes, caching (defineCachedEventHandler), storage layer (useStorage). Nitro umożliwia Nuxt 3 bycie „full-stack framework" bez osobnego backendu.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak testujesz Pinia stores?', 'Bez komponentu: const store = useCounterStore(createPinia()). Testuj actions: store.increment(); expect(store.count).toBe(1). Mockuj dependencies: createPinia() + overrideActions lub vi.mock. Z komponentem: mount(Comp, {global: {plugins: [createTestingPinia({initialState, stubActions: false})]}}). createTestingPinia automatycznie stubuje actions — ważne: stubActions: false jeśli chcesz je testować.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Opisz box model w CSS. Czym różni się content-box od border-box?', 'Box model: content → padding → border → margin. content-box (domyślny): width/height dotyczy tylko content — padding i border dodają do rozmiaru. border-box: width/height zawiera content + padding + border. Praktyka: *, *::before, *::after {box-sizing: border-box} w resecie — przewidywalne rozmiary. Margin nie wchodzi w box-sizing — zawsze na zewnątrz.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używasz Flexbox a kiedy Grid? Podaj konkretne przypadki.', 'Flexbox: jednowymiarowy layout (wiersz LUB kolumna). Grid: dwuwymiarowy (wiersze I kolumny jednocześnie). Flexbox: navbar, toolbar, card footer z przyciskami, centrowanie. Grid: layout strony (header/sidebar/content/footer), galeria zdjęć, dashboard. Reguła: jeśli kontrolujesz jeden kierunek — Flexbox. Jeśli oba — Grid. Można łączyć: Grid na layout, Flex wewnątrz.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij specificity (specyficzność) selektorów CSS.', 'Specyficzność to „waga" selektora: inline style (1000) > ID (100) > class/attribute/pseudo-class (10) > element/pseudo-element (1). Przykład: #nav .link a = 100+10+1=111. !important nadpisuje wszystko (unikaj). Przy równej specyficzności wygrywa ostatnia reguła (cascade). Gotcha: .a.b (20) > .a (10) mimo tej samej ilości klas. Nie licz — rozumiej hierarchię.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są cascade layers (@layer) i jaki problem rozwiązują?', '@layer pozwala jawnie kontrolować kolejność kaskady. Reguły w warstwie o niższym priorytecie przegrywają z wyższą, niezależnie od specyficzności. Kolejność: @layer reset, base, components, utilities. Problem: biblioteka z selektorami o wyższej specyficzności nadpisuje nasze style. Z @layer: @layer lib {css z biblioteki} — łatwo nadpisujemy w wyższej warstwie.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są CSS custom properties (zmienne) i czym różnią się od zmiennych Sass?', 'CSS custom properties: --color: #333; użycie: var(--color, fallback). Różnice od Sass: 1) działają w runtime (dynamiczna zmiana przez JS/media queries), 2) podlegają kaskadzie i dziedziczeniu, 3) responsywne (zmiana w media query). Sass: compile-time, statyczne. Custom properties idealne do: tematów (dark mode), spacing scale, dynamicznych wartości. Sass do: obliczeń compile-time, mixins.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są container queries i jaki problem rozwiązują?', 'Container queries (@container) pozwalają stylizować element na podstawie rozmiaru jego kontenera (nie viewport). Problem: media queries = globalne — komponent w sidebar 300px i main 900px widzi ten sam viewport. Container queries: komponent adaptuje się do swojego kontenera. Wymaga: container-type: inline-size na rodzicu. @container (min-width: 400px) {.card {...}}.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wyjaśnij selektor :has() — do czego służy i dlaczego jest przełomowy?', ':has() to „parent selector" CSS — stylizuje element na podstawie jego dzieci/rodzeństwa. Przykłady: .card:has(img) {padding: 0} (karta z obrazkiem), form:has(:invalid) {border: red} (formularz z błędem), h2:has(+ p) {margin-bottom: 0} (h2 po którym jest p). Przełomowy bo CSS nigdy nie pozwalał selekcji w górę drzewa DOM.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opisz wartości position w CSS i kiedy każdej używasz.', 'static: domyślna, normalny flow. relative: offsetowany od swojej pozycji (kontekst dla absolute dzieci). absolute: wyjęty z flow, pozycjonowany względem najbliższego positioned przodka. fixed: względem viewport (nawigacja sticky, modal). sticky: normalny flow do progu scroll, potem „przykleja się" (nagłówki tabel, sekcji). Gotcha: fixed nie działa wewnątrz transform/filter (tworzy nowy containing block).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest stacking context (kontekst nakładania) i co go tworzy?', 'Stacking context to „warstwa" decydująca o kolejności rysowania elementów. Tworzy go: z-index na positioned element, opacity < 1, transform, filter, will-change, position: fixed/sticky. Ważne: z-index działa TYLKO w ramach tego samego kontekstu — element z z-index: 9999 w niższym kontekście przegra z z-index: 1 w wyższym. Debuguj przez DevTools layers panel.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest BEM i jak pomaga w organizacji CSS?', 'BEM: Block__Element--Modifier. Block: samodzielny komponent (.card). Element: część bloku (.card__title). Modifier: wariant (.card--featured). Korzyści: niska specyficzność (same klasy), jasna zależność, brak kolizji nazw. Wady: długie nazwy, verbose. Alternatywy: CSS Modules, Tailwind, styled-components. BEM nadal popularny w dużych projektach bez CSS-in-JS.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest semantyczny HTML i dlaczego ma znaczenie?', 'Semantyczny HTML to użycie elementów zgodnie z ich znaczeniem: <header>, <nav>, <main>, <article>, <section>, <aside>, <footer> zamiast <div>. Znaczenie: 1) Dostępność — screen readers identyfikują strukturę, 2) SEO — wyszukiwarki rozumieją treść, 3) Czytelność kodu. <article> = niezależna treść, <section> = tematyczna grupa, <aside> = treść poboczna.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie role ARIA są najważniejsze i kiedy ich używasz?', 'ARIA uzupełnia semantykę gdy HTML nie wystarczy. Kluczowe role: role="button" (div jako przycisk), role="dialog" (modal), role="alert" (komunikat), role="navigation" (nawigacja). Stany: aria-expanded, aria-selected, aria-hidden, aria-live. Zasada: preferuj natywny HTML (<button> nie potrzebuje role="button"). ARIA to last resort — nadmiar ARIA jest gorszy niż brak.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zapewnisz dostępność (accessibility) formularza?', 'Checklist: <label for="id"> powiązany z każdym input, aria-describedby dla opisów/błędów, aria-invalid="true" + aria-errormessage dla walidacji, fieldset + legend dla grup, jasny focus order (tabindex), widoczny focus ring, komunikaty błędów z role="alert" (aria-live). Nie usuwaj focus outline — zamiast tego stylizuj :focus-visible. Testuj z klawiatury i screen readerem.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest podejście mobile-first i dlaczego jest preferowane?', 'Mobile-first: bazowe style dla mobile, media queries dodają style dla większych ekranów (min-width). Desktop-first: bazowe dla desktopu, nadpisujesz w dół (max-width). Mobile-first korzyści: progresywne wzbogacanie (mobile = podstawa), mniejszy CSS (mobile dostaje mniej reguł), wymusza prostotę. min-width jest addytywne (dodajesz), max-width jest subtractywne (usuwasz).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa clamp(), min() i max() w CSS?', 'clamp(min, preferred, max): wartość rośnie/maleje z preferred ale nie wychodzi poza min/max. Idealne do fluid typography: font-size: clamp(1rem, 2.5vw, 2rem). min(): wybiera mniejszą wartość, max(): większą. width: min(90%, 1200px) = responsywny max-width bez media query. Te funkcje eliminują wiele media queries i tworzą płynne, responsywne layouty.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się transition od animation w CSS?', 'Transition: reaguje na zmianę stanu (hover, class toggle). Definiuje przejście od A do B. Wymaga triggera. animation: odgrywa się samodzielnie, definiuje @keyframes z wieloma krokami. Nie wymaga triggera (animation-play-state). Transition: proste efekty hover, opacity, transform. Animation: nieskończone pętle, złożone sekwencje, loading spinnery, pojawianie się elementów.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak tworzyć wydajne animacje CSS? Które właściwości animować?', 'Wydajne (GPU-accelerated, nie triggerują layout/paint): transform (translate, scale, rotate) i opacity. Powolne (triggerują layout): width, height, top, left, margin, padding. Powolne (triggerują paint): color, background, box-shadow. will-change: transform informuje przeglądarkę o planowanej animacji (oszczędnie!). Zasada: animuj TYLKO transform i opacity — reszta przez triki (scale zamiast width).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są pseudo-elementy ::before i ::after? Podaj praktyczne zastosowania.', 'Pseudo-elementy tworzą wirtualne elementy w DOM (nie istnieją w HTML). Wymagają content: "". Zastosowania: dekoracyjne elementy (linie, ikony), clearfix (legacy), CSS-only tooltips, overlay na obrazkach, numeracja custom list, dekoracyjne cudzysłowy. Ważne: nie mają semantyki (screen reader ich nie czyta), nie działają na void elements (<input>, <img>).', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to są CSS logical properties i dlaczego warto ich używać?', 'Logical properties używają kierunków inline/block zamiast left/right/top/bottom. margin-inline-start zamiast margin-left, padding-block zamiast padding-top + padding-bottom. Korzyść: automatyczne odwrócenie w RTL (arabski, hebrajski) — bez duplikowania styli. Inline = kierunek tekstu, block = prostopadły. Przyszłość CSS — adopcja rośnie, wspierane we wszystkich przeglądarkach.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa Flexbox — wyjaśnij główną i poprzeczną oś.', 'Flexbox ma main axis (kierunek flex-direction) i cross axis (prostopadła). Row: main = pozioma, cross = pionowa. Column: odwrotnie. justify-content wyrównuje po main axis. align-items po cross axis. flex-grow/shrink/basis kontrolują rozmiar na main axis. gap dodaje odstępy. Gotcha: align-items: stretch (domyślna) rozciąga dzieci na cross axis — może zaskakiwać.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest flex-grow, flex-shrink i flex-basis? Jak działa shorthand flex?', 'flex-basis: początkowy rozmiar (przed grow/shrink). flex-grow: proporcja dodatkowej przestrzeni do przydzielenia. flex-shrink: proporcja kurczenia gdy brak miejsca. flex: 1 = flex: 1 1 0% (rośnie, kurczy się, bazuje na 0). flex: auto = flex: 1 1 auto (bazuje na content). flex: none = flex: 0 0 auto (sztywny). Gotcha: flex-basis: 0 vs auto daje różne rozkłady przestrzeni.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak wycentrować element pionowo i poziomo w CSS? Podaj 3 sposoby.', '1) Flexbox: display: flex; justify-content: center; align-items: center; (najczęstszy). 2) Grid: display: grid; place-items: center; (najkrótszy). 3) Position: position: absolute; inset: 0; margin: auto; (element z width/height). Bonus: translate: transform: translate(-50%, -50%) + top/left 50% (legacy). Flexbox/Grid to dzisiejszy standard — proste, czytelne, responsywne.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest CSS Grid i jak definiujesz grid template?', 'Grid: display: grid na kontenerze. grid-template-columns: repeat(3, 1fr) — 3 równe kolumny. grid-template-rows: auto 1fr auto. Jednostka fr: ułamek wolnej przestrzeni. grid-gap/gap: odstępy. Placement: grid-column: 1 / 3 (span 2 kolumny). Named lines i areas: grid-template-areas: "header header" "sidebar main". Subgrid: dziecko dziedziczy grid rodzica.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest subgrid i jaki problem rozwiązuje?', 'Subgrid pozwala dziecku grid kontenera odziedziczyć linie (tracks) rodzica. Problem: bez subgrid wewnętrzny grid jest niezależny — nagłówki kart w rzędzie mogą mieć różne wysokości. Z subgrid: dziecko grid-template-rows: subgrid wyrównuje swoje rzędy do rodzica. Rozwiązuje alignment w kartach, formularzach, tabelkach. Wspierany we wszystkich nowoczesnych przeglądarkach.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest margin collapse i kiedy występuje?', 'Margin collapse: pionowe marginesy sąsiadujących elementów blokowych łączą się — wygrywamy większy, nie suma. Występuje: sąsiednie rodzeństwo, rodzic z pierwszym/ostatnim dzieckiem (jeśli brak padding/border), pusty element. NIE występuje: elementy flex/grid, floated, inline-block, z overflow nie-visible. Najczęstsza pułapka: margin dziecka „wychodzi" z rodzica — dodaj padding/border/overflow na rodzicu.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zrealizujesz responsywny design bez media queries?', 'Techniki: 1) clamp() dla font-size/padding, 2) Flex wrap: flex-wrap: wrap + flex: 1 1 300px (karty), 3) Grid: repeat(auto-fit, minmax(250px, 1fr)), 4) min()/max(): width: min(100%, 800px), 5) Aspect-ratio: aspect-ratio: 16/9. Te podejścia tworzą „intrinsic design" — elementy adaptują się do dostępnej przestrzeni bez breakpointów. Media queries dla większych zmian layoutu.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest :focus-visible i czym różni się od :focus?', ':focus aktywuje się przy każdym focusie (klik myszy też). :focus-visible aktywuje się tylko gdy focus jest „widoczny" — klawiatura, ale nie klik myszy. Rozwiązuje problem: outline przy kliknięciu przyciskiem myszy irytuje użytkowników, ale jest kluczowy dla dostępności klawiatury. Best practice: button:focus-visible { outline: 2px solid blue; } zamiast button:focus.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa kaskada CSS? Jakie są źródła styli i ich priorytety?', 'Kolejność (od najważniejszej): 1) !important user agent, 2) !important user, 3) !important author @layer, 4) !important author, 5) inline style, 6) author @layer (od ostatniego), 7) author (bez layer), 8) user, 9) user agent. Wewnątrz tego samego źródła: specyficzność, potem kolejność w kodzie. @layer odwraca kolejność !important (wewnętrzna warstwa > zewnętrzna).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest prefers-color-scheme i jak go używasz?', '@media (prefers-color-scheme: dark) {...} wykrywa preferencje systemowe użytkownika. Best practice: definiuj CSS custom properties per schemat: :root {--bg: white;} @media (prefers-color-scheme: dark) {:root {--bg: #1a1a1a;}}. Łącz z data-theme atrybutem dla ręcznego toggle. prefers-reduced-motion analogicznie — wyłącz animacje dla użytkowników z epilepsją/vestibular disorders.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest prefers-reduced-motion i jak go implementujesz?', '@media (prefers-reduced-motion: reduce) eliminuje/upraszcza animacje dla użytkowników, którzy tego życzą (epilepsja, choroba lokomocyjna). Implementacja: @media (prefers-reduced-motion: reduce) { *, *::before, *::after { animation-duration: 0.01ms !important; transition-duration: 0.01ms !important; } }. Alternatywa: definiuj animacje tylko w (prefers-reduced-motion: no-preference).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest aspect-ratio w CSS i jakie ma zastosowania?', 'aspect-ratio: 16/9 utrzymuje proporcje elementu bez padding-top hack. Zastosowania: responsywne video/iframe kontenery, obrazki placeholder (zapobieganie CLS), karty o stałych proporcjach. Działa z: width (height auto-computed), height (width auto-computed), oba (aspect-ratio ignorowany). Zastępuje stary hack: padding-top: 56.25% (16:9) + absolute child.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zapobiegasz CLS (Cumulative Layout Shift) w CSS?', 'CLS to metryka Core Web Vitals mierząca niespodziewane przesunięcia layoutu. Zapobieganie: 1) width/height lub aspect-ratio na obrazkach/video, 2) font-display: optional lub swap + size-adjust, 3) min-height na dynamicznie ładowanych sekcjach, 4) transform zamiast top/left do animacji, 5) content-visibility: auto z contain-intrinsic-size. Biggest offenders: obrazki bez wymiarów, późne ładowanie fontów, wstrzykiwane banery.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest overflow i jak tworzy Block Formatting Context?', 'overflow kontroluje co dzieje się z treścią przekraczającą rozmiar: visible (domyślna — wylewa się), hidden (ukryta), scroll (scrollbar), auto (scrollbar gdy potrzebny). overflow inny niż visible tworzy BFC — blokuje margin collapse, zawiera floated children. Gotcha: overflow: hidden na rodzicu z position: sticky dzieckiem — sticky nie zadziała.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest viewport unit i jakie nowe jednostki istnieją?', 'Klasyczne: vw/vh (1% viewport width/height). Problem: vh na mobile nie uwzględnia paska adresu. Nowe: svh (small viewport — z paskiem), lvh (large viewport — bez paska), dvh (dynamic — zmienia się). svw/lvw/dvw analogicznie. dvh najczęściej pożądany — 100dvh = pełna widoczna wysokość. Jednostki vi/vb (inline/block) dla logical properties.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa CSS Grid auto-placement i kiedy jest przydatne?', 'Grid automatycznie umieszcza elementy w wolnych komórkach: grid-auto-flow: row (domyślna — wypełnia wierszami), column, dense (wypełnia dziury). Dense: elementy wchodzą w wolne miejsca niezależnie od kolejności DOM — przydatne dla galerii/masonry. Auto-placement + repeat(auto-fill/auto-fit, minmax()) = w pełni responsywna siatka bez media queries i bez określania pozycji elementów.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym różni się auto-fill od auto-fit w CSS Grid?', 'Oba automatycznie tworzą kolumny: repeat(auto-fill/auto-fit, minmax(200px, 1fr)). Różnica widoczna gdy elementów jest mniej niż kolumn: auto-fill tworzy puste kolumny (zachowuje tracks). auto-fit collapse''uje puste kolumny (elementy rozciągają się). auto-fit częstszy — elementy wypełniają kontener. auto-fill gdy chcesz zachować stałą siatkę.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa display: contents i kiedy go używasz?', 'display: contents sprawia, że element „znika" z layout — jego dzieci stają się bezpośrednimi dziećmi rodzica layoutowego. Zastosowanie: wrapper div wymagany przez komponent, ale Grid/Flex powinien widzieć grandchildren. Uwaga: element traci box (margin, padding, border) i może tracić semantykę (accessibility issues z elementami jak button). Używaj ostrożnie.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest content-visibility i jak poprawia wydajność?', 'content-visibility: auto mówi przeglądarce, że element poza viewport może pominąć rendering (layout, paint). Przeglądarka renderuje go dopiero gdy zbliży się do viewport. Wymaga contain-intrinsic-size do szacowania rozmiaru (zapobieganie CLS). Idealny dla długich list, artykułów, komentarzy. Może poprawić initial render time o 50%+ dla stron z dużą ilością treści.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest HTML dialog element i jak go używasz?', '<dialog> to natywny element modalny. dialog.showModal() otwiera jako modal z backdrop, dialog.show() jako non-modal. Natywne: focus trapping, Escape zamyka, ::backdrop pseudo-element. Zwraca wartość: <form method="dialog"> zamyka dialog z returnValue. Korzyści: dostępność out of the box, brak potrzeby aria-modal, prawidłowy focus management. Zastępuje 90% potrzeb na custom modale.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest popover API w HTML i czym różni się od dialog?', 'popover attribute to nowe API dla non-modal overlay: tooltips, dropdowns, menus. <button popovertarget="menu"><div id="menu" popover>. Auto dismissal (klik poza), brak focus trappingu (nie jest modal), stacking powyżej content (top layer). Dialog = modal (blokuje interakcję). Popover = non-modal (uzupełnia interakcję). Popover zastępuje custom dropdown/tooltip JS logic.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak obsługujesz niestandardowe fonty i optymalizujesz ich ładowanie?', '@font-face z format() deklaruje font. font-display: swap (FOUT — tekst systemowy → custom), optional (jeśli nie załaduje szybko — pomija). Preload: <link rel="preload" href="font.woff2" as="font" crossorigin>. Subsetting: tylko potrzebne znaki (unicode-range). WOFF2 format (~30% mniejszy). size-adjust, ascent-override zapobiegają CLS. Self-hosting szybszy niż Google Fonts.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest :where() i :is() w CSS? Jak wpływają na specyficzność?', ':is(.a, .b) {color: red} = .a {color: red} .b {color: red}. Specyficzność :is() = najwyższa z listy. :where() działa identycznie, ale ma ZERO specyficzności — idealne do resetów i default styli łatwych do nadpisania. Użycie: :where(article, section, aside) h2 {...} — łatwo nadpiszesz. :is() zachowuje naturalną specyficzność. Oba eliminują duplikację selektorów.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz dark mode w CSS?', 'Podejścia: 1) prefers-color-scheme media query (automatycznie z OS), 2) data-theme atrybut na <html> + CSS custom properties, 3) class toggle (.dark). Best practice: łącz — domyślnie OS preference, toggle nadpisuje. Zdefiniuj kolory jako custom properties: :root {--bg: #fff;} [data-theme=dark] {--bg: #1a1a1a;}. Używaj semantycznych nazw (--bg, --text-primary), nie --white/--black.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest color-scheme i jak się ma do prefers-color-scheme?', 'color-scheme: light dark informuje przeglądarkę, że strona obsługuje oba schematy. Przeglądarka automatycznie dostosowuje: scrollbary, formularze, <select>, ::selection. Meta tag: <meta name="color-scheme" content="light dark">. prefers-color-scheme to media query do custom styli, color-scheme to deklaracja wsparcia dla UA styli. Oba powinny być używane razem.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak działa CSS nesting (zagnieżdżanie)?', 'Natywne CSS nesting: .card { & .title { color: blue; } &:hover { background: gray; } @media (width > 768px) { padding: 2rem; } }. & reprezentuje rodzica. Bez &: selektor potomka. Korzyści: grupowanie powiązanych reguł, czytelność, brak potrzeby preprocesora. Różnica od Sass: & wymagane na początku selektora (w starszych wersjach spec). Wspierane we wszystkich nowoczesnych przeglądarkach.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co to jest contain CSS property i jak wpływa na wydajność?', 'contain informuje przeglądarkę, że element jest izolowany: contain: layout (nie wpływa na layout rodzeństwa), size (nie zmienia rozmiaru), paint (nie maluje poza box), style (counters izolowane). contain: strict = size layout paint style. Korzyść: przeglądarka może optymalizować rendering — zmiany wewnątrz nie wymagają przeliczania reszty strony. Używaj z content-visibility.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak zaimplementujesz responsywną nawigację (hamburger menu)?', 'Mobile: ukryty nav, hamburger button (aria-expanded, aria-controls), klik toggleuje visibility. Desktop: widoczny nav, ukryty hamburger. CSS: @media (min-width: 768px) {.nav {display: flex;} .hamburger {display: none;}}. Accessibility: button nie div, aria-expanded="true/false", focus trap w otwartym menu, Escape zamyka. Animacja: transform: translateX() (wydajne) zamiast left/width.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest inset CSS property?', 'inset to shorthand dla top + right + bottom + left. inset: 0 = top: 0; right: 0; bottom: 0; left: 0 (popularny pattern z position: absolute/fixed do fullscreen overlay). inset: 10px 20px = top/bottom: 10px, left/right: 20px. Logical equivalents: inset-block (top/bottom), inset-inline (left/right). Drastycznie skraca pozycjonowanie elementów. Wspierane we wszystkich przeglądarkach.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak optymalizujesz obrazki na stronie webowej?', 'Format: WebP/AVIF (mniejsze niż JPEG/PNG). <picture> z <source> per format. Lazy loading: loading="lazy" (natywne). Responsive: srcset + sizes dla różnych viewportów. Wymiary: zawsze podawaj width/height (zapobiega CLS). Decoding: decoding="async". CSS: object-fit: cover/contain dla elastycznego skalowania. CDN z automatyczną optymalizacją (Cloudinary, imgix). fetchpriority="high" dla hero image.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest scroll-snap w CSS i jak go konfigurujesz?', 'scroll-snap tworzy „przyciąganie" scrollu do punktów. Kontener: scroll-snap-type: x mandatory (oś + tryb). Dzieci: scroll-snap-align: start/center/end. mandatory: zawsze przyciąga do punktu, proximity: tylko gdy blisko. Zastosowania: karuzele, galerie, strony full-screen, horizontal scrolling. scroll-padding na kontenerze: offset dla fixed header. Natywna alternatywa dla carousel JS bibliotek.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Break the ice', 'Przełamać lody — rozpocząć rozmowę w niezręcznej sytuacji. Np. ''His joke helped break the ice at the meeting.''', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hit the nail on the head', 'Trafić w sedno — powiedzieć dokładnie to, co trzeba. Np. ''You hit the nail on the head with that analysis.''', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A piece of cake', 'Bułka z masłem — coś bardzo łatwego. Np. ''The exam was a piece of cake.''', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bite the bullet', 'Zacisnąć zęby — zrobić coś nieprzyjemnego, co jest nieuniknione. Np. ''I bit the bullet and went to the dentist.''', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cost an arm and a leg', 'Kosztować majątek — być bardzo drogim. Np. ''That designer bag cost an arm and a leg.''', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Let the cat out of the bag', 'Wygadać się — zdradzić sekret. Np. ''She let the cat out of the bag about the surprise party.''', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Once in a blue moon', 'Raz na ruski rok — bardzo rzadko. Np. ''He only visits once in a blue moon.''', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Burn the midnight oil', 'Siedzieć nad czymś do późna — pracować do późnych godzin nocnych. Np. ''She burned the midnight oil to finish the report.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The ball is in your court', 'Twój ruch — teraz od ciebie zależy decyzja. Np. ''I''ve made my offer — the ball is in your court.''', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spill the beans', 'Wygadać się — ujawnić tajemnicę. Np. ''Come on, spill the beans! What happened?''', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kill two birds with one stone', 'Upiec dwie pieczenie na jednym ogniu — osiągnąć dwa cele jednym działaniem. Np. ''By cycling to work, I kill two birds with one stone — I save money and exercise.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Under the weather', 'Kiepsko się czuć — być chorym lub nie w formie. Np. ''I''m feeling a bit under the weather today.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sit on the fence', 'Być niezdecydowanym — nie zajmować stanowiska. Np. ''Stop sitting on the fence and make a decision.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Beat around the bush', 'Owijać w bawełnę — nie mówić wprost. Np. ''Stop beating around the bush and tell me the truth.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Get cold feet', 'Dostać zimnych nóg — stchórzyć w ostatniej chwili. Np. ''He got cold feet before the wedding.''', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A blessing in disguise', 'Szczęście w nieszczęściu — coś pozornie złego, co okazuje się dobre. Np. ''Losing that job was a blessing in disguise.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Barking up the wrong tree', 'Mylić się co do przyczyny — szukać w złym miejscu. Np. ''If you think I did it, you''re barking up the wrong tree.''', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Actions speak louder than words', 'Czyny mówią głośniej niż słowa — to co robisz jest ważniejsze od tego, co mówisz. Np. ''Don''t just promise — actions speak louder than words.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Add insult to injury', 'Dosypać soli do rany — pogorszyć i tak złą sytuację. Np. ''To add insult to injury, it started raining when my car broke down.''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cut to the chase', 'Przejść do rzeczy — pominąć zbędne wstępy. Np. ''Let''s cut to the chase — how much will it cost?''', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Every cloud has a silver lining', 'Nie ma tego złego, co by na dobre nie wyszło. Np. ''I know you''re upset, but every cloud has a silver lining.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Go the extra mile', 'Dać z siebie więcej niż wymagane — wykazać się ponadprzeciętnym zaangażowaniem. Np. ''She always goes the extra mile for her clients.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('It takes two to tango', 'Do tanga trzeba dwojga — obie strony są odpowiedzialne. Np. ''Don''t blame just him — it takes two to tango.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Miss the boat', 'Przegapić okazję — spóźnić się z czymś. Np. ''If you don''t apply today, you''ll miss the boat.''', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('On thin ice', 'Stąpać po cienkim lodzie — być w ryzykownej sytuacji. Np. ''After arriving late again, he''s on thin ice with the boss.''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pull someone''s leg', 'Nabierać kogoś — żartować z kogoś. Np. ''Are you serious or just pulling my leg?''', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The best of both worlds', 'Połączyć przyjemne z pożytecznym — mieć zalety dwóch opcji naraz. Np. ''Working from home gives me the best of both worlds.''', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('When pigs fly', 'Jak rak świśnie — nigdy. Np. ''He''ll clean his room when pigs fly.''', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Steal someone''s thunder', 'Ukraść komuś show — przypisać sobie czyjś sukces. Np. ''She stole my thunder by announcing my idea first.''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The last straw', 'Ostatnia kropla przepełniająca czarę — ostateczny powód wybuchu. Np. ''His rudeness was the last straw — I quit.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Throw in the towel', 'Rzucić ręcznik — poddać się. Np. ''After months of trying, she threw in the towel.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A penny for your thoughts', 'O czym myślisz? — pytanie o czyjeś przemyślenia. Np. ''You look worried — a penny for your thoughts?''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Better late than never', 'Lepiej późno niż wcale. Np. ''You finally started exercising — better late than never!''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Call it a day', 'Zakończyć pracę na dziś — skończyć na dany dzień. Np. ''We''ve done enough — let''s call it a day.''', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Don''t cry over spilt milk', 'Nie płacz nad rozlanym mlekiem — nie rozpaczaj nad tym, czego nie da się cofnąć. Np. ''The vase is broken — don''t cry over spilt milk.''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Easier said than done', 'Łatwiej powiedzieć niż zrobić. Np. ''Quitting smoking is easier said than done.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Get out of hand', 'Wymknąć się spod kontroli. Np. ''The party got out of hand when more people arrived.''', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hang in there', 'Trzymaj się — nie poddawaj się. Np. ''I know it''s tough, but hang in there.''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('In the same boat', 'W tej samej sytuacji — dzielić ten sam problem. Np. ''We''re all in the same boat with these budget cuts.''', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jump on the bandwagon', 'Przyłączyć się do popularnego trendu. Np. ''Everyone jumped on the bandwagon when the stock started rising.''', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Keep your chin up', 'Głowa do góry — nie trać ducha. Np. ''Keep your chin up — things will get better.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leave no stone unturned', 'Nie zostawić kamienia na kamieniu — sprawdzić wszystkie możliwości. Np. ''The police left no stone unturned in their search.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Make a long story short', 'Krótko mówiąc — streścić długą historię. Np. ''To make a long story short, we missed the flight.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('No pain, no gain', 'Bez pracy nie ma kołaczy — trzeba się postarać, żeby coś osiągnąć. Np. ''Keep training — no pain, no gain.''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Off the top of my head', 'Z głowy — bez przygotowania, spontanicznie. Np. ''Off the top of my head, I''d say there were about 50 people.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Put all your eggs in one basket', 'Stawiać wszystko na jedną kartę. Np. ''Don''t put all your eggs in one basket — diversify your investments.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Read between the lines', 'Czytać między wierszami — rozumieć ukryty sens. Np. ''If you read between the lines, she''s not happy with the plan.''', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('See eye to eye', 'Zgadzać się — mieć to samo zdanie. Np. ''We don''t always see eye to eye, but we respect each other.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Take it with a grain of salt', 'Brać z przymrużeniem oka — nie traktować dosłownie. Np. ''He exaggerates — take what he says with a grain of salt.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Under someone''s nose', 'Pod czyimś nosem — tuż obok, niepostrzeżenie. Np. ''The answer was right under my nose the whole time.''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wrap your head around something', 'Ogarnąć coś — zrozumieć coś skomplikowanego. Np. ''I can''t wrap my head around quantum physics.''', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('You can''t judge a book by its cover', 'Nie oceniaj książki po okładce — pozory mylą. Np. ''He looks tough, but he''s kind — you can''t judge a book by its cover.''', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bite off more than you can chew', 'Porwać się z motyką na słońce — podjąć się zbyt dużego zadania. Np. ''I think she bit off more than she can chew with this project.''', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cross that bridge when you come to it', 'Nie wyprzedzać faktów — zająć się problemem, gdy się pojawi. Np. ''Don''t worry now — we''ll cross that bridge when we come to it.''', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Don''t put the cart before the horse', 'Nie stawiaj wozu przed koniem — nie rób rzeczy w złej kolejności. Np. ''Let''s plan first — don''t put the cart before the horse.''', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Give someone the benefit of the doubt', 'Dać komuś kredyt zaufania. Np. ''I''ll give him the benefit of the doubt and assume it was an accident.''', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hit the road', 'Ruszać w drogę — wyruszać. Np. ''It''s getting late — let''s hit the road.''', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('On the same page', 'Być zgodnym — mieć wspólne rozumienie sytuacji. Np. ''Let''s make sure we''re on the same page before the meeting.''', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The tip of the iceberg', 'Wierzchołek góry lodowej — mała widoczna część dużego problemu. Np. ''The complaints we''ve received are just the tip of the iceberg.''', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Up in the air', 'Sprawa nierozstrzygnięta — jeszcze niezadecydowane. Np. ''Our vacation plans are still up in the air.''', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('agenda', 'Porządek obrad — lista tematów do omówienia na spotkaniu. Np. ''Let''s go through the agenda.''', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to schedule a meeting', 'Zaplanować spotkanie. Np. ''Can we schedule a meeting for next Tuesday?''', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('deadline', 'Termin ostateczny — nieprzekraczalna data wykonania zadania. Np. ''The deadline for the report is Friday.''', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to negotiate', 'Negocjować — prowadzić rozmowy w celu osiągnięcia porozumienia. Np. ''We need to negotiate better terms.''', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('revenue', 'Przychód — łączna kwota pieniędzy zarobionych przez firmę. Np. ''Revenue increased by 15% this quarter.''', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('profit margin', 'Marża zysku — procent przychodu, który zostaje jako zysk. Np. ''Our profit margin has improved significantly.''', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('stakeholder', 'Interesariusz — osoba lub grupa mająca wpływ na projekt lub zainteresowana jego wynikiem. Np. ''We need to inform all stakeholders.''', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to delegate tasks', 'Delegować zadania — przydzielać obowiązki innym. Np. ''A good manager knows how to delegate tasks effectively.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('KPI (Key Performance Indicator)', 'Kluczowy wskaźnik efektywności — miara oceny sukcesu. Np. ''Our main KPI is customer satisfaction rate.''', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to brainstorm', 'Burza mózgów — wspólne generowanie pomysłów. Np. ''Let''s brainstorm ideas for the new campaign.''', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('bottom line', 'Wynik końcowy / sedno sprawy — najważniejszy rezultat finansowy. Np. ''The bottom line is we need to cut costs.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to follow up', 'Kontynuować / dopytać — wrócić do sprawy. Np. ''I''ll follow up with you next week on this matter.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('quarterly report', 'Raport kwartalny — sprawozdanie z wyników za kwartał. Np. ''The quarterly report shows strong growth.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to outsource', 'Zlecać na zewnątrz — przekazywać zadania firmie zewnętrznej. Np. ''We decided to outsource our IT support.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ROI (Return on Investment)', 'Zwrot z inwestycji — miara opłacalności inwestycji. Np. ''What''s the expected ROI on this project?''', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to pitch an idea', 'Przedstawić pomysł — zaprezentować koncepcję w celu jej sprzedania. Np. ''She pitched the idea to the board of directors.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('target audience', 'Grupa docelowa — odbiorcy, do których kierowany jest produkt lub komunikat. Np. ''Our target audience is millennials.''', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to close a deal', 'Sfinalizować transakcję — doprowadzić negocjacje do końca. Np. ''We managed to close the deal yesterday.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('cash flow', 'Przepływ pieniężny — ruch środków finansowych w firmie. Np. ''We need to improve our cash flow.''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to scale up', 'Skalować — zwiększać rozmiar operacji lub działalności. Np. ''We plan to scale up production next year.''', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('benchmark', 'Punkt odniesienia — standard, z którym porównuje się wyniki. Np. ''We use industry benchmarks to evaluate our performance.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to streamline', 'Usprawnić — uprościć proces, aby był bardziej efektywny. Np. ''We need to streamline our approval process.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('leverage', 'Dźwignia / wykorzystać — użyć czegoś w celu uzyskania przewagi. Np. ''We can leverage our brand to enter new markets.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to onboard', 'Wdrożyć — wprowadzić nowego pracownika lub klienta. Np. ''We onboarded three new employees this month.''', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('synergy', 'Synergia — współdziałanie dające lepszy efekt niż suma części. Np. ''The merger created strong synergies between teams.''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Please find attached', 'W załączeniu przesyłam — formalna fraza w e-mailach. Np. ''Please find attached the report for Q3.''', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('As per our conversation', 'Zgodnie z naszą rozmową — nawiązanie do wcześniejszych ustaleń. Np. ''As per our conversation, I''m sending the updated proposal.''', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('I look forward to hearing from you', 'Z niecierpliwością czekam na odpowiedź — formalne zakończenie e-maila. Np. ''I look forward to hearing from you at your earliest convenience.''', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to touch base', 'Skontaktować się krótko — sprawdzić aktualny stan sprawy. Np. ''Let''s touch base on Friday to review progress.''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to get the ball rolling', 'Ruszyć z miejsca — rozpocząć działanie. Np. ''Let''s get the ball rolling on this project.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('competitive advantage', 'Przewaga konkurencyjna — cecha wyróżniająca firmę na tle konkurencji. Np. ''Our technology gives us a competitive advantage.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to break even', 'Wyjść na zero — osiągnąć punkt, w którym przychody równają się kosztom. Np. ''We expect to break even by the end of the year.''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to downsize', 'Redukować zatrudnienie — zmniejszać liczbę pracowników. Np. ''The company had to downsize due to the recession.''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('supply chain', 'Łańcuch dostaw — system produkcji i dystrybucji produktu. Np. ''The pandemic disrupted global supply chains.''', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('overhead costs', 'Koszty stałe / ogólne — wydatki niezwiązane bezpośrednio z produkcją (czynsz, media). Np. ''We need to reduce our overhead costs.''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to implement', 'Wdrożyć — wprowadzić w życie plan lub system. Np. ''We''re implementing a new CRM system.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('due diligence', 'Należyta staranność — dogłębna analiza przed decyzją biznesową. Np. ''We conducted due diligence before the acquisition.''', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to diversify', 'Dywersyfikować — różnicować, poszerzać zakres działalności. Np. ''We need to diversify our product portfolio.''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('merger', 'Fuzja — połączenie dwóch firm w jedną. Np. ''The merger created the largest company in the sector.''', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('acquisition', 'Przejęcie — zakup jednej firmy przez drugą. Np. ''The acquisition was worth $2 billion.''', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to allocate resources', 'Przydzielić zasoby — rozdzielić budżet, czas lub ludzi do zadań. Np. ''We need to allocate more resources to R&D.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('turnaround', 'Zwrot / naprawa — proces odwracania negatywnych tendencji w firmie. Np. ''The new CEO led an impressive turnaround.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to liaise with', 'Utrzymywać kontakt / współpracować — pełnić rolę łącznika. Np. ''I liaise with the marketing team on campaign strategy.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ballpark figure', 'Przybliżona kwota — szacunkowa liczba. Np. ''Can you give me a ballpark figure for the project cost?''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('action items', 'Punkty do realizacji — zadania do wykonania po spotkaniu. Np. ''Let me summarize the action items from today''s meeting.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to circle back', 'Wrócić do tematu — ponownie omówić sprawę. Np. ''Let''s circle back on this topic next week.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('pain point', 'Problem / bolączka — trudność, z którą boryka się klient. Np. ''We identified the main pain points of our users.''', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to sign off on', 'Zatwierdzić — dać formalną zgodę. Np. ''The manager needs to sign off on the budget.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('win-win situation', 'Sytuacja korzystna dla obu stron. Np. ''This partnership is a win-win situation for both companies.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to phase out', 'Wycofywać stopniowo — eliminować etapami. Np. ''We''re phasing out the old software over the next six months.''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('feasibility study', 'Studium wykonalności — analiza, czy projekt jest możliwy do realizacji. Np. ''We need a feasibility study before committing funds.''', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to mitigate risks', 'Łagodzić ryzyko — zmniejszać prawdopodobieństwo lub skutki zagrożeń. Np. ''We have a plan to mitigate the main risks.''', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to meet a target', 'Osiągnąć cel — zrealizować założony plan. Np. ''The sales team met their quarterly target.''', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to go live', 'Uruchomić — wdrożyć system do użytku. Np. ''The new website will go live on Monday.''', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('scope creep', 'Pełzanie zakresu — niekontrolowane rozszerzanie się projektu. Np. ''We must avoid scope creep to stay on budget.''', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to ramp up', 'Zwiększać intensywność — przyspieszać. Np. ''We''re ramping up production to meet demand.''', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('pro rata', 'Proporcjonalnie — w stosunku do udziału lub czasu. Np. ''Your bonus will be calculated pro rata.''', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to table a discussion', 'Odłożyć dyskusję na później (AmE) / Przedstawić do dyskusji (BrE). Np. ''Let''s table this and revisit it next meeting.''', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('workflow', 'Przepływ pracy — sekwencja kroków w procesie. Np. ''We redesigned our workflow to improve efficiency.''', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to wrap up', 'Podsumować / zakończyć — zamknąć spotkanie lub temat. Np. ''Let''s wrap up — any final questions?''', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Present Simple — kiedy używamy?', 'Czynności rutynowe, fakty, prawdy ogólne, rozkłady jazdy. Np. ''I work every day.'' ''Water boils at 100°C.'' Przysłówki: always, usually, often, sometimes, never.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Continuous — kiedy używamy?', 'Czynności odbywające się w momencie mówienia, tymczasowe, zaplanowane w bliskiej przyszłości. Np. ''I''m working now.'' ''She''s leaving tomorrow.'' Budowa: am/is/are + V-ing.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Past Simple — kiedy używamy?', 'Czynności zakończone w przeszłości w określonym czasie. Np. ''I visited Paris last year.'' Określniki: yesterday, last week, in 2020, ago.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Past Continuous — kiedy używamy?', 'Czynności trwające w określonym momencie w przeszłości lub przerwane przez inną czynność. Np. ''I was reading when the phone rang.'' Budowa: was/were + V-ing.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Perfect — kiedy używamy?', 'Czynności z przeszłości mające związek z teraźniejszością, doświadczenia życiowe, czynności niezakończone. Np. ''I have visited Paris three times.'' ''She has lived here since 2010.''', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Perfect Continuous — kiedy?', 'Czynności rozpoczęte w przeszłości i trwające do teraz, podkreślenie czasu trwania. Np. ''I have been waiting for two hours.'' Budowa: have/has been + V-ing.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Past Perfect — kiedy używamy?', 'Czynność zakończona przed inną czynnością w przeszłości. Np. ''I had already eaten when she arrived.'' Budowa: had + past participle (V3).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Future Simple (will) vs Going to', '''Will'' — spontaniczne decyzje, przewidywania, obietnice. ''Going to'' — plany, zamiary, wyraźne oznaki. Np. ''I''ll help you.'' vs ''I''m going to study medicine.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używamy ''a'' a kiedy ''an''?', '''a'' przed spółgłoską (dźwięk): a car, a university (ju-). ''an'' przed samogłoską (dźwięk): an apple, an hour (ałer). Decyduje dźwięk, nie litera.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używamy ''the''?', 'Gdy mówimy o czymś konkretnym, znanym rozmówcom, jedynym w swoim rodzaju. Np. ''the sun'', ''the book I told you about''. Nie używamy z nazwami krajów (wyjątki: the UK, the USA), językami, posiłkami.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Countable vs Uncountable nouns', 'Policzalne: a chair, two books — mają liczbę mnogą. Niepoliczalne: water, information, advice, furniture — nie mają l.mn., nie używamy ''a/an''. Używamy: much/little (niepoliczalne), many/few (policzalne).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Some vs Any', '''Some'' — zdania twierdzące i uprzejme prośby: ''I have some money.'' ''Would you like some tea?'' ''Any'' — pytania i przeczenia: ''Do you have any questions?'' ''I don''t have any time.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Much / Many / A lot of', '''Much'' + niepoliczalne (pytania, przeczenia): ''How much water?'' ''Many'' + policzalne: ''How many books?'' ''A lot of'' — uniwersalne, zdania twierdzące: ''I have a lot of friends.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strona bierna (Passive Voice) — budowa', 'Podmiot + be (w odpowiednim czasie) + past participle (V3). Np. Active: ''They build houses.'' Passive: ''Houses are built.'' Past: ''The letter was sent yesterday.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reported Speech — zasady', 'Cofamy czas o jeden stopień: Present → Past, Past → Past Perfect, will → would. Np. ''I am happy'' → He said he was happy. ''I will come'' → She said she would come.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('First Conditional', 'Realna sytuacja w przyszłości. Budowa: If + Present Simple, will + bezokolicznik. Np. ''If it rains, I will stay at home.'' Nie używamy ''will'' po ''if''.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Second Conditional', 'Nierealna/hipotetyczna sytuacja teraźniejsza. Budowa: If + Past Simple, would + bezokolicznik. Np. ''If I had more money, I would travel the world.'' ''If I were you, I would accept.''', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Third Conditional', 'Nierealna sytuacja w przeszłości (żal, wyobrażenie). Budowa: If + Past Perfect, would have + V3. Np. ''If I had studied harder, I would have passed the exam.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Relative clauses — who, which, that', '''who'' — ludzie: ''The man who called you.'' ''which'' — rzeczy: ''The book which I read.'' ''that'' — ludzie i rzeczy (nieformalnie). W defining clauses ''that'' może zastąpić ''who/which''.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gerund vs Infinitive', 'Gerund (-ing) po: enjoy, avoid, finish, mind, suggest. Infinitive (to) po: want, decide, hope, promise, agree. Niektóre zmieniają znaczenie: ''stop smoking'' vs ''stop to smoke''.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Since vs For (czas trwania)', '''Since'' + punkt w czasie: since 2010, since Monday. ''For'' + okres: for 3 years, for 2 hours. Używane z Present Perfect: ''I have lived here since 2010 / for 14 years.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Used to / Would — przeszłe nawyki', '''Used to'' — dawne nawyki i stany: ''I used to play football.'' ''Would'' — tylko powtarzające się czynności (nie stany): ''We would visit grandma every Sunday.'' Nie: ''I would be shy.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Modal verbs — must vs have to', '''Must'' — wewnętrzna konieczność, przekonanie: ''I must study harder.'' ''Have to'' — zewnętrzny przymus: ''I have to wear a uniform.'' Przeczenie: ''mustn''t'' = zakaz, ''don''t have to'' = brak konieczności.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Should / Ought to', 'Rada, zalecenie, oczekiwanie. Np. ''You should see a doctor.'' ''He ought to apologize.'' ''Ought to'' jest bardziej formalny. Przeczenie: ''shouldn''t'', ''ought not to''.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('May vs Might', 'Oba wyrażają możliwość. ''May'' — większe prawdopodobieństwo: ''It may rain today.'' (50/50). ''Might'' — mniejsze prawdopodobieństwo: ''I might come to the party.'' ''May'' też = pozwolenie formalne: ''May I come in?''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Comparative and Superlative adjectives', 'Krótkie (1 syl.): tall → taller → the tallest. Długie (2+ syl.): interesting → more interesting → the most interesting. Nieregularne: good → better → the best, bad → worse → the worst.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prepositions of time: in, on, at', '''At'' — godziny, momenty: at 5 PM, at night, at Christmas. ''On'' — dni, daty: on Monday, on 1st May. ''In'' — miesiące, lata, pory dnia: in June, in 2024, in the morning.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prepositions of place: in, on, at', '''In'' — wewnątrz: in the room, in London. ''On'' — na powierzchni: on the table, on the wall. ''At'' — punkt: at the bus stop, at home, at school.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Question tags', 'Zdanie twierdzące → przeczący tag i odwrotnie. Np. ''You are Polish, aren''t you?'' ''She doesn''t like coffee, does she?'' ''They went home, didn''t they?''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('So vs Such', '''So'' + przymiotnik/przysłówek: ''It''s so cold.'' ''Such'' + (a/an) + przymiotnik + rzeczownik: ''It''s such a beautiful day.'' ''She has such nice friends.'' (l.mn. bez ''a'').', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Too vs Enough', '''Too'' + przymiotnik (za bardzo): ''It''s too expensive.'' Przymiotnik + ''enough'' (wystarczająco): ''She''s old enough to drive.'' ''Enough'' + rzeczownik: ''I don''t have enough time.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Still / Yet / Already', '''Still'' — ciągle (zdania twierdzące, pytania): ''I''m still waiting.'' ''Yet'' — jeszcze nie (przeczenia, pytania): ''I haven''t finished yet.'' ''Already'' — już (twierdzenia): ''I''ve already eaten.''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Although / Despite / In spite of', '''Although'' + zdanie: ''Although it was cold, we went out.'' ''Despite / In spite of'' + rzeczownik/-ing: ''Despite the rain, we went out.'' ''In spite of being tired, she worked.''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Make vs Do', '''Make'' — tworzenie, wywoływanie: make a decision, make a mistake, make money, make progress. ''Do'' — czynności ogólne, obowiązki: do homework, do the dishes, do business, do a favour.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Say vs Tell', '''Say'' — mówić (coś): ''He said he was tired.'' Nie wymaga dopełnienia osobowego. ''Tell'' — powiedzieć (komuś): ''He told me he was tired.'' Wymaga dopełnienia: tell someone something.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wish + Past Simple / Past Perfect', '''I wish'' + Past Simple — życzenie dotyczące teraźniejszości: ''I wish I had a car.'' ''I wish'' + Past Perfect — żal z powodu przeszłości: ''I wish I had studied harder.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Have something done (causative)', 'Zlecenie usługi — ktoś robi coś za nas. Budowa: have + object + past participle. Np. ''I had my hair cut.'' ''She''s having her car repaired.'' Nie: ''I cut my hair'' (= sama się obcięła).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Neither...nor / Either...or', '''Either...or'' — jeden lub drugi: ''Either you come or you stay.'' ''Neither...nor'' — ani jeden, ani drugi: ''Neither Tom nor Anna was there.'' Czasownik zgodny z bliższym podmiotem.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Phrasal verbs — co to jest?', 'Czasownik + przyimek/przysłówek zmieniający znaczenie. Np. ''give up'' = poddać się, ''look after'' = opiekować się, ''put off'' = odłożyć na później, ''turn down'' = odrzucić.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Direct vs Indirect questions', 'Direct: ''Where is the station?'' Indirect (grzeczne): ''Could you tell me where the station is?'' W indirect: szyk oznajmujący (nie inwersja), bez ''do/does/did''.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Adverbs of frequency — szyk zdania', 'Przysłówki częstotliwości (always, usually, often, sometimes, rarely, never) stoją PRZED czasownikiem głównym: ''I always wake up early.'' ALE PO ''be'': ''She is always late.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stative verbs — czym się różnią?', 'Czasowniki stanu nie występują w formach ciągłych (-ing): know, believe, want, need, love, hate, own, seem, belong. Nie: ''I am knowing.'' Tak: ''I know.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('As vs Like', '''Like'' + rzeczownik/zaimek (porównanie): ''She looks like her mother.'' ''As'' + zdanie / funkcja: ''As I said earlier...'' ''He works as a teacher.'' (= jest nauczycielem). Nie: ''He works like a teacher.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Both...and / Not only...but also', '''Both...and'' — oba: ''Both Tom and Anna speak French.'' ''Not only...but also'' — nie tylko, ale także: ''She not only sings but also plays guitar.''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Perfect vs Past Simple', 'Past Simple — określony czas: ''I went to London in 2022.'' Present Perfect — brak określonego czasu / związek z teraźniejszością: ''I have been to London.'' ''I''ve just finished.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Unless = If not', '''Unless'' = jeśli nie. Np. ''Unless you hurry, you''ll miss the bus.'' = ''If you don''t hurry, you''ll miss the bus.'' Po ''unless'' nie używamy przeczenia (podwójne przeczenie!).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Each vs Every', '''Each'' — każdy z osobna (mała grupa): ''Each student received a certificate.'' ''Every'' — każdy (ogólnie, duża grupa): ''Every student must pass the exam.'' ''Each'' może stać samodzielnie: ''each of them''.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Will vs Going to — przewidywania', '''Will'' — przewidywanie oparte na opinii: ''I think it will rain.'' ''Going to'' — przewidywanie oparte na dowodach: ''Look at those clouds — it''s going to rain.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zero Conditional', 'Fakty, prawdy ogólne, prawa natury. Budowa: If + Present Simple, Present Simple. Np. ''If you heat water to 100°C, it boils.'' ''If I drink coffee at night, I can''t sleep.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mixed Conditional', 'Łączy II i III conditional. Przeszły warunek → teraźniejszy skutek: ''If I had studied medicine (III), I would be a doctor now (II).'' Teraźniejszy warunek → przeszły skutek: ''If I were braver (II), I would have spoken up (III).''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Ile przypadków jest w języku niemieckim?', 'Cztery: Nominativ (mianownik — kto?), Akkusativ (biernik — kogo/co?), Dativ (celownik — komu?), Genitiv (dopełniacz — czyj?). Np. Der Mann (Nom.) gibt dem Kind (Dat.) den Ball (Akk.).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — odmiana (Nominativ)', 'der (r.m.), die (r.ż.), das (r.n.), die (l.mn.). Np. der Hund, die Katze, das Haus, die Kinder.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — Akkusativ', 'den (r.m.), die (r.ż.), das (r.n.), die (l.mn.). Zmienia się TYLKO rodzaj męski: der → den. Np. Ich sehe den Mann. Ich sehe die Frau. Ich sehe das Kind.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — Dativ', 'dem (r.m.), der (r.ż.), dem (r.n.), den + -n (l.mn.). Np. Ich gebe dem Mann das Buch. Ich helfe der Frau. Mit den Kindern.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — Genitiv', 'des (r.m. + -s/-es), der (r.ż.), des (r.n. + -s/-es), der (l.mn.). Np. das Auto des Mannes, die Tasche der Frau, das Spielzeug des Kindes.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Szyk zdania w zdaniu głównym (Hauptsatz)', 'Czasownik odmieniony ZAWSZE na 2. pozycji. Np. ''Ich gehe heute ins Kino.'' ''Heute gehe ich ins Kino.'' (podmiot przesuwa się za czasownik — inwersja).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Szyk zdania w zdaniu pobocznym (Nebensatz)', 'Czasownik odmieniony na KOŃCU zdania. Spójniki: weil, dass, wenn, obwohl, als, ob. Np. ''Ich weiß, dass er morgen kommt.'' ''Weil ich müde bin, gehe ich schlafen.''', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki modalne — lista', 'können (móc/umieć), müssen (musieć), dürfen (mieć pozwolenie), sollen (powinien — polecenie), wollen (chcieć), mögen/möchten (lubić/chciałbym). Czasownik główny na końcu: ''Ich kann schwimmen.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Perfekt — budowa', 'haben/sein + Partizip II (na końcu). Np. ''Ich habe gegessen.'' ''Er ist gefahren.'' Sein używamy z czasownikami ruchu (gehen, fahren, kommen) i zmiany stanu (werden, sterben).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Partizip II — jak tworzymy?', 'Regularne: ge- + rdzeń + -t: machen → gemacht, spielen → gespielt. Nieregularne: ge- + rdzeń (zmieniony) + -en: fahren → gefahren, sehen → gesehen. Bez ge-: czasowniki na be-, ver-, er-, ent-: besuchen → besucht.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Präteritum — kiedy używamy?', 'Czas przeszły prosty — głównie w piśmie (literatura, prasa) i z sein/haben. Mówiony niemiecki preferuje Perfekt. Np. ''Ich war müde.'' ''Er hatte keine Zeit.'' ''Sie ging nach Hause.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przyimki z Akkusativ', 'durch (przez), für (dla), gegen (przeciw), ohne (bez), um (wokół/o). Np. ''Ich arbeite für die Firma.'' ''Er geht durch den Park.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przyimki z Dativ', 'aus (z), bei (u/przy), mit (z), nach (po/do), seit (od), von (od/z), zu (do). Np. ''Ich komme aus Polen.'' ''Er wohnt bei seinen Eltern.'' ''Seit einem Jahr.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wechselpräpositionen — przyimki zmienne', 'in, an, auf, über, unter, vor, hinter, neben, zwischen — Akkusativ (ruch/kierunek: wohin?) lub Dativ (miejsce/pozycja: wo?). Np. ''Ich gehe in den Park'' (Akk.) vs ''Ich bin im Park'' (Dat.).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki rozdzielnie złożone (trennbare Verben)', 'Przedrostek odłącza się i idzie na koniec: anfangen → ''Ich fange um 8 Uhr an.'' aufstehen → ''Er steht früh auf.'' W Perfekt: ge- między przedrostkiem a rdzeniem: angefangen, aufgestanden.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odmiana przymiotnika po rodzajniku określonym', 'Nominativ: -e (r.m., r.ż., l.mn.), -e (r.n.). Akkusativ: -en (r.m.), -e (r.ż., r.n.). Dativ: zawsze -en. Np. der große Mann, die große Frau, dem großen Kind.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odmiana przymiotnika po rodzajniku nieokreślonym', 'Nominativ: -er (r.m.), -e (r.ż.), -es (r.n.). Akkusativ: -en (r.m.), -e (r.ż.), -es (r.n.). Np. ein großer Mann, eine große Frau, ein großes Haus.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Konjunktiv II — kiedy i jak?', 'Tryb warunkowy — życzenia, nierealne warunki, grzeczne prośby. Budowa: würde + Infinitiv (większość) lub forma specjalna (hätte, wäre, könnte). Np. ''Ich würde gern reisen.'' ''Wenn ich reich wäre...''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strona bierna (Passiv) — budowa', 'werden + Partizip II. Np. ''Das Haus wird gebaut.'' (dom jest budowany). Perfekt: ''Das Haus ist gebaut worden.'' Passiv z ''von'' (przez kogo): ''Das Buch wird von dem Autor geschrieben.''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki zwrotne (Reflexivpronomen)', 'Akkusativ: mich, dich, sich, uns, euch, sich. Dativ: mir, dir, sich, uns, euch, sich. Np. ''Ich wasche mich.'' (myję się — Akk.) ''Ich wasche mir die Hände.'' (myję sobie ręce — Dat.)', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Negation: nicht vs kein', '''kein'' neguje rzeczowniki z rodzajnikiem nieokreślonym/bez rodzajnika: ''Ich habe kein Auto.'' ''nicht'' neguje czasowniki, przymiotniki, przysłówki: ''Ich komme nicht.'' ''Es ist nicht groß.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zdania względne (Relativsätze)', 'Zaimek względny = rodzajnik określony w odpowiednim przypadku + czasownik na końcu. Np. ''Der Mann, der dort steht, ist mein Lehrer.'' ''Das Buch, das ich lese, ist interessant.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur I — budowa', 'werden + Infinitiv. Np. ''Ich werde morgen kommen.'' Często w praktyce używa się Present + przysłówek czasu: ''Ich komme morgen.'' Futur I używany też do wyrażania przypuszczeń: ''Er wird wohl krank sein.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stopniowanie przymiotników', 'Komparativ: + -er (schnell → schneller). Superlativ: am + -sten (am schnellsten) / der/die/das + -ste. Nieregularne: gut → besser → am besten, viel → mehr → am meisten, gern → lieber → am liebsten.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolejność: TeKaMoLo', 'W zdaniu niemieckim dopełnienia i okoliczniki w kolejności: Temporal (kiedy?) – Kausal (dlaczego?) – Modal (jak?) – Lokal (gdzie?). Np. ''Ich fahre morgen wegen der Arbeit schnell nach Berlin.''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spójniki współrzędne (und, aber, oder, denn, sondern)', 'Nie zmieniają szyku zdania (czasownik na 2. pozycji). Np. ''Ich bin müde, aber ich arbeite weiter.'' ''Er kommt nicht, denn er ist krank.'' ''sondern'' — lecz (po przeczeniu): ''nicht A, sondern B''.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spójniki podrzędne (weil, dass, wenn, obwohl, als, ob)', 'Czasownik odmieniony na końcu zdania pobocznego. Np. ''Ich bleibe zu Hause, weil ich krank bin.'' ''Er fragt, ob du kommst.'' ''als'' = kiedy (jednorazowo w przeszłości), ''wenn'' = kiedy/jeśli (powtarzalnie/przyszłość).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('als vs wenn vs wann', '''als'' — jednorazowe wydarzenie w przeszłości: ''Als ich klein war...'' ''wenn'' — powtarzalne/przyszłe: ''Wenn ich nach Hause komme...'' ''wann'' — pytanie o czas: ''Wann kommst du?''', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki z przyimkiem (Verben mit Präpositionen)', 'Wiele czasowników wymaga określonego przyimka + przypadku. Np. warten auf + Akk. (czekać na), sich freuen auf + Akk. (cieszyć się na), sich freuen über + Akk. (cieszyć się z), denken an + Akk. (myśleć o).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki wymagające Dativ', 'helfen (pomagać), gefallen (podobać się), gehören (należeć do), danken (dziękować), folgen (podążać), antworten (odpowiadać), gratulieren (gratulować). Np. ''Ich helfe dir.'' ''Das Buch gefällt mir.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Podwójny Infinitiv (Doppelter Infinitiv)', 'Z czasownikami modalnymi w Perfekt: ''Ich habe kommen können.'' (Mogłem przyjść) — nie ''gekonnt''. Modalny na końcu, haben jako pomocniczy. Np. ''Er hat nicht arbeiten müssen.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperativ — tryb rozkazujący', 'du: rdzeń (+ -e opcjonalnie): Komm! Geh! Schreib(e)! ihr: rdzeń + -t: Kommt! Geht! Sie (formal): Infinitiv + Sie: Kommen Sie! Gehen Sie! Np. ''Mach die Tür zu!''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki pytające — przypadki', 'Nominativ: wer (kto), was (co). Akkusativ: wen (kogo), was. Dativ: wem (komu). Genitiv: wessen (czyj). Np. ''Wem gehört das Buch?'' ''Wen hast du gesehen?''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('es gibt + Akkusativ', '''Es gibt'' = jest/są (istnieje). Zawsze z Akkusativ. Np. ''Es gibt einen Park in der Nähe.'' ''Gibt es hier ein Restaurant?'' Nie mylić z ''es ist'' (opis stanu): ''Es ist kalt.''', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Partizip I jako przymiotnik', 'Infinitiv + -d = Partizip I. Używany jako przymiotnik (odmienialny). Np. schlafend (śpiący): ''das schlafende Kind'', lächelnd (uśmiechający się): ''die lächelnde Frau''.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Plusquamperfekt — budowa', 'hatte/war + Partizip II. Czynność wcześniejsza od innej w przeszłości. Np. ''Nachdem ich gegessen hatte, ging ich spazieren.'' (Po tym jak zjadłem, poszedłem na spacer).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rzeczowniki złożone (Komposita)', 'Niemiecki łączy rzeczowniki w jedno słowo. Ostatni wyraz określa rodzaj i znaczenie główne. Np. der Kühlschrank (die Kühl- + der Schrank = lodówka), das Schlafzimmer (der Schlaf + das Zimmer = sypialnia).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki nieokreślone: man, jemand, niemand', '''man'' — bezosobowe ''się/ktoś'': ''Man spricht hier Deutsch.'' ''jemand'' — ktoś: ''Jemand hat angerufen.'' ''niemand'' — nikt: ''Niemand weiß das.''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Konjunktiv I — mowa zależna (formal)', 'Rdzeń + końcówki: -e, -est, -e, -en, -et, -en. Używany w prasie/oficjalnie. Np. ''Er sagte, er habe keine Zeit.'' (Powiedział, że nie ma czasu). W mowie potocznej częściej Konjunktiv II lub Indikativ.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Liczba mnoga rzeczowników — wzory', '5 typów: 1) -e: der Tisch → die Tische, 2) -er (+ Umlaut): das Kind → die Kinder, 3) -en/-n: die Frau → die Frauen, 4) - (bez zmian/Umlaut): der Vater → die Väter, 5) -s: das Auto → die Autos.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Infinitiv z ''zu''', 'Po wielu czasownikach/wyrażeniach: versuchen, anfangen, aufhören, es ist wichtig. Np. ''Ich versuche, pünktlich zu kommen.'' Przy trennbare Verben: ''zu'' wpada do środka: ''anzufangen'', ''aufzuhören''.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('um...zu + Infinitiv (cel)', 'Wyrażenie celu — żeby/aby. Np. ''Ich lerne Deutsch, um in Deutschland zu arbeiten.'' (Uczę się niemieckiego, żeby pracować w Niemczech). Podmiot musi być ten sam w obu częściach.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('damit — zdanie celowe (różne podmioty)', 'Kiedy podmioty są różne, używamy ''damit'' + zdanie poboczne: ''Ich erkläre es langsam, damit du es verstehst.'' (Wyjaśniam powoli, żebyś zrozumiał). Czasownik na końcu.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('obwohl vs trotzdem', '''obwohl'' — spójnik podrzędny (czasownik na końcu): ''Obwohl es regnet, gehe ich raus.'' ''trotzdem'' — przysłówek łączący (inwersja po nim): ''Es regnet, trotzdem gehe ich raus.'' Oba = mimo że.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('deshalb / deswegen / darum', 'Wszystkie znaczą ''dlatego'' i powodują inwersję. Np. ''Ich bin müde, deshalb gehe ich ins Bett.'' ''Er hatte Hunger, deswegen hat er etwas gegessen.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki dzierżawcze — odmiana', 'mein, dein, sein, ihr, unser, euer, ihr, Ihr. Odmieniają się jak ''ein'': mein Hund (Nom. m.), meinen Hund (Akk. m.), meinem Hund (Dat. m.), meines Hundes (Gen. m.).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('n-Deklination', 'Niektóre rzeczowniki męskie dodają -n/-en we wszystkich przypadkach oprócz Nominativ. Np. der Junge → den/dem/des Jungen. der Herr → den/dem Herrn / des Herrn. der Student → den/dem/des Studenten.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przyimki z Genitiv', 'wegen (z powodu), während (podczas), trotz (mimo), statt/anstatt (zamiast), innerhalb (wewnątrz), außerhalb (poza). Np. ''wegen des Wetters'', ''während der Pause'', ''trotz des Regens''.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('je...desto / je...umso', 'Im..., tym... Budowa: je + Komparativ..., desto/umso + Komparativ (+ inwersja). Np. ''Je mehr ich lerne, desto besser verstehe ich.'' (Im więcej się uczę, tym lepiej rozumiem).', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('lassen — znaczenia i użycie', '1) Pozwolić: ''Lass mich gehen.'' 2) Kazać/zlecić: ''Ich lasse mein Auto reparieren.'' (= każ naprawić). 3) Zostawić: ''Lass das Buch auf dem Tisch.'' Perfekt: ''Ich habe das Auto reparieren lassen.''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('die Besprechung / die Sitzung', 'Spotkanie / zebranie. Np. ''Die Besprechung findet um 10 Uhr statt.'' (Spotkanie odbywa się o 10).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Termin', 'Termin / umówione spotkanie. Np. ''Ich habe morgen einen Termin beim Arzt.'' Też: deadline — ''der Abgabetermin''.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Bewerbung', 'Aplikacja / podanie o pracę. Np. ''Ich schicke meine Bewerbung per E-Mail.'' sich bewerben = aplikować.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Lebenslauf', 'CV / życiorys. Np. ''Bitte fügen Sie Ihren Lebenslauf bei.'' (Proszę dołączyć CV).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('das Vorstellungsgespräch', 'Rozmowa kwalifikacyjna. Np. ''Ich wurde zum Vorstellungsgespräch eingeladen.'' (Zostałem zaproszony na rozmowę kwalifikacyjną).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Umsatz', 'Obrót / przychód ze sprzedaży. Np. ''Der Umsatz ist um 20% gestiegen.'' (Przychód wzrósł o 20%).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Gewinn', 'Zysk. Np. ''Das Unternehmen hat einen Gewinn von 5 Millionen Euro erzielt.'' der Verlust = strata (przeciwieństwo).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Rechnung', 'Faktura / rachunek. Np. ''Bitte senden Sie mir die Rechnung.'' (Proszę przesłać mi fakturę). eine Rechnung ausstellen = wystawić fakturę.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Abteilung', 'Dział / oddział w firmie. Np. ''Ich arbeite in der Marketingabteilung.'' (Pracuję w dziale marketingu).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Geschäftsführer', 'Dyrektor zarządzający / prezes. Np. ''Der Geschäftsführer leitet das Unternehmen.'' die Geschäftsführerin (ż.).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Verhandlung', 'Negocjacja. Np. ''Die Verhandlungen waren erfolgreich.'' (Negocjacje zakończyły się sukcesem). verhandeln = negocjować.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Vertrag', 'Umowa / kontrakt. Np. ''Wir haben den Vertrag unterschrieben.'' (Podpisaliśmy umowę). einen Vertrag kündigen = wypowiedzieć umowę.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Lieferkette', 'Łańcuch dostaw. Np. ''Die Lieferkette wurde durch die Pandemie unterbrochen.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Buchhaltung', 'Księgowość. Np. ''Die Buchhaltung erstellt den Jahresbericht.'' (Księgowość przygotowuje raport roczny). der Buchhalter = księgowy.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Überweisung', 'Przelew bankowy. Np. ''Die Überweisung wurde gestern ausgeführt.'' (Przelew został wykonany wczoraj). überweisen = przelać pieniądze.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sehr geehrte Damen und Herren', 'Szanowni Państwo — formalne zwroty na początek listu/e-maila, gdy nie znamy adresata. Odpowiednik ''Dear Sir or Madam''.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mit freundlichen Grüßen', 'Z poważaniem — formalne zakończenie listu/e-maila. Skrót: MfG. Odpowiednik ''Yours sincerely / Best regards''.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('im Anhang finden Sie', 'W załączeniu znajdą Państwo — formalna fraza e-mailowa. Np. ''Im Anhang finden Sie die gewünschten Unterlagen.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bezug nehmend auf', 'W nawiązaniu do — formalna fraza korespondencyjna. Np. ''Bezug nehmend auf Ihr Schreiben vom 15. März...''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Frist', 'Termin / deadline. Np. ''Die Frist läuft am Freitag ab.'' (Termin upływa w piątek). eine Frist einhalten = dotrzymać terminu. eine Frist verlängern = przedłużyć termin.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Bestellung', 'Zamówienie. Np. ''Wir haben Ihre Bestellung erhalten.'' (Otrzymaliśmy Państwa zamówienie). bestellen = zamawiać.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Lieferung', 'Dostawa. Np. ''Die Lieferung erfolgt innerhalb von 5 Werktagen.'' (Dostawa w ciągu 5 dni roboczych). liefern = dostarczać.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Kunde / die Kundin', 'Klient / klientka. Np. ''Der Kunde ist König.'' (Klient jest królem). die Kundenzufriedenheit = satysfakcja klienta.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Zusammenarbeit', 'Współpraca. Np. ''Wir freuen uns auf die Zusammenarbeit.'' (Cieszymy się na współpracę). zusammenarbeiten = współpracować.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Schulung', 'Szkolenie. Np. ''Die Schulung findet nächste Woche statt.'' (Szkolenie odbywa się w przyszłym tygodniu). schulen = szkolić.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Ansprechpartner', 'Osoba kontaktowa / odpowiedzialna. Np. ''Ihr Ansprechpartner ist Herr Müller.'' (Państwa osoba kontaktowa to Pan Müller).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Mahnung', 'Wezwanie do zapłaty / ponaglenie. Np. ''Wir mussten eine Mahnung schicken.'' (Musieliśmy wysłać wezwanie do zapłaty). mahnen = upominać.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Tagesordnung', 'Porządek obrad — lista tematów na spotkaniu. Np. ''Der erste Punkt auf der Tagesordnung ist...'' (Pierwszy punkt porządku obrad to...).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('das Protokoll', 'Protokół / notatka ze spotkania. Np. ''Wer schreibt heute das Protokoll?'' (Kto dziś pisze protokół?).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Vorschlag', 'Propozycja / wniosek. Np. ''Ich habe einen Vorschlag.'' (Mam propozycję). vorschlagen = proponować.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Aufgabe', 'Zadanie / obowiązek. Np. ''Meine Aufgabe ist die Kundenkommunikation.'' (Moim zadaniem jest komunikacja z klientami).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('zuständig sein für', 'Być odpowiedzialnym za. Np. ''Ich bin für den Vertrieb zuständig.'' (Jestem odpowiedzialny za sprzedaż). die Zuständigkeit = kompetencja/zakres obowiązków.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Gehaltserhöhung', 'Podwyżka. Np. ''Er hat um eine Gehaltserhöhung gebeten.'' (Poprosił o podwyżkę). das Gehalt = wynagrodzenie (miesięczne).', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('kündigen', 'Wypowiedzieć (umowę, pracę). Np. ''Sie hat gekündigt.'' (Złożyła wypowiedzenie). die Kündigung = wypowiedzenie. die Kündigungsfrist = okres wypowiedzenia.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Besprechungsnotiz', 'Notatka ze spotkania. Np. ''Ich schicke Ihnen die Besprechungsnotiz per E-Mail.'' (Wyślę Państwu notatkę ze spotkania e-mailem).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('das Angebot', 'Oferta. Np. ''Wir unterbreiten Ihnen folgendes Angebot.'' (Przedstawiamy Państwu następującą ofertę). ein Angebot machen = złożyć ofertę.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Anfrage', 'Zapytanie (ofertowe). Np. ''Vielen Dank für Ihre Anfrage.'' (Dziękujemy za zapytanie). anfragen = zapytać.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Zielgruppe', 'Grupa docelowa. Np. ''Unsere Zielgruppe sind junge Berufstätige.'' (Naszą grupą docelową są młodzi profesjonaliści).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Marktanalyse', 'Analiza rynku. Np. ''Die Marktanalyse zeigt positive Trends.'' (Analiza rynku pokazuje pozytywne trendy). der Markt = rynek.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Wettbewerb', 'Konkurencja / konkurs. Np. ''Der Wettbewerb auf dem Markt ist stark.'' (Konkurencja na rynku jest silna). der Wettbewerber = konkurent.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Ser vs Estar — kiedy ser?', 'Ser — tożsamość, zawód, pochodzenie, cechy stałe, materiał, czas, wydarzenia. Np. ''Soy polaco.'' ''Es médico.'' ''La mesa es de madera.'' ''Son las tres.'' Pamięć: DOCTOR — Description, Occupation, Characteristic, Time, Origin, Relationship.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ser vs Estar — kiedy estar?', 'Estar — lokalizacja, stan tymczasowy, emocje, wynik czynności, gerundio. Np. ''Estoy en casa.'' ''Estoy cansado.'' ''La puerta está abierta.'' ''Estoy leyendo.'' Pamięć: PLACE — Position, Location, Action, Condition, Emotion.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ser vs Estar — zmiana znaczenia', 'Niektóre przymiotniki zmieniają znaczenie: ser listo = być bystrym, estar listo = być gotowym. ser aburrido = być nudnym, estar aburrido = być znudzonym. ser malo = być złym, estar malo = być chorym.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Presente de indicativo — czasowniki regularne', '-ar: hablo, hablas, habla, hablamos, habláis, hablan. -er: como, comes, come, comemos, coméis, comen. -ir: vivo, vives, vive, vivimos, vivís, viven.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito indefinido — kiedy?', 'Czynności zakończone w przeszłości w określonym czasie. Np. ''Ayer comí paella.'' ''Viajé a España en 2020.'' Określniki: ayer, anoche, la semana pasada, el año pasado, hace dos días.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito imperfecto — kiedy?', 'Opisy w przeszłości, czynności powtarzające się, nawyki, tło wydarzeń. Np. ''Cuando era niño, jugaba al fútbol.'' ''Hacía sol y los pájaros cantaban.'' Końcówki -ar: -aba, -abas, -aba, -ábamos, -abais, -aban.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Indefinido vs Imperfecto', 'Indefinido = pojedyncze, zakończone zdarzenie: ''Ayer llovió.'' Imperfecto = tło, opis, nawyk: ''Cuando llegué, llovía.'' Razem: ''Leía un libro cuando sonó el teléfono.'' (impf + indef).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito perfecto — budowa i użycie', 'haber (he, has, ha, hemos, habéis, han) + participio (-ado/-ido). Czynności powiązane z teraźniejszością. Np. ''Hoy he comido mucho.'' ''Este año hemos viajado a Italia.'' Określniki: hoy, esta semana, este mes, ya, todavía no.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Participio pasado — formy nieregularne', 'Najważniejsze nieregularne: hacer → hecho, decir → dicho, escribir → escrito, ver → visto, volver → vuelto, poner → puesto, abrir → abierto, morir → muerto, romper → roto.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futuro simple — budowa', 'Bezokolicznik + końcówki: -é, -ás, -á, -emos, -éis, -án. Np. ''Mañana hablaré con él.'' Nieregularne rdzenie: tener → tendr-, poder → podr-, saber → sabr-, hacer → har-, decir → dir-.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Condicional simple — budowa i użycie', 'Bezokolicznik + -ía, -ías, -ía, -íamos, -íais, -ían. Użycie: życzenia, rady, hipotetyczne sytuacje. Np. ''Me gustaría viajar.'' ''¿Podrías ayudarme?'' Te same nieregularne rdzenie co w futuro.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjuntivo — co to jest i kiedy?', 'Tryb łączący — wyrażanie życzenia, emocji, wątpliwości, polecenia, opinii negatywnej. Po: querer que, esperar que, es importante que, no creo que, ojalá. Np. ''Quiero que vengas.'' ''Espero que estés bien.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Presente de subjuntivo — odmiana regularna', '-ar: hable, hables, hable, hablemos, habléis, hablen. -er/-ir: coma, comas, coma, comamos, comáis, coman. Zamiana samogłoski: -ar → -e, -er/-ir → -a.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Presente de subjuntivo — formy nieregularne', 'Oparte na 1. os. presente: tener → tenga, poner → ponga, salir → salga, venir → venga, decir → diga, hacer → haga. Wyjątki: ser → sea, ir → vaya, haber → haya, saber → sepa, dar → dé.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Por vs Para', '''Por'' — przyczyna, zamiana, ''przez'' (czas/miejsce), środek: ''por la mañana'', ''gracias por todo'', ''por correo''. ''Para'' — cel, odbiorca, termin, ''dla'': ''para ti'', ''para aprender'', ''para el lunes''.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki dopełnienia bliższego (OD)', 'me, te, lo/la, nos, os, los/las. Stawiamy PRZED czasownikiem: ''Lo veo.'' (Widzę go). Z bezokolicznikiem/gerundio: na końcu: ''Quiero verlo.'' ''Estoy leyéndolo.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki dopełnienia dalszego (OI)', 'me, te, le, nos, os, les. Np. ''Le doy el libro.'' (Daję mu/jej książkę). Gdy OI + OD razem: le/les → se: ''Se lo doy.'' (Daję mu to). Kolejność: OI + OD + czasownik.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gustar i podobne czasowniki', 'Budowa: OI + gustar + podmiot. ''Me gusta el café.'' (Podoba mi się kawa). ''Me gustan los libros.'' (l.mn.). Podobne: encantar, molestar, importar, interesar, doler, faltar, quedar.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki zwrotne (reflexivos)', 'Zaimki: me, te, se, nos, os, se + czasownik. Np. ''Me levanto a las 7.'' (Wstaję o 7). ''Se llama María.'' Wiele czasowników zmienia znaczenie: ir = iść, irse = odejść; dormir = spać, dormirse = zasnąć.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gerundio — budowa i użycie', '-ar → -ando (hablando), -er/-ir → -iendo (comiendo, viviendo). Nieregularne: leer → leyendo, dormir → durmiendo, decir → diciendo. Użycie z estar: ''Estoy estudiando.'' (Właśnie się uczę).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperativo afirmativo — formy tú', 'Regularne = 3. os. l.p. presente: habla, come, escribe. Nieregularne: tener → ten, venir → ven, salir → sal, hacer → haz, poner → pon, ir → ve, decir → di, ser → sé.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperativo negativo', 'No + presente de subjuntivo. Np. ''¡No hables!'' ''¡No comas!'' ''¡No vengas!'' Obowiązuje dla WSZYSTKICH osób: ''¡No hable usted!'' ''¡No habléis!''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Perífrasis verbales — najważniejsze', 'ir a + infinitivo = zamierzać: ''Voy a estudiar.'' tener que + inf. = musieć: ''Tengo que irme.'' deber + inf. = powinien: ''Debes estudiar.'' estar + gerundio = trwanie: ''Estoy comiendo.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pluscuamperfecto — budowa', 'había/habías/había/habíamos/habíais/habían + participio. Czynność przed inną w przeszłości. Np. ''Cuando llegué, ella ya había salido.'' (Gdy dotarłem, ona już wyszła).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzaj gramatyczny rzeczowników — zasady', 'Męskie: -o (el libro), -ma (el problema, el tema, el sistema). Żeńskie: -a (la mesa), -ción/-sión (la nación), -dad/-tad (la ciudad). Wyjątki: la mano (ż.), el día (m.), el mapa (m.).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Liczba mnoga — zasady', 'Samogłoska → + -s: libro → libros. Spółgłoska → + -es: ciudad → ciudades. -z → -ces: vez → veces, lápiz → lápices. Akcentowane: café → cafés, menú → menús.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przymiotniki — pozycja i odmiana', 'Zazwyczaj PO rzeczowniku: ''un coche rojo'' (czerwony samochód). Przed — zmiana znaczenia: ''un gran hombre'' (wielki) vs ''un hombre grande'' (duży). Odmiana: -o/-a/-os/-as lub -e/-es.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stopniowanie przymiotników', 'Comparativo: más...que (więcej niż), menos...que (mniej niż), tan...como (tak jak). Superlativo: el/la más + adj. Nieregularne: bueno → mejor, malo → peor, grande → mayor, pequeño → menor.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Preposiciones: a, en, de', '''a'' — kierunek, odbiorca, godzina: ''Voy a Madrid.'' ''a las tres''. ''en'' — miejsce, środek transportu: ''Estoy en casa.'' ''en coche''. ''de'' — pochodzenie, posiadanie, materiał: ''Soy de Polonia.'' ''el libro de Juan.''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A personal (a osobowe)', 'Przed dopełnieniem osobowym (osobą) stawiamy ''a'': ''Veo a María.'' ''Llamo a mi madre.'' NIE z rzeczami: ''Veo la película.'' NIE z hay: ''Hay muchas personas.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Oraciones condicionales — typ 1 (realne)', 'Si + presente, futuro/presente/imperativo. Np. ''Si llueve, no saldremos.'' ''Si tienes hambre, come algo.'' Nie używamy futuro po ''si''!', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Oraciones condicionales — typ 2 (nierealne)', 'Si + imperfecto de subjuntivo, condicional. Np. ''Si tuviera dinero, viajaría por el mundo.'' (Gdybym miał pieniądze, podróżowałbym po świecie).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperfecto de subjuntivo — budowa', 'Od 3. os. l.mn. indefinido: hablaron → habla-ra/habla-se. Dwie formy: -ra/-ras/-ra/-ramos/-rais/-ran LUB -se/-ses/-se/-semos/-seis/-sen. Forma -ra częstsza. Np. pudiera / pudiese.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki z oboczną samogłoską (e→ie, o→ue)', 'e→ie: pensar → pienso, querer → quiero, preferir → prefiero. o→ue: poder → puedo, dormir → duermo, volver → vuelvo. Zmiana w os. akcentowanych (nie w nosotros/vosotros).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Estar + participio (stan wynikowy)', 'Opisuje stan będący wynikiem czynności. Np. ''La puerta está cerrada.'' (Drzwi są zamknięte). ''El libro está escrito en español.'' Participio odmienia się jak przymiotnik (-o/-a/-os/-as).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Voz pasiva — strona bierna', 'ser + participio (+ por). Np. ''El libro fue escrito por Cervantes.'' Hiszpański preferuje stronę czynną lub ''se'' pasywne: ''Se habla español aquí.'' (Mówi się tu po hiszpańsku).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito indefinido — formy nieregularne', 'tener → tuve, estar → estuve, poder → pude, poner → puse, saber → supe, hacer → hice, venir → vine, querer → quise, decir → dije, traer → traje. Ser/Ir → fui, fuiste, fue, fuimos, fuisteis, fueron.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Muy vs Mucho', '''Muy'' + przymiotnik/przysłówek: ''muy grande'', ''muy bien''. ''Mucho'' + rzeczownik / samodzielnie / z czasownikiem: ''mucho dinero'', ''como mucho''. NIE: ''muy mucho''. Odmiana: mucho/mucha/muchos/muchas (przed rzeczownikiem).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Saber vs Conocer', '''Saber'' — wiedzieć, umieć (fakty, umiejętności): ''Sé nadar.'' ''No sé dónde está.'' ''Conocer'' — znać (osoby, miejsca, doświadczać): ''Conozco Madrid.'' ''¿Conoces a Juan?''', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pedir vs Preguntar', '''Pedir'' — prosić o coś: ''Pedí un café.'' ''Te pido un favor.'' ''Preguntar'' — pytać o informację: ''Le pregunté la hora.'' ''Pregunta si viene.''', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Quedar vs Quedarse', '''Quedar'' — umawiać się / pozostawać: ''Quedamos a las cinco.'' ''Me quedan dos euros.'' ''Quedarse'' — zostać (w miejscu): ''Me quedé en casa.'' ''Quédate aquí.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Desde / Desde hace / Hace...que', '''Desde'' + punkt w czasie: ''Vivo aquí desde 2010.'' ''Desde hace'' + okres: ''Vivo aquí desde hace 5 años.'' ''Hace...que'' + presente: ''Hace 5 años que vivo aquí.'' Wszystkie = od (pewnego czasu).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aunque + indicativo vs subjuntivo', '''Aunque'' + indicativo = chociaż (fakt): ''Aunque llueve, salgo.'' ''Aunque'' + subjuntivo = nawet jeśli (hipotetycznie): ''Aunque llueva, saldré.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cuando + subjuntivo (przyszłość)', 'Po ''cuando'' odnoszącym się do przyszłości → subjuntivo: ''Cuando tenga tiempo, te llamaré.'' (Kiedy będę miał czas, zadzwonię). Przeszłość/teraźniejszość → indicativo: ''Cuando era joven...''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ojalá + subjuntivo', '''Ojalá'' — wyrażanie życzenia. + presente subj. (możliwe): ''Ojalá venga.'' (Oby przyszedł). + imperfecto subj. (mało prawdopodobne): ''Ojalá pudiera volar.'' (Chciałbym móc latać).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hay vs Está/Están', '''Hay'' — istnienie (coś jest gdzieś, nieokreślone): ''Hay un banco en la esquina.'' ''Está/Están'' — lokalizacja (czegoś określonego): ''El banco está en la esquina.'' Nie: ''Hay el banco.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Llevar + gerundio (trwanie)', 'Wyrażenie czasu trwania czynności. Np. ''Llevo dos años estudiando español.'' (Od dwóch lat uczę się hiszpańskiego). ''¿Cuánto tiempo llevas viviendo aquí?'' Odpowiednik ang. ''have been doing''.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Acabar de + infinitivo', 'Właśnie coś zrobić — niedawno zakończona czynność. Np. ''Acabo de comer.'' (Właśnie zjadłem). ''Acabamos de llegar.'' (Właśnie dotarliśmy). Imperfecto: ''Acababa de salir cuando llamaste.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Soler + infinitivo (zwyczaj)', 'Mieć zwyczaj / zazwyczaj coś robić. Np. ''Suelo desayunar a las 8.'' (Zwykle jadam śniadanie o 8). ''Solía jugar al fútbol.'' (Miałem zwyczaj grać w piłkę). Nie ma formy futuro.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito perfecto de subjuntivo', 'haya/hayas/haya/hayamos/hayáis/hayan + participio. Po wyrażeniach wymagających subjuntivo, gdy czynność jest zakończona. Np. ''Espero que hayan llegado bien.'' (Mam nadzieję, że dobrze dotarli).', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('el aeropuerto', 'Lotnisko. Np. ''¿Cómo llego al aeropuerto?'' (Jak dojadę na lotnisko?).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la tarjeta de embarque', 'Karta pokładowa. Np. ''Aquí tiene su tarjeta de embarque.'' (Proszę, oto Pana/Pani karta pokładowa).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el equipaje / la maleta', 'Bagaż / walizka. Np. ''He perdido mi equipaje.'' (Zgubiłem bagaż). ''Voy a facturar la maleta.'' (Nadam walizkę).', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la puerta de embarque', 'Bramka (na lotnisku). Np. ''La puerta de embarque es la B12.'' (Bramka to B12).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el vuelo', 'Lot. Np. ''Mi vuelo sale a las 10.'' (Mój lot odlatuje o 10). ''El vuelo tiene retraso.'' (Lot jest opóźniony).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la reserva', 'Rezerwacja. Np. ''Tengo una reserva a nombre de García.'' (Mam rezerwację na nazwisko García). reservar = zarezerwować.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la habitación individual / doble', 'Pokój jednoosobowy / dwuosobowy. Np. ''Quisiera una habitación doble con vistas al mar.'' (Chciałbym pokój dwuosobowy z widokiem na morze).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿A qué hora es el check-in?', 'O której jest zameldowanie? Np. ''El check-in es a partir de las 14:00.'' (Zameldowanie od 14:00). la llegada = przyjazd, la salida = wymeldowanie/wyjazd.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Está incluido el desayuno?', 'Czy śniadanie jest wliczone? Np. ''Sí, el desayuno está incluido en el precio.'' (Tak, śniadanie jest wliczone w cenę).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la llave / la tarjeta de la habitación', 'Klucz / karta do pokoju. Np. ''He dejado la llave dentro de la habitación.'' (Zostawiłem klucz w pokoju).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Tiene una mesa para dos?', 'Czy jest stolik dla dwóch osób? Np. ''Buenas noches, ¿tiene una mesa para dos?'' (Dobry wieczór, czy jest stolik dla dwojga?).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la carta / el menú', 'Menu / karta dań. Np. ''¿Me puede traer la carta, por favor?'' (Czy mogę prosić o kartę?). el menú del día = zestaw dnia.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Qué me recomienda?', 'Co Pan/Pani poleca? Np. ''¿Qué plato me recomienda?'' (Jakie danie Pan poleca?). la especialidad de la casa = specjalność zakładu.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('La cuenta, por favor', 'Poproszę rachunek. Np. ''¿Nos trae la cuenta, por favor?'' (Czy może nam Pan przynieść rachunek?). pagar = zapłacić, la propina = napiwek.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Soy alérgico/a a...', 'Jestem uczulony/a na... Np. ''Soy alérgico a los frutos secos.'' (Jestem uczulony na orzechy). ''¿Contiene gluten?'' (Czy zawiera gluten?).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Dónde está la estación de tren?', 'Gdzie jest dworzec kolejowy? Np. ''¿Podría indicarme dónde está la estación de tren?'' (Czy mógłby mi Pan wskazać, gdzie jest dworzec?).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('un billete de ida / de ida y vuelta', 'Bilet w jedną stronę / w obie strony. Np. ''Quisiera un billete de ida y vuelta a Barcelona.'' (Chciałbym bilet powrotny do Barcelony).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿A qué hora sale el próximo tren?', 'O której odjeżdża następny pociąg? Np. ''El próximo tren sale a las 15:30, andén 4.'' (Następny pociąg odjeżdża o 15:30, peron 4). el andén = peron.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Cuánto cuesta...?', 'Ile kosztuje...? Np. ''¿Cuánto cuesta la entrada al museo?'' (Ile kosztuje wejście do muzeum?). ''¿Cuánto es en total?'' (Ile to razem?).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Se puede pagar con tarjeta?', 'Czy można zapłacić kartą? Np. ''¿Aceptan tarjeta de crédito?'' (Czy przyjmujecie kartę kredytową?). en efectivo = gotówką.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Podría hablar más despacio?', 'Czy mógłby Pan mówić wolniej? Np. ''Lo siento, no entiendo. ¿Podría hablar más despacio, por favor?'' Przydatne, gdy nie rozumiemy.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Cómo se llega a...?', 'Jak się dostać do...? Np. ''¿Cómo se llega al centro de la ciudad?'' (Jak dojść do centrum?). todo recto = prosto, a la derecha/izquierda = w prawo/lewo.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Estoy buscando...', 'Szukam... Np. ''Estoy buscando una farmacia.'' (Szukam apteki). ''Estoy buscando la oficina de turismo.'' (Szukam biura turystycznego).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el horario de apertura', 'Godziny otwarcia. Np. ''¿Cuál es el horario de apertura del museo?'' (Jakie są godziny otwarcia muzeum?). abierto = otwarte, cerrado = zamknięte.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la oficina de turismo', 'Biuro turystyczne. Np. ''¿Dónde está la oficina de turismo más cercana?'' (Gdzie jest najbliższe biuro turystyczne?). un mapa = mapa, un folleto = ulotka.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('alquilar un coche', 'Wynająć samochód. Np. ''Quisiera alquilar un coche para una semana.'' (Chciałbym wynająć samochód na tydzień). el alquiler = wynajem, el seguro = ubezpieczenie.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Hay una farmacia cerca?', 'Czy jest tu gdzieś blisko apteka? Np. ''Necesito una farmacia. ¿Hay una cerca de aquí?'' (Potrzebuję apteki. Czy jest jakaś w pobliżu?).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Necesito ayuda / un médico', 'Potrzebuję pomocy / lekarza. Np. ''¡Necesito un médico, por favor!'' la urgencia = nagły wypadek, el hospital = szpital. Numer alarmowy w UE: 112.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la playa', 'Plaża. Np. ''¿Cómo se llega a la playa?'' (Jak dojść na plażę?). la sombrilla = parasol, la toalla = ręcznik, la crema solar = krem z filtrem.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el supermercado', 'Supermarket. Np. ''¿Dónde hay un supermercado?'' (Gdzie jest supermarket?). la bolsa = torba, la caja = kasa.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Me he perdido', 'Zgubiłem się. Np. ''Disculpe, me he perdido. ¿Podría ayudarme?'' (Przepraszam, zgubiłem się. Czy mógłby mi Pan pomóc?).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Tiene WiFi?', 'Czy jest WiFi? Np. ''¿Tiene WiFi? ¿Cuál es la contraseña?'' (Czy jest WiFi? Jakie jest hasło?). la contraseña = hasło.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la propina', 'Napiwek. W Hiszpanii napiwek nie jest obowiązkowy, ale mile widziany. Np. ''¿Se deja propina aquí?'' (Czy zostawia się tu napiwek?). Zazwyczaj 5-10% w restauracji.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Me puede dar un recibo?', 'Czy mogę prosić o paragon? Np. ''¿Me puede dar un recibo, por favor?'' la factura = faktura (biznesowa).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el cambio de moneda', 'Wymiana walut. Np. ''¿Dónde puedo cambiar dinero?'' (Gdzie mogę wymienić pieniądze?). la casa de cambio = kantor. el tipo de cambio = kurs wymiany.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hacer una excursión', 'Pojechać na wycieczkę. Np. ''¿Hay excursiones organizadas?'' (Czy są wycieczki zorganizowane?). la visita guiada = zwiedzanie z przewodnikiem. el guía = przewodnik.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('sacar fotos / hacer fotos', 'Robić zdjęcia. Np. ''¿Se pueden sacar fotos aquí?'' (Czy można tu robić zdjęcia?). ''¿Podría hacernos una foto?'' (Czy mógłby nam Pan zrobić zdjęcie?).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¡Que tengas buen viaje!', 'Miłej podróży! Formalnie: ''¡Que tenga buen viaje!'' Np. ''Gracias por todo. ¡Que tengas buen viaje!'' (Dziękuję za wszystko. Miłej podróży!).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el pasaporte / el DNI', 'Paszport / dowód osobisty. Np. ''¿Tiene su pasaporte?'' (Czy ma Pan paszport?). DNI = Documento Nacional de Identidad. el visado = wiza.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la aduana', 'Odprawa celna. Np. ''¿Tiene algo que declarar en la aduana?'' (Czy ma Pan coś do oclenia?). declarar = zgłosić do cła. el control de pasaportes = kontrola paszportowa.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Présent — odmiana czasowników I grupy (-er)', 'Rdzeń + -e, -es, -e, -ons, -ez, -ent. Np. parler: je parle, tu parles, il parle, nous parlons, vous parlez, ils parlent. Uwaga: końcówki -e, -es, -ent są nieme!', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Présent — odmiana czasowników II grupy (-ir)', 'Rdzeń + -is, -is, -it, -issons, -issez, -issent. Np. finir: je finis, tu finis, il finit, nous finissons, vous finissez, ils finissent. Dotyczy: choisir, réussir, rougir.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Être i avoir — odmiana w présent', 'Être: je suis, tu es, il est, nous sommes, vous êtes, ils sont. Avoir: j''ai, tu as, il a, nous avons, vous avez, ils ont. Dwa najważniejsze czasowniki — czasowniki posiłkowe.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé composé — budowa', 'avoir/être + participe passé. Np. ''J''ai mangé.'' ''Elle est partie.'' Z être: czasowniki ruchu/zwrotne (DR MRS VANDERTRAMP): aller, venir, partir, arriver, naître, mourir, rester, sortir, entrer, descendre, monter, tomber, retourner.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé composé z être — zgodność', 'Participe passé zgadza się z podmiotem w rodzaju i liczbie: ''Elle est allée.'' ''Ils sont partis.'' ''Elles sont venues.'' +e (ż.), +s (l.mn.), +es (ż. l.mn.).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Participe passé — formy nieregularne', 'être → été, avoir → eu, faire → fait, prendre → pris, mettre → mis, dire → dit, écrire → écrit, voir → vu, lire → lu, savoir → su, pouvoir → pu, vouloir → voulu, venir → venu, ouvrir → ouvert.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imparfait — budowa i użycie', 'Rdzeń z nous (présent) + -ais, -ais, -ait, -ions, -iez, -aient. Np. nous parlons → je parlais. Użycie: opisy, nawyki, tło. ''Quand j''étais petit, je jouais au foot.'' Wyjątek: être → j''étais (rdzeń ét-).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé composé vs Imparfait', 'PC = pojedyncze, zakończone zdarzenie: ''Hier, j''ai mangé une pizza.'' Imparfait = tło, opis, nawyk: ''Il faisait beau.'' Razem: ''Je lisais quand le téléphone a sonné.'' (imparfait + PC).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur simple — budowa', 'Bezokolicznik + -ai, -as, -a, -ons, -ez, -ont. Np. parler → je parlerai. Nieregularne rdzenie: être → ser-, avoir → aur-, faire → fer-, aller → ir-, pouvoir → pourr-, vouloir → voudr-, venir → viendr-.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur proche — budowa i użycie', 'aller (odmieniony) + infinitif. Bliska przyszłość, plany. Np. ''Je vais partir demain.'' ''Il va pleuvoir.'' Odpowiednik ang. ''going to''. Częstszy w mowie niż futur simple.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Conditionnel présent — budowa i użycie', 'Rdzeń futur simple + końcówki imparfait: -ais, -ais, -ait, -ions, -iez, -aient. Np. je parlerais, j''aurais, je serais. Użycie: grzeczne prośby, życzenia, hipotetyczne sytuacje. ''Je voudrais un café.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajnik określony: le, la, l'', les', 'le (r.m.): le livre. la (r.ż.): la table. l'' (przed samogłoską/h niemym): l''ami, l''heure. les (l.mn.): les enfants. Używamy z rzeczami ogólnymi: ''J''aime le chocolat.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajnik nieokreślony i cząstkowy', 'un/une/des (nieokreślony): ''J''ai un chat.'' du/de la/de l''/des (cząstkowy — pewna ilość): ''Je mange du pain.'' ''Je bois de l''eau.'' W przeczeniu → de/d'': ''Je n''ai pas de pain.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przeczenie: ne...pas i inne', 'ne...pas: ''Je ne mange pas.'' ne...plus: już nie — ''Je ne fume plus.'' ne...jamais: nigdy — ''Il ne ment jamais.'' ne...rien: nic — ''Je ne vois rien.'' ne...personne: nikt — ''Il ne connaît personne.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki osobowe — COD (dopełnienie bliższe)', 'me, te, le/la, nous, vous, les. Przed czasownikiem: ''Je le vois.'' (Widzę go). ''Il les achète.'' (On je kupuje). PC: ''Je l''ai vu.'' (Widziałem go/ją).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki osobowe — COI (dopełnienie dalsze)', 'me, te, lui, nous, vous, leur. Przed czasownikiem: ''Je lui parle.'' (Mówię do niego/niej). ''Il leur donne un cadeau.'' (Daje im prezent). Kolejność: COI + COD + verbe (ale me/te/nous/vous przed le/la/les).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki Y i EN', '''Y'' zastępuje miejsce (à + rzecz): ''J''y vais.'' (Idę tam). ''J''y pense.'' (Myślę o tym). ''EN'' zastępuje de + rzecz lub ilość: ''J''en veux.'' (Chcę tego). ''J''en ai trois.'' (Mam trzy).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjonctif — kiedy go używamy?', 'Po wyrażeniach: życzenia (je veux que), emocji (je suis content que), wątpliwości (je doute que), konieczności (il faut que), opinii negatywnej (je ne pense pas que). Np. ''Il faut que tu viennes.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjonctif présent — odmiana regularna', 'Rdzeń z ils/elles (présent) + -e, -es, -e, -ions, -iez, -ent. Np. ils parlent → que je parle, que tu parles. Nous/vous: rdzeń z nous présent: que nous parlions, que vous parliez.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjonctif — formy nieregularne', 'être: que je sois, que nous soyons. avoir: que j''aie, que nous ayons. aller: que j''aille, que nous allions. faire: que je fasse. pouvoir: que je puisse. savoir: que je sache. vouloir: que je veuille.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Si + imparfait, conditionnel (2. tryb)', 'Nierealna sytuacja teraźniejsza. Np. ''Si j''avais de l''argent, je voyagerais.'' (Gdybym miał pieniądze, podróżowałbym). Nie używamy conditionnel po ''si''. Si + imparfait → conditionnel présent.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Si + plus-que-parfait, conditionnel passé', 'Nierealna sytuacja przeszła. Np. ''Si j''avais étudié, j''aurais réussi.'' (Gdybym się uczył, zdałbym). Conditionnel passé = aurais/serais + participe passé.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Plus-que-parfait — budowa', 'Avoir/être w imparfait + participe passé. Czynność przed inną w przeszłości. Np. ''Il avait déjà mangé quand je suis arrivé.'' (Już zjadł, kiedy przyjechałem). ''Elle était partie.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki względne: qui, que, où, dont', '''qui'' — podmiot: ''L''homme qui parle.'' ''que'' — dopełnienie: ''Le livre que je lis.'' ''où'' — miejsce/czas: ''La ville où j''habite.'' ''dont'' — de + coś: ''Le film dont je parle.'' (o którym mówię).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przymiotnik — pozycja we francuskim', 'Zazwyczaj PO rzeczowniku: ''une voiture rouge'' (czerwony samochód). Przed rzeczownikiem: BANGS — Beauty (beau), Age (jeune, vieux), Number (premier), Goodness (bon, mauvais), Size (grand, petit).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przymiotnik — zgodność w rodzaju i liczbie', 'Podstawowa reguła: +e (żeński), +s (l.mn.), +es (ż. l.mn.). Np. grand → grande → grands → grandes. Wyjątki: beau → belle, vieux → vieille, nouveau → nouvelle. -eux → -euse: heureux → heureuse.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stopniowanie przymiotników', 'plus...que (bardziej niż): ''Il est plus grand que moi.'' moins...que (mniej niż): ''C''est moins cher.'' aussi...que (tak samo jak): ''Elle est aussi intelligente que lui.'' Nieregularne: bon → meilleur, mauvais → pire.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki zwrotne (verbes pronominaux)', 'Zaimki: me, te, se, nous, vous, se + czasownik. Np. ''Je me lève à 7h.'' (Wstaję o 7). W passé composé z être: ''Elle s''est levée.'' (zgodność!). se laver, se coucher, s''habiller, se souvenir.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Impératif — tryb rozkazujący', 'Trzy formy: tu, nous, vous. Bez zaimka podmiotowego. -er: Parle! Parlons! Parlez! -ir: Finis! Finissons! Finissez! Być: Sois! Soyons! Soyez! Mieć: Aie! Ayons! Ayez! Uwaga: -er bez ''s'' w tu: Mange! (nie Manges).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé récent — venir de + infinitif', 'Właśnie coś zrobić. Np. ''Je viens de manger.'' (Właśnie zjadłem). ''Il vient d''arriver.'' (Właśnie przyjechał). Odpowiednik ''have just done''.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Être en train de + infinitif', 'Trwanie czynności — odpowiednik ang. present continuous. Np. ''Je suis en train de lire.'' (Właśnie czytam). ''Il est en train de cuisiner.'' (On właśnie gotuje).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('C''est vs Il est', '''C''est'' + rodzajnik + rzeczownik / przymiotnik: ''C''est un professeur.'' ''C''est intéressant.'' ''Il est'' + przymiotnik (bez rodzajnika): ''Il est intelligent.'' ''Il est'' + zawód (bez rodzajnika): ''Il est médecin.''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strona bierna (voix passive)', 'être (w odpowiednim czasie) + participe passé + par. Np. ''Le livre est lu par les étudiants.'' ''La maison a été construite en 1900.'' Participe passé zgadza się z podmiotem.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mowa zależna (discours indirect)', 'Cofamy czasy: présent → imparfait, PC → plus-que-parfait, futur → conditionnel. Np. ''Je suis fatigué'' → Il a dit qu''il était fatigué. ''Je viendrai'' → Elle a dit qu''elle viendrait.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pytania — 3 sposoby', '1) Intonacja: ''Tu viens?'' 2) Est-ce que: ''Est-ce que tu viens?'' 3) Inwersja (formalnie): ''Viens-tu?'' Z zaimkami pytającymi: ''Où habites-tu?'' ''Qu''est-ce que tu fais?''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Depuis / Il y a / Pendant', '''Depuis'' = od (trwanie): ''J''habite ici depuis 5 ans.'' (présent!). ''Il y a'' = temu: ''Il y a 5 ans, j''ai déménagé.'' (PC). ''Pendant'' = przez (zakończone): ''J''ai étudié pendant 3 heures.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gérondif — en + participe présent', 'Budowa: en + rdzeń nous présent + -ant. Np. ''en parlant'' (mówiąc), ''en mangeant'' (jedząc). Użycie: jednoczesność, sposób, warunek. ''J''écoute de la musique en travaillant.'' Wyjątki: en étant, en ayant, en sachant.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Qui est-ce qui / que / dont / où', 'Zaimki pytające złożone — kto/co (rozwinięte formy). Qui est-ce qui = kto (podmiot): ''Qui est-ce qui a appelé?'' Qu''est-ce que = co (dopełnienie): ''Qu''est-ce que tu fais?''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Accord du participe passé z avoir', 'Z avoir: participe passé zgadza się z dopełnieniem bliższym, JEŚLI stoi ono PRZED czasownikiem. Np. ''Les fleurs que j''ai achetées.'' (kupiłem — kwiaty, r.ż. l.mn. → achetées). Bez COD przed = brak zgody.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tout / Toute / Tous / Toutes', 'tout + r.m. l.p.: ''tout le monde'' (cały świat). toute + r.ż. l.p.: ''toute la journée'' (cały dzień). tous + r.m. l.mn.: ''tous les jours'' (każdego dnia). toutes + r.ż. l.mn.: ''toutes les femmes''.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bien vs Bon', '''Bon'' = dobry (przymiotnik, z rzeczownikiem): ''un bon repas''. ''Bien'' = dobrze (przysłówek, z czasownikiem): ''Il parle bien français.'' Stopniowanie: bon → meilleur, bien → mieux.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Savoir vs Connaître', '''Savoir'' — wiedzieć, umieć (fakty, umiejętności): ''Je sais nager.'' ''Je sais qu''il est parti.'' ''Connaître'' — znać (osoby, miejsca): ''Je connais Paris.'' ''Tu connais Marie?'' Nie: ''Je sais Marie.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Devoir — znaczenia i użycie', '1) Musieć: ''Je dois partir.'' 2) Powinien (conditionnel): ''Tu devrais dormir.'' 3) Prawdopodobnie (present): ''Il doit être malade.'' 4) Być winnym: ''Je te dois 20 euros.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Il faut + infinitif / que + subjonctif', 'Bezosobowe ''trzeba''. + infinitif (ogólnie): ''Il faut travailler.'' (Trzeba pracować). + que + subjonctif (konkretna osoba): ''Il faut que tu partes.'' (Musisz odejść).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Quel / Quelle / Quels / Quelles', 'Zaimek pytający ''jaki/który'' — zgodny z rodzajem i liczbą. ''Quel livre?'' (m.l.p.) ''Quelle heure est-il?'' (ż.l.p.) ''Quels films?'' (m.l.mn.) ''Quelles idées?'' (ż.l.mn.).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Avant de + infinitif vs Après avoir/être + PP', '''Avant de'' + infinitif: ''Avant de partir, j''ai fermé la porte.'' (Zanim wyszedłem). ''Après avoir'' + PP: ''Après avoir mangé, je suis sorti.'' ''Après être parti(e), elle a pleuré.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ne...que = seulement (tylko)', 'Ograniczenie (nie jest to przeczenie!). Np. ''Je n''ai que 5 euros.'' = ''J''ai seulement 5 euros.'' (Mam tylko 5 euro). ''Il ne mange que des légumes.'' (Je tylko warzywa).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dont — zaimek względny (de)', 'Zastępuje ''de + rzeczownik'' w zdaniu względnym. Np. ''Le livre dont je parle'' (Książka, o której mówię — parler de). ''La fille dont le père est médecin'' (Dziewczyna, której ojciec jest lekarzem).', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur antérieur — budowa', 'Avoir/être w futur simple + participe passé. Czynność zakończona przed inną w przyszłości. Np. ''Quand tu arriveras, j''aurai fini.'' (Gdy przyjedziesz, już skończę). Też: przypuszczenie: ''Il aura oublié.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Même — różne znaczenia', '1) Przymiotnik (ten sam): ''le même jour'' (tego samego dnia). 2) Z zaimkiem (sam): ''moi-même'' (ja sam). 3) Przysłówek (nawet): ''Même les enfants le savent.'' (Nawet dzieci to wiedzą). 4) quand même = mimo to.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('l''entrée (f.)', 'Przystawka — pierwsze danie. Np. ''Comme entrée, je prends la salade de chèvre chaud.'' (Na przystawkę biorę sałatkę z ciepłym kozim serem). Nie mylić z ang. ''entrée'' (= danie główne w USA).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le plat principal', 'Danie główne. Np. ''Le plat principal est un magret de canard.'' (Danie główne to pierś z kaczki). le plat du jour = danie dnia.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le dessert', 'Deser. Np. ''En dessert, je voudrais une crème brûlée.'' (Na deser poproszę crème brûlée). Popularne: tarte tatin, mousse au chocolat, île flottante.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le fromage', 'Ser. Francja ma ponad 400 rodzajów sera. Najsłynniejsze: Camembert, Brie, Roquefort, Comté, Chèvre. ''Un plateau de fromages'' = talerz serów (podawany przed deserem).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la baguette', 'Bagietka — tradycyjny francuski chleb, długi i chrupiący. Np. ''Je vais acheter une baguette à la boulangerie.'' Wpisana na listę UNESCO w 2022. une tranche = kromka.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le croissant', 'Rogalik — maślowe, warstwowe ciasto na śniadanie. Np. ''Un café et un croissant, s''il vous plaît.'' un pain au chocolat = rogalik z czekoladą. la viennoiserie = wypieki wiedeńskie.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la boulangerie', 'Piekarnia. Np. ''La boulangerie ouvre à 6h du matin.'' la pâtisserie = cukiernia. le/la boulanger(-ère) = piekarz/piekarka.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le vin rouge / blanc / rosé', 'Wino czerwone / białe / różowe. Np. ''Je voudrais un verre de vin rouge, s''il vous plaît.'' Regiony: Bordeaux, Bourgogne, Champagne, Loire, Alsace. un cru = rocznik/rodzaj wina.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le marché', 'Targ / rynek. Np. ''Le samedi, je vais au marché acheter des fruits et des légumes.'' (W sobotę idę na targ kupić owoce i warzywa). le marché aux puces = pchli targ.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('faire la cuisine / cuisiner', 'Gotować. Np. ''J''adore faire la cuisine le dimanche.'' (Uwielbiam gotować w niedzielę). une recette = przepis, un ingrédient = składnik, mijoter = dusić na wolnym ogniu.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la crème fraîche', 'Kwaśna śmietana / śmietanka — podstawa kuchni francuskiej. Używana do sosów, zup i deserów. Np. ''Ajoutez une cuillère de crème fraîche à la sauce.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le beurre', 'Masło — kluczowy składnik kuchni francuskiej. Np. ''La cuisine française utilise beaucoup de beurre.'' le beurre doux = masło słodkie, le beurre demi-sel = masło półsłone (Bretania).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('l''ail (m.) / l''oignon (m.) / l''échalote (f.)', 'Czosnek / cebula / szalotka — podstawa wielu francuskich dań. Np. ''Faites revenir l''ail et l''oignon dans du beurre.'' (Podsmażyć czosnek i cebulę na maśle).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la quiche lorraine', 'Tarta lotaryńska — otwarta tarta z jajkami, śmietanką, boczkiem i serem. Pochodzi z regionu Lotaryngii. la pâte brisée = ciasto kruche.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le coq au vin', 'Kogut w winie — klasyczne danie kuchni francuskiej: kurczak duszony w czerwonym winie z warzywami, grzybami i boczkiem. Tradycyjne danie z Burgundii.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la ratatouille', 'Ratatouille — prowansalskie danie warzywne z bakłażana, cukinii, papryki, pomidorów i ziół. Np. ''La ratatouille est un plat typiquement provençal.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la crêpe / la galette', 'Naleśnik. Crêpe = cienki, słodki (mąka pszenna). Galette = słony (mąka gryczana) — specjalność Bretanii. Np. ''Une crêpe au Nutella et une galette complète, s''il vous plaît.'' (complète = z szynką, serem i jajkiem).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bon appétit !', 'Smacznego! Mówi się na początku posiłku. Uwaga: w bardzo formalnym savoir-vivre (etykieta) niektórzy uważają, że nie powinno się tego mówić. W codziennych sytuacjach jest to jednak powszechne i miłe.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Santé ! / Tchin-tchin !', 'Na zdrowie! (toast). ''Santé'' — formalne. ''Tchin-tchin'' — nieformalne. Zasada: patrzeć w oczy przy stukaniu się kieliszkami (niepatrzenie = 7 lat pecha, wg przesądu).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la bise', 'Całus w policzek na powitanie. Liczba zależy od regionu: 2 (Paryż), 3 (południe), 4 (niektóre regiony). Między znajomymi i rodziną. W pracy — zależy od relacji. Po pandemii mniej powszechna.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le pourboire', 'Napiwek. We Francji obsługa jest wliczona w cenę (service compris). Napiwek nie jest obowiązkowy, ale zostawienie drobnych jest mile widziane. Np. ''Gardez la monnaie.'' (Proszę zatrzymać resztę).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le savoir-vivre', 'Znajomość zasad dobrego zachowania / etykieta. Np. mówić ''bonjour'' wchodząc do sklepu, nie kłaść łokci na stole, nie prosić o keczup w restauracji, trzymać ręce na stole (nie na kolanach).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le café / un expresso / un allongé', 'Kawa. ''Un café'' we Francji = mała, mocna kawa (expresso). ''Un allongé'' = rozcieńczona (jak americano). ''Un café crème'' = z mlekiem (na śniadanie). ''Un décaféiné / un déca'' = bezkofeinowa.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('l''apéritif / l''apéro (m.)', 'Aperitif — drink i przekąski przed kolacją. Ważny rytuał społeczny. Popularne: kir (białe wino + likier z czarnej porzeczki), pastis (anyżowy alkohol z południa), champagne. ''On prend l''apéro?''', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le digestif', 'Digestif — alkohol po posiłku, wspomagający trawienie. Popularne: calvados (jabłkowy brandy), cognac, armagnac, eau-de-vie. Pije się powoli.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('une brasserie / un bistrot', 'Brasserie = duża restauracja z pełnym menu, zwykle otwarta cały dzień. Bistrot (bistro) = mała, przytulna restauracja z prostymi, tradycyjnymi daniami. Oba są typowe dla Francji.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('l''addition, s''il vous plaît', 'Poproszę rachunek. We Francji kelner nie przynosi rachunku automatycznie — trzeba poprosić. Np. ''L''addition, s''il vous plaît.'' Posiłek w restauracji może trwać 1,5-2 godziny.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('les herbes de Provence', 'Zioła prowansalskie — mieszanka: tymianek, rozmaryn, oregano, cząber, lawenda. Używane do mięs, ryb, warzyw grillowanych. Np. ''Assaisonnez avec des herbes de Provence.'' (Przyprawić ziołami prowansalskimi).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la soupe à l''oignon', 'Zupa cebulowa — tradycyjna paryska zupa: karmelizowana cebula w bulionie wołowym, zapiekana z grzankami i serem Gruyère. Podawana zwłaszcza zimą.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le foie gras', 'Pasztet z wątroby gęsiej lub kaczej — delikates świąteczny. Podawany z brioche lub tostem i konfiturą z fig. Np. ''Le foie gras est un met traditionnel de Noël.'' Kontrowersyjny ze względów etycznych.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('les escargots (m. pl.)', 'Ślimaki — klasyczne danie francuskie, zwykle podawane z masłem czosnkowym i natką pietruszki (beurre persillé). Np. ''Une douzaine d''escargots de Bourgogne, s''il vous plaît.'' (12 ślimaków burgundzkich).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la pâtisserie', 'Cukiernia / ciastkarstwo. Słynne francuskie desery: macaron, éclair, mille-feuille, Paris-Brest, tarte tatin, opéra. le/la pâtissier(-ière) = cukiernik/cukierniczka.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('un macaron', 'Macaron — delikatne, okrągłe ciasteczko z migdałów z kremowym nadzieniem. Nie mylić z macarON (francuski) i macarOOn (kokosowe). Najsłynniejsze: Ladurée, Pierre Hermé. Różne smaki i kolory.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la charcuterie', 'Wędliny / delikatesy mięsne. Np. jambon (szynka), saucisson (kiełbasa sucha), pâté, rillettes, terrine. ''Une planche de charcuterie'' = deska wędlin (popularna na apéro).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('faire les courses / faire du shopping', '''Faire les courses'' = robić codzienne zakupy (jedzenie). ''Faire du shopping'' = iść na zakupy (ubrania, przyjemność). Np. ''Je fais les courses au supermarché.'' ''On fait du shopping samedi?''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le terroir', 'Terroir — pojęcie bez dokładnego polskiego odpowiednika: unikalne cechy regionu (gleba, klimat, tradycje) nadające produktom charakter. Kluczowe dla wina i sera. Np. ''Ce vin exprime bien son terroir.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('AOC / AOP (Appellation d''Origine)', 'Chronione Oznaczenie Pochodzenia — certyfikat gwarantujący, że produkt pochodzi z konkretnego regionu i spełnia normy. Np. Champagne (tylko z regionu Szampanii), Roquefort, Camembert de Normandie.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vouvoyer vs Tutoyer', '''Vouvoyer'' = mówić ''vous'' (Pan/Pani — formalnie). ''Tutoyer'' = mówić ''tu'' (ty — nieformalnie). Np. ''On peut se tutoyer?'' (Czy możemy mówić sobie ''ty''?). W pracy, z nieznajomymi — ''vous''. Z rodziną, przyjaciółmi — ''tu''.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le 14 juillet', '14 lipca — Święto Narodowe Francji (Dzień Bastylii). Upamiętnia szturm na Bastylię w 1789 roku. Obchody: defilada wojskowa na Polach Elizejskich, fajerwerki, bale strażackie (bals des pompiers).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la Chandeleur', 'Święto Matki Boskiej Gromnicznej (2 lutego) — tradycja jedzenia naleśników (crêpes). Przesąd: trzymać monetę w lewej ręce i przewracać naleśnik prawą — przynosi szczęście i dobrobyt na cały rok.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Opisz fazy cyklu serca', 'Cykl serca składa się z systole (skurcz) i diastole (rozkurcz). Systole obejmuje fazę skurczu izowolumetrycznego i fazę wyrzutu. Diastole obejmuje fazę rozkurczu izowolumetrycznego, szybkiego napełniania i wolnego napełniania (diastasis). Skurcz przedsionków kończy napełnianie komór.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Franka-Starlinga', 'Siła skurczu mięśnia sercowego jest proporcjonalna do stopnia jego rozciągnięcia w fazie rozkurczu (objętości końcoworozkurczowej). Im większe wypełnienie komory, tym większa objętość wyrzutowa — do pewnej granicy. Mechanizm zapewnia równowagę między rzutem prawej i lewej komory.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Objętość wyrzutowa (SV) — definicja i wartość', 'Objętość wyrzutowa to różnica między objętością końcoworozkurczową (EDV, ~120 ml) a końcowoskurczową (ESV, ~50 ml). Prawidłowa SV wynosi ok. 70 ml. SV = EDV − ESV. Zależy od obciążenia wstępnego, następczego i kurczliwości.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rzut serca (CO) — wzór i wartość prawidłowa', 'Rzut serca (cardiac output) = SV × HR. Prawidłowa wartość to ok. 5 L/min w spoczynku. Indeks sercowy (CI) = CO/BSA, norma 2,5–4,0 L/min/m². CO wzrasta przy wysiłku nawet do 25 L/min u osób zdrowych.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Frakcja wyrzutowa (EF) — definicja i znaczenie kliniczne', 'Frakcja wyrzutowa = SV/EDV × 100%. Prawidłowa EF lewej komory wynosi 55–70%. EF < 40% wskazuje na niewydolność serca ze zmniejszoną frakcją wyrzutową (HFrEF). Jest kluczowym parametrem oceny funkcji skurczowej serca w echokardiografii.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obciążenie wstępne (preload)', 'Obciążenie wstępne to stopień rozciągnięcia kardiomiocytów przed skurczem, odpowiadający objętości końcoworozkurczowej (EDV). Zależy od powrotu żylnego, wolemii i podatności komory. Wzrost preloadu zwiększa SV zgodnie z prawem Franka-Starlinga.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obciążenie następcze (afterload)', 'Obciążenie następcze to opór, który musi pokonać komora podczas wyrzutu krwi. Dla lewej komory jest to głównie opór naczyń systemowych (SVR), dla prawej — opór naczyń płucnych (PVR). Wzrost afterloadu zmniejsza SV i zwiększa zużycie tlenu przez mięsień sercowy.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kurczliwość (inotropia) — co ją moduluje?', 'Kurczliwość to zdolność kardiomiocytów do generowania siły niezależnie od preloadu. Działanie inotropowe dodatnie: katecholaminy, digoksyna, Ca²⁺. Działanie inotropowe ujemne: β-blokery, blokery kanałów wapniowych, kwasica, niedokrwienie. Mechanizm: zmiana stężenia Ca²⁺ wewnątrzkomórkowego.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ bodźcoprzewodzący serca', 'Węzeł zatokowo-przedsionkowy (SA) → szlaki międzywęzłowe → węzeł przedsionkowo-komorowy (AV) → pęczek Hisa → odnogi prawy i lewe → włókna Purkinjego. Węzeł SA jest naturalnym rozrusznikiem (60–100/min). Węzeł AV opóźnia przewodzenie (~0,1 s), chroniąc komory przed zbyt szybkim rytmem.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Potencjał czynnościowy kardiomiocytu roboczego — fazy', 'Faza 0: szybka depolaryzacja (kanały Na⁺). Faza 1: wstępna repolaryzacja (przejściowy prąd K⁺). Faza 2: plateau (prąd Ca²⁺ typu L równoważy prąd K⁺). Faza 3: repolaryzacja (prąd K⁺). Faza 4: spoczynkowy potencjał (~−90 mV). Plateau wydłuża okres refrakcji, chroniąc przed tętnem nawrotnym.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Automatyzm komórek rozrusznikowych (faza 4)', 'Komórki węzła SA i AV nie mają stabilnego potencjału spoczynkowego. Faza 4 to powolna spontaniczna depolaryzacja (prąd funny If — Na⁺/K⁺). Po osiągnięciu progu (~−40 mV) otwierają się kanały Ca²⁺ typu L, generując potencjał czynnościowy. Katecholaminy przyspieszają If, acetylocholina zwalnia.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Załamek P w EKG', 'Załamek P odpowiada depolaryzacji przedsionków. Prawidłowy czas trwania < 120 ms, amplituda < 2,5 mm w odprowadzeniu II. Poszerzenie P wskazuje na powiększenie lewego przedsionka (P mitrale), zwiększona amplituda — prawego (P pulmonale).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zespół QRS w EKG', 'Zespół QRS odpowiada depolaryzacji komór. Prawidłowy czas trwania 60–100 ms. Poszerzenie > 120 ms sugeruje blok odnogi pęczka Hisa lub rytm komorowy. Amplituda koreluje z masą mięśniową komory — przerost LV daje wysokie R w V5-V6.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Załamek T w EKG', 'Załamek T odpowiada repolaryzacji komór. Prawidłowo zgodny z kierunkiem QRS. Odwrócenie T może wskazywać na niedokrwienie, przerost komory lub zaburzenia elektrolitowe. Spiczaste, wysokie T sugerują hiperkaliemię.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odcinek ST — znaczenie kliniczne', 'Odcinek ST łączy koniec QRS z początkiem T. Prawidłowo izoelektryczny. Uniesienie ST ≥ 1 mm sugeruje ostry zawał (STEMI) lub zapalenie osierdzia. Obniżenie ST wskazuje na niedokrwienie podwsierdziowe lub działanie digoksyny.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odstęp PQ (PR) w EKG', 'Odstęp PQ mierzy czas od początku depolaryzacji przedsionków do początku depolaryzacji komór. Norma: 120–200 ms. Wydłużenie > 200 ms = blok AV I stopnia. Skrócenie < 120 ms sugeruje zespół preekscytacji (np. WPW).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odstęp QT — znaczenie i korekta', 'Odstęp QT odpowiada całkowitemu czasowi depolaryzacji i repolaryzacji komór. Korygowany wzorem Bazetta: QTc = QT/√RR. Prawidłowy QTc < 440 ms (mężczyźni), < 460 ms (kobiety). Wydłużenie QTc predysponuje do torsade de pointes.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zastawka mitralna (dwudzielna)', 'Zastawka mitralna leży między lewym przedsionkiem a lewą komorą. Posiada dwa płatki (przedni i tylny), struny ścięgniste i mięśnie brodawkowate. Zamknięcie tworzy I ton serca (S1). Niedomykalność objawia się szmerem skurczowym.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zastawka aortalna', 'Zastawka aortalna ma trzy płatki półksiężycowate (prawy, lewy, tylny). Zamknięcie tworzy komponentę aortalną II tonu (A2). Stenoza aortalna daje szmer skurczowy crescendo-decrescendo. Tuż nad zastawką odchodzą tętnice wieńcowe.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tony serca S1 i S2', 'S1 — zamknięcie zastawek przedsionkowo-komorowych (mitralnej i trójdzielnej) na początku skurczu komór. S2 — zamknięcie zastawek półksiężycowatych (aortalnej i płucnej) na początku rozkurczu. S2 fizjologicznie rozdwaja się na wdechu (opóźnione P2).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tony serca S3 i S4', 'S3 — wczesnorozkurczowy ton spowodowany szybkim napełnianiem rozciągniętej komory. Fizjologiczny u młodych, u starszych sugeruje niewydolność serca. S4 — późnorozkurczowy ton towarzyszący skurczowi przedsionków przy zmniejszonej podatności komory (przerost, kardiomiopatia).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie wieńcowe — zaopatrzenie', 'Lewa tętnica wieńcowa (LCA) dzieli się na gałąź przednią zstępującą (LAD — przegroda, ściana przednia) i okalającą (LCx — ściana boczna). Prawa tętnica wieńcowa (RCA) zaopatruje ścianę dolną i węzeł SA (u ~60% osób). U ~85% dominacja prawostronna (RCA daje gałąź zstępującą tylną).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Autoregulacja przepływu wieńcowego', 'Przepływ wieńcowy jest stały przy ciśnieniu perfuzji 60–140 mmHg dzięki autoregulacji metabolicznej. Główny mediator rozszerzający naczynia wieńcowe to adenozyna (uwalniana przy niedokrwieniu). Przepływ w lewej komorze odbywa się głównie w rozkurczu, gdy ciśnienie wewnątrzsercowe jest niskie.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ciśnienie tętnicze — składowe', 'Ciśnienie skurczowe (SBP) zależy głównie od objętości wyrzutowej i podatności aorty. Ciśnienie rozkurczowe (DBP) zależy od oporu obwodowego i czasu rozkurczu. Ciśnienie tętna (PP) = SBP − DBP. Średnie ciśnienie tętnicze (MAP) ≈ DBP + 1/3 PP. Prawidłowe MAP: 70–105 mmHg.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Średnie ciśnienie tętnicze (MAP) — wzór i znaczenie', 'MAP = CO × SVR. Alternatywnie: MAP ≈ DBP + 1/3(SBP − DBP). MAP > 60 mmHg jest minimum do perfuzji narządów. MAP jest regulowane przez układ współczulny, RAAS, ADH i peptydy natriuretyczne. Jest głównym wyznacznikiem perfuzji tkankowej.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Baroreceptory — lokalizacja i funkcja', 'Baroreceptory tętnicze znajdują się w zatoce szyjnej (n. IX — językowo-gardłowy) i łuku aorty (n. X — błędny). Rejestrują rozciągnięcie ściany naczynia. Wzrost ciśnienia → zwiększenie impulsacji → hamowanie ośrodka naczynioruchowego → bradykardia i wazodylatacja. Odruch działa szybko, ale adaptuje się w ciągu 1–2 dni.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch z baroreceptorów przy nagłym spadku ciśnienia', 'Spadek ciśnienia → zmniejszenie rozciągnięcia baroreceptorów → mniejsza impulsacja do jądra pasma samotnego → aktywacja ośrodka naczynioruchowego → wzrost aktywności współczulnej → tachykardia, wzrost kurczliwości, wazokonstrykcja → przywrócenie ciśnienia.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ renina-angiotensyna-aldosteron (RAAS)', 'Spadek ciśnienia/perfuzji nerki → wydzielanie reniny z aparatu przykłębuszkowego → konwersja angiotensynogenu do angiotensyny I → ACE (płuca) → angiotensyna II. Ang II: wazokonstrykcja, wydzielanie aldosteronu (retencja Na⁺/H₂O), wydzielanie ADH, pragnienie. RAAS reguluje długoterminowo ciśnienie.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Angiotensyna II — działanie', 'Ang II jest silnym wazokonstryktorem (receptor AT1). Stymuluje wydzielanie aldosteronu z kory nadnerczy, ADH z tylnego płata przysadki, pobudza pragnienie. Wywołuje przerost mięśnia sercowego i naczyń. Inhibitory ACE i sartany (ARB) blokują ten szlak w leczeniu nadciśnienia i niewydolności serca.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aldosteron — mechanizm działania', 'Aldosteron działa na komórki cewki zbiorczej nerki. Zwiększa ekspresję kanałów ENaC (resorpcja Na⁺) i kanałów ROMK (wydzielanie K⁺). Efekt: retencja sodu i wody, wydalanie potasu. Nadmiar aldosteronu prowadzi do hipokaliemii i nadciśnienia (zespół Conna).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wazopresyna (ADH) — rola w regulacji ciśnienia', 'ADH jest wydzielana z tylnego płata przysadki w odpowiedzi na wzrost osmolalności lub spadek wolemii. Receptor V2 (cewka zbiorcza) — wbudowanie akwaporyn, retencja wody. Receptor V1 (naczynia) — wazokonstrykcja. W dużych dawkach ADH istotnie podnosi ciśnienie tętnicze.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Peptyd natriuretyczny typu B (BNP)', 'BNP jest wydzielany przez kardiomiocyty komór w odpowiedzi na rozciągnięcie ściany. Powoduje natriurezę, diurezę i wazodylatację oraz hamuje RAAS i współczulny układ nerwowy. NT-proBNP jest markerem niewydolności serca — poziom koreluje z ciężkością choroby.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tlenek azotu (NO) — rola naczyniowa', 'NO jest wytwarzany przez syntazę NO (eNOS) w śródbłonku z argininy. Dyfunduje do mięśni gładkich naczyń → aktywacja cGMP → rozkurcz naczyń. Hamuje agregację płytek i adhezję leukocytów. Dysfunkcja śródbłonka z upośledzeniem NO jest wczesnym etapem miażdżycy.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Endotelina-1 — rola naczyniowa', 'Endotelina-1 jest najsilniejszym znanym wazokonstryktorem. Wytwarzana przez komórki śródbłonka, działa na receptory ETA (mięśnie gładkie — skurcz) i ETB (śródbłonek — wydzielanie NO). Podwyższony poziom w nadciśnieniu płucnym. Antagoniści endoteliny (bosentan) stosowani w leczeniu nadciśnienia płucnego.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opór obwodowy (SVR) — co go determinuje?', 'SVR zależy głównie od promienia naczyń oporowych (arterioli) zgodnie z prawem Poiseuille''a (R ∝ 1/r⁴). Regulacja: układ współczulny (noradrenalina → α1 → skurcz), NO i prostacyklina (rozkurcz), angiotensyna II (skurcz). MAP = CO × SVR, więc SVR bezpośrednio wpływa na ciśnienie.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Poiseuille''a — zastosowanie hemodynamiczne', 'Przepływ Q = (ΔP × π × r⁴) / (8 × η × L). Promień naczynia (r) ma największy wpływ — zmiana o 50% zmienia przepływ 16-krotnie. Zwiększona lepkość krwi (η, np. czerwienica) zwiększa opór. Prawo tłumaczy, dlaczego skurcz arterioli drastycznie zmniejsza perfuzję.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Laplace''a dla naczyń', 'Napięcie ściany (T) = P × r / grubość ściany. Duże, rozszerzone naczynia (tętniaki) mają większe napięcie ściany przy tym samym ciśnieniu → ryzyko pęknięcia. Kapilarny mały promień pozwala wytrzymać ciśnienie mimo cienkich ścian.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mikrokrążenie — wymiana przezkapilarną (hipoteza Starlinga)', 'Filtracja netto zależy od: ciśnienia hydrostatycznego kapilarnego (wypycha płyn) i onkotycznego osocza (zatrzymuje płyn). Jnet = Kf [(Pc − Pi) − σ(πc − πi)]. Na końcu tętniczym kapilary dominuje filtracja, na żylnym — reabsorpcja. Zaburzenia powodują obrzęki.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obrzęk — patofizjologia', 'Obrzęk to nadmierne gromadzenie płynu w przestrzeni śródmiąższowej. Przyczyny: wzrost ciśnienia hydrostatycznego (niewydolność serca), spadek ciśnienia onkotycznego (hipoalbuminemia), wzrost przepuszczalności naczyń (zapalenie), upośledzenie drenażu limfatycznego (obrzęk limfatyczny).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Powrót żylny — mechanizmy wspomagające', 'Powrót żylny jest wspomagany przez: pompę mięśniową (skurcz mięśni szkieletowych), zastawki żylne (zapobiegają cofaniu), pompę oddechową (ujemne ciśnienie w klatce piersiowej na wdechu), tonus żylny (regulacja współczulna). Unieruchomienie zmniejsza powrót żylny → ryzyko zakrzepicy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie płucne — cechy hemodynamiczne', 'Krążenie płucne jest niskociśnieniowe (PAP skurczowe ~25 mmHg, średnie ~15 mmHg) i niskooporowe. Naczynia płucne reagują na hipoksję wazokonstrykcją (odruch Eulera-Liljestrandta) — to odwrotnie niż systemowe. Chronicza hipoksja prowadzi do nadciśnienia płucnego i przerostu prawej komory.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hipoksyjna wazokonstrykcja płucna (odruch Eulera-Liljestrandta)', 'W odpowiedzi na hipoksję pęcherzykową naczynia płucne kurczą się, kierując krew do lepiej wentylowanych obszarów. Mechanizm: hamowanie kanałów K⁺ w mięśniach gładkich → depolaryzacja → napływ Ca²⁺. Jest to odwrotność reakcji naczyń systemowych i optymalizuje stosunek V/Q.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie mózgowe — autoregulacja', 'Przepływ mózgowy (CBF) jest utrzymywany stały (~750 ml/min) przy MAP 60–150 mmHg dzięki autoregulacji miogennej i metabolicznej. CO₂ jest najsilniejszym regulatorem — hiperkapnia rozszerza naczynia mózgowe, hipokapnia je zwęża. Poniżej MAP 60 mmHg autoregulacja zawodzi → niedokrwienie.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krążenie nerkowe — autoregulacja', 'Przepływ nerkowy (~1200 ml/min, ~25% CO) jest autoregulowany przy MAP 80–180 mmHg. Mechanizmy: odpowiedź miogenna (efekt Baylissa) i sprzężenie cewkowo-kłębuszkowe (macula densa — adenozyna). Poniżej MAP 80 mmHg GFR spada. Angiotensyna II zwęża tętniczkę odprowadzającą, podtrzymując GFR przy niskim ciśnieniu.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wpływ układu współczulnego na serce', 'Stymulacja współczulna (noradrenalina → receptory β1): efekt chronotropowy dodatni (wzrost HR), inotropowy dodatni (wzrost kurczliwości), dromotropowy dodatni (przyspieszenie przewodzenia AV), luzytropowy dodatni (przyspieszenie rozkurczu). Mechanizm: cAMP → PKA → fosforylacja kanałów Ca²⁺ i fosfolambanu.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wpływ układu przywspółczulnego na serce', 'Nerw błędny (acetylocholina → receptory M2): efekt chronotropowy ujemny (zmniejszenie HR), dromotropowy ujemny (spowolnienie przewodzenia AV). Minimalny wpływ na kurczliwość komór (mało unerwienia wagalnego). Mechanizm: otwarcie kanałów K⁺-ACh → hiperpolaryzacja, hamowanie If i kanałów Ca²⁺.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Receptory adrenergiczne w układzie krążenia', 'α1 — mięśnie gładkie naczyń → wazokonstrykcja. β1 — serce → wzrost HR i kurczliwości. β2 — mięśnie gładkie naczyń (mięśnie szkieletowe, wieńcowe) → wazodylatacja. Adrenalina w niskich stężeniach pobudza głównie β2 (wazodylatacja), w wysokich α1 (wazokonstrykcja).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fazy cyklu serca — diagram Wiggera', 'Diagram Wiggera pokazuje jednoczesne zmiany ciśnień (aorta, komora, przedsionek), objętości komory, EKG, fonokardiogramu w czasie. Pozwala zrozumieć: otwarcie/zamknięcie zastawek, tony serca, fazy skurczu i rozkurczu. Kluczowe punkty: S1 przy zamknięciu zastawek AV, S2 przy zamknięciu zastawek półksiężycowatych.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wpływ wysiłku fizycznego na układ krążenia', 'Wysiłek: wzrost HR (do ~200/min), wzrost SV (do ~120 ml), wzrost CO (do 25 L/min). Wazodylatacja w mięśniach (metabolity, NO), wazokonstrykcja w nerkach i jelitach. Spadek SVR mimo wzrostu CO. SBP rośnie, DBP pozostaje stałe lub lekko spada. Redystrybucja przepływu krwi.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs kardiogenny — patofizjologia', 'Wstrząs kardiogenny to niewydolność pompy sercowej (najczęściej rozległy zawał, > 40% LV). Spadek CO → hipotonia → aktywacja współczulna i RAAS → wzrost SVR i retencja płynów → dalsze obciążenie serca → błędne koło. Objawy: hipotonia, tachykardia, zastój w płucach, zimne kończyny. Śmiertelność ~40%.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Objętość oddechowa (TV — tidal volume)', 'Objętość powietrza wdychana i wydychana podczas spokojnego oddychania. Wartość prawidłowa: ok. 500 ml. Część TV (~150 ml) wypełnia przestrzeń martwą anatomiczną i nie uczestniczy w wymianie gazowej.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapasowa objętość wdechowa (IRV)', 'Maksymalna dodatkowa objętość powietrza, którą można wciągnąć ponad spokojny wdech. Wynosi ok. 3000 ml. IRV stanowi rezerwę wentylacyjną wykorzystywaną przy wysiłku fizycznym.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapasowa objętość wydechowa (ERV)', 'Maksymalna dodatkowa objętość powietrza, którą można wydmuchać po spokojnym wydechu. Wynosi ok. 1100 ml. ERV jest zmniejszona u osób otyłych i w ciąży z powodu uniesienia przepony.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Objętość zalegająca (RV — residual volume)', 'Objętość powietrza pozostająca w płucach po maksymalnym wydechu. Wynosi ok. 1200 ml. Nie można jej zmierzyć spirometrem — wymaga pletyzmografii lub rozcieńczenia helem. RV jest zwiększona w rozedmie i obturacji.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pojemność życiowa (VC — vital capacity)', 'VC = TV + IRV + ERV ≈ 4600 ml. Maksymalna objętość powietrza, którą można wydmuchać po maksymalnym wdechu. Zmniejszona w chorobach restrykcyjnych (zwłóknienie, deformacje klatki piersiowej) i ciężkiej obturacji.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Całkowita pojemność płuc (TLC)', 'TLC = VC + RV ≈ 5800 ml. Objętość powietrza w płucach po maksymalnym wdechu. Zwiększona w rozedmie (hiperinflacja). Zmniejszona w chorobach restrykcyjnych.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czynnościowa pojemność zalegająca (FRC)', 'FRC = ERV + RV ≈ 2300 ml. Objętość powietrza w płucach po spokojnym wydechu. Punkt równowagi sił sprężystych płuc i klatki piersiowej. FRC jest zwiększona w obturacji (pułapka powietrzna) i zmniejszona w restrykcji.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('FEV1 i FVC — interpretacja', 'FEV1 — objętość wydmuchana w 1. sekundzie natężonego wydechu. FVC — całkowita objętość natężonego wydechu. FEV1/FVC (wskaźnik Tiffeneau): norma > 0,70. Obniżony w obturacji (astma, POChP). W restrykcji oba zmniejszone, ale stosunek prawidłowy lub podwyższony.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przestrzeń martwa anatomiczna i fizjologiczna', 'Przestrzeń martwa anatomiczna (~150 ml): drogi oddechowe bez wymiany gazowej (nos, gardło, tchawica, oskrzela). Przestrzeń martwa fizjologiczna = anatomiczna + pęcherzykowa (pęcherzyki wentylowane, ale nieperfundowane). U zdrowych obie są prawie równe.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wentylacja minutowa i pęcherzykowa', 'Wentylacja minutowa (VE) = TV × częstość oddechów = 500 × 12 = 6000 ml/min. Wentylacja pęcherzykowa (VA) = (TV − Vd) × f = (500 − 150) × 12 = 4200 ml/min. VA jest kluczowa dla wymiany gazowej. Oddychanie szybkie i płytkie zwiększa VE, ale zmniejsza VA.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wymiana gazowa — dyfuzja przez barierę pęcherzykowo-włośniczkową', 'Bariery: nabłonek pęcherzykowy (typ I), błona podstawna pęcherzyka, błona podstawna kapilary, śródbłonek. Grubość ~0,5 μm. Dyfuzja zgodnie z prawem Ficka: przepływ ∝ (powierzchnia × ΔP) / grubość. Powierzchnia wymiany: ~70 m². O₂ i CO₂ osiągają równowagę w ~0,25 s (czas tranzytu ~0,75 s).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ciśnienia parcjalne gazów w powietrzu pęcherzykowym', 'PAO₂ ≈ 100 mmHg, PACO₂ ≈ 40 mmHg. W krwi żylnej mieszanej: PvO₂ ≈ 40 mmHg, PvCO₂ ≈ 46 mmHg. Gradient ciśnień napędza dyfuzję O₂ do krwi (ΔP = 60 mmHg) i CO₂ do pęcherzyków (ΔP = 6 mmHg). CO₂ dyfunduje 20× szybciej niż O₂ dzięki wyższej rozpuszczalności.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równanie gazowe pęcherzykowe (uproszczone)', 'PAO₂ = FiO₂ × (Patm − PH₂O) − PACO₂/R. Przy oddychaniu powietrzem: PAO₂ = 0,21 × (760 − 47) − 40/0,8 ≈ 100 mmHg. R (współczynnik oddechowy) = VCO₂/VO₂ ≈ 0,8. Gradient pęcherzykowo-tętniczy (A-a) prawidłowo < 15 mmHg. Zwiększony A-a gradient sugeruje zaburzenia dyfuzji lub shunt.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stosunek wentylacji do perfuzji (V/Q)', 'Idealny V/Q = 1. W pozycji stojącej: szczyty płuc V/Q > 1 (nadmierna wentylacja względem perfuzji), podstawy V/Q < 1 (nadmierna perfuzja). Średni V/Q ≈ 0,8. V/Q = 0: shunt (perfuzja bez wentylacji). V/Q = ∞: przestrzeń martwa (wentylacja bez perfuzji).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Shunt prawo-lewy — wpływ na PaO₂', 'Shunt to przepływ krwi omijający wentylowane pęcherzyki (V/Q = 0). Przyczyny: niedodma, zapalenie płuc, wrodzone wady serca. Hipoksemia z powodu shuntu NIE odpowiada na tlenoterapię 100% O₂ (krew shuntowa nie kontaktuje się z pęcherzykami). To odróżnia shunt od zaburzeń V/Q.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Krzywa dysocjacji hemoglobiny — kształt i znaczenie', 'Krzywa ma kształt sigmoidalny dzięki kooperatywności wiązania O₂. Plateau (PO₂ > 60 mmHg): Hb prawie wysycona — zabezpieczenie przed hipoksją. Stroma część (PO₂ 20–60 mmHg): duże uwalnianie O₂ w tkankach. P50 = PO₂ przy 50% saturacji ≈ 26,7 mmHg.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Efekt Bohra', 'Spadek pH (wzrost H⁺) lub wzrost PCO₂ przesuwa krzywą dysocjacji Hb w prawo → zmniejszone powinowactwo Hb do O₂ → łatwiejsze uwalnianie O₂ w tkankach. Znaczenie kliniczne: aktywne tkanki (wysiłek, zapalenie) produkują CO₂ i kwas mlekowy → ułatwione dostarczanie O₂.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przesunięcie krzywej dysocjacji Hb w prawo', 'Przesunięcie w prawo (mniejsze powinowactwo do O₂): wzrost temperatury, wzrost PCO₂, spadek pH, wzrost 2,3-DPG. Klinicznie: ułatwia oddawanie O₂ tkankome. 2,3-DPG wzrasta w anemii, na wysokości, w hipofosfatemii jest obniżone.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przesunięcie krzywej dysocjacji Hb w lewo', 'Przesunięcie w lewo (większe powinowactwo do O₂): spadek temperatury, spadek PCO₂, wzrost pH, spadek 2,3-DPG, hemoglobina płodowa (HbF), karboksyhemoglobina (CO). Utrudnia oddawanie O₂ tkankom. Zatrucie CO: Hb chętnie wiąże O₂, ale nie oddaje go.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Transport CO₂ we krwi', 'CO₂ jest transportowany w trzech formach: rozpuszczony w osoczu (~7%), jako wodorowęglan HCO₃⁻ (~70%, konwersja przez anhydrazę węglanową w erytrocytach), jako karbaminohemoglobina (~23%, wiązanie z NH₂ Hb). Efekt Haldane''a: odtlenowana Hb wiąże więcej CO₂.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Efekt Haldane''a', 'Deoksyhemoglobina ma większe powinowactwo do CO₂ i H⁺ niż oksyhemoglobina. W tkankach (niska PO₂): Hb oddaje O₂ i chętniej wiąże CO₂. W płucach (wysoka PO₂): Hb wiąże O₂ i uwalnia CO₂. Efekt Haldane''a odpowiada za ~50% wymiany CO₂.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Surfaktant płucny — funkcja i skład', 'Surfaktant produkowany przez pneumocyty typu II, główny składnik: dipalmitoilofosfatydylocholina (DPPC). Zmniejsza napięcie powierzchniowe w pęcherzykach, zapobiega ich zapadaniu (niedodmie). Stabilizuje małe pęcherzyki (prawo Laplace''a: P = 2T/r). Niedobór u wcześniaków → zespół zaburzeń oddychania (RDS).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prawo Laplace''a w kontekście pęcherzyków płucnych', 'P = 2T/r, gdzie T = napięcie powierzchniowe, r = promień. Małe pęcherzyki miałyby większe ciśnienie i zapadały się (wydmuchując powietrze do dużych). Surfaktant redukuje T bardziej w małych pęcherzykach (większe stężenie na mniejszej powierzchni), wyrównując ciśnienie i stabilizując wentylację.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Podatność płuc (compliance)', 'Podatność = ΔV/ΔP — zmiana objętości na jednostkę zmiany ciśnienia. Wysoka podatność: płuca łatwo się rozciągają (rozedma — destrukcja elastyny). Niska podatność: płuca sztywne (zwłóknienie, brak surfaktantu, obrzęk). Podatność zmniejsza się przy dużych i małych objętościach płuc.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opór dróg oddechowych', 'Największy opór w oskrzelach średniego kalibru (4–8 generacja). Oskrzeliki końcowe mają mały indywidualny opór, ale ogromna ich liczba daje niski opór łączny. Regulacja: układ współczulny (β2 → rozkurcz), przywspółczulny (M3 → skurcz). W astmie: skurcz mięśni gładkich + obrzęk + wydzielina → zwiększony opór.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ośrodek oddechowy w pniu mózgu', 'Ośrodek oddechowy w rdzeniu przedłużonym: grupa grzbietowa (DRG — wdech, n. przeponowy), grupa brzuszna (VRG — natężony wydech). Most: ośrodek pneumotaksyczny (hamuje wdech, przyspiesza oddech), ośrodek apneustyczny (pobudza wdech). Rdzeń zapewnia rytm, most moduluje.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chemoreceptory centralne', 'Chemoreceptory centralne leżą na brzusznej powierzchni rdzenia przedłużonego. Reagują na wzrost H⁺ w płynie mózgowo-rdzeniowym (pochodzący z CO₂ — CO₂ przenika przez barierę krew-mózg, tworzy H⁺ via anhydraza węglanowa). PCO₂ jest głównym regulatorem wentylacji w warunkach fizjologicznych.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chemoreceptory obwodowe', 'Kłębki szyjne (n. IX — językowo-gardłowy) i aortalne (n. X — błędny). Reagują na spadek PaO₂ (głównie < 60 mmHg), wzrost PaCO₂ i spadek pH. Kłębki szyjne są głównym sensorem hipoksji. U pacjentów z POChP z chroniczną hiperkapnią, hipoksja staje się głównym bodźcem oddechowym (uwaga przy tlenoterapii!).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odpowiedź wentylacyjna na CO₂', 'Wzrost PaCO₂ o 1 mmHg zwiększa wentylację minutową o ~2–3 L/min (via chemoreceptory centralne). Jest to najsilniejszy bodziec wentylacyjny. Odpowiedź jest osłabiona przez: sen, narkotyki, znieczulenie, POChP z przewlekłą hiperkapnią. Hipoksja i kwasica nasilają odpowiedź na CO₂.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odpowiedź wentylacyjna na hipoksję', 'Istotna stymulacja wentylacji pojawia się przy PaO₂ < 60 mmHg (chemoreceptory obwodowe — kłębki szyjne). Powyżej PaO₂ 60 mmHg (plateau krzywej dysocjacji) — minimalna stymulacja. U pacjentów z POChP i chroniczną hiperkapnią hipoksja może być jedynym bodźcem oddechowym — podanie 100% O₂ grozi bezdechem.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mięśnie oddechowe', 'Główny mięsień wdechowy: przepona (n. przeponowy C3-C5). Pomocnicze wdechowe: mięśnie międzyżebrowe zewnętrzne, mostkowo-obojczykowo-sutkowe, pochyłe. Spokojny wydech jest bierny (sprężystość płuc). Natężony wydech: mięśnie brzuszne, mięśnie międzyżebrowe wewnętrzne.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ciśnienie wewnątrzopłucnowe', 'Ciśnienie wewnątrzopłucnowe jest ujemne (ok. −5 cmH₂O na końcu spokojnego wydechu) z powodu przeciwnych sił sprężystych płuc (do wewnątrz) i klatki piersiowej (na zewnątrz). Staje się bardziej ujemne na wdechu (−8 cmH₂O). Odma opłucnowa (powietrze w jamie opłucnej) znosi ujemne ciśnienie → zapadnięcie płuca.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odma opłucnowa prężna — mechanizm', 'Powietrze wchodzi do jamy opłucnej przez mechanizm zastawkowy (na wdechu wpływa, na wydechu nie ucieka). Narastające ciśnienie w jamie opłucnej → zapadnięcie płuca → przesunięcie śródpiersia na stronę zdrową → kompresja żył głównych → spadek powrotu żylnego i CO. Stan zagrożenia życia — wymaga odbarczenia igłą.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spirometria — wzorzec obturacyjny', 'Obturacja: FEV1 zmniejszone, FVC prawidłowe lub lekko zmniejszone, FEV1/FVC < 0,70. Krzywa przepływ-objętość: wklęsła faza wydechowa. Przyczyny: astma (odwracalna po bronchodylatatynie), POChP (nieodwracalna). Test odwracalności: poprawa FEV1 > 12% i > 200 ml po salbutamolu.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spirometria — wzorzec restrykcyjny', 'Restrykcja: FVC zmniejszone, FEV1 zmniejszone, FEV1/FVC prawidłowy lub podwyższony (> 0,70). TLC zmniejszona (wymaga pletyzmografii do potwierdzenia). Przyczyny: zwłóknienie płuc, choroby nerwowo-mięśniowe, deformacja klatki piersiowej, otyłość, wysięk opłucnowy.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równowaga kwasowo-zasadowa — rola płuc', 'Płuca regulują PaCO₂, a CO₂ + H₂O ⇌ H₂CO₃ ⇌ H⁺ + HCO₃⁻. Hiperkapnia → kwasica oddechowa. Hipokapnia → zasadowica oddechowa. Kompensacja jest szybka (minuty). Pacjent z kwasicą metaboliczną hiperwentyluje (oddech Kussmaula), obniżając PaCO₂ kompensacyjnie.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwasica oddechowa — przyczyny i kompensacja', 'Przyczyna: retencja CO₂ (hipowentylacja) — POChP, depresja ośrodka oddechowego, choroby nerwowo-mięśniowe. Gazometria: pH < 7,35, PaCO₂ > 45 mmHg. Kompensacja nerkowa (wolna, 3–5 dni): zwiększona reabsorpcja HCO₃⁻ i wydzielanie H⁺. Ostra: ΔpH duże. Przewlekła: ΔpH minimalne.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hipoksemia — przyczyny (5 mechanizmów)', '1. Niska FiO₂ (wysokość). 2. Hipowentylacja (wzrost PACO₂ → spadek PAO₂). 3. Zaburzenia dyfuzji (zwłóknienie). 4. Niedopasowanie V/Q (POChP, astma). 5. Shunt prawo-lewy (niedodma, ASD/VSD). Tylko shunt nie poprawia się przy 100% O₂. Gradient A-a prawidłowy w hipowentylacji i niskiej FiO₂; podwyższony w pozostałych.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemoglobina płodowa (HbF) — znaczenie', 'HbF (α₂γ₂) ma wyższe powinowactwo do O₂ niż HbA (α₂β₂), ponieważ łańcuchy γ słabo wiążą 2,3-DPG. Krzywa dysocjacji przesunięta w lewo. Ułatwia to transport O₂ z krwi matki do płodu przez łożysko. HbF stanowi ~60% Hb noworodka, spada do < 2% do 6. miesiąca życia.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wysokość — adaptacja oddechowa', 'Na wysokości spada ciśnienie atmosferyczne → niższe PiO₂ i PAO₂ → hipoksja. Ostra adaptacja: hiperwentylacja (chemoreceptory obwodowe) → spadek PaCO₂ → zasadowica oddechowa. Przewlekła: wzrost 2,3-DPG, poliglobulia (erytropoetyna), przebudowa naczyń płucnych. Choroba wysokościowa: obrzęk mózgu i płuc.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Potencjał spoczynkowy neuronu — wartość i mechanizm', 'Potencjał spoczynkowy wynosi ok. −70 mV (wnętrze komórki ujemne). Utrzymywany przez: pompę Na⁺/K⁺-ATPazę (3 Na⁺ na zewnątrz, 2 K⁺ do wewnątrz), dominującą przepuszczalność dla K⁺ (kanały nieszczelne K⁺) i równowagę Donnana. Równanie Nernsta dla K⁺: EK ≈ −90 mV.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równanie Nernsta', 'E = (RT/zF) × ln([ion]zewn/[ion]wewn). Dla K⁺ w 37°C: EK = 61,5 × log(4/140) ≈ −90 mV. Dla Na⁺: ENa = 61,5 × log(140/14) ≈ +60 mV. Potencjał spoczynkowy bliższy EK, bo błona jest bardziej przepuszczalna dla K⁺.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Równanie Goldmana-Hodgkina-Katza', 'Uwzględnia przepuszczalności dla wielu jonów: Vm = (RT/F) × ln[(PK[K⁺]e + PNa[Na⁺]e + PCl[Cl⁻]i) / (PK[K⁺]i + PNa[Na⁺]i + PCl[Cl⁻]e)]. Dokładniejsze niż równanie Nernsta, bo uwzględnia względne przepuszczalności. W spoczynku PK >> PNa, więc Vm bliskie EK.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pompa Na⁺/K⁺-ATPaza', 'Transportuje 3 Na⁺ na zewnątrz i 2 K⁺ do wewnątrz komórki, zużywając 1 ATP. Jest elektrogeniczna (netto ujemny prąd do wewnątrz). Utrzymuje gradient jonowy niezbędny dla potencjałów i transportu wtórnego. Hamowana przez glikozydy nasercowe (digoksyna) i brak ATP.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Potencjał czynnościowy — faza depolaryzacji', 'Bodziec progowy depolaryzuje błonę do ~−55 mV → otwieranie bramek aktywacyjnych kanałów Na⁺ (napięciowo-zależnych) → szybki napływ Na⁺ → dalsze otwarcie kanałów (sprzężenie zwrotne dodatnie) → szczyt +30 mV (zbliża się do ENa). Faza trwa ~0,5 ms. Zasada „wszystko albo nic".', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Potencjał czynnościowy — faza repolaryzacji', 'Po ~0,5 ms bramki inaktywacyjne kanałów Na⁺ zamykają się (inaktywacja). Jednocześnie otwierają się kanały K⁺ napięciowo-zależne (opóźniony prąd wyprostowujący) → wypływ K⁺ → potencjał wraca do wartości ujemnych. Hiperpolaryzacja przejściowa (undershoot) poniżej −70 mV, bo kanały K⁺ zamykają się wolno.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Okres refrakcji bezwzględnej i względnej', 'Bezwzględny: kanały Na⁺ inaktywowane, żaden bodziec nie wywoła PA. Zapewnia jednokierunkowe przewodzenie i maksymalną częstotliwość impulsów. Względny: część kanałów Na⁺ odzyskała stan spoczynkowy, silniejszy bodziec może wywołać PA (mniejsza amplituda). Okres refrakcji chroni przed tetanizacją nerwy i mięsień sercowy.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przewodzenie skokowe (saltatory conduction)', 'W włóknach mielinowych PA przeskakuje między przewężeniami Ranviera (jedyne miejsca z kanałami Na⁺). Prąd lokalny depolaryzuje następne przewężenie. Szybkość: 5–120 m/s (proporcjonalna do średnicy). Znacznie szybsze i energooszczędne niż ciągłe przewodzenie we włóknach bezmielinowych (0,5–2 m/s).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mielinizacja — rola i patologia', 'Mielina tworzona przez oligodendrocyty (OUN) i komórki Schwanna (obwodowy UN). Izoluje akson, zwiększa szybkość przewodzenia. Stwardnienie rozsiane (SM): demielinizacja OUN → zaburzenia przewodzenia, objawy wieloogniskowe. Zespół Guillaina-Barrégo: demielinizacja obwodowa → wstępujące porażenie.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synapsa chemiczna — etapy transmisji', '1. PA dociera do zakończenia presynaptycznego. 2. Otwarcie kanałów Ca²⁺ napięciowo-zależnych. 3. Napływ Ca²⁺ → fuzja pęcherzyków z błoną (via SNARE). 4. Egzocytoza neuroprzekaźnika do szczeliny synaptycznej. 5. Wiązanie z receptorami postsynaptycznymi. 6. Inaktywacja: wychwyt zwrotny, degradacja enzymatyczna, dyfuzja.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('EPSP i IPSP', 'EPSP (pobudzający potencjał postsynaptyczny): depolaryzacja przez napływ Na⁺ lub Ca²⁺ (np. glutaminian → AMPA). IPSP (hamujący): hiperpolaryzacja przez napływ Cl⁻ lub wypływ K⁺ (np. GABA → GABA-A). Sumowanie przestrzenne i czasowe EPSP/IPSP na wzgórku aksonu decyduje, czy powstanie PA.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Acetylocholina (ACh) — receptory i funkcje', 'Receptory nikotynowe (jonotropowe, kanał Na⁺): złącze nerwowo-mięśniowe, zwoje autonomiczne, OUN. Receptory muskarynowe (metabotropowe, G-protein): M1 (OUN, żołądek), M2 (serce — bradykardia), M3 (mięśnie gładkie, gruczoły — skurcz, wydzielanie). ACh rozkładany przez acetylocholinesterazę (AChE).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dopamina — szlaki i znaczenie kliniczne', 'Szlaki dopaminergiczne: 1. Nigrostriatalna (SN → striatum) — kontrola ruchu, ubytek → Parkinson. 2. Mezolimbiczna (VTA → nucleus accumbens) — nagroda, nadmiar → psychoza. 3. Mezokortykalna (VTA → kora przedczołowa) — funkcje poznawcze. 4. Tuberoinfundibularna (podwzgórze → przysadka) — hamowanie prolaktyny.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Serotonina (5-HT) — funkcje i znaczenie', 'Serotonina syntetyzowana z tryptofanu (jądra szwu w pniu mózgu). Reguluje nastrój, sen, apetyt, ból. Receptory: 5-HT1A (anksjoliza), 5-HT2A (halucynacje), 5-HT3 (nudności). Niedobór → depresja. SSRI (fluoksetyna) hamują wychwyt zwrotny 5-HT. 90% serotoniny w komórkach enterochromafinowych jelita.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('GABA — główny neuroprzekaźnik hamujący OUN', 'GABA (kwas γ-aminomasłowy) syntetyzowany z glutaminianu (GAD — dekarboksylaza glutaminianowa). Receptor GABA-A: kanał Cl⁻ (szybkie hamowanie). Miejsce wiązania benzodiazepin (nasilają działanie GABA), barbituranów, etanolu. Receptor GABA-B: metabotropowy (kanał K⁺, hamowanie presynaptyczne). Deficyt GABA → drgawki.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glutaminian — główny neuroprzekaźnik pobudzający OUN', 'Receptory jonotropowe: AMPA (szybki EPSP, kanał Na⁺), NMDA (Ca²⁺/Na⁺, zależny od napięcia — blok Mg²⁺, kluczowy w LTP i pamięci), kainianowe. Receptory metabotropowe (mGluR). Nadmiar glutaminianu → ekscytotoksyczność (śmierć neuronów przez nadmiar Ca²⁺) — udar, urazy, choroby neurodegeneracyjne.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Noradrenalina — funkcje ośrodkowe i obwodowe', 'Ośrodkowo: jądro sinawego (locus coeruleus) → czuwanie, uwaga, reakcja na stres. Obwodowo: neuroprzekaźnik pozazwojowych neuronów współczulnych. Receptory α1 (wazokonstrykcja), α2 (presynaptyczne hamowanie wydzielania NA), β1 (serce — tachykardia, wzrost kurczliwości), β2 (rozkurcz oskrzeli, naczyń).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Endorfiny i enkefaliny — układ opioidowy', 'Endogenne opioidy: endorfiny (β-endorfina — przysadka), enkefaliny (rdzeń, jelita), dynorfiny. Receptory: μ (analgezja, euforia, depresja oddechowa), κ (analgezja, dysforia), δ (modulacja). Morfina i inne opioidy działają na receptory μ. System endokanabinoidowy współdziała z opioidowym w modulacji bólu.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ współczulny — przegląd', 'Neurony przedzwojowe: rdzeń kręgowy Th1-L2, krótkie, ACh → receptory nikotynowe na zwojach. Neurony pozazwojowe: długie, noradrenalina (wyjątek: ACh w gruczołach potowych ekrynowych). Rdzeń nadnerczy: uwalnia adrenalinę (80%) i noradrenalinę (20%). Reakcja „walcz lub uciekaj": tachykardia, rozszerzenie źrenic, rozszerzenie oskrzeli.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ przywspółczulny — przegląd', 'Neurony przedzwojowe: pień mózgu (nn. III, VII, IX, X) i rdzeń krzyżowy (S2-S4), długie, ACh → receptory nikotynowe. Neurony pozazwojowe: krótkie, ACh → receptory muskarynowe. Nerw błędny (X) unerwia narządy klatki piersiowej i jamy brzusznej. Odpoczynek i trawienie: bradykardia, perystaltyka, zwężenie źrenicy.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nerw błędny (n. X) — funkcje', 'Najdłuższy nerw czaszkowy. Unerwienie przywspółczulne: serce (bradykardia), płuca (skurcz oskrzeli), przewód pokarmowy (perystaltyka, wydzielanie). Komponenta czuciowa: gardło, krtań, narządy wewnętrzne. Ruchowa: mięśnie krtani i gardła. Stymulacja wagalna: odruch okulokardialny, manewr Valsalvy.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nerwy czaszkowe — I do VI', 'I (węchowy): węch. II (wzrokowy): wzrok. III (okoruchowy): ruchy gałki ocznej, zwężenie źrenicy, akomodacja. IV (bloczkowy): m. skośny górny. V (trójdzielny): czucie twarzy, żucie (V3). VI (odwodzący): m. prostych boczny. Zapamiętywanie: „Oh Oh Oh To Touch And Feel...".', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nerwy czaszkowe — VII do XII', 'VII (twarzowy): mimika, smak 2/3 języka, łzawienie, ślinianki. VIII (przedsionkowo-ślimakowy): słuch, równowaga. IX (językowo-gardłowy): smak 1/3 języka, zatoka szyjna. X (błędny): narządy wewnętrzne. XI (dodatkowy): m. czworoboczny, mostkowo-obojczykowo-sutkowy. XII (podjęzykowy): ruchy języka.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bariera krew-mózg (BBB)', 'Tworzona przez śródbłonek naczyń mózgowych z tight junctions, otoczony stopkami astrocytów i pericytami. Przepuszcza: O₂, CO₂, małe lipofilne cząsteczki, glukozę (GLUT1), aminokwasy (transportery). Nie przepuszcza: białek osocza, dużych hydrofilnych leków, wielu antybiotyków. Zaburzenie BBB: zapalenie, guzy, udar.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Płyn mózgowo-rdzeniowy (CSF) — produkcja i krążenie', 'CSF produkowany przez sploty naczyniówkowe komór (500 ml/dobę, objętość ~150 ml). Krąży: komory boczne → otwory Monro → komora III → wodociąg mózgu → komora IV → otwory Luschki i Magendiego → przestrzeń podpajęczynówkowa → kosmki pajęczynówki → zatoki żylne. Wodogłowie: zablokowanie odpływu.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Długotrwałe wzmocnienie synaptyczne (LTP)', 'LTP to trwałe wzmocnienie transmisji synaptycznej po intensywnej stymulacji, podstawa uczenia i pamięci. Mechanizm w hipokampie: silna depolaryzacja → usunięcie bloku Mg²⁺ z kanału NMDA → napływ Ca²⁺ → aktywacja CaMKII → wbudowanie dodatkowych receptorów AMPA → silniejsza odpowiedź na glutaminian.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hipokamp — rola w pamięci', 'Hipokamp (płat skroniowy przyśrodkowy) jest kluczowy dla konsolidacji pamięci krótkotrwałej w długotrwałą (pamięć deklaratywna — fakty i zdarzenia). Uszkodzenie obustronne → amnezja następcza (brak tworzenia nowych wspomnień). Pamięć proceduralna (umiejętności ruchowe) zależy od jąder podstawy i móżdżku.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jądra podstawy — funkcja i patologia', 'Jądra podstawy (striatum, globus pallidus, substantia nigra, nucleus subthalamicus) modulują ruchy dobrowolne, planowanie ruchu i selekcję działań. Szlak bezpośredni (D1) → ułatwianie ruchu. Szlak pośredni (D2) → hamowanie ruchu. Choroba Parkinsona: utrata neuronów dopaminergicznych SN → hipokinezja, sztywność, drżenie spoczynkowe.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Móżdżek — funkcje', 'Kora móżdżku: koordynacja ruchów, równowaga, napięcie mięśniowe, uczenie ruchowe. Archicerebellum (kłaczkowo-grudkowy): równowaga, ruchy oczu. Paleocerebellum (robak): napięcie, chód. Neocerebellum (półkule): koordynacja ruchów precyzyjnych. Uszkodzenie: ataksja, dysmetria, adiadochokinezja, nystagmus, mowa skandowana.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kora ruchowa — organizacja', 'Kora ruchowa pierwotna (M1, pole 4): wykonanie ruchu, organizacja somatotopowa (homunculus ruchowy). Kora przedruchowa (pole 6): planowanie ruchów. Dodatkowa kora ruchowa (SMA): sekwencje ruchowe. Aksony: droga korowo-rdzeniowa (piramidowa), skrzyżowanie w rdzeniu przedłużonym → kontrola kontralateralna.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Droga piramidowa (korowo-rdzeniowa)', 'Zaczyna się w korze ruchowej → torebka wewnętrzna → szypuła mózgu → most → piramidy rdzenia przedłużonego (90% skrzyżowanie — tractus corticospinalis lateralis). Uszkodzenie neuronu górnego: spastyczność, wygórowane odruchy, objaw Babińskiego. Uszkodzenie neuronu dolnego: wiotkie porażenie, zanik mięśni, fascykulacje.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kora czuciowa somatyczna — organizacja', 'Kora S1 (zakręt zaśrodkowy, pola 3,1,2): odbiór czucia dotyku, bólu, temperatury, propriocepcji. Organizacja somatotopowa (homunculus czuciowy — największa reprezentacja: dłoń, usta, twarz). Informacja dochodzi przez wzgórze (jądro VPL — tułów/kończyny, VPM — twarz).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Droga czucia dotyku i propriocepcji (sznury tylne)', 'Receptory → neuron I (zwój rdzeniowy) → sznury tylne (fasciculus gracilis — kończyny dolne, cuneatus — górne) → jądra smukłe/klinowate (rdzeń przedłużony) → skrzyżowanie → lemnisc przyśrodkowy → wzgórze (VPL) → kora S1. Przekazuje dotyk precyzyjny, wibrację, propriocepcję. Uszkodzenie: ataksja czuciowa, objaw Romberga dodatni.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Droga czucia bólu i temperatury (szlak rdzeniowo-wzgórzowy)', 'Receptory → neuron I (zwój rdzeniowy) → synaps w rogu tylnym rdzenia → skrzyżowanie (na tym samym segmencie) → sznur boczny (tractus spinothalamicus lateralis) → wzgórze (VPL) → kora S1. Ból i temperatura krzyżują się na poziomie wejścia do rdzenia. Jamistość rdzenia (syringomyelia): utrata bólu/temp. przy zachowanym dotyku.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Teoria bramki bólu (Melzacka i Walla)', 'Pobudzenie grubych włókien czuciowych Aβ (dotyk) aktywuje interneurony hamujące w substancji galaretowatej rdzenia, blokując transmisję bólu z cienkich włókien Aδ i C. Wyjaśnia, dlaczego masowanie bolesnego miejsca zmniejsza ból. Zstępujące hamowanie: szlaki z PAG (istota szara okołowodociągowa) → jądro wielkie szwu → enkefaliny/serotonina.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Włókna bólowe — typy', 'Aδ (mielinowe, szybkie, ~20 m/s): ostry, dobrze zlokalizowany „pierwszy ból". C (bezmielinowe, wolne, ~1 m/s): tępy, rozlany „drugi ból", piekący. Receptory bólowe (nocyceptory): wolne zakończenia nerwowe aktywowane przez bodźce mechaniczne, termiczne, chemiczne (bradykinina, prostaglandyny, substancja P).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ból rzutowany (referred pain)', 'Ból z narządów wewnętrznych odczuwany na powierzchni skóry. Mechanizm: włókna trzewne i somatyczne zbiegają się na tych samych neuronach rdzenia. Przykłady: zawał → ból lewego ramienia/żuchwy; zapalenie pęcherzyka żółciowego → ból prawego barku; zapalenie wyrostka → ból w okolicy pępka → prawy dół biodrowy.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch rozciągowy (miotatyczny)', 'Rozciągnięcie mięśnia → wrzeciona mięśniowe (Ia) → rdzeń kręgowy → monosynaptyczny EPSP na motoneuron α → skurcz tego samego mięśnia. Jednocześnie hamowanie reciprokalne antagonisty (via interneuron hamujący). Przykład: odruch kolanowy (uderzenie w więzadło rzepki → skurcz m. czworogłowego). Wygórowanie: uszkodzenie neuronu górnego.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch cofnięcia i skrzyżowany wyprostny', 'Bodziec bólowy → włókna Aδ/C → interneurony rdzenia → zgięcie kończyny bodźcowanej (odruch cofnięcia) + jednoczesny wyprost kończyny przeciwnej (odruch skrzyżowany wyprostny). Jest to odruch polisynaptyczny, obronny. Pozwala utrzymać równowagę przy cofaniu kończyny od bodźca.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Narząd wzroku — droga wzrokowa', 'Siatkówka → nerw wzrokowy (II) → skrzyżowanie wzrokowe (włókna nosowe krzyżują się) → pasmo wzrokowe → ciało kolankowate boczne (LGN) wzgórza → promienistość wzrokowa → kora wzrokowa pierwotna (V1, pole 17, bruzda ostrogowa). Uszkodzenie skrzyżowania (guz przysadki): niedowidzenie dwuskroniowe (bitemporal hemianopia).', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odruch źreniczny na światło', 'Światło → siatkówka → nerw II → jądra okolicowe (pretectum) → jądro Edingera-Westphala (obustronne) → nerw III → zwoj rzęskowy → m. zwieracz źrenicy → zwężenie źrenicy obustronne. Bezpośredni (ipsilateralny) i konsensualny (kontralateralny). RAPD (relative afferent pupillary defect) — wada dośrodkowa (uszkodzenie nerwu II).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Narząd słuchu — droga słuchowa', 'Fale dźwiękowe → błona bębenkowa → kosteczki słuchowe → okienko owalne → perylimfa (scala vestibuli) → membrana podstawna (narząd Cortiego) → komórki rzęsate → nerw VIII → jądra ślimakowe → oliwka górna → wzniesienie → ciało kolankowate przyśrodkowe → kora słuchowa (zakręt Heschla). Tonotopia zachowana na całej drodze.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ przedsionkowy — kanały półkoliste', 'Trzy kanały półkoliste w każdym uchu (przedni, tylny, boczny) wykrywają przyspieszenia kątowe (rotacje głowy). Endolimfa porusza bańkę (crista ampullaris) → odchylenie kinocilium → depolaryzacja lub hiperpolaryzacja komórek rzęsatych. Informacja via nerw VIII → jądra przedsionkowe → odruch przedsionkowo-oczny (VOR), równowaga.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Podwzgórze — funkcje', 'Podwzgórze (hypothalamus) reguluje: temperaturę ciała (termostat), pragnienie i bilans wodny (osmoreceptory), głód i sytość (jądra boczne vs brzuszno-przyśrodkowe), rytm dobowy (jądro nadskrzyżowaniowe, SCN), funkcje autonomiczne, emocje. Kontroluje przysadkę mózgową (oś podwzgórze-przysadka-narządy docelowe).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wzgórze (thalamus) — funkcje', 'Wzgórze jest „bramą do kory" — przekaźnik niemal wszystkich informacji czuciowych (wyjątek: węch). Jądra: VPL/VPM (czucie somatyczne), LGN (wzrok), MGN (słuch), VA/VL (motoryka — z móżdżku i jąder podstawy). Jądra niespecyficzne: regulacja czuwania i uwagi. Uszkodzenie → zespół wzgórzowy (ból wzgórzowy).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ limbiczny — struktury i funkcja', 'Układ limbiczny: hipokamp (pamięć), ciało migdałowate (emocje, strach), zakręt obręczy (motywacja, ból), ciała suteczkowate (pamięć). Ciało migdałowate: warunkowanie strachu, rozpoznawanie zagrożeń. Uszkodzenie bilateralne: zespół Klüvera-Bucy''ego (brak strachu, hiperoralność, hiperseksualność).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl sen-czuwanie — fazy snu', 'Sen NREM: stadium N1 (senność, fale theta), N2 (wrzeciona snu, kompleksy K), N3 (sen głęboki, fale delta — SWS). Sen REM: szybkie ruchy oczu, atonia mięśni, marzenia senne, fale EEG jak w czuwaniu. Cykl ~90 min, 4–6 cykli/noc. SWS dominuje w I połowie nocy, REM w II. SWS: konsolidacja pamięci deklaratywnej. REM: pamięć proceduralna.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Neurotransmisja w cyklu sen-czuwanie', 'Czuwanie: noradrenalina (locus coeruleus), serotonina (jądra szwu), acetylocholina (jądro podstawne Meynerta), histamina (jądro guzowo-suteczkowe), oreksyna/hipokretyna (podwzgórze boczne). Sen REM: aktywacja cholinergiczna, zahamowanie NA i 5-HT. Narkolepsja: utrata neuronów oreksynowych → napady senności i katapleksja.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki glejowe OUN — typy i funkcje', 'Astrocyty: BBB (stopki naczyniowe), wychwyt glutaminianu, homeostaza K⁺, blizna glejowa. Oligodendrocyty: mielinizacja OUN (jeden mielinizuje wiele aksonów). Mikroglej: fagocytoza, odpowiedź immunologiczna OUN (makrofagi rezydentne). Komórki wyściółki: wyściółka komór, produkcja CSF (sploty naczyniówkowe).', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Złącze nerwowo-mięśniowe — transmisja i patologia', 'PA w neuronie ruchowym → Ca²⁺ → egzocytoza ACh → receptory nikotynowe na płytce ruchowej → depolaryzacja (potencjał płytki końcowej) → PA mięśnia → skurcz. Miastenia gravis: autoprzeciwciała anty-AChR → osłabienie mięśni. Jad kiełbasiany (botulinum): hamowanie egzocytozy ACh → porażenie wiotkie. Kurara: blokada receptorów nikotynowych.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Glikoliza — lokalizacja i bilans', 'Glikoliza zachodzi w cytozolu. Glukoza → 2 pirogroniany. Bilans netto: 2 ATP (fosforylacja substratowa), 2 NADH. W warunkach tlenowych pirogronian wchodzi do mitochondriów. W beztlenowych → mleczan (dehydrogenaza mleczanowa regeneruje NAD⁺).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glikoliza — enzymy regulatorowe', 'Trzy nieodwracalne etapy: 1. Heksokinaza (glukoza → G-6-P, hamowana przez G-6-P). 2. Fosfofruktokinaza-1 (PFK-1, główny regulator — aktywowana przez AMP, fruktozo-2,6-bisfosforan; hamowana przez ATP, cytrynian). 3. Kinaza pirogronianowa (PEP → pirogronian, hamowana przez ATP, alaninę, aktywowana przez F-1,6-BP).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fruktozo-2,6-bisfosforan — rola regulacyjna', 'F-2,6-BP jest najsilniejszym aktywatorem PFK-1 (glikoliza) i inhibitorem fruktozo-1,6-bisfosfatazy (glukoneogeneza). Wytwarzany przez PFK-2/FBPazę-2 (enzym dwufunkcyjny). Insulina → defosforylacja → aktywność PFK-2 → więcej F-2,6-BP → glikoliza. Glukagon → fosforylacja → aktywność FBPazy-2 → mniej F-2,6-BP → glukoneogeneza.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kompleks dehydrogenazy pirogronianowej (PDH)', 'Pirogronian + CoA + NAD⁺ → acetylo-CoA + CO₂ + NADH. Lokalizacja: macierz mitochondrialna. Wymaga 5 koenzymów: tiamina (B1), FAD (B2), NAD⁺ (B3), CoA (B5, kwas pantotenowy), kwas liponowy. Aktywacja: piruwat, CoA, NAD⁺. Hamowanie: acetylo-CoA, NADH, ATP. Niedobór tiaminy → kwasica mleczanowa, encefalopatia Wernickego.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl Krebsa — przegląd', 'Acetylo-CoA (2C) + oksalooctan (4C) → cytrynian (6C). Cykl 8 reakcji w macierzy mitochondrium. Na 1 acetylo-CoA: 3 NADH, 1 FADH₂, 1 GTP, 2 CO₂. Enzymy regulatorowe: syntaza cytrynianowa, dehydrogenaza izocytrynianowa, dehydrogenaza α-ketoglutaranowa. Inhibitory: NADH, ATP. Aktywatory: ADP, Ca²⁺.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl Krebsa — dehydrogenaza izocytrynianowa', 'Izocytrynian → α-ketoglutaran + CO₂ + NADH. Kluczowy enzym regulatorowy cyklu Krebsa. Aktywowana allosterycznie przez ADP i Ca²⁺. Hamowana przez ATP i NADH. Jest to główny punkt kontroli szybkości cyklu, reagujący na stan energetyczny komórki.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Łańcuch transportu elektronów — kompleksy', 'Wewnętrzna błona mitochondrium. Kompleks I: NADH → ubichinon (2,5H⁺). Kompleks II: FADH₂ → ubichinon (sukcynian → fumaran, 0 H⁺). Kompleks III: ubichinon → cytochrom c (1,5H⁺). Kompleks IV: cytochrom c → O₂ → H₂O (2H⁺). Gradient protonowy napędza syntazę ATP (kompleks V).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fosforylacja oksydacyjna — bilans ATP', 'NADH → ~2,5 ATP (kompleksy I→III→IV). FADH₂ → ~1,5 ATP (kompleksy II→III→IV). 1 glukoza → glikoliza (2 NADH, 2 ATP) + 2 PDH (2 NADH) + 2 cykle Krebsa (6 NADH, 2 FADH₂, 2 GTP) = ~30–32 ATP łącznie. Zależy od wahadłowca (malate-aspartate: 2,5 ATP/NADH; glycerol-3P: 1,5 ATP/NADH).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Inhibitory łańcucha oddechowego', 'Kompleks I: rotenon, barbiturany. Kompleks III: antymycyna A. Kompleks IV: cyjanek (CN⁻), tlenek węgla (CO). Kompleks V (syntaza ATP): oligomycyna. Rozprzęgacze (np. 2,4-DNP, termogenina/UCP1): rozpraszają gradient H⁺ → energia jako ciepło, bez ATP. Termogenina w brązowej tkance tłuszczowej — termogeneza.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glukoneogeneza — lokalizacja i substraty', 'Głównie wątroba (90%), nerki (10%). Substraty: mleczan (cykl Cori), alanina (cykl alaninowy), glicerol (z lipolizy), aminokwasy glukogenne. Enzymy kluczowe (omijające nieodwracalne etapy glikolizy): karboksylaza pirogronianowa (mitochondrium), PEPCK, fruktozo-1,6-bisfosfataza, glukoza-6-fosfataza (ER). Koszt: 6 ATP + 2 GTP na glukozę.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl Cori', 'Mięśnie (beztlenowe) produkują mleczan → krew → wątroba → glukoneogeneza → glukoza → krew → mięśnie. Koszt netto: 4 ATP (wątroba zużywa 6 ATP, mięśnie zyskują 2 ATP z glikolizy). Umożliwia aktywność anaerobową mięśni kosztem energii wątroby.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glikogeneza i glikogenoliza', 'Glikogeneza: glukoza → G-6-P → G-1-P → UDP-glukoza → syntaza glikogenowa (aktywowana przez insulinę, defosforylacja). Glikogenoliza: fosforylaza glikogenowa (aktywowana przez glukagon/adrenalinę via cAMP → PKA → fosforylacja). Wątroba: utrzymanie glikemii. Mięśnie: energia lokalna (brak glukoza-6-fosfatazy).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Choroby spichrzeniowe glikogenu — przykłady', 'Von Gierke (typ I): niedobór glukoza-6-fosfatazy → hipoglikemia, hepatomegalia, kwasica mleczanowa. Pompe (typ II): niedobór α-glukozydazy lizosomalnej → kardiomiopatia. McArdle (typ V): niedobór fosforylazy mięśniowej → nietolerancja wysiłku, brak wzrostu mleczanu. Cori (typ III): niedobór enzymu odgałęziającego.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Szlak pentozofosforanowy (PPP)', 'Lokalizacja: cytosol. Faza oksydacyjna: G-6-P → rybulozo-5-P + 2 NADPH + CO₂. Enzym regulatorowy: dehydrogenaza glukozo-6-fosforanowa (G6PD). NADPH: ochrona antyoksydacyjna (redukcja glutationu), synteza kwasów tłuszczowych, sterydogeneza. Faza nieoksydacyjna: rybozo-5-P (synteza nukleotydów). Niedobór G6PD → anemia hemolityczna (brak NADPH → uszkodzenie erytrocytów przez ROS).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('β-oksydacja kwasów tłuszczowych', 'Lokalizacja: macierz mitochondrium. Transport przez CPT-I i CPT-II (karnityna). Cykl: odcięcie 2C jako acetylo-CoA. Jeden cykl daje: 1 FADH₂, 1 NADH, 1 acetylo-CoA. Kwas palmitynowy (C16): 7 cykli → 8 acetylo-CoA + 7 FADH₂ + 7 NADH → ~106 ATP (netto, po odliczeniu aktywacji). CPT-I hamowana przez malonylo-CoA (stan sytości).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ketogeneza — kiedy i gdzie?', 'Wątroba, mitochondria. Zachodzi przy nadmiarze acetylo-CoA (głodzenie, cukrzyca, dieta ketogeniczna). Acetylo-CoA → acetoacetylo-CoA → HMG-CoA → acetooctan → β-hydroksymaślan lub aceton. Ciała ketonowe: paliwo dla mózgu (nie może używać kwasów tłuszczowych bezpośrednio). Nadmiar → kwasica ketonowa (DKA w cukrzycy typu 1).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synteza kwasów tłuszczowych (lipogeneza)', 'Cytosol. Acetylo-CoA → malonylo-CoA (karboksylaza acetylo-CoA — enzym regulatorowy, aktywowana przez cytrynian, insulinę; hamowana przez palmitoilo-CoA, glukagon). Syntaza kwasów tłuszczowych (FAS): wieloenzymatyczny kompleks, dodaje po 2C. Produkt: palmitynian (C16). Wymaga NADPH (z PPP i enzymu jabłczanowego).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synteza cholesterolu — regulacja', 'Wątroba, cytosol/ER. Acetylo-CoA → HMG-CoA → mewalonowy → skwalen → cholesterol. Enzym regulatorowy: reduktaza HMG-CoA (cel statyn). Cholesterol hamuje reduktazę (feedback ujemny) i obniża ekspresję receptorów LDL (SREBP). Insulina aktywuje syntezę, glukagon hamuje. Cholesterol: membrany, hormony steroidowe, kwasy żółciowe, witamina D.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lipoproteiny — podział i funkcje', 'Chylomikrony: transport tłuszczów pokarmowych z jelita. VLDL: transport triacylogliceroli z wątroby. IDL → LDL: transport cholesterolu do tkanek („zły cholesterol" — miażdżyca). HDL: transport zwrotny cholesterolu do wątroby („dobry cholesterol"). ApoB-100: LDL. ApoB-48: chylomikrony. ApoE: wychwyt remnantów.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl mocznikowy — przegląd', 'Lokalizacja: wątroba (mitochondria + cytosol). NH₃ + CO₂ → karbamoilofosforan (CPS-I, mitochondrium, wymaga NAG) → cytrulina → argininobursztynian → arginina → mocznik + ornityna. Bilans: 3 ATP/cykl. Mocznik wydalany przez nerki. Defekty cyklu → hiperamonemia → encefalopatia (NH₃ toksyczny dla OUN).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hiperamonemia — patofizjologia', 'NH₃ przenika BBB → astrocyty: glutaminian + NH₃ → glutamina (syntetaza glutaminowa) → obrzęk astrocytów (osmotyczny) → obrzęk mózgu. NH₃ wyczerpuje α-ketoglutaran z cyklu Krebsa → deficyt energetyczny neuronów. Objawy: dezorientacja, asterixis, śpiączka. Leczenie: laktuloza (eliminacja NH₃ przez jelita), ryfaksymina, benzoesany.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aminokwasy glukogenne i ketogenne', 'Glukogenne: szkielet węglowy → pirogronian lub intermedia cyklu Krebsa → glukoneogeneza. Większość aminokwasów. Ketogenne: szkielet → acetylo-CoA lub acetoacetylo-CoA → ciała ketonowe/kwasy tłuszczowe. Wyłącznie ketogenne: leucyna i lizyna. Zarówno gluko- jak i ketogenne: izoleucyna, fenyloalanina, tryptofan, treonina, tyrozyna.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aminokwasy egzogenne (niezbędne)', 'Nie mogą być syntetyzowane de novo przez organizm. Mnemotechnika: PVT TIM HALL — fenyloalanina (Phe), walina (Val), treonina (Thr), tryptofan (Trp), izoleucyna (Ile), metionina (Met), histydyna (His), arginina (Arg — warunkowo), leucyna (Leu), lizyna (Lys). Niedobory prowadzą do ujemnego bilansu azotowego.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fenyloketonuria (PKU)', 'Autosomalny recesywny niedobór hydroksylazy fenyloalaninowej (fenyloalanina → tyrozyna) lub kofaktora BH4. Nagromadzenie Phe → upośledzenie umysłowe, jasna karnacja (brak melaniny — tyrozyna jest prekursorem), mysi zapach (fenylooctan). Leczenie: dieta niskofenyloalaninowa od urodzenia. Screening noworodków obowiązkowy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina B1 (tiamina) — rola metaboliczna', 'Tiamina (koenzym TPP) jest kofaktorem: dehydrogenazy pirogronianowej (PDH), dehydrogenazy α-ketoglutaranowej (cykl Krebsa), transketolazy (szlak pentozofosforanowy), dehydrogenazy α-ketokwasów rozgałęzionych. Niedobór: beri-beri (mokra — niewydolność serca; sucha — neuropatia), encefalopatia Wernickego (alkoholizm).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina B3 (niacyna/NAD⁺) — rola metaboliczna', 'Niacyna (nikotynamid) tworzy NAD⁺ i NADP⁺ — koenzymy reakcji redox. NAD⁺: katabolizm (glikoliza, cykl Krebsa, β-oksydacja). NADPH: anabolizm (synteza kwasów tłuszczowych, ochrona antyoksydacyjna). Niedobór: pelagra (3D — dermatitis, diarrhea, dementia). Syntetyzowana z tryptofanu.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina B12 (kobalamina) — rola i niedobór', 'Kofaktor: syntazy metioninowej (homocysteina → metionina, wymaga też folianu) i mutazy metylomalonylo-CoA (metylomalonylo-CoA → sukcynylo-CoA). Niedobór: anemia megaloblastyczna + objawy neurologiczne (degeneracja powrózków tylnych i bocznych). Przyczyny: anemia złośliwa (brak IF), weganizm. Kwas metylomalnonowy podwyższony.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwas foliowy — rola metaboliczna', 'THF (tetrahydrofolian) przenosi jedności jednowęglowe (metyl, metylen, formyl). Niezbędny do syntezy nukleotydów (dTMP — tymidylanu, puryn) i konwersji homocysteiny → metionina. Niedobór: anemia megaloblastyczna (BEZ objawów neurologicznych — różnica od B12). W ciąży: suplementacja zapobiega wadom cewy nerwowej.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Insulina — mechanizm działania', 'Insulina → receptor (kinaza tyrozynowa) → autofosforylacja → IRS → PI3K → Akt/PKB. Efekty: translokacja GLUT4 (wychwyt glukozy — mięśnie, tkanka tłuszczowa), aktywacja glikogenosyntetazy, aktywacja PFK-2, synteza białek, lipogeneza. Hamowanie: glukoneogenezy, glikogenolizy, lipolizy, ketogenezy. Hormon anaboliczny.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glukagon — mechanizm działania', 'Glukagon (komórki α trzustki) → receptor sprzężony z Gs → cAMP → PKA. Efekty w wątrobie: aktywacja fosforylazy glikogenowej (glikogenoliza), aktywacja glukoneogenezy (PEPCK, F-1,6-BPaza), aktywacja β-oksydacji i ketogenezy. Hamowanie glikolizy (inaktywacja PFK-2) i lipogenezy. Glukagon działa głównie na wątrobę. Hormon kataboliczny.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cukrzyca typu 1 vs typu 2', 'Typ 1: autoimmunologiczne zniszczenie komórek β → brak insuliny. Młodzi pacjenci, szczupli. Skłonność do kwasicy ketonowej (DKA). Leczenie: insulina. Typ 2: insulinooporność + postępujący defekt sekrecji. Starsi, otyli. Zespół metaboliczny. Hiperglikemia hiperosmolarna (HHS). Leczenie: zmiana stylu życia, metformina, inne leki.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwasica ketonowa cukrzycowa (DKA)', 'Brak insuliny → niekontrolowana lipoliza → nadmiar acetylo-CoA → ketogeneza → acetooctan, β-hydroksymaślan → kwasica metaboliczna z luką anionową. Objawy: oddech Kussmaula, zapach acetonu, odwodnienie, bóle brzucha, nudności. Gazometria: pH < 7,3, HCO₃⁻ < 18. Leczenie: płyny, insulina i.v., suplementacja K⁺.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemoglobina glikowana (HbA1c)', 'HbA1c to hemoglobina z nieenzymatycznie przyłączoną glukozą do łańcucha β. Odzwierciedla średnią glikemię z ostatnich 2–3 miesięcy (czas życia erytrocytu ~120 dni). Norma < 5,7%. Prediabetes: 5,7–6,4%. Cukrzyca: ≥ 6,5%. Cel terapeutyczny u większości diabetyków: < 7%. Wynik fałszywie niski w hemolizie, krwawieniu.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Transkrypcja — etapy u eukariontów', 'Inicjacja: czynniki transkrypcyjne (TFIID → TATA box) + polimeraza RNA II. Elongacja: synteza pre-mRNA 5''→3''. Terminacja: sygnał poliadenylacji. Modyfikacje potranslacyjne: czapeczka 5'' (7-metyloguanozyna), ogon poli-A 3'', splicing (usuwanie intronów przez spliceosom). Mutacje splicingowe mogą powodować choroby genetyczne.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Translacja — etapy', 'Inicjacja: mała podjednostka rybosomu + mRNA + tRNA-Met (kodon AUG). Elongacja: aminoacylo-tRNA wchodzi do miejsca A → wiązanie peptydowe (peptydylotransferaza — rRNA) → translokacja (EF-G/eEF2). Terminacja: kodon stop (UAA, UAG, UGA) → czynnik uwalniający. Antybiotyki: aminoglikozydy (30S), makrolidy/chloramfenikol (50S), tetracykliny (30S).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kod genetyczny — cechy', 'Trójkowy: 3 nukleotydy = 1 kodon. Zdegenerowany: wiele kodonów dla jednego aminokwasu (64 kodony, 20 aminokwasów). Uniwersalny (z wyjątkami: mitochondria). Jednoznaczny: 1 kodon = 1 aminokwas. Nieprzekrywający się. Kodon inicjacyjny: AUG (Met). Kodony stop: UAA, UAG, UGA. Wobble: tolerancja w trzeciej pozycji kodonu.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mutacje punktowe — typy i skutki', 'Ciche (silent): zmiana kodonu, ten sam aminokwas (degeneracja kodu). Zmiany sensu (missense): inny aminokwas (np. sierpowatokrwinkowość: GAG→GUG, Glu→Val w β-globinie). Nonsensowna: kodon stop → skrócone białko. Przesunięcie ramki odczytu (frameshift): insercja/delecja nie będąca wielokrotnością 3 → zmiana całej sekwencji downstream.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Naprawa DNA — mechanizmy', 'Naprawa wycinająca nukleotydy (NER): usuwanie dimerów tyminy (UV) — defekt → xeroderma pigmentosum. Naprawa wycinająca zasady (BER): usuwanie uszkodzonych zasad (glikozylaza). Naprawa niesparowanych zasad (MMR): korekta błędów replikacji — defekt → zespół Lyncha (HNPCC). Naprawa DSB: rekombinacja homologiczna (BRCA1/2) lub NHEJ.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Synteza hemu i porfirie', 'Synteza hemu: sukc-CoA + glicyna → ALA (ALA-syntaza, mitochondrium, kofaktor: B6) → porfobilinogen → uroporfirynogen → koproporfirynogen → protoporfiryna IX + Fe²⁺ → hem. Defekty enzymów → porfirie. Ostra przerywana (ALA-dehydrataza/PBG-deaminaza): bóle brzucha, neuropatia, objawy psychiatryczne. Porfiria skórna: fotowrażliwość.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Degradacja hemu — bilirubina', 'Hem → biliwerdyna (oksygenaza hemowa) → bilirubina niesprzężona (pośrednia, nierozpuszczalna, wiązana z albuminą) → wątroba: sprzężenie z glukuronianem (UDP-glukuronylotransferaza) → bilirubina sprzężona (bezpośrednia) → żółć → jelito → urobilinogen → sterkobilina (kał) / urobilina (mocz). Żółtaczka: przeszkodowa, miąższowa, hemolityczna.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metabolizm żelaza', 'Wchłanianie w dwunastnicy (Fe²⁺ via DMT1). Transport: transferyna (Fe³⁺). Magazynowanie: ferrytyna (wewnątrzkomórkowa), hemosyderyna (nadmiar). Regulacja: hepcydyna (wątroba) — hamuje ferroportynę → zmniejsza wchłanianie i uwalnianie Fe. Niedobór Fe: anemia mikrocytarna. Nadmiar (hemochromatoza): uszkodzenie wątroby, serca, trzustki.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina D — metabolizm i funkcje', 'Skóra: 7-dehydrocholesterol + UV → cholekalcyferol (D3). Wątroba: 25-hydroksylacja → 25(OH)D (kalcydiol — marker poziomu). Nerki: 1α-hydroksylacja → 1,25(OH)₂D (kalcytriol — aktywna forma). Funkcje: wchłanianie Ca²⁺ i PO₄³⁻ z jelita, mineralizacja kości. Niedobór: krzywica (dzieci), osteomalacja (dorośli).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina K — funkcja i znaczenie kliniczne', 'Witamina K jest kofaktorem γ-karboksylazy glutaminianu — niezbędna do aktywacji czynników krzepnięcia II, VII, IX, X oraz białek C i S. γ-karboksylacja umożliwia wiązanie Ca²⁺. Warfaryna hamuje reduktazę epoksydu witaminy K. Niedobór: koagulopatia. Noworodki: profilaktycznie podaje się wit. K (zapobieganie VKDB).', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Witamina C (kwas askorbinowy) — funkcja', 'Kofaktor hydroksylazy prolinowej i lizylowej (synteza kolagenu). Antyoksydant (regeneracja witaminy E). Ułatwia wchłanianie żelaza (redukcja Fe³⁺ → Fe²⁺). Niezbędna w syntezie karnityny, katecholamin, kwasów żółciowych. Niedobór: szkorbut — krwawienie z dziąseł, wybroczyny, upośledzenie gojenia ran, rozluźnienie zębów.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Koenzym A (CoA) — rola', 'Składnik: kwas pantotenowy (witamina B5) + cysteamina + ADP. Grupa tiolowa (-SH) tworzy wysokoenergetyczne wiązania tioesterowe z grupami acylowymi. Acetylo-CoA: centralny metabolit łączący glikolizę, β-oksydację, cykl Krebsa, ketogenezę, syntezę cholesterolu i kwasów tłuszczowych. CoA jest niezbędny w ~100 reakcjach enzymatycznych.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stres oksydacyjny — wolne rodniki i obrona', 'ROS: anion ponadtlenkowy (O₂⁻), nadtlenek wodoru (H₂O₂), rodnik hydroksylowy (OH•). Źródła: łańcuch oddechowy, NADPH oksydaza. Obrona: dysmutaza ponadtlenkowa (SOD: O₂⁻ → H₂O₂), katalaza i peroksydaza glutationowa (H₂O₂ → H₂O). Glutation (GSH) — główny antyoksydant wewnątrzkomórkowy, regenerowany przez reduktazę glutationową (NADPH).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cykl alaninowo-glukozowy', 'Mięśnie: transaminacja pirogronianu + aminokwasy → alanina → krew → wątroba → transaminacja → pirogronian → glukoneogeneza → glukoza → mięśnie. Równocześnie NH₂ z mięśni transportowany do wątroby jako alanina (bezpieczny nośnik azotu). W wątrobie NH₃ wchodzi do cyklu mocznikowego.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reakcje transaminacji', 'Transaminazy (aminotransferazy) przenoszą grupę aminową z aminokwasu na α-ketokwas. Koenzym: fosforan pirydoksalu (PLP, witamina B6). ALT: alanina + α-ketoglutaran ⇌ pirogronian + glutaminian (marker wątroby). AST: asparaginian + α-ketoglutaran ⇌ oksalooctan + glutaminian (wątroba, serce, mięśnie). Podwyższone w uszkodzeniu hepatocytów.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kinetyka enzymatyczna — Michaelis-Menten', 'v = Vmax × [S] / (Km + [S]). Km = stężenie substratu przy v = Vmax/2. Niskie Km = wysokie powinowactwo. Vmax zależy od stężenia enzymu. Inhibicja kompetycyjna: zwiększa Km (pozorne), Vmax bez zmian. Inhibicja niekompetycyjna: Km bez zmian, Vmax zmniejszone. Wykres Lineweavera-Burka: 1/v vs 1/[S].', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Regulacja allosteryczna enzymów', 'Enzymy allosteryczne mają kinetykę sigmoidalną (nie Michaelis-Menten). Efektory wiążą się w miejscu allosterycznym (nie aktywnym). Aktywatory obniżają K0,5 (pozorny Km), inhibitory podwyższają. Przykłady: PFK-1 (aktywator: AMP, F-2,6-BP; inhibitor: ATP, cytrynian). Regulacja allosteryczna zapewnia szybką odpowiedź na zmiany metaboliczne.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Nabłonek jednowarstwowy płaski — lokalizacja i funkcja', 'Pojedyncza warstwa spłaszczonych komórek na błonie podstawnej. Lokalizacja: śródbłonek naczyń, mezotelium (opłucna, otrzewna, osierdzie), pęcherzyki płucne, pętla Henlego, torebka Bowmana. Funkcja: ułatwia dyfuzję gazów, filtrację, transport płynów. Bardzo cienki — nie chroni mechanicznie.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek jednowarstwowy sześcienny — lokalizacja', 'Komórki sześcienne (kwadratowe w przekroju) na błonie podstawnej. Lokalizacja: cewki nerkowe (proksymalne i dystalne), tarczyca (pęcherzyki), powierzchnia jajnika, przewody wydzielnicze gruczołów. Funkcja: wydzielanie i wchłanianie. Nabłonek cewek proksymalnych ma rąbek szczoteczkowy zwiększający powierzchnię.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek jednowarstwowy walcowaty — typy i lokalizacja', 'Komórki kolumnowe (wyższe niż szerokie). Bez rzęsek: żołądek, jelita (komórki kubkowe produkujące śluz, enterocyty z mikrokosmkami). Z rzęskami: jajowody (transport komórki jajowej), drogi oddechowe (oczyszczanie śluzowo-rzęskowe). Funkcja: wchłanianie, wydzielanie, ochrona.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek wielorzędowy — cechy i lokalizacja', 'Pseudostratified — wszystkie komórki dotykają błony podstawnej, ale nie wszystkie sięgają powierzchni. Jądra na różnych wysokościach → wrażenie wielu warstw. Lokalizacja: drogi oddechowe (z rzęskami i komórkami kubkowymi), najądrze, przewody wyprowadzające ucha. Oczyszczanie śluzowo-rzęskowe.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek wielowarstwowy płaski rogowaciejący', 'Wiele warstw komórek, warstwa powierzchniowa — martwe, zrogowaciałe (keratyna). Lokalizacja: skóra (naskórek). Najgrubszy nabłonek. Funkcja: ochrona mechaniczna, bariera przed utratą wody i mikroorganizmami. Warstwy naskórka: podstawna, kolczysta, ziarnista, jasna (dłonie/stopy), rogowa.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek wielowarstwowy płaski nierogowaciejący', 'Wiele warstw, warstwa powierzchniowa — żywe, nierogowaciejące komórki. Lokalizacja: jama ustna, gardło, przełyk, pochwa, rogówka, kanał odbytu. Funkcja: ochrona mechaniczna w wilgotnych środowiskach. W przełyku może ulegać metaplazji do nabłonka walcowatego (przełyk Barretta) pod wpływem refluksu.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nabłonek przejściowy (urotelium)', 'Specjalny nabłonek wielowarstwowy dróg moczowych. Komórki powierzchniowe — „parasole" (umbrella cells, białko uroplakin). Zmienia grubość: rozciągnięty (2–3 warstwy) vs pusty pęcherz (5–6 warstw). Lokalizacja: miedniczka nerkowa, moczowód, pęcherz moczowy. Bariera dla moczu (nieprzepuszczalny).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Błona podstawna — budowa i funkcje', 'Warstwa pozakomórkowa pod nabłonkiem. Budowa: lamina lucida, lamina densa (kolagen IV, laminina, proteoglikany), lamina reticularis (kolagen III). Funkcje: zakotwiczenie nabłonka, filtracja (kłębuszek nerkowy), bariera dla komórek nowotworowych (naciekanie = przełamanie błony). Przeciwciała anty-błonie podstawnej → zespół Goodpasture''a.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Złącza ścisłe (tight junctions / zonula occludens)', 'Pasmo białek (klaudyny, okludyny) otaczające szczyt komórki nabłonkowej. Funkcja: bariera paracelularna — kontrola przepuszczalności między komórkami, zapobieganie mieszaniu się białek apikalnych i bazolateralnych (polarność). Najsilniejsze w BBB i nabłonku pęcherza moczowego. Osłabienie → przecieki, obrzęk.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Desmosomy (macula adherens)', 'Punktowe połączenia mechaniczne między komórkami. Białka: kadheryny desmosomalne (desmogleina, desmocolina) zakotwiczone w plakoglobinie → filament pośredni keratynowy. Liczne w nabłonku narażonym na stres mechaniczny (naskórek, mięsień sercowy). Pęcherzyca zwykła: autoprzeciwciała anty-desmogleina → oddzielanie naskórka → pęcherze.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Złącza szczelinowe (gap junctions)', 'Kanały (koneksony = 6 koneksyn) łączące cytoplazmę sąsiednich komórek. Przepuszczają jony i małe cząsteczki (< 1 kDa). Funkcja: komunikacja elektryczna i metaboliczna. Kluczowe w: mięśniu sercowym (synchroniczny skurcz), mięśniu gładkim, hepatocytach, astrocytach. Mutacje koneksyny 26 → głuchota dziedziczna.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gruczoły egzokrynne — klasyfikacja wg wydzieliny', 'Surowicze (serozne): cienka, wodnista wydzielina bogata w enzymy. Ciemne jądra, wąskie światło (np. przyusznica, trzustka egzokrynna). Śluzowe: gęsty śluz (mucyny). Jasna cytoplazma, spłaszczone jądra przy podstawie (np. podniebienne). Mieszane (seromukozne): oba typy, surowicze półksiężyce Giannuzziego (np. podżuchwowa).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gruczoły — mechanizmy wydzielania', 'Merokrynowe: egzocytoza bez utraty cytoplazmy (większość gruczołów — ślinianki, trzustka, gruczoły potowe ekrynowe). Apokrynowe: odcinanie szczytowej części cytoplazmy z wydzieliną (gruczoły mlekowe, gruczoły potowe apokrynowe — pachy). Holokrynowe: cała komórka rozpada się stając się wydzieliną (gruczoły łojowe).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka łączna właściwa wiotka (luźna)', 'Więcej substancji podstawowej niż włókien. Zawiera kolagen I i III, włókna sprężyste, fibroblasty, makrofagi, komórki tuczne, adipocyty. Lokalizacja: pod nabłonkami (lamina propria), wokół naczyń i nerwów, podskórna. Funkcja: wypełnienie, obrona immunologiczna, odżywianie nabłonka.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka łączna właściwa zbita — regularna i nieregularna', 'Zbita regularna: równoległe wiązki kolagenu I → duża wytrzymałość w jednym kierunku. Lokalizacja: ścięgna, więzadła, rozcięgna. Zbita nieregularna: wiązki kolagenu w różnych kierunkach → wytrzymałość wielokierunkowa. Lokalizacja: skóra właściwa (dermis), okostna, torebki narządów, zastawki serca.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolagen — typy i znaczenie kliniczne', 'Typ I: kości, ścięgna, skóra, rogówka (90% kolagenu). Typ II: chrząstka szklista i sprężysta. Typ III: siatkowy — naczynia, narządy, razem z I. Typ IV: błona podstawna (sieć, nie włókna). Synteza wymaga wit. C (hydroksylacja Pro/Lys). Osteogenesis imperfecta: defekt kolagenu I → łamliwość kości. Zespół Ehlersa-Danlosa: hiperelastyczność.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Włókna sprężyste (elastyna)', 'Elastyna + fibrylina → włókna sprężyste. Rozciągliwe i powracające do kształtu. Lokalizacja: ściana aorty, więzadła żółte, płuca, skóra, chrząstka sprężysta. Zespół Marfana: defekt fibryliny-1 → tętniak aorty, podwichnięcie soczewki, wysoki wzrost, arachnodaktylia. Rozedma płuc: zniszczenie elastyny (elastaza neutrofilów, niedobór α1-antytrypsyny).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fibroblasty — funkcje', 'Główne komórki tkanki łącznej. Syntetyzują składniki macierzy pozakomórkowej: kolagen, elastynę, proteoglikany, glikozaminoglikany, fibronektynę. Aktywne fibroblasty: obfite RER, jasne jądro. Nieaktywne (fibrocyty): wrzecionowate, ciemne jądro. Miofibroblasty (aktyna α-gładkomięśniowa): obkurczanie ran.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Makrofagi tkankowe — nazwy w różnych narządach', 'Makrofagi pochodzą z monocytów krwi. Nazwy lokalne: komórki Kupffera (wątroba), makrofagi pęcherzykowe (płuca — „komórki kurzu"), mikroglej (OUN), osteoklasty (kość), komórki Langerhansa (naskórek — komórki dendrytyczne). Funkcje: fagocytoza, prezentacja antygenów (APC), wydzielanie cytokin (IL-1, TNF-α, IL-6).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki tuczne (mastocyty)', 'Duże komórki z licznymi ziarnistościami metachromatycznymi (toluidyna — czerwono-fioletowe). Zawierają histaminę, heparynę, tryptazę, leukotrieny, cytokiny. Receptor FcεRI wiąże IgE. Degranulacja po kontakcie alergenu z IgE → reakcja anafilaktyczna (typ I). Lokalizacja: tkanka łączna skóry, drogi oddechowe, przewód pokarmowy.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka tłuszczowa biała vs brązowa', 'Biała: jednolokularna (jedna duża kropla tłuszczu), spłaszczone jądro na obwodzie. Funkcje: magazynowanie energii, izolacja termiczna, ochrona mechaniczna, funkcja endokrynna (leptyna, adiponektyna). Brązowa: wielolokularna (wiele kropli), liczne mitochondria (kolor), UCP1 (termogenina). Funkcja: termogeneza bezdrżeniowa. U noworodków i w małych ilościach u dorosłych.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chrząstka szklista (hyalinowa)', 'Najczęstszy typ chrząstki. Kolagen II, proteoglikany (agrekan), chondrocyty w lakunach. Przezroczysto-niebieska, szklista. Lokalizacja: powierzchnie stawowe, chrząstki żebrowe, nos, krtań, tchawica (pierścienie C), oskrzela. Brak naczyń krwionośnych — odżywiana dyfuzją z ochrzęstnej. Regeneracja ograniczona.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chrząstka sprężysta', 'Podobna do szklistej + dodatkowo włókna sprężyste (elastyna) → większa elastyczność. Żółtawa barwa. Lokalizacja: małżowina uszna, nagłośnia, przewód słuchowy zewnętrzny, chrząstki krtani (rożkowata, klinowata). Otoczona ochrzęstną. Nie ulega wapnieniu (w odróżnieniu od chrząstki szklistej).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Chrząstka włóknista', 'Dużo kolagenu I (wiązki widoczne w preparacie) + mniejsze ilości kolagenu II. Brak ochrzęstnej. Chondrocyty w rzędach między wiązkami kolagenu. Łączy cechy chrząstki i tkanki łącznej zbitej. Lokalizacja: dyski międzykręgowe (pierścień włóknisty), łąkotki kolana, spojenie łonowe, przyczepy ścięgien. Wytrzymałość na ściskanie i rozciąganie.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kość zbita (korowa) — budowa', 'Jednostka strukturalna: osteon (system Haversa). Centralny kanał Haversa (naczynia, nerwy) otoczony koncentrycznymi lamelami kostnymi z osteocytami w lakunach, połączonymi kanalikikami. Kanały Volkmanna łączą osteony ze sobą i z okostną. Okostna: warstwa włóknista (kolagen) i osteogenna (osteoblasty). Stanowi ~80% masy szkieletu.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kość gąbczasta (beleczkowa)', 'Sieć beleczek (trabekul) kostnych otaczających szpik. Brak osteonów — osteocyty odżywiane dyfuzją z naczyń szpiku. Lokalizacja: nasady kości długich, trzony kręgów, kości płaskie (diploe). Powierzchnia wewnętrzna: śródkostna (endosteum — osteoblasty, osteoklasty). Osteoporoza dotyka głównie kości gąbczastej (np. złamania trzonów kręgów).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Osteoblasty, osteocyty, osteoklasty', 'Osteoblasty: syntetyzują osteoid (kolagen I + proteoglikany), mineralizacja (hydroksyapatyt). Markery: fosfataza alkaliczna, osteokalcyna. Osteocyty: dojrzałe osteoblasty zamurowane w lakunach, połączone kanalikikami — mechanosensory. Osteoklasty: duże, wielojądrowe (z monocytów), resorpcja kości (kwas + TRAP + katepsyna K). Ruffled border, Howshippy''s lacunae.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kostnienie wewnątrzbłonowe vs chrzęstne', 'Wewnątrzbłonowe (desmalne): bezpośrednio z mezenchymu (bez chrząstki). Kości płaskie czaszki, obojczyk. Osteoblasty różnicują się z mezenchymu → osteoid → mineralizacja. Chrzęstne (endochondralne): model chrząstkowy zastępowany kością. Kości długie, kręgosłup, miednica. Płytka wzrostowa: strefy spoczynku, proliferacji, hipertrofii, mineralizacji, kostnienia.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka mięśniowa szkieletowa — cechy histologiczne', 'Włókna wielojądrowe (syncytium), jądra obwodowe (pod sarkolemmą). Prążkowanie poprzeczne (sarkomery). Sarkomer: od linii Z do Z. Pasmo A (anizotropowe — ciemne, miozynowe). Pasmo I (izotropowe — jasne, aktynowe). Strefa H (tylko miozyna). Linia M (środek sarkomeru). Podczas skurczu: I i H skracają się, A nie zmienia długości.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mechanizm skurczu mięśnia szkieletowego', 'PA → cewka T → receptor DHP → aktywacja receptora rianodynowego (RyR1) na SR → uwalnianie Ca²⁺ → Ca²⁺ wiąże troponinę C → zmiana konformacji tropomiozyny → odsłonięcie miejsc aktywnych aktyny → mostek krzyżowy miozyny → cykl mostu (ATP-zależny) → skurcz. Rozkurcz: Ca²⁺ pompowane z powrotem do SR przez SERCA.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Typy włókien mięśniowych szkieletowych', 'Typ I (wolne, czerwone): dużo mitochondriów i mioglobiny, metabolizm tlenowy, odporne na zmęczenie. Mięśnie posturalne. Typ IIa (szybkie oksydacyjno-glikolityczne): pośrednie. Typ IIb (szybkie glikolityczne, białe): mało mitochondriów, szybko się męczą, duża siła. Sprinterzy. Proporcje zależne od treningu i genetyki.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka mięśniowa sercowa — cechy histologiczne', 'Komórki rozgałęzione, jedno centralne jądro (czasem dwa). Prążkowanie jak w szkieletowej. Krążki wstawkowe (intercalated discs): desmosomy (połączenie mechaniczne) + gap junctions (połączenie elektryczne — syncytium czynnościowe). Dysmorfologia serca: brak regeneracji — zastępowanie blizną po zawale. Liczne mitochondria (~40% objętości).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sprzężenie elektromechaniczne w mięśniu sercowym', 'PA → cewka T → receptor DHP (kanał Ca²⁺ typu L) → napływ Ca²⁺ z zewnątrz → aktywacja RyR2 na SR → uwolnienie Ca²⁺ z SR (CICR — calcium-induced calcium release). Ca²⁺ → troponina C → skurcz. Rozkurcz: SERCA (SR), wymiennik Na⁺/Ca²⁺ (sarkolemma). Digoksyna: hamuje Na⁺/K⁺-ATPazę → więcej Ca²⁺ → silniejszy skurcz.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka mięśniowa gładka — cechy', 'Komórki wrzecionowate, jedno centralne jądro, brak prążkowania (brak sarkomerów — aktyna i miozyna w sieciach). Skurcz: Ca²⁺ → kalmodulina → kinaza lekkiego łańcucha miozyny (MLCK) → fosforylacja miozyny → mostek krzyżowy. Wolny, toniczny skurcz. Lokalizacja: ściany naczyń, przewód pokarmowy, drogi moczowe, macica, tęczówka.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Różnice między mięśniem szkieletowym, sercowym i gładkim', 'Szkieletowy: wielojądrowy, dowolny, szybki, brak gap junctions. Sercowy: 1–2 jądra, mimowolny, gap junctions (krążki wstawkowe), CICR, automatyzm. Gładki: 1 jądro, mimowolny, brak prążkowania, MLCK-zależny, powolny, gap junctions (niektóre), plastyczność skurczu. Regeneracja: gładki > sercowy (minimalna) ≈ szkieletowy (komórki satelitarne).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Neuron — budowa', 'Ciało komórkowe (perikarion): jądro, substancja Nissla (RER), aparat Golgiego. Dendryty: liczne, rozgałęzione, odbierają sygnały. Akson: jeden, długi, przewodzi PA od wzgórka aksonu. Osłona mielinowa (komórki Schwanna/oligodendrocyty). Synapsa: zakończenie presynaptyczne (pęcherzyki), szczelina, membrana postsynaptyczna.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Klasyfikacja neuronów wg budowy', 'Wielobiegunowe: jeden akson, wiele dendrytów — większość neuronów OUN, neurony ruchowe. Dwubiegunowe: jeden akson, jeden dendryt — siatkówka, nabłonek węchowy, zwój przedsionkowo-ślimakowy. Pseudojednobiegunowe: jeden wyrostek dzielący się na T — zwoje rdzeniowe (czuciowe). Klinicznie: neuropatie dotyczą najdłuższych aksonów (polineuropatia dystalna).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Astrocyty — funkcje szczegółowe', 'Protoplazmatyczne (istota szara) i włókniste (istota biała). Funkcje: 1) BBB (stopki naczyniowe). 2) Wychwyt glutaminianu i K⁺ (zapobieganie ekscytotoksyczności). 3) Metabolizm glikogenu (rezerwowy substrat energetyczny). 4) Blizna glejowa po uszkodzeniu (glioza). 5) Regulacja synaptogenezy. GFAP — marker immunohistochemiczny astrocytów.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Oligodendrocyty vs komórki Schwanna', 'Oligodendrocyty: OUN, jeden oligodendrocyt mielinizuje fragmenty wielu aksonów (do 50). Komórki Schwanna: obwodowy UN, jedna komórka mielinizuje jeden segment jednego aksonu. Regeneracja nerwu obwodowego możliwa (komórki Schwanna tworzą tunel Büngera). W OUN regeneracja utrudniona (inhibicja przez Nogo, MAG).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mikroglej — funkcje', 'Komórki rezydentne pochodzenia mezenchymalnego (szpikowego), nie neuroektodermalnego. Makrofagi OUN. Funkcje: nadzór immunologiczny, fagocytoza szczątków komórkowych i patogenów, prezentacja antygenów, wydzielanie cytokin (TNF-α, IL-1β). Aktywacja w stanach zapalnych, udarze, chorobach neurodegeneracyjnych. Nadmierna aktywacja → neurotoksyczność.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki wyściółki (ependymocyty)', 'Jednowarstwowe komórki walcowate/sześcienne wyściełające komory mózgu i kanał centralny rdzenia. Rzęski — ruch CSF. W splotach naczyniówkowych: modyfikowane ependymocyty produkujące CSF (ultrafiltracja osocza + aktywny transport). Tanycyty: wyspecjalizowane ependymocyty w III komorze — chemosensory (glukoza, hormony).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemidesmosomy', 'Łączą podstawę komórek nabłonkowych z błoną podstawną (w odróżnieniu od desmosomów łączących komórki ze sobą). Białka: integryna α6β4, kolagen XVII (BP180), plektyna → filament keratynowy. Pemfigoid pęcherzowy: autoprzeciwciała anty-BP180/BP230 → oddzielenie naskórka od błony podstawnej → pęcherze podskórne (napięte, w odróżnieniu od wiotkich w pęcherzycy).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Substancja podstawna tkanki łącznej', 'Galaretowata, amorficzna matryca między komórkami i włóknami. Składniki: glikozaminoglikany (GAG: hialuronian, chondroitynosiarczan, heparanosiarczan, keratanosiarczan), proteoglikany (GAG + białko rdzeniowe, np. agrekan). Funkcje: uwodnienie, sprężystość, odporność na ściskanie, filtracja, bariera dyfuzyjna. Mukopolisacharydozy: brak enzymów degradujących GAG.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metaplazja — definicja i przykłady', 'Metaplazja to odwracalna przemiana jednego typu dojrzałej tkanki w inny. Reakcja adaptacyjna na chroniczne podrażnienie. Przykłady: nabłonek dróg oddechowych (wielorzędowy rzęskowy → wielowarstwowy płaski u palaczy), przełyk Barretta (wielowarstwowy płaski → walcowaty z komórkami kubkowymi — refluks). Metaplazja zwiększa ryzyko dysplazji i nowotworu.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Komórki satelitarne mięśni szkieletowych', 'Komórki macierzyste mięśniowe leżące między sarkolemmą a błoną podstawną włókna mięśniowego. W odpowiedzi na uszkodzenie aktywują się, proliferują i łączą z uszkodzonym włóknem lub tworzą nowe. Odpowiadają za regenerację mięśnia szkieletowego. Z wiekiem ich liczba maleje → zmniejszona zdolność regeneracyjna. Marker: Pax7.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tkanka łączna siateczkowata', 'Delikatna sieć włókien retikulinowych (kolagen III) z komórkami siateczkowatymi. Tworzy zrąb narządów limfatycznych (węzły chłonne, śledziona, szpik kostny), wątroby, nerek. Barwienie: impregnacja srebrem (PAS+). Fibroza: włókna retikulinowe mogą być zastępowane kolagene I (marskość wątroby).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Naczynia włosowate (kapilary) — typy', 'Ciągłe: śródbłonek ciągły + błona podstawna ciągła. Mięśnie, płuca, OUN. Okienkowe (fenestrowane): okienka (fenestry) z diafragmą. Kłębuszki nerkowe, jelita, gruczoły dokrewne. Sinusoidalne: duże, nieregularne, z przerwami w śródbłonku i błonie podstawnej. Wątroba, śledziona, szpik. Pozwalają na przejście komórek krwi i dużych białek.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pneumocyty typu I i II', 'Typ I: płaskie, pokrywają ~95% powierzchni pęcherzyków. Cienkie → ułatwiają wymianę gazową. Nie dzielą się. Typ II: sześcienne, ~5% powierzchni, ale ~60% komórek pęcherzykowych. Produkują surfaktant (ciałka blaszkowate). Komórki macierzyste pęcherzyka — regenerują typ I i II po uszkodzeniu.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Barwienie H&E — co pokazuje', 'Hematoksylina (zasadowa, niebiesko-fioletowa): barwi kwasy nukleinowe (jądra), rybosomy, RER. Eozyna (kwaśna, różowa): barwi białka cytoplazmatyczne, kolagen, mięśnie. Podstawowe barwienie histologiczne. Jądro: niebieskie. Cytoplazma: różowa. Kolagen: różowy. Erytrocyty: jasno-czerwone. Mięśnie: intensywnie różowe.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Keratyna i filamenty pośrednie — znaczenie diagnostyczne', 'Filamenty pośrednie (10 nm) są markerami różnicowania tkankowego w immunohistochemii. Cytokeratyny: nabłonek (karcynomy). Wimentyna: mezenchyma (mięsaki). Desmina: mięśnie. GFAP: astrocyty (glejaki). Neurofilamenty: neurony. Pomocne w diagnostyce nowotworów o nieznanym punkcie wyjścia (CUP — cancer of unknown primary).', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Zapalenie ostre — cechy kardynalne', 'Pięć cech zapalenia (Celsus + Virchow): rubor (zaczerwienienie — wazodylatacja), tumor (obrzęk — zwiększona przepuszczalność), calor (ciepło — zwiększony przepływ), dolor (ból — mediatory: bradykinina, prostaglandyny), functio laesa (upośledzenie funkcji). Zapalenie ostre: szybki początek, krótki czas, nacieki neutrofilowe.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie ostre — sekwencja zdarzeń naczyniowych', 'Krótkotrwałe zwężenie naczyń → wazodylatacja (histamina, NO) → spowolnienie przepływu → marginalizacja leukocytów → toczenie się (selektyny E, P) → adhezja (integryny LFA-1 → ICAM-1) → diapedeza (migracja przez ścianę naczynia) → chemotaksja (C5a, LTB4, IL-8) → fagocytoza w ognisku zapalnym.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Histamina — źródło i efekty', 'Źródło: komórki tuczne, bazofile, płytki. Uwalniana przez: IgE (alergia), C3a/C5a (anafilatoksyny), uraz fizyczny. Efekty: wazodylatacja arterioli (H1), zwiększona przepuszczalność żyłek (H1), skurcz oskrzeli (H1), wydzielanie HCl (H2), świąd (H1). Antyhistaminiki H1: loratadyna, cetyryzyna. H2: ranitydyna, famotydyna.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prostaglandyny — rola w zapaleniu', 'Kwas arachidonowy → cyklooksygenaza (COX-1/COX-2) → prostaglandyny. PGE2: ból (sensytyzacja nocyceptorów), gorączka (hipotalamus), wazodylatacja. PGI2 (prostacyklina): wazodylatacja, hamuje agregację płytek. TXA2 (tromboksan, z płytek): wazokonstrykcja, agregacja płytek. NLPZ (ibuprofen, aspiryna) hamują COX → zmniejszenie bólu, gorączki, zapalenia.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leukotrieny — rola w zapaleniu', 'Kwas arachidonowy → 5-lipoksygenaza → leukotrieny. LTB4: silny chemoatraktant neutrofilów. LTC4, LTD4, LTE4 (dawniej SRS-A): skurcz oskrzeli (100× silniejszy niż histamina), zwiększona przepuszczalność naczyń, wydzielanie śluzu. Kluczowe w astmie. Antagoniści receptora leukotrienowego: montelukast.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cytokiny w zapaleniu — TNF-α i IL-1', 'TNF-α i IL-1 (z makrofagów) są kluczowymi cytokinami zapalenia ostrego. Efekty lokalne: aktywacja śródbłonka (selektyny, ICAM), chemotaksja, aktywacja leukocytów. Efekty systemowe: gorączka (PGE2 w hipotalamusie), białka ostrej fazy (CRP, fibrynogen — wątroba), leukocytoza, kacheksja (TNF-α = kachektyna). Anty-TNF (infliksymab): leczenie chorób zapalnych.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Układ dopełniacza — szlaki aktywacji', 'Klasyczny: kompleks antygen-przeciwciało (IgM, IgG) → C1 → C4, C2. Alternatywny: spontaniczna hydroliza C3 na powierzchni drobnoustrojów → czynnik B, D. Lektynowy: MBL wiąże mannozę drobnoustrojów. Wszystkie → C3-konwertaza → C3a (anafilatoksyna), C3b (opsonizacja) → C5a (chemotaksja, anafilatoksyna) → C5b-9 (MAC — liza komórek).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie ostre — typy wysięku', 'Surowiczy: płyn ubogobiałkowy (oparzenie, zapalenie surowicze). Włóknikowy: bogaty w fibrynogen → fibryna (zapalenie osierdzia, opłucnej). Ropne (gnilne): nagromadzenie neutrofili → ropień (otorbiony) lub ropniak (w jamie ciała). Krwotoczny: uszkodzenie naczyń (meningokoki, nowotwory). Wrzodziejący: martwica nabłonka.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie przewlekłe — cechy', 'Zapalenie trwające tygodnie-lata. Jednoczesna destrukcja i naprawa tkanek. Naciek: makrofagi, limfocyty, plazmocyty (nie neutrofile). Tworzenie ziarniny (angiogeneza + fibroblasty). Włóknienie. Przyczyny: przetrwałe zakażenia (TB, wirusy), choroby autoimmunologiczne, ciała obce. Może być od początku przewlekłe (bez fazy ostrej).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zapalenie ziarniniakowe — definicja i przyczyny', 'Ziarniniak: ognisko zorganizowanych makrofagów (komórki nabłonkowate, wielojądrowe komórki olbrzymie Langerhansa). Przyczyny: gruźlica (ziarniniak serowaciejący), sarkoidoza (nieserowaciejący), trąd, kiła, choroba kociego pazura, Crohn, ciała obce (szwy, talk). Ziarniniak gruźliczy: centralna martwica serowata + komórki nabłonkowate + komórki Langerhansa.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gojenie ran — fazy', '1. Hemostaza (sekundy-minuty): skurcz naczyń, agregacja płytek, fibryna. 2. Zapalenie (1–3 dni): neutrofile, potem makrofagi — oczyszczanie. 3. Proliferacja (3–21 dni): angiogeneza, fibroblasty, kolagen, tkanka ziarninowa, naskórkowanie. 4. Przebudowa (tygodnie-lata): dojrzewanie kolagenu (III → I), obkurczanie blizny. Wytrzymałość blizny maks. ~80% normy.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gojenie pierwotne vs wtórne', 'Pierwotne (per primam intentionem): brzegi rany zbliżone (szew), minimalna tkanka ziarninowa, mała blizna. Np. rana chirurgiczna. Wtórne (per secundam intentionem): rana otwarta, duża utrata tkanki, dużo tkanki ziarninowej, obkurczanie (miofibroblasty), duża blizna. Np. owrzodzenie, ropień po drenażu.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czynniki upośledzające gojenie ran', 'Zakażenie (najczęstszy), niedokrwienie i hipoksja, cukrzyca (mikroangiopatia, neuropatia), ciała obce, niedobory żywieniowe (wit. C — kolagen, cynk — proliferacja), glikokortykosteroidy (hamują zapalenie i syntezę kolagenu), wiek zaawansowany, niedożywienie białkowe, napromienianie.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nowotwór łagodny vs złośliwy — cechy', 'Łagodny: dobrze ograniczony (torebka), wolny wzrost, dobrze zróżnicowany, nie daje przerzutów, nazwa: -oma (np. gruczolak, tłuszczak). Złośliwy: naciekanie (brak torebki), szybki wzrost, atypie, przerzuty, martwica, nazwa: -carcinoma (nabłonek), -sarcoma (mezenchyma). Wyjątki w nazewnictwie: chłoniak, czerniak, białaczka — są złośliwe.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dysplazja — definicja i znaczenie', 'Dysplazja to zaburzenie dojrzewania i organizacji komórek nabłonkowych: zwiększona mitotyczna aktywność, atypie jądrowe, utrata polarności, ale bez naciekania błony podstawnej. Stopnie: lekka (CIN I), umiarkowana (CIN II), ciężka (CIN III / carcinoma in situ). Może cofnąć się lub postępować do raka inwazyjnego. Nie jest nowotworem, ale stanem przedrakowym.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przerzuty — drogi szerzenia się nowotworu', 'Szerzenie lokalne: naciekanie (kolagenazy, metaloproteazy). Przerzuty krwiopochodne: mięsaki → żyły → płuca; guzy jelita → żyła wrotna → wątroba. Przerzuty limfogenne: raki → regionalne węzły chłonne (pierwsza stacja). Przeszczep (seeding): jama otrzewnej (rak jajnika, żołądka), CSF (medulloblastoma). Kaskada przerzutowa: odłączenie → inwazja → intravasation → przeżycie → extravasation → kolonizacja.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Grading vs staging nowotworów', 'Grading (stopień złośliwości histologicznej): G1 — dobrze zróżnicowany, G2 — umiarkowanie, G3 — nisko, G4 — niezróżnicowany. Oparty na wyglądzie mikroskopowym (mitotyczność, atypie). Staging (stopień zaawansowania): TNM — T (wielkość guza), N (węzły chłonne), M (przerzuty odległe). Staging ma większe znaczenie rokownicze niż grading.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Onkogeny — definicja i przykłady', 'Protoonkogeny to prawidłowe geny pobudzające wzrost komórkowy. Mutacja „gain of function" → onkogen → konstytutywna aktywacja → proliferacja. Przykłady: RAS (mutacja punktowa, 30% nowotworów), HER2/neu (amplifikacja, rak piersi), MYC (translokacja, chłoniak Burkitta), BCR-ABL (translokacja t(9;22), CML — chromosom Philadelphia). Działanie dominujące — wystarczy 1 zmutowany allel.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Geny supresorowe nowotworu — definicja i przykłady', 'Geny supresorowe hamują proliferację. Mutacja „loss of function" → utrata hamowania → nowotwór. Wymagane mutacje obu alleli (hipoteza dwóch uderzeń Knudsona). Przykłady: TP53 (p53 — „strażnik genomu", kontrola cyklu, apoptoza; zmutowany w >50% raków), RB (retinoblastoma), APC (polipowatość rodzinna, rak jelita grubego), BRCA1/BRCA2 (rak piersi/jajnika).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Białko p53 — funkcje', 'TP53 koduje czynnik transkrypcyjny aktywowany przez uszkodzenie DNA, hipoksję, aktywację onkogenów. Funkcje: 1) Zatrzymanie cyklu komórkowego (G1 — p21 hamuje CDK). 2) Naprawa DNA. 3) Apoptoza (Bax, PUMA). 4) Hamowanie angiogenezy. Mutacja TP53 (zespół Li-Fraumeni): zwiększone ryzyko wielu nowotworów w młodym wieku.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Markery nowotworowe — przykłady', 'PSA: rak prostaty (screening, monitorowanie). CEA: rak jelita grubego (monitorowanie, nie screening). AFP: rak wątrobowokomórkowy, guzy zarodkowe. CA-125: rak jajnika. CA 19-9: rak trzustki. β-hCG: choriocarcinoma, seminoma. Kalcytonina: rak rdzeniasty tarczycy. Markery służą głównie do monitorowania leczenia, nie do rozpoznania.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zespoły paranowotworowe — przykłady', 'Objawy odległe od guza, nie związane z przerzutami. Hiperkalcemia: PTHrP (rak płaskonabłonkowy płuca). SIADH: ADH ektopowe (drobnokomórkowy rak płuca). Cushing: ACTH ektopowe (drobnokomórkowy rak płuca). Czerwienica: erytropoetyna (rak nerki). Zapalenie wielomięśniowe/skórnomięśniowe: rak płuca, jajnika. Acanthosis nigricans: rak żołądka.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Triada Virchowa — zakrzepica', 'Trzy czynniki predysponujące do zakrzepicy: 1) Uszkodzenie śródbłonka (miażdżyca, uraz, zapalenie). 2) Zaburzenia przepływu krwi — zastój (żylna) lub turbulencja (tętnicza). 3) Nadkrzepliwość (trombofilia — czynnik V Leiden, deficyt białka C/S, antytrombiny III, zespół antyfosfolipidowy, nowotwory, OCP). Zakrzepica żylna → PE; tętnicza → zawał, udar.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zatorowość płucna (PE) — patofizjologia', 'Najczęściej zator z zakrzepicy żył głębokich kończyn dolnych (DVT). Zator blokuje tętnice płucne → wzrost oporu płucnego → ostra prawokomorowa niewydolność → spadek rzutu lewej komory → hipotensja. Masywna PE (> 60% łożyska płucnego) → wstrząs obstrukcyjny, nagły zgon. Objawy: duszność, tachykardia, ból opłucnowy, D-dimery↑. Profilaktyka DVT: heparyna, mobilizacja.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Typy zatorów', 'Zakrzepowy (najczęstszy, >95%): z DVT → PE. Tłuszczowy: po złamaniach kości długich → petechie, duszność, splątanie (po 24–72h). Powietrzny: procedury chirurgiczne, cewnikowanie, barotrauma. Płynu owodniowego: podczas porodu, DIC. Cholesterolowy (miażdżycowy): „blue toe syndrome". Nowotworowy: fragmenty guza w naczyniach. Septyczny: zapalenie wsierdzia → ropnie narządowe.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zawał — definicja i typy', 'Zawał = martwica niedokrwienna z powodu okluzji naczynia. Biały (anemiczny): narządy z jednym krążeniem końcowym (serce, nerki, śledziona, mózg). Klin z martwicą skrzepową. Czerwony (krwotoczny): narządy z podwójnym krążeniem (płuca, wątroba, jelita) lub po reperfuzji. Zawał mięśnia sercowego: podwsierdziowy (NSTEMI) vs pełnościenny (STEMI).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Martwica skrzepowa (koagulacyjna)', 'Najczęstszy typ martwicy. Zachowana architektura tkankowa (kontury komórek widoczne, ale jądra zanikają). Denaturacja białek strukturalnych i enzymatycznych. Lokalizacja: serce, nerki, wątroba, śledziona (narządy lite — zawał). Wyjątek: mózg — martwica rozpływna (liquefaction), nie koagulacyjna, z powodu dużej zawartości lipidów.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Martwica rozpływna (liquefaction)', 'Enzymy lizosomalne trawią tkankę → płynna masa. Typowa dla: mózgu (zawał mózgu → jama), ropni (neutrofile uwalniają enzymy). Trzustkowa martwica tłuszczowa: lipaza trzustkowa trawi tłuszcz → zmydlenie (saponifikacja — kredowobiałe ogniska). Martwica serowata: gruźlica — bezstrukturalna, serowata masa (lipidy + białka).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Apoptoza vs martwica', 'Apoptoza: programowana śmierć komórkowa. Kurczenie komórki, kondensacja chromatyny, ciałka apoptotyczne, brak zapalenia. Wewnętrzna (mitochondrialna, cytochrom c, kaspazy-9) lub zewnętrzna (Fas/FasL, TNF, kaspazy-8). Martwica: śmierć patologiczna. Obrzęk komórki, rozpad błony, uwalnianie zawartości → zapalenie. Nieprogramowana. Kaspazy wykonawcze obu szlaków: kaspaza-3.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Obrzęk — podział i mechanizmy', 'Przesięk (transsudate): niskie białko (< 3 g/dl), niska LDH. Przyczyny: niewydolność serca (zastój), marskość wątroby (hipoalbuminemia, nadciśnienie wrotne), zespół nerczycowy. Wysięk (exudate): wysokie białko (> 3 g/dl), wysoka LDH. Przyczyny: zapalenie, infekcja, nowotwór. Kryteria Lighta różnicują wysięk i przesięk w płynie opłucnowym.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs — definicja i klasyfikacja', 'Wstrząs = nieadekwatna perfuzja tkankowa → hipoksja komórkowa → niewydolność narządowa. Typy: 1) Hipowolemiczny (krwotok, oparzenia, biegunka). 2) Kardiogenny (zawał, tamponada). 3) Dystrybucyjny: septyczny (wazodylatacja, przeciek kapilarny), anafilaktyczny (histamina), neurogenny (utrata tonu współczulnego). 4) Obstrukcyjny (PE, odma prężna).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs septyczny — patofizjologia', 'Infekcja → SIRS (uogólniona odpowiedź zapalna) → sepsa → wstrząs septyczny. Lipopolisacharyd (LPS, gram-) → TLR4 → TNF-α, IL-1, IL-6 → wazodylatacja systemowa (NO↑) → spadek SVR → hipotensja. Zwiększona przepuszczalność kapilar → obrzęk, hipowolemia. DIC (rozsiane wykrzepianie). Niewydolność wielonarządowa (MOF). Ciepły wstrząs → zimny wstrząs.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wstrząs — fazy', 'Faza kompensacji: tachykardia, wazokonstrykcja (współczulna), oliguria (RAAS), zachowana świadomość. Ciśnienie może być jeszcze prawidłowe. Faza dekompensacji: hipotensja, kwasica mleczanowa, splątanie, oliguria progresywna. Faza nieodwracalna: niewydolność wielonarządowa (MODS), DIC, kwasica, brak odpowiedzi na leczenie, śmierć.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu I (natychmiastowa)', 'IgE-zależna. Faza uczulenia: antygen → Th2 → IL-4 → limfocyty B → IgE → opłaszczenie mastocytów. Reekspozycja: antygen krzyżowo wiąże IgE → degranulacja mastocytów → histamina, leukotrieny, prostaglandyny. Faza wczesna (minuty): wazodylatacja, skurcz oskrzeli, obrzęk. Faza późna (6–24h): naciek eozynofilowy. Przykłady: anafilaksja, astma alergiczna, katar sienny, pokrzywka.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Anafilaksja — objawy i postępowanie', 'Systemowa reakcja typu I (IgE). Objawy: hipotensja (wazodylatacja), tachykardia, bronchospazm, obrzęk krtani, pokrzywka, świąd, wymioty. Może być śmiertelna w minutach. Leczenie: adrenalina i.m. (NATYCHMIAST — α1 wazokonstrykcja + β2 bronchodylatacja + β1 serce), płyny i.v., antyhistaminiki, kortykosteroidy, pozycja Trendelenburga.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu II (cytotoksyczna)', 'Przeciwciała IgG/IgM skierowane przeciwko antygenom na powierzchni komórek. Mechanizmy uszkodzenia: 1) Opsonizacja → fagocytoza (autoimmunologiczna anemia hemolityczna). 2) Aktywacja dopełniacza → liza (reakcja poprzetoczeniowa). 3) ADCC (zależna od przeciwciał cytotoksyczność komórkowa — NK). 4) Przeciwciała anty-receptorowe: stymulujące (Graves) lub blokujące (miastenia gravis).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu III (kompleksy immunologiczne)', 'Kompleksy antygen-przeciwciało odkładają się w tkankach → aktywacja dopełniacza → rekrutacja neutrofilów → uszkodzenie tkanki. Lokalne (reakcja Arthusa): obrzęk, martwica w miejscu wstrzyknięcia. Systemowe: choroba posurowicza (gorączka, wysypka, zapalenie stawów, kłębuszkowe zapalenie nerek). Inne: SLE (DNA + anty-DNA), zapalenie naczyń, postreptokokowe GN.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Nadwrażliwość typu IV (opóźniona, komórkowa)', 'Mediowana przez limfocyty T (nie przeciwciała). Rozwija się w 24–72 h. Mechanizm: antygen prezentowany przez APC → aktywacja Th1 → IFN-γ → aktywacja makrofagów → zapalenie ziarniniakowe. Lub: CD8+ (cytotoksyczne) → liza komórek. Przykłady: test tuberkulinowy (PPD), kontaktowe zapalenie skóry (nikiel, poison ivy), odrzucanie przeszczepu, choroba Hashimoto, reakcja na leki.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tolerancja immunologiczna — centralna i obwodowa', 'Centralna: eliminacja autoreaktywnych limfocytów T w grasicy (selekcja negatywna — komórki mTEC prezentują autoantigeny, gen AIRE) i B w szpiku. Obwodowa: anergia (brak sygnału kostymulującego), supresja (limfocyty Treg — FOXP3, IL-10, TGF-β), delecja (apoptoza przez Fas/FasL). Zaburzenie tolerancji → autoimmunizacja.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Toczeń rumieniowaty układowy (SLE) — patogeneza', 'Choroba autoimmunologiczna z przeciwciałami anty-dsDNA i anty-Smith (Sm). Kompleksy immunologiczne odkładają się w nerkach (nefropatia toczniowa), stawach, skórze, sercu. Typ III nadwrażliwości (głównie). Objawy: rumień motylkowaty, zapalenie stawów, nefritis, zapalenie osierdzia/opłucnej, pancytopenia. Kobiety >> mężczyźni. ANA pozytywne (~100%), ale niespecyficzne.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reumatoidalne zapalenie stawów (RZS) — patogeneza', 'Przewlekłe autoimmunologiczne zapalenie stawów. Zapalenie błony maziowej (pannus) → destrukcja chrząstki i kości. RF (czynnik reumatoidalny): IgM anty-IgG Fc — mało specyficzny. Anty-CCP (antycytrulinowe): bardziej specyficzne. Symetryczne zajęcie małych stawów rąk (PIP, MCP, nie DIP). Guzki reumatoidalne. Manifestacje pozastawowe: płuca, naczynia, serce.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Amyloidoza — definicja i typy', 'Odkładanie się nierozpuszczalnych włókien białkowych (β-harmonijka) w tkankach. AL (łańcuchy lekkie immunoglobulin): szpiczak, gammapatia monoklonalna → serce, nerki, nerwy. AA (amyloid A osocza — białko ostrej fazy): przewlekłe zapalenie (RZS, TB) → nerki, wątroba. Barwienie: czerwień Kongo → jabłkowo-zielona dwójłomność w świetle spolaryzowanym.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('DIC (rozsiane wykrzepianie wewnątrznaczyniowe)', 'Jednoczesna aktywacja krzepnięcia i fibrynolizy. Przyczyny: sepsa (LPS → TF), powikłania położnicze, nowotwory (TF, mucyny), uraz, ukąszenia węży. Klinicznie: mikrozakrzepy → niewydolność narządowa + zużycie czynników i płytek → krwawienie. Lab: PT↑, aPTT↑, fibrynogen↓, D-dimery↑, płytki↓, schistocyty w rozmazie. Leczenie: przyczynowe + płytki/FFP w aktywnym krwawieniu.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Adaptacja komórkowa — hiperplazja i hipertrofia', 'Hiperplazja: wzrost liczby komórek (wymaga zdolności do podziału). Fizjologiczna: endometrium (estrogeny), laktacja (gruczoł piersiowy). Patologiczna: łagodny przerost prostaty (BPH), endometrium (nadmiar estrogenów → ryzyko raka). Hipertrofia: wzrost rozmiaru komórek. Serce (ciśnieniowe → koncentryczna, objętościowe → ekscentryczna), mięśnie szkieletowe (trening).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Adaptacja komórkowa — zanik (atrofia)', 'Zmniejszenie rozmiaru komórek i/lub ich liczby. Przyczyny: odnerwianie (polio → zanik mięśni), niedostateczne odżywienie, utrata stymulacji hormonalnej (menopauza → zanik endometrium), zmniejszony przepływ krwi (niedokrwienie), ucisk (guz uciskający tkankę). Mechanizmy: zmniejszenie syntezy białek, wzrost proteolizy (ubikwityna-proteasom, autofagia). Lipofuscyna w zanieczych komórkach.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Uszkodzenie komórki odwracalne vs nieodwracalne', 'Odwracalne: obrzęk komórki (zaburzenie pompy Na⁺/K⁺), obrzęk ER, utrata mikrokosmków, zwyrodnienie tłuszczowe. Nieodwracalne: uszkodzenie błony komórkowej (utrata integralności), masywny napływ Ca²⁺, obrzęk mitochondriów z gęstościami amorficznymi, rozpad lizosomów → autoliza, karioliza/karioreksja/piknoza jądra. Punkt bez powrotu: uszkodzenie błon.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Uszkodzenie reperfuzyjne', 'Paradoksalnie reperfuzja po niedokrwieniu może pogorszyć uszkodzenie. Mechanizmy: 1) Wolne rodniki tlenowe (reoxygenation injury — ksantynooksydaza, neutrofile). 2) Napływ Ca²⁺ do uszkodzonych komórek. 3) Nacieki neutrofilowe (adhezja do reaktywowanego śródbłonka). 4) Aktywacja dopełniacza. Klinicznie: po angioplastyce (STEMI), po transplantacji narządu.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Miażdżyca (atherosclerosis) — patogeneza', 'Uszkodzenie śródbłonka → retencja LDL w intimie → oksydacja LDL → makrofagi fagocytują ox-LDL → komórki piankowate → pasmo tłuszczowe → migracja mięśni gładkich → blaszka włóknisto-tłuszczowa (czapeczka włóknista + rdzeń lipidowy). Pęknięcie cienkiej czapeczki → zakrzep → zawał. Czynniki ryzyka: dyslipidemia, nadciśnienie, cukrzyca, palenie, wiek, płeć męska.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hemostaza — kaskada krzepnięcia (uproszczona)', 'Hemostaza pierwotna: adhezja płytek (vWF → GP1b), aktywacja (TXA2, ADP), agregacja (fibrynogen → GPIIb/IIIa). Hemostaza wtórna: kaskada krzepnięcia. Szlak zewnętrzny: TF + VII → Xa (PT/INR). Szlak wewnętrzny: XII→XI→IX→VIII→Xa (aPTT). Wspólny: Xa + Va → protrombina → trombina → fibrynogen → fibryna. XIIIa stabilizuje skrzep.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Białka antykoagulacyjne — antytrombina III, białko C i S', 'Antytrombina III (AT III): hamuje trombinę i czynniki IXa, Xa, XIa. Heparyna wzmacnia działanie AT III ~1000×. Białko C (aktywowane przez trombomodulynę → APC): inaktywuje czynniki Va i VIIIa. Białko S: kofaktor białka C. Niedobory: trombofilia → zakrzepica żylna. Czynnik V Leiden: oporność na APC — najczęstsza wrodzona trombofilia.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
